-- Poems batch 156
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('bde1f094-9c02-484e-965e-8eaf9342aa9c','吳參議達觀齋','樓鑰','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','君不見大鵬與鸒鳩，自適俱是逍遥游。',260,'全唐诗/poet.song.158000.json','["君不見大鵬與鸒鳩，自適俱是逍遥游。", "又不見大椿視朝菌，一脩一短終期盡。", "况乎秋豪爲大泰山小，莫壽殤子彭爲夭。", "漆園老子超衆作，立論雖奇定非矯。", "鳬脛從短鶴脛長，蠻觸亦能成戰場。", "譽堯非桀兩置之，讀書博簺俱亡羊。", "世人顛倒名利途，躋攀分寸爭錙銖。", "河伯猶驚北海若，井蛙醯雞何足誅。", "試同萬衆走城市，躍馬徒行分賤貴。", "却登高處望塵中，但見紛紛如聚蟻。", "暫高猶爾况真高，神游八表非矜豪。", "寧能高舉去人世，勿以役役隨滔滔。", "是知達人有大觀，蝶夢爲周聊自玩。", "翛然無入不自得，處若終身仕成漫。", "吳侯晚到東海濱，飽諳世故無戚欣。", "相逢一笑成莫逆，似知我亦箇中人。"]'),
('4f0d3555-e5bc-4555-84ae-dfddee228476','送姜子謙丞於潜','樓鑰','宋','宋诗','song-poetry','','[]','處則有超蓮，出則將哦松。',264,'全唐诗/poet.song.158000.json','["處則有超蓮，出則將哦松。", "眉宇無一塵，出處皆雍容。", "君看妙蓮華，本出汙泥中。", "兩松痛埽溉，下有簿書叢。", "汙潔無二致，喧寂本亦同。", "於潜今畿邑，蜀道萬里通。", "至今存古意，民風尚醇醲。", "一邑既當問，尤宜撫疲癃。", "藍田文最高，後學仰韓公。", "彼言蓋有激，昧者但稱工。", "成案漫不省，丞哉豈真聾。", "姜氏太嶽後，夷門慕家風。", "教子延名師，列碑多儒宗。", "宮庠既開荒，書種慶所鍾。", "換桂雙枝秀，益見筆研功。", "後生日加勉，衣鉢傳無窮。", "君才有餘刃，壯行氣方充。", "功名此椎輪，勁翮看摩空。", "我歸幸同社，棋酒時相從。", "尊前不忍別，吟愁夕陽舂。", "我家老揚州，五紀有遺蹤。", "向來耕織圖，爲煩訪溪翁。"]'),
('05bca7de-ec63-4243-839c-5c0f4261bd0d','送從弟叔韶尉東陽','樓鑰','宋','宋诗','song-poetry','','[]','阿連少也爽，孤立生氣燄。',288,'全唐诗/poet.song.158000.json','["阿連少也爽，孤立生氣燄。", "壯年淬詞鋒，傾心事鉛槧。", "膠庠困虀鹽，世科終穩占。", "再興連桂堂，爾祖真不忝。", "况將尉東白，士友尚歆豔。", "惟我愛子深，老矣猶不厭。", "固知爲子喜，頗亦動吾念。", "贈子當以言，苦口當針砭。", "此邑子舊游，歷歷數行店。", "棠陰見郎君，遺老喜窺覘。", "其民最服義，情僞靡容掩。", "莫恃采棒威，要使慕巾墊。", "子文多立就，詞采更華贍。", "吾聞恃俊者，塞門差反坫。", "前賢最加謹，臨用更重撿。", "他時可待取，天庭得錦掞。", "吾家有素風，耳目久濡染。", "毋庸慕豪舉，助廉先以儉。", "湎酒更宜戒，平地有深塹。", "酣暢當有時，勿習盃瀲灩。", "持論毋過高，斯言却防玷。", "立節毋務奇，躐等恐成僣。", "外物思過分，檢身但多欠。", "勿嫌一尉卑，封清尚爲傔。"]'),
('61f207a4-535e-4d4b-b5f2-25c008a11084','送制帥林和叔歸','樓鑰','宋','宋诗','song-poetry','','[]','使君一何清，鶴骨天與瘦。',288,'全唐诗/poet.song.158000.json','["使君一何清，鶴骨天與瘦。", "少年場屋聲，六藝飽芳漱。", "一行起作吏，所立已不苟。", "立朝凜大節，論事幾及霤。", "發言必體國，平正無矯揉。", "藜藿爲不採，風采照宇宙。", "出入有本末，眼見凡三就。", "來不爲苟合，薦召乃結綬。", "去亦不好高，三宿徐出晝。", "天官豈不貴，陳義堅素守。", "贛川嘗報政，復來守鄞鄮。", "不求赫赫名，實出龔黄右。", "情僞千萬端，到眼輒空透。", "撫民過嬰兒，閭里息爭鬭。", "姦胥及强梗，時用霹靂手。", "人誦南山判，情通理亦究。", "六邑俱帖靜，稱贊不容口。", "律身至嚴冷，無能掣吾肘。", "吏事精且勤，呼燭侵夜漏。", "公退入家塾，諸孫後來秀。", "吏卒不識面，洛誦出窗牖。", "幾年南塘路，來往困僵仆。", "一朝平似掌，行歌紛老幼。", "公心信如水，古井波不皺。"]'),
('3588b239-69e5-45dc-9a34-b623258436b5','賦揚州伯父海檜','樓鑰','宋','宋诗','song-poetry','','[]','潜虬拔地徑夭矯，騰拏勢出青雲表。',272,'全唐诗/poet.song.158000.json','["潜虬拔地徑夭矯，騰拏勢出青雲表。", "爲誰猶向此中蟠，坐閲春秋昏復曉。", "團團高蓋月輪平，矗矗蒼叢衆星小。", "枯槎當面結生香，外有霜皮細勻遶。", "乃知造化有神巧，散作樛枝窮樹杪。", "雖非直榦棟梁材，怪怪奇奇樂幽窈。", "獨秀海山臨浩漾，駭浪翻空雲縹渺。", "茁芽自有甘露滋，弄影幾經霜月皎。", "崢嶸老氣本天然，後生矯揉何時了。", "我家揚州真好事，買歸但覺千金少。", "夜半有力欲負之，護持和璧終歸趙。", "從來寫照無髣髴，畫師欲快毫端掃。", "解衣盤礴意慘澹，卷起生綃色徒愀。", "我來青邊立寒峭，自憐氣與秋天杳。", "倚筇一笑賓亦歡，開尊相與傾清醥。", "謂當好此如好賢，爲君三復緇衣篇。", "時時來前看不足，終待結屋平湖邊。"]'),
('b87f541c-ce42-4828-9909-556f13721b59','跋綦北海扈從書事詩','樓鑰','宋','宋诗','song-poetry','','[]','晉陽固自有高共，奉天豈可無宣公。',64,'全唐诗/poet.song.158000.json','["晉陽固自有高共，奉天豈可無宣公。", "當時扶日滄海東，尚想健筆驅長風。", "指揮諸將如奴童，中興內相當推功。", "斷碑毋庸詫詩工，制藁具在鑾坡中。"]'),
('c6ed67cf-e6a5-4479-942d-bcaa12f6ac71','送萬耕道帥瓊管','樓鑰','宋','宋诗','song-poetry','','[]','黎山千仞摩蒼穹，顓顓獨在大海中。',384,'全唐诗/poet.song.158000.json','["黎山千仞摩蒼穹，顓顓獨在大海中。", "自從漢武置兩郡，黎人始與南州通。", "歷歷更革不勝計，唐設五筦如容邕。", "皇朝聲教久漸被，事體全有中華風。", "生黎中居不可近，熟黎百洞蟠疆封。", "或從徐聞向南望，一粟不見波吞空。", "靈神致禱如響答，征帆飽掛輕飛鴻。", "曉行不計幾多里，彼岸往往夕陽舂。", "流求大食更天表，舶交海上俱朝宗。", "勢須至此少休息，乘風徑集番禺東。", "不然舶政不可爲，兩地雖遠休戚同。", "古今事變無定論，難信捐之與揚雄。", "四州隅分各置守，瓊臺帥閫尤尊崇。", "高牙大纛擁方伯，鼓吹振響驚蛟龍。", "漢家威名兩伏波，盧丁以來幾宗工。", "衛公精爽尚如生，妙語况有玉局翁。", "史君吏事素高了，明若古鏡摩青銅。", "叱馭行行不作難，平生惟仗信與忠。", "布宣王靈萬里外，益使向化來蠻賨。", "第惟遐方習疎慢，政化要當率以躬。", "霧中能見越王石，自然心服令易從。", "頑獷未率宜以漸，勿示駭政先含容。", "平平之策用定遠，下下之考書陽公。", "吏民生長固安土，尚當摩撫如童蒙。"]'),
('07cba70e-754f-48b5-b964-242400b01f40','寄題高汝一少卿識山堂','樓鑰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山之高誰不識，欲識其真了難得。',128,'全唐诗/poet.song.158000.json','["廬山之高誰不識，欲識其真了難得。", "往來山中最親切，嶺爲橫看峯是側。", "曾從彭蠡望山外，識得山南昧山北。", "山體如如本不動，人苦求之愈多惑。", "君今一堂據湓城，香爐五老皆嘉賓。", "莫問後前與向背，面目還君多識真。", "君今與山如故人，慎毋忽作白頭新。", "堂中燕坐靜且壽，君其於此知吾心。"]'),
('e83df106-4b7e-4dd2-8cf0-e4674f0fa3a3','侍仲舅同諸表游山','樓鑰','宋','宋诗','song-poetry','','[]','來游大梅山，涉山知幾重。',168,'全唐诗/poet.song.158000.json','["來游大梅山，涉山知幾重。", "平行千仞岡，俯瞰他山峯。", "一步一步高，勢欲凌虛空。", "左顧九地底，樓臺鳴鼓鍾。", "蓬萊反在下，直恐船引風。", "又疑海水竭，洞見馮夷宮。", "行行愈就順，故步尋苔封。", "十年舊主人，相對如夢中。", "清談虛閣上，坐到夕陽舂。", "年來頗畏影，掣身慕冥鴻。", "入山非不深，猶有行人蹤。", "安得更深居，尚友荷衣翁。", "未問梅子熟，寧能噉青松。", "庶幾適吾心，餘生得從容。"]'),
('00639def-8f52-4ff5-b3d4-fb81e7d8f8ab','大梅山','樓鑰','宋','宋诗','song-poetry','','[]','此山名大梅，驅車入山麓。',120,'全唐诗/poet.song.158000.json','["此山名大梅，驅車入山麓。", "試問山中人，山名竟誰屬。", "禪家開道場，爲說梅子熟。", "僊家指爲巖，曾此隠梅福。", "或云古有梅，其大蔽山谷。", "至今二梅梁，靈響皆其族。", "他山抗驚湍，禹祠橫殿屋。", "三者尚誰憑，禪師有遺躅。", "餘皆不可辨，安得究圖錄。", "但愛山又山，喬林間脩竹。"]'),
('5cd6c650-d4f1-45ab-ab79-7dfaa6d733c3','金峨漱石亭','樓鑰','宋','宋诗','song-poetry','','[]','溪聲真是廣長舌，歷劫談空聲不絕。',64,'全唐诗/poet.song.158000.json','["溪聲真是廣長舌，歷劫談空聲不絕。", "不知來自何處山，一意傾東忘萬折。", "我欲漱石向水濱，無奈齒牙摇落頻。", "夜半寒聲到客枕，只疑身是枕流人。"]'),
('0af52967-f64e-4dab-9e05-f4f24176f7aa','寄題台州倅廳雲壑','樓鑰','宋','宋诗','song-poetry','','[]','頃年登臨赤城裏，江遶城中萬家市。',224,'全唐诗/poet.song.158000.json','["頃年登臨赤城裏，江遶城中萬家市。", "治中寄我雲壑圖，快讀新詩眼如洗。", "回思歲月如星流，念念飛空尋舊游。", "披圖哦詩想幽致，直欲携筇上山頭。", "聞有於菟在岑蔚，晚徑寒鴉敢翔集。", "幾年榛棘蔽鼪鼯，一朝絕境從中出。", "細路雖非五達康，縈回自覺阻且長。", "萬壑風煙開絕頂，一丘曲折於中藏。", "老砂射日銀星炯，梅峽含風襟袖冷。", "千巖高下各異狀，如障如鋒亦如領。", "天景須憑意匠營，山不在高僊則名。", "規撫已定力未暇，他時會有滕王亭。", "風浪隔闊天垂幕，安得叩門親剝啄。", "詩成夢到故山川，睡美不知鍾鼓傳。"]'),
('f8bd8f5a-c84f-44a7-9877-706397f0df56','王原慶新遷居南堂以古風求寫恕齋二大字并石刻次韻','樓鑰','宋','宋诗','song-poetry','','[]','三槐諸孫有奇士，才高特未遇時爾。',336,'全唐诗/poet.song.158000.json','["三槐諸孫有奇士，才高特未遇時爾。", "作詩尤能備衆體，短章大篇仍雜擬。", "解紛使掉三寸舌，隨陸蘇張何足比。", "鵰鶚猶未離風塵，蛟螭尚爾蟠泥滓。", "平生曳裾向侯門，豪傑聞風競瞻企。", "只今交游亦凋落，凜凜一身嗟獨峙。", "槐陰滿庭渺何在，久寓瀛壖成故里。", "瀕湖小樓太孤露，何殊玉川洛城裏。", "邇來深入作郊居，高屋好山成二美。", "未能拔劔斬樓蘭，幾欲袖椎摧晉鄙。", "便將拂袖武陵溪，誰能著脚長安市。", "西門性急佩柔韋，柳子氣高戕曲几。", "衡宇全似歸柴桑，茅茨大勝居儋耳。", "我詩非工字尤拙，荷子愛忘剛見喜。", "夜來縱筆寫恕齋，自笑黔馿技止此。", "更求古刻訪少作，頗記醉中曾諾唯。", "舊書紛沓費搜尋，魚鑰未開塵事起。", "呼童卷送三數軸，僅可障風同故紙。", "新詩鼎來亟予和，顛字敢追張長史。", "不須更投苦海中，一笑以還隨棄毀。", "徑須携酒登南堂，朗詠白駒三四章。"]'),
('06ba4163-eb8e-4128-9c19-0f8f7d4e84cd','又次韻','樓鑰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','投老歸稱前進士，時與田夫相汝爾。',336,'全唐诗/poet.song.158000.json','["投老歸稱前進士，時與田夫相汝爾。", "淵明賦歸何敢望，曼容自免差可擬。", "門前爵羅真可設，老圃灌畦聊自比。", "恕齋空洞最相親，笑談頗覺清無滓。", "時時過我共銜盃，望望不來予爲企。", "丈夫未遇困泥塗，誰識鸞停兼鵠峙。", "方期從容結詩社，相與浮湛向閭里。", "一朝別我欲遠游，欲入桃源深洞裏。", "爲言半隠欲偕行，二子風流真儷美。", "向來早有四方志，行盡東南到邊鄙。", "只今名利遂兩忘，爭心無復於朝市。", "祇有哦詩興未闌，連得新詩照塵几。", "調高韻險不易和，白雪陽春驚俚耳。", "年登六十鬢未斑，乘興一行若可喜。", "宗盟莫逆素相忘，並轡笑談無彼此。", "湖海豪氣儘收歛，以恕名齋幾一唯。", "匆匆摻袪不得留，巵酒未乾人欲起。", "寄聲半隠不容言，空有語離書滿紙。", "歸時賡和必盈箱，寫盡山川詩作史。", "送子才歸深閉門，莫問是非并譽毀。", "但期遠歸亦升堂，西湖仍訪老知章。"]'),
('1640c0df-ea4f-4d41-8261-c9dce9435a37','送鄭楚客司法之岳陽','樓鑰','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','先生作賦真八吟，高處獨步無古今。',384,'全唐诗/poet.song.158000.json','["先生作賦真八吟，高處獨步無古今。", "少從三山來四明，一郡士子多青衿。", "我嘗學事六七載，膏馥沾丐資之深。", "竊名文場掌帝制，至今不敢忘指南。", "英英二子俱秀爽，遺以一經無籝金。", "長公奉母上巴陵，念君遠去因論心。", "見君詩編筆雖敏，三嘆未見朱弦音。", "海瀕熬波幸解組，未知宦路多嶇嶔。", "先生賦編更熟讀，非止駢儷誇詞林。", "其中關鍵妙一世，字字諧協如鳴琴。", "談經况有著述在，持論肯爲向與歆。", "青箱但能世其業，前躡雋軌將駸駸。", "君家曾無錐可卓，遲次幸此突不黔。", "不惟母老身非少，廉介又務循官箴。", "量入爲出可不謹，斤斤饑食寒有衾。", "非求多藏第約己，瓶儲紙裹迹可尋。", "法曹持平守三尺，平反一笑神所臨。", "謹毋失己毋失人，同列當和時盍簪。", "上官善事免曠職，首上尻高宜致欽。", "岳陽樓號天下稀，地坼吳楚連衡郴。", "洞庭漫汗天立壁，君山當中出青岑。", "向來命名字以楚，宦游直到重湖潯。", "登樓談笑領僚屬，風流欣遇賢侯任。", "君行應得江山助，新篇寄我毋浮沉。"]'),
('4ff10d01-377d-44a1-bb26-547b6e26c609','周伯範棋會以足疾不赴走筆寄坐客','樓鑰','宋','宋诗','song-poetry','','[]','里閭講棋社，大要率且真。',120,'全唐诗/poet.song.158000.json','["里閭講棋社，大要率且真。", "豈惟簡苛禮，正欲聚首頻。", "向來賞花約，深恐負此春。", "春來顧多事，殆如參與辰。", "今朝怡怡堂，坐上凡幾賓。", "默計病或故，約略三數人。", "益知會合難，舉酒勿問巡。", "棋枰誰勝負，清新想歌脣。", "僵卧一榻上，執熱難屈伸。", "斐然申前盟，余將踵後塵。"]'),
('53c830f3-795c-41c4-b3ba-079d409e5ef1','史清翁次前韻覓酒以金川玉友一枕瓶西安酒一斗送之次韻','樓鑰','宋','宋诗','song-poetry','','[]','社中日相從，此意豈不真。',120,'全唐诗/poet.song.158000.json','["社中日相從，此意豈不真。", "其初定要約，深期往來頻。", "今年苦多故，孤負四郊春。", "清和到新秋，其間足良辰。", "而我獨抱痾，未能會嘉賓。", "近又得玉友，風味尤可人。", "思與君痛飲，欲招復逡巡。", "忽焉得新酒，亟遣徑入脣。", "別有酒一斗，併使君意伸。", "我雖不敢嘗，爲洗胸中塵。"]'),
('3394e746-8314-4c0e-8050-88be5aa65e30','陳天成用東坡趙清獻高齋詩韻賦適齋次韻','樓鑰','宋','宋诗','song-poetry','','[]','二公晚辭軒冕勞，兩齋莫辨適與高。',160,'全唐诗/poet.song.158000.json','["二公晚辭軒冕勞，兩齋莫辨適與高。", "嘗登雲山仰清獻，平地著屋山周遭。", "白頭日過適齋下，釣游尚想隨兒曹。", "方從家舅與俱隠，野鶴誰能鳴九臯。", "加我數年未納祿，解去簪紱甘同袍。", "世間此事要識破，差處不可容一毫。", "潁川尉僊賦長句，數寸之管煩君操。", "欲追險韻繼坡老，詞鋒犀銳真吹毛。", "舅家見詩勉續貂，長松相倚慙青蒿。", "我本無復望祿仕，不應招我更由敖。"]'),
('83f3c9b2-4b4b-489a-99e1-0788fbfa923f','送元衛弟赴長亭鹽場','樓鑰','宋','宋诗','song-poetry','','[]','阿連生而秀，二親所甚愛。',264,'全唐诗/poet.song.158000.json','["阿連生而秀，二親所甚愛。", "仲兄勤拊養，遇事輒加誨。", "幹蠱靜而辦，胸次無卑隘。", "今焉職牢盆，官宇臨渤澥。", "毋謂官爲小，要使所居大。", "毋言才可了，檢身到纖介。", "我家門戶重，衣冠綿數代。", "當以誠心求，子視勿自懈。", "亭民亦良民，孰謂俱無頼。", "官吏既擾之，兼并責逋債。", "熬波亦良苦，樂歲色猶菜。", "輸鹽不得錢，何以禁私賣。", "所在積蠹久，良法浸多壞。", "吾聞不無術，更當審利害。", "熟視不爲謀，空餐媿難蓋。", "不應行一切，遽使絕稱貸。", "富者能寡取，倍息久仍在。", "貧者庶少寬，公私可緩带。", "母年登九十，家居幸康泰。", "其家不從政，禮經有深戒。", "幸子去不遠，時時可歸拜。", "小別不足惜，輕舟送前邁。"]'),
('73e840db-d9e3-4b95-95a2-c18f9f9a6b76','送從子沆宰鄖鄉','樓鑰','宋','宋诗','song-poetry','','[]','小阮幼鍾愛，長乃遭百罹。',204,'全唐诗/poet.song.158000.json','["小阮幼鍾愛，長乃遭百罹。", "風木既深痛，棣華更纏悲。", "所頼有吾子，獨立守家規。", "上有門戶託，傍有孤與嫠。", "忽爲麏國行，泝江秋爲期。", "冬澇與夏漲，漢水足險巇。", "摻袪送子去，風帆不可覊。", "城中楮爲幣，邑下尤可知。", "定知公事少，不必事作爲。", "用智正惡鑿，大道本自夷。", "家無壯子弟，宗族各天涯。", "幸有知己人，方且把一麾。", "四海皆兄弟，官寮善待之。", "眠食謹調攝，家務須自持。", "俸薄用宜嗇，無使實漏巵。", "此別動深念，毋忘故鄉思。", "一書抵萬金，時寄賓鴻歸。"]'),
('558c413e-6a9b-4ccc-88b3-e48257ca15d4','送高仲遠赴滁倅','樓鑰','宋','宋诗','song-poetry','','[]','高氏在四明，於今爲清門。',288,'全唐诗/poet.song.158000.json','["高氏在四明，於今爲清門。", "貳卿道素高，夫人德尤尊。", "子弟盡恂恂，夫君更春溫。", "昔年奉慈親，定省嚴晨昏。", "今日當門戶，友愛深弟昆。", "伉儷信緣合，端良由性根。", "門中有孤嫠，極意均撫存。", "與我親兒女，次第了嫁婚。", "不可解於心，肯自以爲恩。", "不言而躬行，後生熟見聞。", "諸郎已秀發，穎異有佳孫。", "鄉評共歸重，內外無間言。", "公勤官業廣，所至治不煩。", "僊舟何遽西，行行佐侯藩。", "環滁皆好山，風月當平分。", "醉翁與樂全，遺蹟今尚存。", "况有賢史君，易鎮方北轅。", "公餘陪嘯詠，相映如瑶琨。", "生來仕平進，自此朱兩轓。", "從兄今鼎貴，鼇禁兼掖垣。", "君其繼英躅，復收舊青氈。", "老我得投閑，頻年接清歡。", "同社摻君袪，戀戀傾離樽。", "梅風吹溽暑，祝君尚加餐。"]'),
('23fafa64-9006-48b4-98b4-97e8db337bc8','秋雨兀坐王原慶携孫吉父菊花倡和見過有分遺之意次韻','樓鑰','宋','宋诗','song-poetry','','[]','五載杜門居海角，無復翻階賦紅藥。',224,'全唐诗/poet.song.158000.json','["五載杜門居海角，無復翻階賦紅藥。", "自憐荒徑菊猶存，夕餐空待秋英落。", "眼明喜見綠叢叢，始也抽苗今滿握。", "扶筇著意養孤芳，荆棘旁連細開斫。", "天香入骨徐吐芬，中有秋風非外鑠。", "傳聞南堂有佳種，願過屠門思大嚼。", "頗亦有意欲見之，此意未容兒輩覺。", "乃知便許移芳根，不止園官供小摘。", "要令壽客來駢肩，何用潭水求延年。", "有時採之東籬邊，不覺南山在眼前。", "淵明千載幸同調，老我此際方悠然。", "西風吹花日夜急，散金坐看開田田。", "兩詩先到衡門下，思向平臺尋戲馬。", "從君九日去行樂，莫爲登高淚盈把。"]'),
('16ce496d-0701-4efd-b3cf-02595164e578','送王粹中教授入蜀','樓鑰','宋','宋诗','song-poetry','','[]','萬山四塞圍平陸，大爲關中次爲蜀。',384,'全唐诗/poet.song.158000.json','["萬山四塞圍平陸，大爲關中次爲蜀。", "我生東南未曾到，蜀士游從聞頗熟。", "自從襄陽上峻途，高欲登天下臨谷。", "女媧大山塞空虛，麻綫名堆千萬曲。", "行人一升鹿頭關，下瞰平川如畫幅。", "幅員二百四十里，里出萬緡民日蹙。", "向來陝西五路兵，退守諸關疆地促。", "計臣權宜重增賦，民力尚寬隨所欲。", "爾來因仍七十年，鬼不輸錢無雨粟。", "民生哀哉不堪命，外若富饒中不足。", "益梓尚有繁盛風，夔峽窮民幾比屋。", "側耕危穫供稅租，飯多稊稗無嘉穀。", "朝廷謀帥弄印久，宣諭尚書剖符竹。", "尚書當今第一流，翁婿相望冰映玉。", "貽書挽君爲此行，古人義槩非流俗。", "君亦慨然挈家去，摻袪未免再三祝。", "君行豈爲溫飽計，一舉高飛快鴻鵠。", "丈夫生有四方志，登覽山川非碌碌。", "頃爲假吏到燕山，未行先取山經讀。", "所至訪尋多得力，中原至今在吾目。", "北征西征昔有賦，何肯徒行空逐逐。", "子西嘗因過峴首，遐想羊公欲相沃。", "關右放賈眼拔鏃，表留卒使癰潰肉。", "試推此意向前去，到處前人有遺躅。"]'),
('9acc6193-32cd-4122-b15e-0cb037becf5f','山行歸來喜栽新竹','樓鑰','宋','宋诗','song-poetry','','[]','平生好看竹，每見覺相與。',120,'全唐诗/poet.song.158000.json','["平生好看竹，每見覺相與。", "小大或疎密，一一皆媚嫵。", "恨無地可種，所至造竹所。", "近方闢門徑，得地尋丈許。", "乞鄰栽百箇，參差正當戶。", "天公有老眼，惠以三日雨。", "山行不厭泥，但喜竹無苦。", "歸來報平安，翠葉多楚楚。", "不妨來子猷，奚必希蔣詡。", "何當遶扶疎，歲寒與君侶。"]'),
('022299ad-4d3f-46ce-887a-24a372ecf355','小溪道中','樓鑰','宋','宋诗','song-poetry','','[]','晚出城西門，循牆過南境。',48,'全唐诗/poet.song.158000.json','["晚出城西門，循牆過南境。", "夏橋日沉輝，沈店月成影。", "納納川路遥，聒聒水聲冷。", "欹枕擁衾裯，樂此寒夜永。"]'),
('21a7fb4b-687c-4179-8715-5e598d9d954a','醉題魚屏','樓鑰','宋','宋诗','song-poetry','','[]','五千買得見屏風，白魚相逐菰蒲中。',64,'全唐诗/poet.song.158000.json','["五千買得見屏風，白魚相逐菰蒲中。", "俊尾撥剌有生意，旁人未易分雌雄。", "屏後諸孫更雍容，濈濈無數迷西東。", "我雖非魚知魚樂，樂處未必魚知儂。"]'),
('70edf26e-877d-4ed1-a3e3-d7218cca8d5e','范牛','樓鑰','宋','宋诗','song-poetry','','[]','人問吾何愛一牛，范僊真筆倍風流。',32,'全唐诗/poet.song.158000.json','["人問吾何愛一牛，范僊真筆倍風流。", "繩牽雖未如自放，猶勝更著金籠頭。"]'),
('54e31abb-3d27-49dc-86eb-f20d65845557','白醉','樓鑰','宋','宋诗','song-poetry','','[]','處世難獨醒，時作映簷醉。',108,'全唐诗/poet.song.158000.json','["處世難獨醒，時作映簷醉。", "年少足裘馬，安知老夫味。", "天梳與日帽，且免供酒事。", "謫居幸三適，得此更慙媿。", "向來六逍遥，特書見清異。", "君家老希夷，相求諒同氣。", "曲身成直身，朝寒俄失記。", "醉中知其天，不飲乃同意。", "書生暫奇溫，難語純綿麗。"]'),
('916df75f-5831-4d2e-8f7d-e573dd3a85bd','贈范緯文秀才','樓鑰','宋','宋诗','song-poetry','','[]','中興道士以牛鳴，淡墨百果尤著聲。',160,'全唐诗/poet.song.158000.json','["中興道士以牛鳴，淡墨百果尤著聲。", "妙入神品仍有靈，我不識之欽其名。", "曾得烏犍兩橫軸，又有石榴才一幅。", "武昌使君舊寄詩，末言秀才乃其族。", "忽有緯文來款門，自言真是當家孫。", "口誦羅詩若翻水，他詩歷歷俱能言。", "一見前畫歎真蹟，願得生綃奮吾筆。", "爲作來禽對石榴，一掃橫枝生意出。", "我詩不工人已陳，有詩豈復能動人。", "爲君一寫史君語，更求知己如羅君。"]'),
('2295a5da-cfb6-452b-9d79-a30d92cc0fb2','送陳表道宰南豐','樓鑰','宋','宋诗','song-poetry','','[]','與客出西郊，送子之南旴。',288,'全唐诗/poet.song.158000.json','["與客出西郊，送子之南旴。", "子爲名父子，才器真璠璵。", "乃翁老從臣，循吏追兩都。", "益公工擬人，謂比王仲舒。", "積善必餘慶，于公大門閭。", "子能傳家學，何止讀父書。", "執喪真有聞，孺慕久不渝。", "彈琴不成聲，西上何徐徐。", "文場嘗得雋，一跌重歎吁。", "通籍金閨中，夷庚因少迂。", "邑中有三曾，聲名照堪輿。", "士夫秀而文，比屋多爲儒。", "萬里此發軔，胸中有全模。", "將別更求言，老馬從問途。", "乃翁同汪出，親誼崇終初。", "以規不以頌，不自知其愚。", "民社非細事，况此壯大區。", "不飲第一策，精神長有餘。", "以此奉塵剎，以此當萬殊。", "何官不可爲，禍福皆在吾。", "劇邑最爲難，謹畏可無虞。", "試看悔吝者，實惟予之辜。", "民力久已困，未免索稅租。", "欲如古什一，攻瑟難吹竽。"]'),
('01794c5f-c414-45f9-9a6f-6d2f6d64eca8','陳天成詩多和東坡韻茲因寄喜雨詩走筆謝之','樓鑰','宋','宋诗','song-poetry','','[]','一春垂垂困多雨，雖曰如膏反成苦。',320,'全唐诗/poet.song.158000.json','["一春垂垂困多雨，雖曰如膏反成苦。", "自知潦後必成旱，果見晴天雨黄土。", "連旬不雨已歎嗟，滌滌山川雲不吐。", "未聞鵓鳩鳴屋角，但有蚊蠅爭振羽。", "一梅無望望重梅，旱魃爲妖無術禦。", "閒居憂國徯雲霓，夜夜三星正當戶。", "君王側身歎凉德，雲漢之詩無媿古。", "避殿減膳率以躬，己責縱囚真有補。", "史君精禱盡誠意，千里歸心稱杜母。", "四郊神物招螉蜒，所在疲氓加手撫。", "風伯在今誠可訟，已聞石燕空中舞。", "時時小雨慰人心，渴瓦流膏僅兒乳。", "傳言望日當通濟，老巫已得靈神語。", "霈然三日果應期，靡神不舉誰爲主。", "河流頓已復舊痕，良苗喜見興南畝。", "中宵愁念不成夢，摩挲便腹眠清午。", "從今一飽便可望，坻京行見曾孫庾。", "陳侯忽就舂容篇，徑遣長須入城府。", "歎君健筆今已老，不草敕書招贊普。", "坡翁相去已百年，時出新詩追步武。"]'),
('eb2aa8d6-990d-4d30-a956-7e1ad36d7201','六月十六夜觀月翌早紀所見成長謠','樓鑰','宋','宋诗','song-poetry','','[]','海雲湧立雙鐵山，明月正在山中間。',248,'全唐诗/poet.song.158000.json','["海雲湧立雙鐵山，明月正在山中間。", "初疑渼陂藍田出水面，又似長風吹度玉門關。", "須臾雲過月愈上，太虛點綴從飛翻。", "白衣蒼狗不足究，千變萬態俱可觀。", "忽焉橫卧如蒼龍，驪珠頷下光團團。", "山河清影見歷歷，桂枝扶疎若可攀。", "夜深醉倒雞鳴起，光景不類居塵寰。", "長庚曄然朝曦發，望舒猶掛西林端。", "我欲呼吸晶華駐朱顔，左有金丹右玉丹。", "昔聞兩曜在天如磨蟻，日行日止一度慳。", "太陰行速朔必會，金餠旋復成弓彎。", "八卦萬物盡關繫，歷古不已真跳丸。", "急景戃恍難控摶，但見霞彩生斕斑。", "老我已復卦氣闌，學道無成空自嘆。", "不如安坐委天順，一聽運化更循環。"]'),
('c899d738-6eea-4bce-8ab5-9d0dd776ea02','它山堰','樓鑰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','它山堰頭足奇觀，百萬雷霆聲不斷。',352,'全唐诗/poet.song.158000.json','["它山堰頭足奇觀，百萬雷霆聲不斷。", "誰把并州快剪刀，平剪波瀾成兩段。", "四明山深水源遠，衆壑會谿長漫汗。", "滔天狂潦不少留，瀉入長江勢奔竄。", "賢哉唐家王長官，欲圖永利輸長算。", "想得慘澹經營時，下上山川應飽看。", "西偏千嶺相屬聯，惟有茲山擁東岸。", "遂於此地築橫埭，截取衆流心自斷。", "斟酌利害不全取，高下參差僅强半。", "水大十分七入江，徐挹三分供溉灌。", "支流瀰瀰穿郡城，脉絡貫通平且緩。", "旱時反此水亦足，坐使千年忘旱暵。", "無窮廟祀報元功，像設森嚴人敢玩。", "梅梁夭矯有冥助，大患于今尚能捍。", "前輩所作多神靈，日月真成赤心貫。", "後人小智或更易，費盡工夫隨破散。", "河堙盍浚謀不集，堤斷河傾流甚悍。", "富民縮手人受殃，仰望古人重興歎。", "老木號風波湛碧，畫屏俯仰丹青煥。", "更須積雨看驚湍，濡足褰裳何足憚。", "去家不遠時一游，短艇垂綸流可亂。", "八月儻有僊槎來，便欲乘之泝天漢。"]'),
('de851025-f298-47d2-a3be-c484231c40e0','林復之求僧陳君舉爲寫山谷與俞清老詩而和之次韻','樓鑰','宋','宋诗','song-poetry','','[]','歸墨氣何銳，爲儒意何闌。',48,'全唐诗/poet.song.158000.json','["歸墨氣何銳，爲儒意何闌。", "勸沮皆不可，要惟心所安。", "何必收澄觀，强欲加巾冠。", "余看飲光衣，以次傳阿難。"]'),
('3f64e90f-5708-4679-a208-345c139815c1','送秦仲防制幹','樓鑰','宋','宋诗','song-poetry','','[]','秦郎相家子，被服一寒士。',240,'全唐诗/poet.song.158000.json','["秦郎相家子，被服一寒士。", "不味膏粱珍，嗜書如嗜芰。", "仕途樂平進，欲上行或止。", "制使護瀛壖，婉畫幕中試。", "不避癡兒譏，但欲了官事。", "君賢他可及，好善無與比。", "公餘仍進學，訪問無巨細。", "片言苟有聞，必欲窮根柢。", "一介有可觀，窮閻必躬履。", "老我甘投閑，衡門人所棄。", "惟君異時好，時來訪生死。", "淡交久而敬，清談或移晷。", "一朝語余別，摻袪不容已。", "向來二三公，頗亦同臭味。", "去去群欲空，今君又行矣。", "欲歸投金瀨，尚眷甬東水。", "結交多老蒼，要路有知己。", "青氈我家舊，勉旃收上第。", "先聽傳除書，使我喜不寐。", "別後未相忘，毋愛書一紙。"]'),
('fe399075-bf72-4ab7-998d-2c9baf2da520','送蔣德常宰鄱陽','樓鑰','宋','宋诗','song-poetry','','[]','棋社頗寥落，聚會多差參。',264,'全唐诗/poet.song.158000.json','["棋社頗寥落，聚會多差參。", "矧如夫君賢，貴重雙南金。", "豈可無此君，周旋相與深。", "一別歸未久，征鞍又駸駸。", "老我苦多病，別酒難重斟。", "摻袪不可留，贈言效規箴。", "吾聞古番君，甚得江湖心。", "官無崇與庳，時無古與今。", "古人乃能爾，歛衽當致欽。", "我亦一丈夫，毋謂力難任。", "未暇言偃歌，肯彈宓賤琴。", "明恕加撫摩，細故多親臨。", "罔密吏易姦，賦重民弗禁。", "飛鴞懷桑葚，烹魚溉釜鬵。", "此邦熟往來，當有慰黎黔。", "君能踐世科，朝行佇朋簪。", "公餘昌遠業，書讀松竹林。", "故家未見書，校讎如向歆。", "時時爲尋訪，歸來共書淫。", "勿以三徑荒，閒作莊舄吟。", "勉哉赴功名，莫待二毛侵。", "數年儻加我，寒盟尚能尋。"]'),
('641099b1-3458-41bc-84ac-a5f3d4c9e084','題家藏二畫 二龍','樓鑰','宋','宋诗','song-poetry','','[]','老龍卧海沙，覺來未欠伸。',144,'全唐诗/poet.song.158000.json','["老龍卧海沙，覺來未欠伸。", "珠光發海底，闖然目有神。", "畫龍不畫全，必雜煙與雲。", "此龍未嘗動，具見爪與鱗。", "一龍望見之，爭心生怒嗔。", "奮迅勇欲前，便爾雲滿身。", "不知出誰筆，定非塵中人。", "若非親見之，何由寫其真。", "雲濤方洶湧，恍若渺無津。", "爲霖會有時，正爾良苦辛。", "乃知青雲高，不如寂寞濱。", "深虞或飛去，十襲聊自珍。"]'),
('46111a05-e446-4460-ba96-cf213f191b62','題家藏二畫 二虎','樓鑰','宋','宋诗','song-poetry','','[]','一虎弭耳行，一虎立而顧。',144,'全唐诗/poet.song.158000.json','["一虎弭耳行，一虎立而顧。", "猛鷙乃天資，亦爾相媚嫵。", "媚嫵尚眈眈，况復逢其怒。", "吾聞宣城包，今古稱獨步。", "投老筆愈精，利牙爪可怖。", "方其欲畫時，閉戶張絹素。", "磨墨備丹彩，飲酒至斗許。", "解衣恣盤礴，手足平地踞。", "顧眄或騰拏，窺之真是虎。", "捉筆一揮成，神全威不露。", "此其真是歟，爲我振蓬戶。", "藜藿將不採，何止讋狐兔。"]'),
('42b84ab0-9c65-4801-9964-e46811e9144c','送陳進道倅三山','樓鑰','宋','宋诗','song-poetry','','[]','陳侯少有場屋聲，歲在壬午聯薦名。',256,'全唐诗/poet.song.158000.json','["陳侯少有場屋聲，歲在壬午聯薦名。", "晚年倦游安里居，君亦懷綬歸家庭。", "齊年連姻更同社，臭味相與如弟兄。", "一朝話別欲遠去，洗盞更酌歌渭城。", "合沙樂土宜宦游，或謂不減洛與京。", "平分風月信可樂，人家弦誦幾連甍。", "豈惟帥閫頼關決，定知秋闈望陶成。", "西都外司掌宗盟，煩君共二爲之丞。", "勿謂爲丞但虛稱，亨途要當自此升。", "惟君儒雅聞簪纓，種學歲久筆縱橫。", "奧篇隠帙了如響，清談吐屑四坐傾。", "詩筒來往附郵傳，時出妙語人爲驚。", "梅花萬樹照山白，荔子百種輝空明。", "九門雄尊盛官府，三山森聳多地靈。", "長樂一志書不盡，平生頗恨未經行。", "煩君傑句爲摹寫，遠寄使我心神清。"]'),
('4c7442a8-aa1e-4fb6-a49a-4ad66a809ad1','送姜子謙宰鍾離','樓鑰','宋','宋诗','song-poetry','','[]','濠梁自古揚州域，禹娶塗山城尚留。',384,'全唐诗/poet.song.158000.json','["濠梁自古揚州域，禹娶塗山城尚留。", "鍾離雖嘗作楚縣，子男之國書春秋。", "卑梁爭桑起吳釁，陰陵失道除漢讎。", "嬴秦屬之九江郡，典午置郡任愈優。", "蕭梁尤重北徐鎮，高齊又爲西楚州。", "貞觀割淮疆理失，元和加水號名脩。", "陽冰篆虎書戶冊，奇畫于今照譙樓。", "浮山築堰誰與謀，漫引童謠爲激溝。", "役工沈鐵不勝計，欲灌壽陽爲廢丘。", "霧昏三日水怪出，一決空貽千古羞。", "上格下格果何在，西濠東濠猶並流。", "守邊在人不在險，險阻如故事不侔。", "元魏擁兵數十萬，義之堅守竄其酋。", "向來橫澗一失據，凜凜重貽宵旰憂。", "刺史舊带兩城使，渦口兩城今在不。", "君侯妙年筆爲投，名位詎肯卑微休。", "世科高挹更膴仕，哦松壯志未足酬。", "欲效金城上方略，宦游直到窮邊頭。", "三光五嶽氣猶分，故疆慨想何時收。", "邑事不足煩大手，往訪古今資遠猷。", "老我無用重多病，爲君相與數觥籌。", "棋社冷落故人少，況復臨風送行舟。", "看君徑赴功名會，努力自取公與侯。", "又聞魚臺在近境，誰知魚樂如莊周。"]'),
('cd87e49e-3adb-43e2-87cf-93015c9941f1','送潚丞剡川','樓鑰','宋','宋诗','song-poetry','','[]','工部丞崑丘，我生丁巳年。',288,'全唐诗/poet.song.158000.json','["工部丞崑丘，我生丁巳年。", "比吾既逾冠，再轉丞金囦。", "年齡過半百，奏子哦松軒。", "親見勤小物，如彼少壯然。", "受輸導行費，略不取一錢。", "飛糠至瞇目，猶恐勞弗宣。", "汝方壯有室，行行貳剡川。", "地近既便親，俸外有圭田。", "惟當念爾祖，奉職罔不虔。", "邑無不當問，事亦不得專。", "退無爲避事，進勿至侵權。", "莊生才不才，其間要求旃。", "去年苦旱歉，穀熟殊頗偏。", "未知催科時，何取何當蠲。", "二十七鄉民，戶口富人煙。", "去天曾不遠，美惡易以傳。", "大寧九十餘，父母俱華顛。", "況子勤幹蠱，豈不深愛憐。", "食祿須盡瘁，毋歎我獨賢。", "不應頻往來，恃有檄可沿。", "時時寄安書，何殊在目前。", "秋賦已復近，公餘更加鞭。", "金罍喜接境，一水通鄉船。", "他時儻少病，尚能催擊鮮。"]'),
('9d415fc3-be6d-48f9-88ff-d199b52050d9','送王知復宰建德','樓鑰','宋','宋诗','song-poetry','','[]','筮仕一何早，字民一何遲。',288,'全唐诗/poet.song.158000.json','["筮仕一何早，字民一何遲。", "歷歷三十年，中間多險巇。", "宦途祇平進，分寸窮攀躋。", "最後官胄監，一蹴黄金閨。", "低徊能自愛，風鷁甘退飛。", "寧爲紅蓮幕，往尋武陵谿。", "親黨多勸止，君去獨不疑。", "治家有賢媛，應門委佳兒。", "安居捨大厦，列屋間歌姬。", "風霜登客路，單車如雞棲。", "勇決有如此，端是英雄姿。", "有志事竟成，不後一年期。", "明詔趣鵷班，壯縣催瓜時。", "贏得爲君子，否泰相因依。", "古郡足蕭灑，年來困征追。", "守宰俱賢明，斯民其庶幾。", "杭葦欲走別，有足如縶維。", "舉酒向西望，離愁渺天涯。", "惟君才素高，邑若不足爲。", "謂難易將至，謂易後難支。", "老我百念冷，安能效良規。", "猶記簿領初，過庭聞舊詩。", "惟畏爲過寡，惟勤無功虧。", "遺訓儼如在，終身當誦之。"]'),
('b4672e92-bf87-435f-8466-345a2147bb23','題趙尊道渥洼圖','樓鑰','宋','宋诗','song-poetry','','[]','良馬六十有四蹄，騰驤進止紛不齊。',128,'全唐诗/poet.song.158000.json','["良馬六十有四蹄，騰驤進止紛不齊。", "權奇倜儻多不覊，亦有顧影成驕嘶。", "或行或涉更相顧，交頸相靡若相語。", "畫出老杜沙苑行，將軍弟子早有聲。", "中間名種雞群鶴，無復瘦瘡烏暮啄。", "當時玉花可媒龍，後日去盡鳥呼風。", "開元四十萬匹馬，俯仰興亡空見畫。", "龍眠妙手欲希韓，莫遣鐵面關西看。"]'),
('6df304b3-22d3-482d-949f-8c04aa2ab279','題高麗行看子','樓鑰','宋','宋诗','song-poetry','','[]','竹批雙耳風入蹄，霜鬣剪作三花齊。',128,'全唐诗/poet.song.158000.json','["竹批雙耳風入蹄，霜鬣剪作三花齊。", "相隨西去皆良種，撼首勢竄迎風嘶。", "丹青不減陸與顧，麗人傳來譯通語。", "裝爲橫軸看且行，云是韓幹非虛聲。", "圉人乘馬如乘鶴，人馬相諳同呼啄。", "中有二匹真游龍，爬梳迥立綠楊風。", "賈胡携金贖此馬，亟呼工人臨舊畫。", "我詩無分到三韓，寫向新圖時自看。"]'),
('ca61f313-6998-4e47-8b29-e170c3fb95c0','跋李少裴脩禊序','樓鑰','宋','宋诗','song-poetry','','[]','蘭亭修禊永和中，羣賢高會俱雍容。',288,'全唐诗/poet.song.158000.json','["蘭亭修禊永和中，羣賢高會俱雍容。", "右軍作序亦寓耳，藁草乃致傳無窮。", "自言疑若有神助，他日屢書終不同。", "歷代傳寶在祕府，尤其甚者唐太宗。", "當時搜取極心力，模本一一攽羣公。", "惟此真蹟最奇絕，蕭梁開皇有遺蹤。", "親御奎文賜元嘉，龍蟠鳳翥何其工。", "辯才所取祕昭陵，此本一洗凡馬空。", "崔家兄弟列清要，誨子况復稱龜龍。", "圖書四部資校讎，當時尚有貞觀風。", "自云此爲最善本，冰御臣液題甚恭。", "李王深得撥鐙法，筆力絕勁雄江東。", "右軍以來皆妙筆，名勝異代如相從。", "病餘扶憊行掃松，李君携來爲發蒙。", "平生多看舊墨本，一見使我開心胸。", "摩挲歎息不自已，至寶盍入明光宮。", "隠居懷寶正不惡，異氣或能牛斗衝。", "叩門有客勿傾倒，恐有御史來乘驄。"]'),
('a6ba1b68-24f0-4d31-a917-f7a37d8f506f','趙資政建三層樓中層藏書','樓鑰','宋','宋诗','song-poetry','','[]','危樓傑立潭府雄，仰望驚瞿何穹窿。',352,'全唐诗/poet.song.158000.json','["危樓傑立潭府雄，仰望驚瞿何穹窿。", "擎以八柱真良工，恍如木天移海東。", "扶欄三級橫復縱，八窗交映光玲瓏。", "更上一層迥不同，歷覽萬象俱空濛。", "東南太白金峩峯，西山千疊青芙蓉。", "環遶不斷如屏風，平疇彌望禾芃芃。", "城郭市井聚螘蜂，煙樹高低知幾叢。", "澄湖一片磨青銅，潮來江漲銀在鎔。", "海匝三垂屬提封，四山寬圍城在中。", "地平樓小望易窮，安得高卧陳元龍。", "麗譙公府難從容，二閣均在道佛宮。", "江山得助無遺蹤，眼前突兀忽此逢。", "主人榦國成棟隆，鼎彜久書柱石功。", "名遂身退茲明農，卜築深靜依高墉。", "百間朗朗羅心胸，咄嗟不待鼛鼓鼕。", "最後奇觀凌虛空，窗戶未須濕青紅。", "似聞廬陵周益公，亦作此樓高於崧。", "相望落落見兩翁，心匠不謀如影從。", "我欲效顰意方濃，一朝登眺若發矇。", "不願侍公飲千鍾，不願舞女紛歌僮。", "插架三萬牙籤重，此身願爲書蠹蟲。", "不然相陪夕陽舂，與公憑欄送冥鴻。"]'),
('c1a5cac9-4459-4d0e-88a9-1025d03b3b38','再題行看子','樓鑰','宋','宋诗','song-poetry','','[]','先引護欄毬子驄，九馬近遠俱相從。',322,'全唐诗/poet.song.158000.json','["先引護欄毬子驄，九馬近遠俱相從。", "黑駒騧黄騅素騮，亦有笏面仍銀鬃。", "夏國一種青於藍，五明錯靴皆如龍。", "或驂或引恣馳驟，坐覺隠耳聲瓏瓏。", "人間安得有此輩，一一必自天閑中。", "不惟骨相異凡馬，圉人貴介多雍容。", "三花翦鬣自官樣，空鞍更以香羅幪。", "中間二者蓋天馬，齒雖已老氣尚雄。", "不知幾出橫門道，雙立柳下青陰濃。", "擡韁捽頷刷背膂，旋梳鬃尾摇清風。", "人人生意馬欲動，態度曲盡各不同。", "韓生去我幾百年，藻色尚濕青與紅。", "不知何時墮雞林，萬里遠在東海東。", "賈人携來得寓目，一見絕歎丹青工。", "千金可買真不惜，忽復携去何匆匆。", "亟令臨寫得形似，如此神駿那得逢。", "開元內外馬盈億，色別爲群從登封。", "韓生所貌定傑出，七尺爲騋八尺駥。", "向來鶑邊繫金狨，歸乘款段頭已童。", "伏櫪寧能志千里，却笑區區據鞍矍鑠翁。"]'),
('7e5dd2e9-35ec-403f-a1d5-6f31eb2fa642','寄題吳漢英玩芳亭','樓鑰','宋','宋诗','song-poetry','','[]','吳侯奕奕天分高，歷記萬卷無差毫。',128,'全唐诗/poet.song.158000.json','["吳侯奕奕天分高，歷記萬卷無差毫。", "青雲垂上忽歸去，年來益收湖海豪。", "志同三閭時則異，玩此芳物亭之臯。", "視彼顦顇亦何苦，鼻間栩栩忘鬰陶。", "詩文滿軸寄海嶠，靈均細論無乃勞。", "與君齊年況同袍，祇今衡門沒蓬蒿。", "有芳可玩便自適，草間野卉時一遭。", "蘺芷辛夷蘭杜若，未暇一一追離騷。"]'),
('35641228-a915-42bc-b50c-248b9f0eb0d9','送孫子祥赴新昌主簿','樓鑰','宋','宋诗','song-poetry','','[]','高士不爲簿，子嚴論獨殊。',204,'全唐诗/poet.song.158000.json','["高士不爲簿，子嚴論獨殊。", "不遭何不可，而況主簿乎。", "夫君豈其裔，南明筮仕初。", "要知官無卑，祿可代耕鋤。", "正須勾小稽，使民能樂輸。", "矧復兼尉曹，鼠竊隨除驅。", "兩職去民近，亨途此權輿。", "君誠吾里秀，賢厚素有餘。", "埋蛇有陰德，映雪讀古書。", "起家決儒科，鄉評足名譽。", "妻以兄之子，相與久相娛。", "小別不足惜，未免摻子袪。", "邑境連台剡，好山環四隅。", "二子丞鄰封，川陸通舟車。", "乘興或一往，徑欲造庭除。", "公餘想績文，尤當惜居諸。", "會看興公賦，擲地金聲如。"]'),
('caa8ff5e-4185-4819-b424-1daa7981cfbc','送淳丞上虞','樓鑰','宋','宋诗','song-poetry','','[]','我老不復仕，行將掛衣冠。',288,'全唐诗/poet.song.158000.json','["我老不復仕，行將掛衣冠。", "兩子俱貳令，官職恰一般。", "剡川且書考，上虞亦之官。", "人言易捧檄，歸奉重親歡。", "我意正不爾，期汝政可觀。", "食焉怠其事，古訓戒捨鏝。", "汝職去民親，簿書當細看。", "一邑無不問，正爾良獨難。", "江海匝三垂，長隄捍驚湍。", "埭高幾如山，潮至不留殘。", "宣和有遺迹，能使潮浸灘。", "陂湖謹蓄洩，可以救旱乾。", "長溝濟漕運，浚治令通寬。", "此皆丞所職，勿憚心力殫。", "江頭有東山，永懷謝家安。", "邑有李與豐，況復居二潘。", "尚友更從游，問學加研鑽。", "平時固知汝，廉謹無欺謾。", "涉世終未深，送汝能忘言。", "故鄉去帝鄉，舟馭多往還。", "失己固不可，待人亦多端。", "罔求違道譽，善遣非意干。", "窮達自有時，此理真如丹。", "聚散不足較，豈得長團欒。"]'),
('b6776dac-0f91-4dfb-b691-2d95fbb49806','送伯中弟尉新喻','樓鑰','宋','宋诗','song-poetry','','[]','伯父盛德人，伯中實暮子。',240,'全唐诗/poet.song.158000.json','["伯父盛德人，伯中實暮子。", "不惟能象賢，氣貌亦相似。", "幼日讀父書，結字得皮髓。", "粹然金玉姿，少日期千里。", "寧知游上庠，蹉跎困名第。", "晚始著青衫，酸寒就一尉。", "欻然報瓜時，往戍真樂事。", "自惟群從希，惜別不能已。", "中年重離別，況我衰如此。", "親故例作惡，況復於吾弟。", "茲行豈得休，雅懷聊漫仕。", "勿憚三年留，江南富山水。", "尉曹官雖卑，去民最密邇。", "一日斯必葺，職務毋少弛。", "善保金石軀，離觴且同醉。", "歸來畢婚嫁，相從期暮齒。", "教子以義方，忍貧授經史。", "素業俱有傳，見進未見止。", "大兒方決科，如摘頷髭耳。", "子尚徐其驅，中途聽捷喜。"]'),
('e4db02d1-0154-4ada-824d-9811badb9eb8','送張子宓分教澧陽','樓鑰','宋','宋诗','song-poetry','','[]','澧陽渺何許，遠在天盡頭。',288,'全唐诗/poet.song.158000.json','["澧陽渺何許，遠在天盡頭。", "頃爲郡樓記，圖志不可求。", "王侯錄故實，頗亦費冥搜。", "忠以申明著，學有車公優。", "外挹蘭江水，下俯僊明洲。", "讀書記群玉，採藥思浮丘。", "況得子厚語，謂冠漢南州。", "見謂頗詳盡，豐碑照城陬。", "可憐城與樓，百姓不知修。", "乃知尚有遺，家傳載鄴侯。", "張君將客授，蓋嘗敘其由。", "爲我謝澧人，聊以遮前羞。", "君家世爲儒，青箱襲箕裘。", "太玄洎潛虛，探賾深可鈎。", "君才兼數器，博洽誰與儔。", "南廟推第一，鵰鶚快九秋。", "得官愈嗜學，手抄不能休。", "館殿要人物，衆寶登琳璆。", "演綸及視草，如君真勝流。", "蘭芷生顔色，暫煩爲遠游。", "君方俟瓜時，相依意綢繆。", "樽酒接從容，詩篇更唱酬。", "論文究今昔，析理到孔周。", "老我澹無伴，摻袪不容留。"]'),
('b7cdd7c1-ee71-440d-a3e0-72f53e9cf7c3','送周君可宰會稽','樓鑰','宋','宋诗','song-poetry','','[]','作邑誠匪易，況子之稽山。',288,'全唐诗/poet.song.158000.json','["作邑誠匪易，況子之稽山。", "銀茜視兩赤，朝家知其難。", "鼎鼎數萬戶，賦重民生囏。", "山陵五雲飛，辦護力更殫。", "預買萬世敝，法貪至於殘。", "越人瘠已甚，當饋幾發歎。", "名臣爲竭力，減額宜少寬。", "不齊物之情，茲事終變翻。", "箕歛及雞豚，詭戶多容姦。", "竟未得要領，條令何其煩。", "通才善剸劇，南康遂通班。", "誠心試求之，要使後可觀。", "古仕不出鄉，習俗皆素閑。", "東嘉嘗客授，尋乃乘朱轓。", "略如仕於鄉，非意不得干。", "況昔攝邑久，疾苦知民間。", "故吏想猶在，疲氓知長官。", "宜若差易耳，未免送以言。", "權雖與正同，事體終兩般。", "趣辦不計久，爲真事多端。", "遇事勿生風，三思庶能安。", "試登寬簡堂，取我前碑看。", "六一真格言，坐右當銘盤。", "向來難奉母，版輿今似潘。"]'),
('cf0f3a2c-a19f-4734-bc52-a1df962e49f3','錢清王千里得王大令保母磚刻爲賦長句','樓鑰','宋','宋诗','song-poetry','','[]','書家千載稱蘭亭，蘭亭真蹟藏昭陵。',368,'全唐诗/poet.song.158000.json','["書家千載稱蘭亭，蘭亭真蹟藏昭陵。", "只今定本誇第一，貞觀臨寫鎸瑶瓊。", "黄閍岡下得寶墨，古人燒磚堅於石。", "大令親書保母銘，况是當時晉人刻。", "磚雖破裂文多全，妙畫遠過蘭亭鎸。", "其間曲水悲夫字，駸駸欲度驊騮前。", "我家阿連縛虎手，更得退堂方外友。", "王君系出三槐家，參坐會文真耐久。", "田丁初來獻小硯，尋見津津若微溜。", "細看背刻晉獻之，永和彷佛在旁右。", "亟訪田家叩所從，始知墓崩隨意取。", "大磚支牀得前段，掀倒浮屠全尾首。", "字爲十行行十二，百十有七二字漏。", "交螭方壺不復見，貞石摧藏松亦朽。", "我得此碑喜不寐，摩挲三歎歎未有。", "興寧甲子十四周，更閲三年仍乙丑。", "若非洞曉未來數，安知八百餘年後。", "坡翁應未見此志，金蟬之銘何絕類。", "又知文章有暗合，智謀所見略相似。", "二王遺蹤無所遺，誰知地下此段奇。", "三君共爲成勝事，至寶呈露端有時。", "越山盤屈獻與羲，付與耳孫世守之。", "煩君更爲護幽竁，或恐意如猶有知。"]'),
('2d1629ed-d6f8-4ecc-a252-dd41948fde65','趙資政招賞川海棠次袁和叔韻','樓鑰','宋','宋诗','song-poetry','','[]','少陵千古詩人傑，每見名花輒題絕。',208,'全唐诗/poet.song.158000.json','["少陵千古詩人傑，每見名花輒題絕。", "錦棠無如蜀川盛，見說千林天染纈。", "大篇短章合無數，忍對此花舌如結。", "黄鵠銜子萬里來，春光頗向東南洩。", "槹閒老子携春歸，移石鬰林表高潔。", "崇桃炫晝不足言，紅艷燒林疑益烈。", "棠梨小紅自退聽，不待騷人定優劣。", "兩登蜀道歸海濱，一琴一龜全晚節。", "嘉招容我到花下，春酒新篘公自挈。", "攀翻亂插人共醉，十二金釵不成列。", "袁安參坐爲長哦，同氣相求磁石鐵。", "不須高燭映紅粧，佳月自能明作哲。", "紅潮滿頰卧林間，風流誰敢來分別。"]'),
('6358dd26-b5f7-441e-9632-b23f402e9cb2','泉口浄明院晝寢','樓鑰','宋','宋诗','song-poetry','','[]','沙頭古招提，往來幾經行。',168,'全唐诗/poet.song.158000.json','["沙頭古招提，往來幾經行。", "茲來當春晝，解衣愒西楹。", "玉立青琅玕，小窗虛且明。", "紙帳白如雪，牀軟枕更平。", "偃仰四體適，欠伸困思生。", "須臾右脇卧，徑入華胥城。", "無人夢自覺，閴然四無聲。", "林間婆餠焦，悠悠時一鳴。", "翻身更從容，意泰氣亦清。", "連朝走丘壟，百拜不遑寧。", "老我久倦游，幸茲息營營。", "衰相益已迫，世念日愈輕。", "自欣天與閒，身是半髮僧。", "未能遂高隠，庶幾保餘齡。"]'),
('006e9223-0b3d-464f-a900-174139f25698','賦蔣甥若水番馬圖','樓鑰','宋','宋诗','song-poetry','','[]','何處驅來良馬六，騮黄參錯如花簇。',164,'全唐诗/poet.song.158000.json','["何處驅來良馬六，騮黄參錯如花簇。", "胡爲不作騰驤去，各有游韁縶前足。", "胡人下馬俱少休，背倚氈裘眠正熟。", "酋豪揀箭奚奴撚，意欲射麞不遺鏃。", "琵琶橫倚續續彈，一夫坐聽胡中曲。", "卧擁提壺將引飲，英氣虬鬚皆貴族。", "沙磧坡陀高復低，天寒不見寸草綠。", "我行燕薊頗見之，狼帽烏靴乃其俗。", "勿云恃勇不知義，要以赤心置其腹。", "嗚呼安得壯士健馬咸作使，坐令戎虜爲臣僕。"]'),
('1cf7f590-97e8-44cb-86dc-257b062d887a','陳表道惠米纜','樓鑰','宋','宋诗','song-poetry','','[]','平生所嗜惟湯餠，下箸輒空真雋永。',192,'全唐诗/poet.song.158000.json','["平生所嗜惟湯餠，下箸輒空真雋永。", "年來風痹忌觸口，厭聞來力敕正整。", "江西誰將米作纜，捲送銀絲光可鑑。", "仙禾爲餠亞來牟，細剪暴乾供健啗。", "如來螺髻一毛拔，卷然如蠆都人髮。", "新絃未上尚盤盤，獨繭長繰猶軋軋。", "旴江珍品推南豐，荷君來歸携來東。", "知君正直如羔羊，貽我素絲踰五總。", "仙禾本出從嘉穀，色味俱同無餠毒。", "鼎深熟煮葱豉香，大美元年加臠肉。", "有時飯素芼以虀，饞口屬饜味更奇。", "束晳一賦不及此，爲君却作補亡詩。"]'),
('39e3de7c-077c-4f09-8170-7b4822d54ebc','盧甥申之自吳門寄顔樂間畫牋','樓鑰','宋','宋诗','song-poetry','','[]','年來吳門箋，色澤勝西蜀。',132,'全唐诗/poet.song.158000.json','["年來吳門箋，色澤勝西蜀。", "春膏最宜書，葉葉瑩栗玉。", "賢甥更好奇，惠我小畫幅。", "開緘粲殷紅，展玩光溢目。", "巧隨砑光花，傅色濕丹綠。", "桃杏春共嫵，蘭桂秋始肅。", "趙昌工折枝，露華清可掬。", "妙手真似之，臧去不忍觸。", "苟非歐虞輩，誰敢當簡牘。", "又聞樂間君，古篆頗絕俗。", "併求數紙書，寄我慰幽獨。"]'),
('9de2fba5-fbbe-4b00-93ff-d1d4ff34f967','題申之寄示春郊畫軸','樓鑰','宋','宋诗','song-poetry','','[]','郊原膴膴春意足，細草淒迷芳樹綠。',64,'全唐诗/poet.song.158000.json','["郊原膴膴春意足，細草淒迷芳樹綠。", "鴈鶩無數泛陂塘，羊牛相與隨芻牧。", "幾年不泛浙西船，恍如蘇臺俯平川。", "閑人憂國無他策，但願好雨成豐年。"]'),
('419e30b1-01da-48e5-b308-5b26a3b3973b','六言問天池寶華','樓鑰','宋','宋诗','song-poetry','','[]','昔年曾賦虎丘，猶恨靈巖未游。',56,'全唐诗/poet.song.158000.json','["昔年曾賦虎丘，猶恨靈巖未游。", "天池之景絕勝，寶華有水倒流。", "老矣不復西去，夢入陶朱扁舟。", "煩君爲我尋訪，能以新詩寄不。"]'),
('f4b1bc90-25bb-4d3d-9e15-811ccf31f6a5','贈成都魯講書','樓鑰','宋','宋诗','song-poetry','','[]','君家江發源，我生瀛之壖。',264,'全唐诗/poet.song.158000.json','["君家江發源，我生瀛之壖。", "相望萬里外，中間幾山川。", "近聞今子敬，文價驚鸞鵷。", "何由夢見之，失喜瞻在前。", "幅巾聳英標，銜袖出文編。", "倒屣平生歡，劇談河漢懸。", "老我三入朝，廣識兩蜀賢。", "相與論諸公，與君最周旋。", "自言隠太城，讀書三十年。", "城中竹谿居，肥遯遠市廛。", "清谿擁屋後，綠樹環前軒。", "一舟號橫雪，可泝復可沿。", "拂衣下三峽，非爲名利牽。", "灧澦追古作，海潮賦新篇。", "舊依槹閒公，來乘甬東船。", "顧我何所取，有懷俱盡言。", "老親苦多病，嘗藥冀少痊。", "佳客不容留，欲著歸驂鞭。", "間爲惡草具，願君少留連。", "報無錦繡段，贈有朱絲絃。", "一別無復會，摻袪意茫然。", "蜀山渺何許，同聲惟杜鵑。"]'),
('a6cd8bab-3272-41fc-869a-1ed207ab437e','趙資政當山堂','樓鑰','宋','宋诗','song-poetry','','[]','我公仁存心，樂山心如丹。',264,'全唐诗/poet.song.158000.json','["我公仁存心，樂山心如丹。", "平生經行處，不厭行路難。", "青城及大面，萬疊連百蠻。", "捫參仰脅息，亦嘗坐長歎。", "功成歸四明，得地數畝慳。", "城隅路窮際，小橋水汪灣。", "蕭條漁家市，中有屋百間。", "危樓俯人世，一看山四環。", "堂深無他景，猶以城當山。", "城荒披綠莎，青青透槹閒。", "秀潤長滿門，坐對無躋攀。", "日夕氣亦佳，鳥飛相與還。", "終日看不厭，徙倚十二欄。", "有如擁泰華，管窺見一斑。", "况茲綠陰成，連朝雨潺潺。", "濃翠真欲滴，秀色幾可餐。", "我家但環堵，窮年困彎跧。", "出門得曠望，遥碧羅煙鬟。", "有時碧雲湧，半空聳商顔。", "須臾輒變滅，欲駐良亦艱。", "羨公得佳趣，容我游其藩。", "悠然時見之，重門勿令關。"]'),
('2c9f7600-079d-4d83-ba13-78864c24145c','風琴','樓鑰','宋','宋诗','song-poetry','','[]','淵明有琴本無絃，白傅偏喜聽人彈。',176,'全唐诗/poet.song.158000.json','["淵明有琴本無絃，白傅偏喜聽人彈。", "不如空中風度曲，隨風往來聲斷續。", "非宮非商從君聽，不中律呂無虧成。", "大如角韻來孤城，細似蚓竅蒼蠅聲。", "華亭夜鶴圓吭清，顫動長引寒蟬鳴。", "或疑鳳咮叫霄漢，又恐僊佩雲中行。", "使其似曲無別調，安得自在聲泠泠。", "蛙喧尚謂勝鼓吹，牛鳴猶以黄鍾稱。", "絲不如竹亦漫語，頼此七竅俱瓏玲。", "幽人院靜新涼生，八風不問來縱橫。", "短簟六尺午睡足，彷彿神來傳廣陵。"]'),
('b480c2d4-3082-468f-a01a-2f88c22be3c3','寄題臨江徐祕閣儒榮堂','樓鑰','宋','宋诗','song-poetry','','[]','滄水海豹來京畿，繫裙堯舜深惡之。',364,'全唐诗/poet.song.158000.json','["滄水海豹來京畿，繫裙堯舜深惡之。", "元祐政和能幾時，女真航海來乞師。", "以燕伐燕夷攻夷，吾國何與潛與期。", "島夷日張耶律卑，城門失火殃魚池。", "督亢雖入空無貲，免夫賦及東南垂。", "廟謨顛倒幾逆施，中原丘墟責誰尸。", "高皇匹馬興渙濉，南巡國步尤阽危。", "神旌北指虜屢隳，天雖悔禍庭未犂。", "兩邦交聘玉節馳，廿年不見紅旌旗。", "狂胡窮凶不自知，意欲投箠凌江湄。", "安知送死蕪城西，倒戈勢如蟻潰隄。", "三年拜賜無能爲，再尋和議平創痍。", "中間紀載紛是非，顛末不備多懷私。", "痛定泣血作者誰，僉言亂華疑傳疑。", "徐君憂世老不衰，會粹衆作無棼絲。", "東觀直筆多所資，蓬萊漢閣生光輝。", "儒榮名堂本訓辭，大書流詠見豐碑。", "我昔假吏陪琬圭，故宮禾黍傷離離，洪河大山望而悲。", "壯士無數胡馬肥，謂國有人何至斯。", "此心耿耿淚自揮，年運而往不可追。", "因君來覓儒榮詩，感觸義槩矢以詞。", "無由縱覽讀書帷，願得版行用激臣子無窮思。"]'),
('8d91bc57-e434-415b-898d-acbc2f66dc3f','送袁恭安赴江州節推','樓鑰','宋','宋诗','song-poetry','','[]','袁氏四世凡五公，唐朝三相傳家風。',288,'全唐诗/poet.song.158000.json','["袁氏四世凡五公，唐朝三相傳家風。", "君家幾代擅儒業，高曾藝苑俱稱雄。", "大父謙尊古君子，諸父名高表吾里。", "一門子弟更競爽，挹取乙科自君始。", "九江需次今幾年，去去淥水依紅蓮。", "忘年論交正相予，叱馭欲往難留連。", "老我秋來抱病久，臨岐無由置尊酒。", "祇從卧內敘離懷，戀戀摻袪仍握手。", "鵬程萬里茲權輿，平時義方師有餘。", "送人以言古所重，雖誦所聞寧起予。", "君看公孝與孟博，太守坐嘯仍畫諾。", "一郡之政頼關決，千里應須念民瘼。", "鄉州義事煩主盟，纖悉於余無隠情。", "處事條理亦爲政，知君出仕當有聲。", "尊公亦入閩中幕，公退著書端不惡。", "君才更得江山助，簡書既省尋家學。", "君行遠業未可量，弟兄丹桂終齊芳。", "老悖無庸況多病，尚能留眼看翱翔。"]'),
('7fd6bc06-1bd8-4a7c-ac5b-4cd707798837','趙南仲寄王朴畫貓犬戲爲之賦','樓鑰','宋','宋诗','song-poetry','','[]','䰐鬖兩狻猊，胡爲到庭戶。',120,'全唐诗/poet.song.158000.json','["䰐鬖兩狻猊，胡爲到庭戶。", "細觀畫手妙，模寫真態度。", "意足謝繁筆，不待丹青汙。", "亂掃腹背毛，頭足巧分布。", "尨也如愁胡，眉攢眼光注。", "豈惟足生氂，垂耳紛敗絮。", "掉尾固自若，狸奴爲驚瞿。", "側耳實畏之，衝目猶敢怒。", "誠知取形似，不吠亦不捕。", "對之輒一笑，聊用慰沈痼。"]'),
('adadcca8-1028-49e6-b772-17644a45bf54','朱季公寄詩有懷真率之集次韻','樓鑰','宋','宋诗','song-poetry','','[]','伊昔羊尹臨丹陽，真率之名初濫觴。',288,'全唐诗/poet.song.158000.json','["伊昔羊尹臨丹陽，真率之名初濫觴。", "香山尚齒當會昌，卧雲不羨坐巖廊。", "七人各列官與鄉，年德俱高世所臧。", "丙午同甲遥相望，清談生風想琅琅。", "耆英人物尤軒昂，賦詩遠追白侍郎。", "文富歸休壽而康，衣冠十二何鏘鏘。", "吾鄉五老如鴈行，至今月評尚推揚。", "家舅仕宦接王楊，眉壽遂及渭水姜。", "我如傷禽趁鸞凰，忽驚騎箕歸銀潢。", "向來雅約猶寶藏，菜羹草具烹彘肪。", "四皓中間有夏黄，藹藹義風誇句章。", "年來抱痾久在牀，同社闊別如河梁。", "君嘗遠宦踰沅湘，又向封川憇甘棠。", "瘴雨蠻煙暗桄榔，何時歸安朝士坊。", "忽傳新詩几生光，歛衽正色而寒芒。", "詩境幾成破天荒，徐爲續貂未須忙。", "靜揣歸期應未央，歸縱未衰亦老蒼。", "莫年甘與子同裳，何事相望天一方。"]'),
('d965556d-d4b5-4e8b-a93c-3a99ec8ce6b9','吳少由惠詩百篇久未及謝又以委貺勉次來韻','樓鑰','宋','宋诗','song-poetry','','[]','江左一世稱名公，首出劉惔與王濛。',384,'全唐诗/poet.song.158000.json','["江左一世稱名公，首出劉惔與王濛。", "自高直以天自况，何止數仞言高墉。", "虛聲一傳實何在，但知景附而風從。", "我朝諸公門戶闊，普納萬象如虛空。", "羣才俱入大鑪鞴，鑄人端如金在鎔。", "又如東君一布令，白者自白紅自紅。", "巖巖千載玉局老，少年徑以吾道東。", "首干樂全次六一，二公自是燕許宗。", "奏篇六論初流傳，四海一日俱承風。", "其間傑出六君子，香薰班馬尤爲濃。", "涪翁又分江西派，作圖序次由本中。", "哦詩作文各務實，薦鶚不媿北海融。", "坐令文物掩前代，主盟豈非諸老功。", "固知文氣僵湜籍，亦許詩律沾徐洪。", "宛丘諸黄接前輩，宜有此甥風味同。", "蚤嘗決勝翰墨場，筆端豪健誰爭工。", "新篇句句多灑落，妙畫字字真玲瓏。", "惜哉生晚百餘載，歐蘇之門欠登龍。", "尚茲踸踔未闊步，吞舟之魚溝豈容。", "我方投老與世隔，映窗愛景方朣朧。", "十年屏居可羅爵，何人來顧一禿翁。", "儼然衣冠見吾子，文書銜袖名自通。", "向來兩卷餘百篇，諷味抵今未能窮。", "更携大篇如拱璧，刻畫無鹽賁孤蹤。"]'),
('1405e3a2-ab72-4fc0-bbc3-9c3645dccd0a','龍潭丈室一筍穿入露滿其上因賦之','樓鑰','宋','宋诗','song-poetry','','[]','一筍入屋照座寒，凌晨仍有清露漙。',64,'全唐诗/poet.song.158000.json','["一筍入屋照座寒，凌晨仍有清露漙。", "益信露珠自根起，正如真水朝泥丸。", "厦屋不應爲汝穿，不肯屈節斜倚欄。", "干霄拂雲已在望，且復自保青琅玕。"]'),
('42b15db7-4764-4e56-afe3-0e2e68e26c2e','旱久無水王伯容分惠桃源大谿泉將以長篇水至已雨走筆次韻','樓鑰','宋','宋诗','song-poetry','','[]','七十老翁門晝閉，終日蕭然無一事。',278,'全唐诗/poet.song.158000.json','["七十老翁門晝閉，終日蕭然無一事。", "却因不雨動衰懷，擁笏黄堂與祠祀。", "兼旬旱涸舟不通，井泉欲竭知無計。", "僮奴抱甕扣比鄰，水不得清僅無滓。", "舊時見說橫谿源，有水側出萬竹前。", "考之爾雅名汍泉，頗思走介分微涓。", "去之一驛不易到，午暑坐想空垂涎。", "不知何人剝啄扣我門，惠以小罌童稚驚相傳。", "啟封一勺挹清泚，烹試茗碗真增妍。", "况當精禱已孚應，三日簷溜傾潺湲。", "病中一笑成莞爾，城闉安有泉如此。", "吳松四橋思陸羽，白帝城西歌子美。", "何用中泠取揚子，已覺清甘冰人齒。", "前人所品殊不定，一下一高隨所喜。", "老我住世能幾年，引飲一瓢幾子淵。", "行見甫田取十千，坐使遠近俱安然。", "欲和大篇不覺沉吟久，擊鉢成章慙敏手。"]'),
('af227410-b021-4588-b4ff-2499f43645f1','送潚宰富陽','樓鑰','宋','宋诗','song-poetry','','[]','富春富山水，地勝雄三吳。',180,'全唐诗/poet.song.158000.json','["富春富山水，地勝雄三吳。", "壯哉十萬戶，畿邑拱行都。", "大江橫吾前，上下萬賈趨。", "吾子丞剡川，攝事姦已鉏。", "試縣力愈難，勉旃立規橅。", "治縣古有譜，近頗多著書。", "槹閒愛汝厚，誨語皆良圖。", "老我不惜別，所望安官居。", "汝亦頗練事，正恐才尚疎。", "我以熱肺腸，有求應所須。", "遇事費十思，一跌真不虞。", "雖當縱心年，兢兢矩不踰。", "况汝年方壯，勿恃才有餘。", "據輪始窺井，任誕寧失拘。", "三年待汝歸，二親真倚閭。"]'),
('79cb1c4a-2b3f-49de-8642-4fe6ffb9e88c','又送從子㴶','樓鑰','宋','宋诗','song-poetry','','[]','二孫吾所愛，別去殊關情。',48,'全唐诗/poet.song.158000.json','["二孫吾所愛，別去殊關情。", "阿剡將賞延，伴子性亦靈。", "煩子善誘之，他日使有成。", "公餘松竹林，共勉洛誦聲。"]'),
('fc1fdb7e-3b5d-4e20-81f9-eda04181e1d2','寄題林宗山巢龜','樓鑰','宋','宋诗','song-poetry','','[]','彼澤之陂蒲與荷，有美一人傷如何。',64,'全唐诗/poet.song.158000.json','["彼澤之陂蒲與荷，有美一人傷如何。", "潔清如許豈不好，紉蘭綴蘺何足多。", "七十二鑽無遺策，不靈於己徒遭厄。", "人生何用千歲爲，願似巢蓮足清白。"]'),
('925f41bd-92d7-4995-879e-af4c294d1e1d','送趙仲禮守天台','樓鑰','宋','宋诗','song-poetry','','[]','槹閒社稷臣，卷藏經濟手。',168,'全唐诗/poet.song.158000.json','["槹閒社稷臣，卷藏經濟手。", "功名付諸郎，秀出諸公右。", "大兒倅東嘉，洗印未云久。", "次子鎮赤城，急流去何驟。", "二者皆爲親，欲奉喬松壽。", "況有戲綵堂，可繼清獻後。", "鄰封尤便養，榮侍各晝繡。", "春風扇微和，安輿雲出岫。", "家傳吏師法，從政於何有。", "還歸鴛鷺行，金印當繫肘。", "向來嘗佐郡，山川若僚友。", "南渡多北客，風味中都舊。", "士夫喜公來，紛然迎馬首。", "其中多故知，頗問老夫否。"]'),
('1c4e2591-15b4-488a-877d-46a18479d423','贈相手文李道人','樓鑰','宋','宋诗','song-poetry','','[]','生有文在手，縱橫殆天予。',192,'全唐诗/poet.song.158000.json','["生有文在手，縱橫殆天予。", "其閒動成字，往往傳自古。", "舜褎梁武武，老十子貢五。", "季友太叔虞，仲子竟歸魯。", "仲弓有鈎文，宰我亦握戶。", "敏士自文雅，習道本因輔。", "鄧淵彭神符，瑣瑣不足數。", "李郃陶士衡，三公皆定數。", "白帝矜奇瑞，見誚漢世祖。", "何爲言禍福，歷歷如君語。", "自言傳希夷，妙處勝貌取。", "見手知國封，況此細紋縷。", "研油燎旃檀，始見掌中虜。", "何如一覽頃，坐談樂與苦。", "老我縮袖閒，不復煩推步。", "子其訪塵中，英傑在何許。"]'),
('cb73354e-36c6-446d-beff-b240eaf807a5','跋余子壽所藏山谷書范孟博傳','樓鑰','宋','宋诗','song-poetry','','[]','宜人初謂宜於人，菜肚老人竟不振。',192,'全唐诗/poet.song.158000.json','["宜人初謂宜於人，菜肚老人竟不振。", "承天院記顧何罪，一斥致死南海濱。", "賢哉別駕眷遷客，不恤罪罟深相親。", "衮衮不容處城闉，夜遣二子從夫君。", "一日携紙丐奇畫，引筆行墨生煙雲。", "南方無書可尋閲，默寫此傳終全文。", "補亡三篋比安世，偶熟此卷非張巡。", "巖巖汝南范孟博，清裁千載無比倫。", "坡翁侍母曾啟問，百謫九死氣自伸。", "別駕去官公亦已，身雖既衰筆有神。", "我聞此書久欲見，摹本尚爾況其真。", "輟公清俸登堅珉，可立懦夫羞佞臣。"]'),
('1f77e867-7ece-44e2-a073-6189e56cb455','謝葉處士寫照','樓鑰','宋','宋诗','song-poetry','','[]','老我舊曾官日邊，隨衆年除仍歲遷。',320,'全唐诗/poet.song.158000.json','["老我舊曾官日邊，隨衆年除仍歲遷。", "母子日夜念鄉國，但欲共耕綿上田。", "葉君寫照妙一世，畫我形模在山水。", "有如虎頭貌幼輿，正合置之巖石裏。", "猶記有客爲諛言，盍更野服爲貂蟬。", "我笑不答心不然，拂衣徑得歸林泉。", "歸來歲月不知久，十餘年中何不有。", "此心炯炯尚如丹，只爲幽憂成老醜。", "久矣與世俱相忘，荷君念我應老蒼。", "新圖白髭添一二，豈知雙鬢皆成霜。", "兩圖對掛耿相照，顧盼從容成一笑。", "更添松竹作壽星，我已甘心就枯槁。", "人言姿態與真同，如照止水窺青銅。", "明知已非故吾矣，小孫指點能呼翁。", "君居天街號稱首，侯王生面羅左右。", "邊頭飛將新立功，颯爽英氣照窗牖。", "名滿四方求者多，千金造門君不呵。", "能事固不受促迫，應酬雖繁可柰何。", "胡爲有暇及衰朽，楚楚裝池意尤厚。", "我今已是行路人，不須重累丹青手。"]'),
('623a879b-56e1-49a5-bd74-90e3e07e4931','送宣宗禹保寧軍掌書記','樓鑰','宋','宋诗','song-poetry','','[]','宣之爲姓世所稀，暇日試爲君家推。',256,'全唐诗/poet.song.158000.json','["宣之爲姓世所稀，暇日試爲君家推。", "宋之宣公舍與夷，子孫相承此爲基。", "或云出自魯宣伯，元和姓纂言則非。", "西京功臣虎與義，侯封累世皆宗枝。", "盛哉雲陽宣巨公，光武稱其勝二龔。", "酆爲司空懷在趙，遥遥久矣無亢宗。", "君家本自太末來，世以儒術爲家風。", "尚及詹識諸父行，君方髫齔成孤童。", "艱難歷徧屹中立，五行俱下攻時習。", "自從一登賢士庭，貴名日起人誰及。", "舍選真似青銅錢，一躍龍門浪三級。", "吾鄉驚喜破天荒，歸見朋儔愈謙挹。", "寶婺古郡名浙東，往泛綠水依芙蓉。", "如君入幕假途爾，及今民事宜加工。", "亨途萬里才發軔，摻袪勿使金樽空。", "從今家聲當愈大，坐使宣氏崔盧同。"]'),
('f77a3fbd-1eb0-47bc-a480-598187415a7e','林和叔侍郎龜潭莊','樓鑰','宋','宋诗','song-poetry','','[]','頃年曾記游花谿，宗樞潭府谿之湄。',384,'全唐诗/poet.song.158000.json','["頃年曾記游花谿，宗樞潭府谿之湄。", "徘徊其上嘆秀爽，宜有英才瑞明時。", "巖巖林公天與奇，勁氣不爲金石移。", "少以六義鳴上庠，游宦所至英聲馳。", "瀾翻薦口徹旒冕，通籍直上黄金閨。", "出宰長城如卓魯，至今遺愛人歌之。", "入朝一冠御史豸，臺綱振厲先光輝。", "光宗聖度如天大，俾承舊制形宸奎。", "言所當言公不屈，上喜抗直深倚毗。", "歷居三院上橫榻，首尾獨擊及四期。", "擢居小天不肯住，遠指章貢把一麾。", "政成召節不旋踵，神與清漲促公歸。", "代言批敕節彌勵，藜藿不採非公誰。", "竟以松班分制閫，海邦雖陋不鄙夷。", "撫摩赤子厪一稔，功利及物難周知。", "公方在臺我立螭，臺省相望心事齊。", "皇上初政公賜環，我居青瑣公紫薇。", "時平論事同努力，寄名雷霆如恐遲。", "我求外補徑投閒，公亦出關喜相隨。", "受廛親見賢郡侯，攀轅卧轍同旄倪。", "公時自謂二宜去，吏民猶誦三不欺。", "棠陰蔽芾勿翦伐，萬人來往城南隄。", "書來不復說餘事，頗言別墅躬鉏犁。", "頻年日涉愈成趣，去家三里共游嬉。"]'),
('82125215-a573-4189-9a16-b6ec7fab8aca','次韵黄文叔正言送日鑄茶','樓鑰','宋','宋诗','song-poetry','','[]','古人養老食而酳，後人既飽須啜茗。',256,'全唐诗/poet.song.158000.json','["古人養老食而酳，後人既飽須啜茗。", "唐稱陽羨顧渚茶，惠建之名猶未省。", "小團花𩊓矞雲龍，競巧爭妍動天聽。", "要之造化生萬物，甘苦酸鹽適其性。", "古來水品多異同，茶品知誰真得正。", "芽新火活善調湯，種類雖殊俱雋永。", "坡翁立論亦頗當，一貶一褒何太猛。", "北苑固爲天下最，未必餘茶盡邪懭。", "越山日鑄名最高，種在陽坡性非冷。", "父老不堪痛摧抑，待以奴隸心若鯁。", "草木端有地所宜，此品標奇惟一嶺。", "祇因雜取應人須，寖使虛名成畫餠。", "坡公殆未識吾真，真者如珠光自炯。", "白頭拾遺辨真贋，非是容心爲鄉井。", "寄來雙缶妙絕倫，病叟新嘗信僥倖。", "七碗自煎成水厄，笑看腹似支離癭。"]'),
('aa1c83b3-9339-4c7f-9c15-c8c49e5826be','長生草','樓鑰','宋','宋诗','song-poetry','','[]','我方髫齔時，已復見茲草。',144,'全唐诗/poet.song.158000.json','["我方髫齔時，已復見茲草。", "仲舅尉江陽，奉親顔色好。", "窗門掛經冬，蛛絲罩輕縞。", "意爲霜雪殘，白花乃明杲。", "世間三友外，此有歲寒操。", "年至十七八，童心如木槁。", "隨時到柯山，逢人細訪考。", "買之野人手，何須訪蓬島。", "嘗爲伯氏壽，作詩頌難老。", "經今五十年，得自江南道。", "老我日就衰，歲月豈長保。", "一笑哦子詩，猶將伴梨棗。"]'),
('fa61206f-125a-460b-9589-3849108beace','又次王恭叔韵  其一','樓鑰','宋','宋诗','song-poetry','','[]','仲冬方寒荔挺出，仲夏方炎靡草死。',96,'全唐诗/poet.song.158000.json','["仲冬方寒荔挺出，仲夏方炎靡草死。", "若將朝菌比大椿，相去何啻千萬里。", "金芝僊草不可見，長生之草畧相似。", "少時曾識青青色，今日得之乃真是。", "天工矜憫輕喪生，故出珍苗普相示。", "若言神僊可學致，自是未得養生理。"]'),
('9964fa6e-9f09-4c20-87c5-974123163152','又次王恭叔韵  其二','樓鑰','宋','宋诗','song-poetry','','[]','人爲天地最靈物，野卉無情猶若此。',96,'全唐诗/poet.song.158000.json','["人爲天地最靈物，野卉無情猶若此。", "石間薜荔水昌陽，卷柏生崖并葛藟。", "是皆草中號長久，未見懸空解葩蘂。", "柯葉不改耐歲寒，土著青松那可擬。", "不須丹砂訪葛洪，毋用僊方傳李耳。", "未知此種誰爲傳，烏有先生子虛子。"]'),
('992897e9-9615-42cd-be28-c6b1747a8998','寄題閬風劉允叔月波','樓鑰','宋','宋诗','song-poetry','','[]','浮海思乘桴，拾月或掛席。',96,'全唐诗/poet.song.158000.json','["浮海思乘桴，拾月或掛席。", "何如閬風僊，渤澥坐中得。", "隠几時觀瀾，黏天四無壁。", "清夜水不摇，孤蟾靜沈璧。", "飄風一過之，波光湛空碧。", "萬頃玻璃田，蕩以黄金液。", "我欲從之游，尚恐一層隔。", "何當携珍茶，石井試餘滴。"]'),
('e41e2182-0e63-4f2d-bde4-64f64b89c660','題楊子元琪所藏東坡古木','樓鑰','宋','宋诗','song-poetry','','[]','東坡筆端游戲，槎牙老氣橫秋。',28,'全唐诗/poet.song.158000.json','["東坡筆端游戲，槎牙老氣橫秋。", "笑揖退廉博士，信酷似文湖州。"]'),
('52389571-0a07-4723-8aa3-3a8c997512c5','同倪正甫尚書游西湖','樓鑰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','舊說西湖比西子，君言西湖似賢士。',96,'全唐诗/poet.song.158000.json','["舊說西湖比西子，君言西湖似賢士。", "于嗟契闊十五年，一日相逢祇如此。", "南山北山兩高峰，春波灧灧摩青銅。", "未能蕩槳窮勝處，倚欄一望開心胸。", "老我掛冠隠田里，豈知再見烟連水。", "小須夏日醉滿荷，脫屣東歸甘已矣。"]'),
('3515456d-9d22-4bcf-a27b-fd66a89e2070','贈犁春謝耕道','樓鑰','宋','宋诗','song-poetry','','[]','歸耕十三年，此來殊欿然。',48,'全唐诗/poet.song.158000.json','["歸耕十三年，此來殊欿然。", "一犁正春雨，君行欲何處。", "我方買紅船，重歸尋舊廛。", "君亦早歸來，勿荒負郭田。"]'),
('f2c430a3-4153-4b67-be9a-24afd98f7fa6','訪李國器於包山同登寺後山菴','樓鑰','宋','宋诗','song-poetry','','[]','訪客包家山，相與登層顛。',108,'全唐诗/poet.song.158000.json','["訪客包家山，相與登層顛。", "嶙峋巨石中，屈曲扶欄干。", "夜來雨初過，石罅時涓涓。", "輕輿到岡頭，大江橫吾前。", "亭午潮方盛，千艘散平川。", "道人茅三間，花木羅後先。", "朅來汩京塵，曠望爲洗湔。", "山斷塔層層，西陵渺蒼烟。", "此道走邯鄲，歸心更翩翩。"]'),
('66f1b0bb-0edf-4469-99ed-34d63de1de26','謝林德久正字惠詩次韵','樓鑰','宋','宋诗','song-poetry','','[]','老我甘投閒，晏然十三秋。',120,'全唐诗/poet.song.158000.json','["老我甘投閒，晏然十三秋。", "茲來何所似，反衣狐白裘。", "京塵素爲緇，夢寐思首丘。", "低徊未成去，黽勉終自羞。", "久聞歌楚騷，欲見知無由。", "詩文惠盈軸，一誦消百憂。", "便當細論文，夜雨同春蒭。", "平生萬事了，此去復何求。", "尚貪未見書，痛洗千斛愁。", "得此不翅足，携歸老先疇。"]'),
('26167cc2-a0d1-4805-8b17-c35e368f5e56','次韵東坡武昌西山詩','樓鑰','宋','宋诗','song-poetry','','[]','黨論一興誰可回，賢路荆棘爭先栽。',224,'全唐诗/poet.song.158000.json','["黨論一興誰可回，賢路荆棘爭先栽。", "竄流多能擅筆墨，囚拘或可爲鹽梅。", "雪堂先生萬人敵，議論磊落心崔嵬。", "向來羅織脫一死，至今詩話存烏臺。", "憑高望遠想宏放，眼界四海空無埃。", "黄岡踏遍興未盡，絕江浪破琉璃堆。", "漫郎神交信如在，石爲窊樽勝金罍。", "鄧侯先曾訪遺跡，銘文深刻山之隈。", "山荒地僻分埋沒，二公前後搜莓苔。", "元祐一洗人間怨，天地清寧公道開。", "玉堂同念舊游勝，筆端萬物挫欲摧。", "時哉難得復易失，弟兄遠過崖與雷。", "北歸天涯望陽羨，買田不及歸去來。", "我爲長歌弔此老，慟哭未抵長歌哀。"]'),
('a72c58f3-356b-41e4-8fd1-19d2142f6843','次韻雷知院觀音詩因敘家中銅像之詳','樓鑰','宋','宋诗','song-poetry','','[]','鼻祖家住江東邊，推擇爲吏心靜淵。',384,'全唐诗/poet.song.158000.json','["鼻祖家住江東邊，推擇爲吏心靜淵。", "朝朝趨邑過圮上，時見暗磧光煜然。", "平時奉佛心至謹，建立塔廟崇諸天。", "試令便介識所在，退公始得來其前。", "揮鉏去沙若有物，微見銅像傷其顛。", "須臾衆覩全體見，端嚴相好巧且堅。", "迎歸供養備精潔，我家舊物猶青氈。", "銖衣飄摇俱梵相，珠纓垂裊穿淮蠙。", "雖非丈六黄金身，他處像設無能先。", "不知何人妙陶冶，底用五色增華妍。", "自茲累葉永爲寶，如以衣鉢更相傳。", "是時承平最盛際，正在景德咸平間。", "畫工難貌天人妙，劫風不動神光圓。", "益知佛教來已遠，徧滿震旦尊金僊。", "慈悲無量應成禱，影響若與人周旋。", "耳則聞音目可觀，此有妙理誰能詮。", "寶光燄燄擁身後，貝花葉葉俱成全。", "頂戴天冠工莫及，中有一佛立不偏。", "有孫是爲鄉先生，決科衣冠遂蟬聯。", "大父持喪久廬墓，曾以此事形碑鎸。", "起身月卿出爲郡，殿上寤主以一言。", "易守鄉邦凡五年，寵光赫奕當政宣。", "移至湖心值兵燬，精廬灰滅因亡焉。", "初聞諸父話遺跡，興歎欲見無因緣。"]'),
('7be665f6-eecd-4f12-8632-a4bbee6870ab','桃源圖','樓鑰','宋','宋诗','song-poetry','','[]','桃源初傳武陵谿，靖節作記人不疑。',384,'全唐诗/poet.song.158000.json','["桃源初傳武陵谿，靖節作記人不疑。", "其先深避嬴政虐，嘉遯與世真相違。", "尚不知漢況晉魏，子孫綿遠無終期。", "正如三韓有秦語，傳爲神僊愈難知。", "桃林洞府漁人窺，別有天地均四時。", "意必智者塞其蹊，不然將爲世所羈。", "後人想像作圖畫，但見耋稚咸嬉嬉。", "人家隨處成井市，畎畝頗亦分塍畦。", "井鬼下照坤之維，方士異人多崛奇。", "筠籠二版堅如鐵，能刻景物窮纖微。", "浄室給以酒盈斗，一昔圖成了無虧。", "同寮欲求第二本，版忽震裂人已非。", "夷堅志怪言歷歷，何意今乃親見之。", "未知桃源有此否，此事茫昧不可稽。", "初疑長房縮地脈，又似照影歸摩尼。", "巨麗寫成阿房賦，牽連貌出連昌辭。", "采女細數七十二，人言霓裳舞羽衣。", "樓閣玲瓏在縹緲，其間恐有太真妃。", "刻畫工巧世固鮮，磨以歲月或可爲。", "彩鸞唐韵已甚捷，未見神速能如斯。", "尚有漁舟傍階墀，咫尺安知前路迷。", "天聖已踰三甲子，何人寶藏至今茲。", "南豐丈人惠墨本，老眼增明失昏眵。", "固知凡蹤不可到，一夢遊僊猶庶幾。"]'),
('d5c8d950-abab-4e31-9864-045bee85b9c2','吳山井','樓鑰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','錢塘東南一都會，西湖宛在高城外。',192,'全唐诗/poet.song.158000.json','["錢塘東南一都會，西湖宛在高城外。", "鑿爲六井引入城，唐相鄴侯功尚在。", "吳山橫亙城中央，左右江湖盡襟带。", "寒泉迸溢清且甘，發自靈源匪分派。", "天目兩乳龍鳳來，秀氣所鍾此其最。", "海濱斥鹵潤作鹹，安得一泉獨滂沛。", "四朝駐蹕八十年，民聚五方真衆大。", "抱甕桔槹萬夫汲，飛泉仰流筒吸快。", "大旱不乾潦不溢，數里赬肩競分賣。", "人言神龍宅其下，濟物陰功至今在。", "川澤固多資灌溉，此井猶能濟闤闠。", "皇家德澤如此泉，福祚與之俱不改。"]'),
('e9076444-f858-4845-8287-ff1669fb8a0c','代書寄內弟耐翁總幹','樓鑰','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我昔生外家，半世猶相依。',288,'全唐诗/poet.song.158000.json','["我昔生外家，半世猶相依。", "至今連牆居，日日相聞知。", "諸表如羣從，休戚真同之。", "耐翁生而秀，愛惜從兒時。", "文采既俊發，吏才人共推。", "低徊久選調，每每爲歎咨。", "茲行佐王人，未到聲已蜚。", "郵置屢得書，論事語益奇。", "使長首推薦，婉畫多所資。", "近觀會稽編，分析及毫釐。", "益知足心計，薦書徧諸司。", "正欲助才選，非敢請以私。", "惜君年欲侵，正以遠大期。", "得書再三讀，惘然增愕眙。", "非所望于子，所言何背馳。", "江湖兩路間，弄兵分潢池。", "羽檄以時至，廟堂日三思。", "調度供軍需，發兵匝四垂。", "吾事誠可慮，彼亦安能爲。", "豈曰白頭賊，指日當誅夷。", "使子任賊衝，尚望羽扇揮。", "如何隔千里，遽求奉檄歸。", "長沙屹巨鎮，洞庭渺無涯。", "鄂渚屯重兵，上游藉兵威。"]'),
('de1f4947-43c9-4ac9-8a47-06f054a20932','題汪季路家藏吳彩鸞唐韵後','樓鑰','宋','宋诗','song-poetry','','[]','舊說僊人吳彩鸞，日書切韵歸毫端。',288,'全唐诗/poet.song.158000.json','["舊說僊人吳彩鸞，日書切韵歸毫端。", "不應神速有如此，令人至今疑稗官。", "相傳此事三百載，誰知真蹟儼然在。", "筆精墨妙信入神，間以朱丹倍晶彩。", "法言初爲此韵時，賸裒文字覺後知。", "寧知遂經謫僊手，諱字曾闕民與基。", "經生矻矻盡精力，摩以歲月或可得。", "動翰如飛猶恐遲，一日一揮出心畫。", "神僊之說云渺茫，僊凡配耦尤荒唐。", "蕭史弄玉乘鳳去，藍田空說容裴航。", "文簫之遇真是否，豈比虛名傳不朽。", "五篇歷歷爲全書，始信傳聞是真有。", "當時所直才五緡，于今千金價未均。", "十年蓋有數百本，未知幾本傳今人。", "惜哉字畫太纖細，後日傳之知幾歲。", "祇今已有字不全，欲鎸翠珉固非易。", "我踰七十方見之，暫借一觀聊自怡。", "平生願見心便足，何必更謀身後爲。"]'),
('a612705a-e3ba-4c98-bcb3-0df64e896c23','題汪宏甫三馬圖','樓鑰','宋','宋诗','song-poetry','','[]','玉花流雲照夜白，開元尚想行天街。',32,'全唐诗/poet.song.158000.json','["玉花流雲照夜白，開元尚想行天街。", "韓李鄭君俱已矣，健筆誰能如順齋。"]'),
('a2bf3269-5c05-4e48-b44b-62e492979c91','樞密府雪後作故韓氏子舍也','樓鑰','宋','宋诗','song-poetry','','[]','平生好流水，雅欲臨流賦。',228,'全唐诗/poet.song.158000.json','["平生好流水，雅欲臨流賦。", "澗谿或過之，眷眷不能去。", "青山圍故鄉，不肯入城府。", "寧知開八袠，重爲尋故步。", "勢家遺故居，傳舍偶成寓。", "軒楹立奇石，巉巖高丈許。", "三面立屏障，曲沼水深貯。", "荏苒將半載，未見有時雨。", "新春積雪餘，簷聲夜如注。", "曉起推閒窗，石穴水噴吐。", "下穿玲瓏餘，數尺成瀑布。", "髣髴小龍湫，雖微體略具。", "退公輒對之，相逢歎遲暮。", "有客與同賞，酌酒更告語。", "雖云京塵深，燕坐得幽趣。", "懸崖掛長藤，絕頂列佳樹。", "微風一披拂，墜點紛無數。", "吾方謀乞身，信美難久駐。", "未能寫成圖，聊用賦長句。"]'),
('f1814cd1-bb95-4893-9a11-14588b55b25e','謝文思許尚之石函廣陵散譜','樓鑰','宋','宋诗','song-poetry','','[]','叔夜千載人，生也當晉魏。',288,'全唐诗/poet.song.158000.json','["叔夜千載人，生也當晉魏。", "君卑臣寖强，駸駸司馬氏。", "幽憤無所洩，舒寫向桐梓。", "慢商與宮同，慘痛聲足備。", "規橅既弘闊，音節分巨細。", "撥剌洎全扶，他曲安有是。", "昌黎贈穎師，必爲此曲製。", "昵昵變軒昂，悲壯見英氣。", "形容泛絲聲，雲絮無根蔕。", "孤鳳出喧啾，或失千丈勢。", "謂此琵琶詩，歐蘇俱過矣。", "余生無他好，嗜此如嗜芰。", "清彈五十年，良夜或無寐。", "向時幾似之，激烈至流涕。", "素考韓臯言，神授託奇詭。", "別姊取韓相，多用聶政事。", "近讀清真序，始知石函祕。", "賢哉許阿訥，自言家有此。", "文君昔寶藏，人亡琴亦廢。", "荷君重然諾，寫譜遠相寄。", "按拍三十六，大同小有異。", "此即名止息，八拍信爲贅。", "君遠未能來，我老從此逝。", "何當爲君彈，更窮不盡意。"]'),
('0394e58d-e9fd-4ea9-8096-5427ccf34176','王叔達以尉彭澤潛玉洞述見示','樓鑰','宋','宋诗','song-poetry','','[]','書巖已奇甚，潛玉尤偉哉。',48,'全唐诗/poet.song.158000.json','["書巖已奇甚，潛玉尤偉哉。", "李君漫盤谷，元子空峿臺。", "神不得自祕，天應爲君開。", "淵明如得此，應不賦歸來。"]'),
('f4a7d7c6-604a-4e8b-a873-ce95d2fa108a','題董亨道八景圖','樓鑰','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u6d1e\u5ead\u6e56"]','錢塘怒濤天下無，誰將尺紙爲新圖。',192,'全唐诗/poet.song.158000.json','["錢塘怒濤天下無，誰將尺紙爲新圖。", "賀家湖上如鏡浄，屢向烟波逢釣徒。", "彩虹橫卧吳淞上，洞庭一螺浮具區。", "亦曾泛舟彭蠡湖，插立千劍名大孤。", "廬山高哉不得到，歷歷五老聯香爐。", "上鍾下鍾夾湖口，半江清濁涇渭如。", "多景雄據金焦間，夕陽微照海門山。", "其餘知名不知處，赤壁但歌前後賦。", "江漢至鄂始合流，黄鶴樓前鸚鵡洲。", "瀟湘見說青如染，道林岳麓橫清秋。", "我欲遠遊嗟暮齒，蝶夢翩翩漫千里。", "但欲絕江尋越山，歸老故山吾已矣。"]'),
('bf968763-cf61-479b-805a-3ae18a5acefe','魚計亭','樓鑰','宋','宋诗','song-poetry','','[]','平生信天公，頹然不作計。',96,'全唐诗/poet.song.158000.json','["平生信天公，頹然不作計。", "顧我雖非魚，想見亦相似。", "潛深本其性，魚亦非有意。", "浮陽或在渚，不能終自祕。", "或爲饑所驅，危機在香餌。", "輕絲引纖鉤，性命困刀几。", "魚以味得烹，我以名自累。", "安得兩相忘，容我從此逝。"]'),
('b0e457ca-1b63-4a63-906a-f3b16c729735','跋盧申之所藏韋偃三馬','樓鑰','宋','宋诗','song-poetry','','[]','嗟哉馬之生，馳驟乃其性。',168,'全唐诗/poet.song.158000.json','["嗟哉馬之生，馳驟乃其性。", "一爲人所羈，寸步不得騁。", "局促閑廐中，專俟圉人令。", "調服無踶齧，始可用朝請。", "戰騎冒鋒鏑，或致隕其命。", "繡羈非不華，金狨號爲盛。", "青黄木之災，此亦馬所病。", "立仗尤貴重，一鳴輒斥屏。", "何如在牧時，卧起玩烟景。", "豐草勝芻豆，清波恣游泳。", "韋侯擅筆精，幻出無人境。", "思陵賜珍題，昭回光炳炳。", "身方縛名韁，三年慙負乘。", "細窺樂寬閒，悠然動歸興。"]'),
('25873d10-26dc-4bcc-b25b-8eab52323e50','宇文樞密借示范寬春山圖妙絕一時以詩送還','樓鑰','宋','宋诗','song-poetry','','[]','范生本以寬得名，不學關仝與李成。',192,'全唐诗/poet.song.158000.json','["范生本以寬得名，不學關仝與李成。", "筆端自出一機杼，理通神會真其能。", "橫披小軸屢到眼，頗亦時能辨真贋。", "未見弘大如公藏，茂樹喬山春爛漫。", "此圖不是江南山，寒空青嶂疑商顔。", "高高下下幾佳處，莊家時有茅三間。", "橋梁樓觀各有趣，一夫驅馿何處去。", "安得隨入杳靄間，布襪青鞋踏空霧。", "近山忽斷見遥碧，天涯一望無中極。", "胸中丘壑誰測知，鐵屋石人驚筆力。", "鵝谿六幅高堂空，終日對坐心神融。", "看罷爲我捲還客，自此歸余境夢中。"]'),
('17510e21-6476-4c31-83fd-18235703f14d','錢文季少卿以蜀中織成山谷書廬山高爲壽次韵','樓鑰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','七十衰翁年愈高，意氣銷盡湖海豪。',160,'全唐诗/poet.song.158000.json','["七十衰翁年愈高，意氣銷盡湖海豪。", "平生萬事不翅足，但欲乞身歸故巢。", "幾番掛冠不容去，歸夢屢涉滄浪濤。", "縱使不去豈能久，命如槁葉風將飄。", "一陽來復值初度，方念吹棘心夭夭。", "何期老友加記錄，乃爲衰朽親揮毫。", "廬山高哉山谷字，蜀女織就新冰綃。", "安得東歸抱四絕，雙鳬飛舄追王喬。", "張圖痛飲信一快，更須傳寶留兒曹。", "慶朝非遠却圖報，別當作頌齊崧高。"]'),
('454bc658-c4bb-4695-8aba-63ffeb61e8a1','以太湖石響板爲文季壽','樓鑰','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','太湖中心洞庭山，千巖萬壑高孱顔。',144,'全唐诗/poet.song.158000.json','["太湖中心洞庭山，千巖萬壑高孱顔。", "風濤舂撞自太古，漱成樂石如雕剜。", "玲瓏中空窮變態，奇奇怪怪羅滄灣。", "良工巧手琢威鳳，片雲承足同飛翻。", "叩之五聲八音足，疑有僊風摇珮環。", "月卿蜚聲塞宇宙，文如九苞瑞世間。", "祇今在治真若鳳，朝陽一鳴聞九關。", "先從鵷閣掌帝制，徑上鸞臺領朝班。", "德既不衰石不泐，祝公遐壽如彭籛。"]'),
('53c56ee8-9418-402d-92a7-375d07b67998','次韵章樞密賦吳彩鸞玉篇','樓鑰','宋','宋诗','song-poetry','','[]','文簫躡彩鸞，夜半恐不逮。',240,'全唐诗/poet.song.158000.json','["文簫躡彩鸞，夜半恐不逮。", "山深忽呼名，驚喜不得退。", "僊謫無所逃，士貧何可耐。", "乃以三生緣，遂爲二姓配。", "至人與凡夫，伉儷豈其輩。", "鬻書以自給，細字如玉碎。", "一一存楷法，明珠蔑瑕纇。", "初如鶼比翼，久若魚同隊。", "終日了韵編，心畫亡罣礙。", "人間八百本，終古知敬愛。", "玉篇尤可珍，何必贈雜佩。", "倘邀千黄金，雖貧亦當貸。", "摩挲惜見晚，老眼看茫昧。", "墨妙饒精神，筆勁含姿態。", "次第部居中，盤曲法庫內。", "九齡美風度，孟博信清裁。", "書拙無合作，見此增愧慨。", "尤物難久假，雪窗暫相對。", "遺蹤雖已邈，真跡儼然在。", "輒效西子顰，小楷書牘背。"]'),
('8abd841c-db09-44da-89e5-143502d0431d','題太乙宮武林山贈易高士','樓鑰','宋','宋诗','song-poetry','','[]','易居求賦武林山，日困塵勞無暫閒。',224,'全唐诗/poet.song.158000.json','["易居求賦武林山，日困塵勞無暫閒。", "我求掛冠欲歸去，念此詩債須當還。", "武林山出武林水，靈隠後山無乃是。", "此山亦復用此名，細考其來真有以。", "天目兩乳到錢塘，一山環湖萬龍翔。", "扶輿磅礴擁王氣，皇居壯麗環宮牆。", "湖陰一峰如怒猊，勢臨城北尤瑰奇。", "吳越大作緇黄廬，爲穿百井以厭之。", "從來有龍必有珠，此雖培塿千山餘。", "中興南渡爲行都，崇列原廟太乙廬。", "曾因祀事來登眺，闤闠塵中有圜嶠。", "薰風時來洗袢暑，綠樹陰陰隠殘照。", "我得暫來猶醒心，羨君清福住年深。", "長安信美非吾土，倦翼惟思歸故林。"]'),
('9a5a53a6-2af8-4ce7-b599-735a75b2a647','寄題王以道蘭墅','樓鑰','宋','宋诗','song-poetry','','[]','百卉生深林，無人皆自芳。',108,'全唐诗/poet.song.158000.json','["百卉生深林，無人皆自芳。", "楚騷發妙意，惟蘭乃能當。", "我欲效潞公，賸種坡之陽。", "不須强披拂，風來味愈長。", "君乃先爲之，滋畹雙雁鄉。", "正欲生階庭，聚書教諸郎。", "父子自同心，久之不聞香。", "老我行西歸，一造君子堂。", "勉哉篤義方，雙雁看高翔。"]'),
('542c2931-0991-4488-a626-6c8bf20cd2f4','蕉菴雜言','樓鑰','宋','宋诗','song-poetry','','[]','環植巒蕉數十株，幻成方丈一屠蘇。',128,'全唐诗/poet.song.158000.json','["環植巒蕉數十株，幻成方丈一屠蘇。", "幾重青蒼兩邊合，四壁穿空一物無。", "早凉日薄坐其下，爽氣肅颯風來徐。", "此爲天下易生物，不多歲月真可廬。", "王愷謾夸紫步障，石崇安得青珊瑚。", "寓居得地不畝許，好事便可傳規模。", "顧余老矣豈久處，後來得此自足娛。", "若謂霜雪成摧枯，環臺瑶室今何如。"]'),
('c38cab72-2d6d-4bc8-8da0-06dfa71c6bc2','石時亨飽山閣','樓鑰','宋','宋诗','song-poetry','','[]','層層得好山，是處足飽看。',288,'全唐诗/poet.song.158000.json','["層層得好山，是處足飽看。", "君真樂山者，心地尤平寬。", "生長山水縣，慣見青巑岏。", "築室欲飫賞，憑虛著危欄。", "天亦遂君意，俾君老其間。", "場屋早得名，晚始就一官。", "官又不得進，甘心樂瓢簞。", "官少家食多，知更幾暑寒。", "朝見山嵐高，暮喜山雲還。", "山氣日夕佳，秀色幾可餐。", "晴雨各變態，雪月更萬端。", "于山真屬饜，清明流肺肝。", "膏粱與芻豢，與世殊鹹酸。", "久矣謝世紛，屏息專內觀。", "鬢無一莖白，八十顔如丹。", "所得不既多，愈飽天不慳。", "此閣本不華，何處無此山。", "苟爲名利驅，人境無相關。", "吾鄉山苦遠，可望不可攀。", "東樓快登眺，聳翠羅烟鬟。", "年來勇欲歸，匏繫未許閒。", "君索飽山詩，南明恍在前。", "十年兩訪君，共醉苜蓿盤。", "向時多名流，與君平生歡。"]'),
('08ab1e4d-533b-4844-b1b2-6500f0ff049c','林德久祕書寄楚辭故訓傳及叶音草木疏求序于余病中未暇因以詩寄謝','樓鑰','宋','宋诗','song-poetry','','[]','平時感歎屈靈均，離騷三誦涕欲零。',224,'全唐诗/poet.song.158000.json','["平時感歎屈靈均，離騷三誦涕欲零。", "向來傳注頼王逸，尚以舛陋遭譏評。", "河東天對最傑作，釋問多本山海經。", "練塘後出號詳備，晦翁集註尤精明。", "比逢善本窮日誦，章分句析無遁情。", "林侯忽又示此帙，正欲參考搴華英。", "屬余近歲方苦疾，筆硯廢墮幾塵生。", "嘗鼎一臠已知味，始知用工久已成。", "況復身到荆楚地，詳究蘭芷聞芳馨。", "前此同朝幸相與，錦囊詩文爲我傾。", "惜哉不早見此書，病中欲續神不寧。", "年老耄及屢求去，倘得掛冠早歸耕。", "尚當一一爲尋繹，期以爝火裨明星。", "謾揮斐語塞厚意，深媿所報非瓊瑩。"]'),
('ef7defa5-96af-42d1-8342-7a5226f58091','贈黄真護道人游茅山','樓鑰','宋','宋诗','song-poetry','','[]','少年曾上三茅山，千巖萬壑窮躋攀。',384,'全唐诗/poet.song.158000.json','["少年曾上三茅山，千巖萬壑窮躋攀。", "烟霏空翠不可狀，弟兄聯騎欣清閒。", "回頭五十有餘載，至今夢境猶班班。", "初從崇禧入僊境，元符玉晨紛幢幡。", "草庵精舍不知數，各占山麓清溪灣。", "蓑衣相見黑虎谷，蒼然白髮猶朱顔。", "延之土窟款清論，桃皮釀酒無留殘。", "達道所居更奇絕，萬山開豁如重關。", "一山巉巖似筆格，聳秀正矗湖中間。", "白馬真人尚生氣，長史舊井藏餘丹。", "異石若碎還復合，豢龍幾處多澄瀾。", "華陽洞門閉已久，傳聞亦有游其藩。", "撫掌浮漚湧如沸，僊人捧石手可扳。", "最奇無如大茅峰，千尋直上天市壇。", "中峰小峰如雁行，下視堆阜羅烟鬟。", "三君司命時歸降，往往天風吹珮環。", "人言春日羽衣會，胎禽終日來飛翻。", "玄帝大鼎秦皇璧，丹砂六千在流泉。", "地無虺虎與荆棘，但有衆藥堪延年。", "洞天凡蹤不易到，我欲再往良獨難。", "有時慨想舊游處，陟岡惘惘涕爲潸。", "江夏僊人有僊骨，卓爾拔俗甘瓢簞。", "摇鈴真能徹帝所，揮钁自足驅神姦。", "曾入金華訪初平，今往地肺求洞玄。"]'),
('a98773de-6074-46c5-8912-a077c4f572ea','代魏丞相爲錢參政壽','樓鑰','宋','宋诗','song-poetry','','[]','天台傑立滄海東，古今名士長相從。',224,'全唐诗/poet.song.158000.json','["天台傑立滄海東，古今名士長相從。", "神遊八極司馬子，擲金作賦孫興公。", "松窗先生千載士，文價道骨相與同。", "芙蓉爲裳蘭爲佩，一笑坐斷千山峰。", "向來羽扇揮羣雄，貔貅給使如奴僮。", "淮南草木識姓字，烽燧一掃邊庭空。", "勳名巍峨謝不有，天子神聖非臣功。", "黄扉安坐斷國論，精神自折千里衝。", "東山之志意不改，歸來碧落稱僊翁。", "調元老手自燮理，鬖鬖綠髮雙方瞳。", "蒼生顒望謝公起，中興事業須宗工。", "新冬五日記穀旦，霜餘和氣回春風。", "門牆老生繫郡紱，欲借壽斚斟吳松。", "祝公壽考與家世，山河带礪俱無窮。"]'),
('d211e4d7-faf3-4b21-80f8-e1a6cfb5431c','代仲舅尚書賦江山得助樓','樓鑰','宋','宋诗','song-poetry','','[]','江山信美非吾土，王粲登樓意凄楚。',260,'全唐诗/poet.song.158000.json','["江山信美非吾土，王粲登樓意凄楚。", "麗譙井幹高則高，未免綺羅相滓污。", "君家華屋照城隅，丹壁重重不知數。", "誰令作此三層樓，雪脊干霄千尺所。", "幾番貽書來索詩，只許歸田爲君賦。", "快哉今日真得歸，無復黄塵涴巾屨。", "試凭欄干俯人世，城郭村畦可枚數。", "四山雲物任卷舒，大江波濤恣吞吐。", "曉看紅日上滄溟，夜見冰蟾轉天宇。", "四明山水秀東南，祇恨青山不肯入城府。", "我家朗朗屋百間，欲創一樓兄未許。", "羨君輪奐日日新，鼛鼓一聲紛郢斧。", "眼明見此高突兀，騷人當得江山助。", "我久欲歸未得間，門巷相望纔尺五。", "賦詩幸不負前盟，但慚筆底無風雨。", "從今造門不復問主人，醉倒樓上君莫嗔。"]'),
('4a24d594-8a7f-4e64-859d-7c9a582ec125','代求子紹上魏邸壽詩','樓鑰','宋','宋诗','song-poetry','','[]','皇家基業天與隆，金枝玉葉槃石宗。',272,'全唐诗/poet.song.158000.json','["皇家基業天與隆，金枝玉葉槃石宗。", "我皇聖德摩蒼穹，朱邸森列慶所鍾。", "仲氏吹箎何雝雝，雲夢八九羅心胸。", "羣經讀遍巾箱中，筆端豪氣舒長虹。", "殿前玉佩聲冬瓏，天人眉宇輝宸楓。", "大名起魏茅士封，黄旛豹尾雙鎮雄。", "宣城名郡煩憑熊，政績越過黄與龔。", "樓前疊嶂橫雲空，佳句不減玄暉工。", "賢王易鎮甬水東，陽春有脚皆仁風。", "百蠻面內文軌同，坐清聚蟻驅屯蠭。", "碧海萬里樓船通，天子神聖非臣功。", "薰風入弦槐陰濃，新荷泛綠榴花紅。", "曉來佳氣飛青葱，驚詫野老田家翁。", "簫鼓動地光融融，堂上帝子方雍容。", "清旦燕賀簪笏叢，負弩小吏隨登龍。", "由來降靈自神崧，難老何用齊喬松。", "年年箕翼壽兩宮，捧觴戲彩俱無窮。"]'),
('9e4dca8b-b002-44e9-b0d3-0a823084b197','代毛崇夫賀婦翁黄圮老生朝','樓鑰','宋','宋诗','song-poetry','','[]','東都競風節，清裁稱巨賢。',288,'全唐诗/poet.song.158000.json','["東都競風節，清裁稱巨賢。", "焱馳不自定，相與扶其顛。", "獨立黄徵君，道周性具全。", "辟舉既不就，言論亦無傳。", "當時論篤士，比之孔與顔。", "陳蕃爲三公，自媿不敢先。", "丈人豈苗裔，德高靜而專。", "不清復不濁，量陂渺無邊。", "學問粹然正，師友承淵源。", "詞章玉無瑕，作者當摩肩。", "向來登王畿，悟主在一言。", "校讎天祿閣，朱黄手自研。", "郎潛不啻足，肯羨歲九遷。", "清朝奬廉退，擢居西府員。", "膴仕皆坐致，高懷越拘攣。", "出乘使者車，徑歸卧林泉。", "出處無戚欣，鼻間栩栩然。", "謝公恐未免，召馹行著鞭。", "松山介閩浙，淑氣常蜿蜒。", "隆冬正凝沍，愛日回春妍。", "懸弧慶生申，飄若區中僊。", "僊風自難老，何須記椿年。", "賤子託枌榆，掃門如宿緣。", "叨在玉潤選，得窺樂廣天。"]'),
('4a6ee341-af99-4b84-9d8a-8d8a5366328c','曾吏部壽詩集老杜句','樓鑰','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','刺史諸侯貴，春城海水邊。',288,'全唐诗/poet.song.158000.json','["刺史諸侯貴，春城海水邊。", "層城臨媚景，水合數百源。", "山色佳有餘，雲門吼瀑泉。", "遊山憶謝公，頻遊任履穿。", "三寸如黄金，朱橘不論錢。", "瀟灑到江心，石瀨月娟娟。", "翠華擁吳岳，誰扶黄屋尊。", "御榻在嵽嵲，佳氣拂周旋。", "多除南省郎，一麾出守還。", "城中賢府主，今之黄潁川。", "筆落驚風雨，談論淮湖奔。", "羣書一萬卷，分明在眼前。", "老氣橫九州，黄鵠摩蒼天。", "歷職漢庭久，磊落映時賢。", "否臧太常議，正直朱絲弦。", "東下姑蘇臺，戮力効鷹鸇。", "謁帝似馮唐，明公獨妙年。", "列宿頓輝光，馨香粉署妍。", "卿月昇金掌，等級敢比肩。", "巢許山林志，虛心味道玄。", "此邦承平日，接近與名藩。", "時節立復度，水旱其數然。", "百谷漏波濤，狂風大放顛。", "江流氣不平，地軸爲之翻。"]'),
('b0750788-a2fd-4051-add0-40bf763eb685','七月上浣游裴園醉翁操','樓鑰','宋','宋诗','song-poetry','','[]','茫茫，蒼蒼。',111,'全唐诗/poet.song.158000.json','["茫茫，蒼蒼。", "青山，遶千頃。", "波光，新秋露風荷吹香。", "悠颺心地翛然，生清凉。", "古岸摇垂楊，時有白鷺飛來雙。", "隠君如在，鶴與翱翔。", "老先何處，尚有流風未忘。", "琴與君兮宮商，酒與君兮杯觴。", "清歡殊未央，西山忽斜陽。", "欲去且徜徉，更將霜鬢臨滄浪。"]'),
('d4068f3e-3ad0-4bd8-8729-619fdbc0825f','和東坡醉翁操韵詠風琴','樓鑰','宋','宋诗','song-poetry','','[]','泠然，輕圓。',111,'全唐诗/poet.song.158000.json','["泠然，輕圓。", "誰彈，向屋山。", "何言，清風至陰德之天。", "悠颺餘響嬋娟，方晝眠。", "迥立八風前，八音相宣知孰賢。", "有時悲壯，鏗若龍泉。", "有時幽杳，彷彿猿吟鶴怨。", "忽若巍巍山顛，蕩蕩幾如流川。", "聊將娛暮年，聽之身欲僊。", "弦索滿人間，未有逸韵如此弦。"]'),
('595dbbd7-5de5-4dd7-b823-211432cc044e','雪谿仙隠','樓鑰','宋','宋诗','song-poetry','','[]','君之生兮天之西，望雪山兮名之以雪谿。',214,'全唐诗/poet.song.158000.json','["君之生兮天之西，望雪山兮名之以雪谿。", "君之游兮海之湄，隠于雪竇兮杳然何歸。", "子從其父兮孫訪吾祖，子志不遂兮孫之心良苦。", "嗟嗟，閬中君兮棄家而遠遊，蹇胡爲乎不久留。", "其遂蟬蛻塵埃而僊耶，其亦肥遯得道不死而隠于四窗之幽耶。", "捫蘿以尋于爛平兮既不可見，莽白雲之廿里兮欲進兮焉求。", "青欞兮實繁，莎羅兮花稠。", "鞠侯兮相與羣，白鷳兮嘯其儔。", "謂爲遠兮何景物之良是，謂在邇耶將徑之何由。", "肖君像兮茲堂，謹奉嘗兮良疇。", "君其來兮庶幾其見之，君之不來兮徒相羊以夷猶。"]'),
('1d98b1f7-3a13-442b-9cee-d26bafc8a182','姚江高風閣','樓鑰','宋','宋诗','song-poetry','','[]','不從文叔作三公，歸著羊裘大澤中。',64,'全唐诗/poet.song.158000.json','["不從文叔作三公，歸著羊裘大澤中。", "石瀨釣臺非故地，雲山江水自高風。", "烟迷宿草古遺恨，樹擁危樓新奏功。", "僊馭飄颻疑不遠，翩然獨鶴度寒空。"]'),
('7db91f39-3763-4ba6-8a1d-2e674e53cbc4','夜坐','樓鑰','宋','宋诗','song-poetry','','[]','重雲烟雨日冥冥，柱礎流津意未晴。',64,'全唐诗/poet.song.158000.json','["重雲烟雨日冥冥，柱礎流津意未晴。", "頼得谿風送雲出，放開山月照人明。", "紛紜世態長松影，荏苒時光流水聲。", "坐久蕭然轉琴軸，爲君更作九臯鳴。"]'),
('277dff97-8ca1-41dd-891e-7b432f5e8371','山陰道中  其一','樓鑰','宋','宋诗','song-poetry','','[]','昨望山陰古道中，蕺山直上最高峰。',32,'全唐诗/poet.song.158000.json','["昨望山陰古道中，蕺山直上最高峰。", "今朝更踏山陰道，却向雲間認八松。"]'),
('30e09cbb-d0e6-44ea-bdfb-19d58dac0c31','山陰道中  其二','樓鑰','宋','宋诗','song-poetry','','[]','捲上疎簾莫放垂，迎眸景色自淋漓。',64,'全唐诗/poet.song.158000.json','["捲上疎簾莫放垂，迎眸景色自淋漓。", "有雲更覺千山秀，不雨爭知萬壑奇。", "古道經行盡遺跡，羣賢風度想當時。", "奚囊莫怪新篇少，應接山川不暇詩。"]'),
('00edc54a-b1bb-40cc-93af-830be59f2c74','蘭亭別丁杲卿','樓鑰','宋','宋诗','song-poetry','','[]','山陰巖壑妙人寰，十載扁舟空往還。',64,'全唐诗/poet.song.158000.json','["山陰巖壑妙人寰，十載扁舟空往還。", "贊府端能慰牢落，連朝相與上孱顔。", "龍盤鳳翥無奇畫，霞蔚雲蒸有舊山。", "弔古凄凉更離別，滿懷秋思到眉間。"]'),
('dedee719-e4b9-4f1b-870a-89d91193eb09','早行','樓鑰','宋','宋诗','song-poetry','','[]','水餘枯枿尚棲苴，催促征夫趁曉鴉。',64,'全唐诗/poet.song.158000.json','["水餘枯枿尚棲苴，催促征夫趁曉鴉。", "細路繚山穿亂石，輕輿掠樹得飛花。", "柔桑彌望兩三里，修竹深藏四五家。", "徑處不容行客戀，可憐一步一天涯。"]'),
('2e2da635-1bdf-4035-8b2a-a8428656af4c','水漲乘小舟','樓鑰','宋','宋诗','song-poetry','','[]','一番凍雨洗郊丘，冷逼征衫四月秋。',64,'全唐诗/poet.song.158000.json','["一番凍雨洗郊丘，冷逼征衫四月秋。", "只喜青山瀉懸瀑，不知黄潦漲平疇。", "登途已厭頻輿轎，得意何妨且榜舟。", "處順安貧聊自適，未應坎止愧乘流。"]'),
('435a9b65-07fc-465b-9991-dbd2bbba8732','繡川道中','樓鑰','宋','宋诗','song-poetry','','[]','伏波莫作賈胡留，雨意垂垂未肯休。',64,'全唐诗/poet.song.158000.json','["伏波莫作賈胡留，雨意垂垂未肯休。", "不憚征衫有微濕，只愁平地又橫流。", "行人自厭衝泥苦，野老方當得意秋。", "倦僕如何致千里，登天徒笑傳鳴鳩。"]'),
('05142481-4e06-45af-be27-9ad0a27d4350','過蘇谿','樓鑰','宋','宋诗','song-poetry','','[]','處處谿環舍，家家石累牆。',48,'全唐诗/poet.song.158000.json','["處處谿環舍，家家石累牆。", "有時逢老稚，無事只耕桑。", "野色撩詩思，村醪引醉鄉。", "山川已如許，急雨更斜陽。"]'),
('015ad2ff-22f6-4d92-a380-574c6b6087b4','東陽遇雨','樓鑰','宋','宋诗','song-poetry','','[]','萬壑千巖已飽看，更尋佳處爲開顔。',32,'全唐诗/poet.song.158000.json','["萬壑千巖已飽看，更尋佳處爲開顔。", "無端早上一番雨，遮盡東陽縣裏山。"]'),
('1d7c39e1-9798-47ff-832e-4f94f3f14cd8','即事','樓鑰','宋','宋诗','song-poetry','','[]','雨外山光淡，烟中草色鮮。',48,'全唐诗/poet.song.158000.json','["雨外山光淡，烟中草色鮮。", "斷橋依古岸，流水自斜川。", "紫椹餘桑表，青藤遶樹顛。", "人情兼物態，只合付天然。"]'),
('56805a26-c4a6-4100-812a-f959342bebe2','行荆坑道中','樓鑰','宋','宋诗','song-poetry','','[]','古澗隨山轉，征人趁水行。',48,'全唐诗/poet.song.158000.json','["古澗隨山轉，征人趁水行。", "懸崖當步險，空翠逼人清。", "石路無尋直，沙田不畝平。", "千巖得一二，亦足慰平生。"]'),
('d739a14d-c18f-4a0c-bb98-b705d74593b1','馮公嶺','樓鑰','宋','宋诗','song-poetry','','[]','百級山田带雨耕，驅牛扶耒半空行。',32,'全唐诗/poet.song.158000.json','["百級山田带雨耕，驅牛扶耒半空行。", "不如身倚市門者，飽食豐衣過一生。"]'),
('db4722f5-515c-4d2f-a512-04409453fea0','括蒼烟雨樓','樓鑰','宋','宋诗','song-poetry','','[]','莫爲看山只凭欄，遠懷猶恨兩山間。',32,'全唐诗/poet.song.158000.json','["莫爲看山只凭欄，遠懷猶恨兩山間。", "坐深却得無窮趣，祇看平川一半山。"]'),
('3dbf4d87-f063-4f1d-a0ae-d9f18f52d2af','晚步少微閣','樓鑰','宋','宋诗','song-poetry','','[]','落日謝虛閣，橫琴相對閒。',24,'全唐诗/poet.song.158000.json','["落日謝虛閣，橫琴相對閒。", "片雲將急雨，一笑失前山。"]'),
('66410dfe-3025-43a5-a660-8182c00f4623','夜坐燒香臺','樓鑰','宋','宋诗','song-poetry','','[]','長晝苦炎熱，夜分凉始生。',48,'全唐诗/poet.song.158000.json','["長晝苦炎熱，夜分凉始生。", "電中千嶂立，琴外一蛩鳴。", "急雨催詩思，遥空答鼓聲。", "誰知一府地，得此意凄清。"]'),
('feabaf56-a196-4886-a7be-d1adde1c5f75','即事','樓鑰','宋','宋诗','song-poetry','','[]','睡重不知曉，山高意得秋。',48,'全唐诗/poet.song.158000.json','["睡重不知曉，山高意得秋。", "風來已落葉，潦去忽中洲。", "幽閴素所願，登臨儘自由。", "瀕溪千萬壑，何日上扁舟。"]'),
('400dcb89-cad7-4260-9f26-d0ad681267b3','小雨','樓鑰','宋','宋诗','song-poetry','','[]','好風先雨到危欄，却送殘雲過別山。',32,'全唐诗/poet.song.158000.json','["好風先雨到危欄，却送殘雲過別山。", "不用開襟强披拂，自然凉意滿人間。"]'),
('acf53a4c-0ae0-4fb1-af33-f1d4a195388e','烟雨樓夜坐','樓鑰','宋','宋诗','song-poetry','','[]','暮靄橫空黯未收，晚來凉動滿懷秋。',64,'全唐诗/poet.song.158000.json','["暮靄橫空黯未收，晚來凉動滿懷秋。", "澹雲影裏千山月，殘角聲中百尺樓。", "參坐共爲文字飲，高談不見古今愁。", "夜闌半醉意方適，徑欲乘風汗漫遊。"]'),
('663547a3-1eef-4130-a24e-7ad155e5804b','晚自擬滁亭轉烟雨樓聽角','樓鑰','宋','宋诗','song-poetry','','[]','兩寺疎鐘夾岸聞，荒烟無數亂前村。',64,'全唐诗/poet.song.158000.json','["兩寺疎鐘夾岸聞，荒烟無數亂前村。", "山銜落日雲生彩，谿溜孤舟水不痕。", "蟲羽凄凄鳴綠暗，星暉隠隠照黄昏。", "欲歸重到層樓上，更爲梅花一斷魂。"]'),
('1220bfa2-b902-461b-ac8f-4a55ea6e1c84','重陽','樓鑰','宋','宋诗','song-poetry','','[]','佳處逢佳節，寧辭望眼勞。',48,'全唐诗/poet.song.158000.json','["佳處逢佳節，寧辭望眼勞。", "有樓皆眺遠，無日不登高。", "野栗炊新秫，寒萸泛濁醪。", "黄花何太晚，籬落上蕭騷。"]'),
('ed8d2e1c-3270-4a79-999f-222b70254e06','北行雪中渡淮','樓鑰','宋','宋诗','song-poetry','','[]','風捲清淮夜不休，曉驚急雪遍郊丘。',64,'全唐诗/poet.song.158000.json','["風捲清淮夜不休，曉驚急雪遍郊丘。", "坐令和氣三邊滿，便覺胡塵萬里收。", "瑟瑟江頭輝玉節，蕭蕭馬上點貂裘。", "歸來風物渾相似，二月楊花遶御溝。"]'),
('75129fb6-65e7-46a5-bc95-b5c95e73c496','泗州道中','樓鑰','宋','宋诗','song-poetry','','[]','宿雪助寒色，相看汴水濱。',48,'全唐诗/poet.song.158000.json','["宿雪助寒色，相看汴水濱。", "輕車兀殘夢，羣馬濺飛塵。", "行役過周地，官儀泣漢民。", "中原陸沈久，任責豈無人。"]'),
('c4b5c2ba-9b06-4044-8868-559f2c37bc4f','靈壁道中','樓鑰','宋','宋诗','song-poetry','','[]','古汴微流絕，餘民尚孑遺。',48,'全唐诗/poet.song.158000.json','["古汴微流絕，餘民尚孑遺。", "高丘祠漢祖，荒草葬虞姬。", "垓下空陳迹，鴻溝愴近時。", "膏腴滿荆棘，傷甚黍離離。"]'),
('615e0b78-43a3-41d3-a69b-ba6a1a969677','陳留柏','樓鑰','宋','宋诗','song-poetry','','[]','驛門深閉柏參天，月可中庭夜影圓。',32,'全唐诗/poet.song.158000.json','["驛門深閉柏參天，月可中庭夜影圓。", "人靜好風喧客枕，坐令歸夢到林泉。"]'),
('62572cc9-e1c8-4283-8ff0-bcfe4dffa5cc','相州道中','樓鑰','宋','宋诗','song-poetry','','[]','千古興亡一夢驚，就中物理似持衡。',64,'全唐诗/poet.song.158000.json','["千古興亡一夢驚，就中物理似持衡。", "茜花空染朝歌血，荒草猶祠羑里城。", "但見反身知自咎，誰言修政欲相傾。", "知音只有昌黎操，臣罪當誅主聖明。"]'),
('5496358a-d8b2-497a-b228-749c588a1e8e','即事','樓鑰','宋','宋诗','song-poetry','','[]','行盡窮邊歲亦殫，倚門應是念衣單。',64,'全唐诗/poet.song.158000.json','["行盡窮邊歲亦殫，倚門應是念衣單。", "寧知今日幕南地，不似去年江上寒。", "乘馬惟欣日可愛，逢人長說雪初乾。", "三衾四襖半無用，何必重歌行路難。"]'),
('49386471-b08d-4af0-bb8b-f7713a8547bf','臘月二十五日大人生朝','樓鑰','宋','宋诗','song-poetry','','[]','去年沙岸倚歸舟，今日驅車古涿州。',64,'全唐诗/poet.song.158000.json','["去年沙岸倚歸舟，今日驅車古涿州。", "綵服難陪萊子戲，巴詞應付雪兒謳。", "客途行及五千里，壽宴須開十二樓。", "南望飛雲天樣遠，太行山外久凝眸。"]'),
('c054a1e3-eaa1-4a1b-974d-01bd570a5729','初出燕山','樓鑰','宋','宋诗','song-poetry','','[]','去國三千里，還家第一程。',48,'全唐诗/poet.song.158000.json','["去國三千里，還家第一程。", "都緣人意樂，便覺馬蹄輕。", "落日催心速，飛雲逐望生。", "莫嫌歸去晚，猶得趁清明。"]'),
('5ccac49b-07f8-4a76-9a43-78d8f6edc356','春雨  其一','樓鑰','宋','宋诗','song-poetry','','[]','石斗微微覆淺沙，蘭叢短短茁青芽。',32,'全唐诗/poet.song.158000.json','["石斗微微覆淺沙，蘭叢短短茁青芽。", "春花著眼未云久，花事于人漸有涯。"]'),
('44a09d37-59c9-4e00-a665-0c3c0fdcab88','春雨  其二','樓鑰','宋','宋诗','song-poetry','','[]','漫漫平湖接遠天，濛濛細雨濕輕烟。',32,'全唐诗/poet.song.158000.json','["漫漫平湖接遠天，濛濛細雨濕輕烟。", "野橋橫著草深外，何處渡頭人上船。"]'),
('2dff94a9-a3c3-42af-b602-86f614763f0b','送人之官池州','樓鑰','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','春空吹雨作餘寒，去去扁舟不可扳。',64,'全唐诗/poet.song.158000.json','["春空吹雨作餘寒，去去扁舟不可扳。", "伊昔曾游三大水，到今獨記九華山。", "想君脈脈征途遠，屬我悠悠夢境閒。", "回首江山固無恙，懷人倚待好詩還。"]'),
('44cf5db5-3bff-42ef-9492-6c160867c02a','春遊遇雨','樓鑰','宋','宋诗','song-poetry','','[]','公子喜青春，歡遊弗厭頻。',48,'全唐诗/poet.song.158000.json','["公子喜青春，歡遊弗厭頻。", "久晴都不問，好雨却成嗔。", "桃杏紅方入，禾苗綠未勻。", "請君停杖履，俯念耦耕人。"]'),
('aba36444-b361-47d8-9ba4-5c5e941658a6','糧料院葵向亭','樓鑰','宋','宋诗','song-poetry','','[]','結屋蒼崖晝不譁，崚嶒亂石遶簾牙。',64,'全唐诗/poet.song.158000.json','["結屋蒼崖晝不譁，崚嶒亂石遶簾牙。", "濤江渺莽三千頃，烟瓦參差百萬家。", "雉堞環山餘暮雪，龍樓聳闕煥朝霞。", "登臨可是望都省，但有葵心向日華。"]'),
('8349d0a3-4b50-4760-99e9-b5fd247e4731','廨舍小軒','樓鑰','宋','宋诗','song-poetry','','[]','衮衮羣山尾，橫窗更此岑。',48,'全唐诗/poet.song.158000.json','["衮衮羣山尾，橫窗更此岑。", "塵埃遮物外，風物宛山陰。", "作吏何妨隠，尋山不用深。", "居然一丘壑，便足快登臨。"]'),
('cdb1456a-834a-40ed-87e6-3286036fe994','尺五亭','樓鑰','宋','宋诗','song-poetry','','[]','舊說城南社，今登山外亭。',48,'全唐诗/poet.song.158000.json','["舊說城南社，今登山外亭。", "宮牆步可到，御柳望中青。", "引嘯千巖響，哦詩過鳥聽。", "曲欄頻徙倚，歸思渺東溟。"]'),
('55d6bfe9-6253-402e-9584-f2448a57b5c0','挈從子滌歸烏戍外家','樓鑰','宋','宋诗','song-poetry','','[]','五年不泛浙西船，今日重來倍黯然。',64,'全唐诗/poet.song.158000.json','["五年不泛浙西船，今日重來倍黯然。", "葦席不重寒刺被，菱歌孤唱月摇川。", "吚啞回櫓鳬鷗狎，來往輕帆風雨便。", "點檢湖山固無恙，鴒原遺恨到黄泉。"]'),
('b9e9cfab-a8b4-4c3a-b420-cbfd41c0e0b2','烏戍道中','樓鑰','宋','宋诗','song-poetry','','[]','田在港西家港東，斷橋春水步難通。',32,'全唐诗/poet.song.158000.json','["田在港西家港東，斷橋春水步難通。", "束蘆挾甕穩來去，不礙小船分釣筒。"]'),
('224fd144-3a4b-4437-9317-14eeb7e3286e','重陽寄雪窗從叔','樓鑰','宋','宋诗','song-poetry','','[]','秋意未教籬菊知，不妨烏帽著風吹。',64,'全唐诗/poet.song.158000.json','["秋意未教籬菊知，不妨烏帽著風吹。", "絕憐對酒君歸矣，更欲登高誰共之。", "風雨滿城千里夢，茱萸綴席一年期。", "君非俗物敗意者，莫爲催租便不詩。"]'),
('55f840fc-d714-4184-88f8-6e683b22d66b','次伯舅汪運幹所寄韵','樓鑰','宋','宋诗','song-poetry','','[]','遥憶牢之舅，功名志欲成。',48,'全唐诗/poet.song.158000.json','["遥憶牢之舅，功名志欲成。", "離思滿方寸，望眼費雙明。", "攬筆四愁詠，登樓千里情。", "賢勞休自歎，幢下本書生。"]'),
('ed617801-621c-46fb-be16-d036f12bb5e8','佛日山','樓鑰','宋','宋诗','song-poetry','','[]','曉出都城暮入山，杖藜蕭散易開顔。',32,'全唐诗/poet.song.158000.json','["曉出都城暮入山，杖藜蕭散易開顔。", "松風五里未行盡，隠隠疎鐘紫翠間。"]'),
('2bd9bf21-114a-4c3e-a92b-f03e048d7015','遊香山次王正言韵','樓鑰','宋','宋诗','song-poetry','','[]','四山過雨翠光流，境勝心閒自點頭。',64,'全唐诗/poet.song.158000.json','["四山過雨翠光流，境勝心閒自點頭。", "野鳥叫春多格磔，晚風吹鬢故颼飀。", "三年幾作舊山夢，一笑喜成今日遊。", "獨歎寒泉本無意，强隨機械走溪溝。"]'),
('70abd506-7252-4e2e-8545-ee03eb537576','過西興','樓鑰','宋','宋诗','song-poetry','','[]','幾載京塵涴客裘，江村乍入倍清幽。',64,'全唐诗/poet.song.158000.json','["幾載京塵涴客裘，江村乍入倍清幽。", "柔桑穉麥寒猶在，流水落花春又休。", "蒼狗浮空驚易失，白駒過隙若爲留。", "細思誰似垂綸者，寘酒烹魚百不憂。"]'),
('1992c16a-06ce-4b5e-8746-7c36e109a940','携家再游姚江','樓鑰','宋','宋诗','song-poetry','','[]','又作泛舟行，浮家一葉輕。',48,'全唐诗/poet.song.158000.json','["又作泛舟行，浮家一葉輕。", "潮生江外晚，月比夜來明。", "雲盡天容徹，風高水氣清。", "五湖乘興去，何苦慕功名。"]'),
('68baf1cc-728e-4f35-aeb0-e3643cca0c82','渡揚子','樓鑰','宋','宋诗','song-poetry','','[]','江豚吹浪雨颼飀，望斷天涯人白頭。',32,'全唐诗/poet.song.158000.json','["江豚吹浪雨颼飀，望斷天涯人白頭。", "一舸乘風渡揚子，數鷗導我過瓜州。"]'),
('1eeb7459-cb0a-4788-9e2c-e4700a7eba40','曉霧','樓鑰','宋','宋诗','song-poetry','','[]','曉霧冥濛水拍堤，稜嶒亂石與雲齊。',32,'全唐诗/poet.song.158000.json','["曉霧冥濛水拍堤，稜嶒亂石與雲齊。", "扁舟不用兼程去，到得稽城日已西。"]'),
('eb220a9e-4391-4309-ab19-1514b2cfcb56','登蕺山','樓鑰','宋','宋诗','song-poetry','','[]','晚步蕺山上，休辭脚力窮。',48,'全唐诗/poet.song.158000.json','["晚步蕺山上，休辭脚力窮。", "八松不礙眼，萬里欲乘風。", "逸興浮滄海，高歌徹太空。", "羲之不可見，猶得想胸中。"]'),
('f5aab49a-b809-4c34-b85c-cfb9a239b6d3','永嘉試院謝曾使君送酒  其一','樓鑰','宋','宋诗','song-poetry','','[]','一簾疎雨洗塵埃，滿架酴醾自在開。',32,'全唐诗/poet.song.158000.json','["一簾疎雨洗塵埃，滿架酴醾自在開。", "正恨烹茶殺風景，忽驚門外白衣來。"]'),
('7d22d9f1-3fe3-4cc9-aedc-66e73fb6fe2f','永嘉試院謝曾使君送酒  其二','樓鑰','宋','宋诗','song-poetry','','[]','脫身場屋幾春秋，故步重尋我自羞。',64,'全唐诗/poet.song.158000.json','["脫身場屋幾春秋，故步重尋我自羞。", "閉置有如三日婦，畫成應遣一生愁。", "與錢誰是老司業，送酒更無賢郡侯。", "掩卷出門花下坐，真成一酌散千憂。"]'),
('59825e82-cf49-468c-9b8e-483693efa01b','木藴之國博遷居  其一','樓鑰','宋','宋诗','song-poetry','','[]','寄齋今日又遷居，門巷相過五尺餘。',64,'全唐诗/poet.song.158000.json','["寄齋今日又遷居，門巷相過五尺餘。", "王子何妨借人屋，淵明不必愛吾廬。", "大千眼裏無非寄，三十乘中皆是書。", "祀竈卜鄰無用爾，祇今天上有鋒車。"]'),
('de4ad25d-d41d-4dde-b853-2915555f974a','木藴之國博遷居  其二','樓鑰','宋','宋诗','song-poetry','','[]','名大人稱屈，心閒我自餘。',48,'全唐诗/poet.song.158000.json','["名大人稱屈，心閒我自餘。", "言詩今子貢，作賦古玄虛。", "鳳沼定平進，鷗盟殊未疎。", "潭潭府中去，只作寄齋居。"]'),
('b6b9d48f-72be-4d5c-b612-e1621e3056b0','次南真宮龔道士壁間韵','樓鑰','宋','宋诗','song-poetry','','[]','幽舍足留客，疎篁不用林。',48,'全唐诗/poet.song.158000.json','["幽舍足留客，疎篁不用林。", "相過幾樽酒，清坐一瑶琴。", "野鶴伴僊隠，閒雲寄此心。", "黄冠如有許，來者爲低簪。"]'),
('c4135d6a-b6d4-4404-bdd2-add21e3d660a','送樂清姚令行可','樓鑰','宋','宋诗','song-poetry','','[]','長官清政玉無瑕，卓魯循良不足誇。',64,'全唐诗/poet.song.158000.json','["長官清政玉無瑕，卓魯循良不足誇。", "前席有期吾黨喜，挽鬚無路邑人嗟。", "才高雁蕩千峰石，惠足河陽一縣花。", "欲信三年渾不擾，遊山今日始携家。"]'),
('7a9473b4-1bd3-4cb4-a3dc-c87a72264c5e','入雁山過雙峰','樓鑰','宋','宋诗','song-poetry','','[]','眼前未見古龍湫，望望前山景自幽。',64,'全唐诗/poet.song.158000.json','["眼前未見古龍湫，望望前山景自幽。", "紅日一門千嶂曉，翠峰雙聳半空秋。", "風高落木無邊下，氣勁閒雲逐處收。", "要識雁山真面目，直須霜後一來遊。"]'),
('e6fd8b6c-672e-4224-ac6a-93a0059e87ca','靈峰','樓鑰','宋','宋诗','song-poetry','','[]','老筇扶我轉林丘，直到僧房最上頭。',64,'全唐诗/poet.song.158000.json','["老筇扶我轉林丘，直到僧房最上頭。", "地擁雙峰遮勝境，天分半石閟靈湫。", "空中大士澹相對，山罅清泉空自流。", "人謂石崖宜置我，不知來此有緣不。"]'),
('ad1d75f0-2180-498d-b950-9a101d24d6dd','龍湫','樓鑰','宋','宋诗','song-poetry','','[]','地聳峰巒秀，天開氣象寬。',48,'全唐诗/poet.song.158000.json','["地聳峰巒秀，天開氣象寬。", "九霄銀漢落，千古玉龍寒。", "壯觀供尊者，幽居稱冷官。", "何時遂肥遯，不厭白頭看。"]'),
('1ad2b3bd-b542-4cd0-baf4-b00856c9fc97','又次王瑞安韵','樓鑰','宋','宋诗','song-poetry','','[]','雲鎖千峰碧，泉飛百尺湫。',48,'全唐诗/poet.song.158000.json','["雲鎖千峰碧，泉飛百尺湫。", "山蹊驚險絕，洞府足深幽。", "谷靜摇虛箔，巖高卧老虬。", "賈胡還似我，到處輒遲留。"]'),
('b4561d30-3177-4968-8699-40bd6d39c4f2','忘歸亭','樓鑰','宋','宋诗','song-poetry','','[]','一峰凜凜插烟霏，誰築新亭占石磯。',32,'全唐诗/poet.song.158000.json','["一峰凜凜插烟霏，誰築新亭占石磯。", "標榜未應專一壑，此山何處不忘歸。"]'),
('3122572b-f584-4c7d-833f-d79383980ec0','登馬鞍嶺','樓鑰','宋','宋诗','song-poetry','','[]','軋軋輕輿上馬鞍，半天嵐翠逼人寒。',32,'全唐诗/poet.song.158000.json','["軋軋輕輿上馬鞍，半天嵐翠逼人寒。", "從教宿靄迷清嶂，明日晴空取意看。"]'),
('f1c83f32-c5ca-4952-903d-fb98a0ed1508','游西山次范丞韵','樓鑰','宋','宋诗','song-poetry','','[]','東風吹我上西岡，更覺僧房白晝長。',64,'全唐诗/poet.song.158000.json','["東風吹我上西岡，更覺僧房白晝長。", "草色已翻新歲碧，梅花祇是去年香。", "好山圍繞屏三面，野竹蕭森玉數行。", "千里同遊逢范叔，綈袍他日未相忘。"]'),
('88630e64-2801-4f17-b940-fc0cd2d784a8','喜雪','樓鑰','宋','宋诗','song-poetry','','[]','曉風吹起雪漫漫，來兆豐年喜有端。',64,'全唐诗/poet.song.158000.json','["曉風吹起雪漫漫，來兆豐年喜有端。", "玉樹瓊枝無限好，雪窗高閣不勝寒。", "直疑天上梅花落，莫作人間柳絮看。", "我欲乘風游汗漫，倚欄空自羨飛翰。"]'),
('d3ee96b3-fb68-4ac5-873f-bc2901e0b922','同年翁處度招遊北山次韵','樓鑰','宋','宋诗','song-poetry','','[]','不嫌屐齒碎莓苔，祇要吾人得得來。',64,'全唐诗/poet.song.158000.json','["不嫌屐齒碎莓苔，祇要吾人得得來。", "見說飛泉高落澗，待尋曲水作流杯。", "竹林素約羣賢集，雞黍相過一笑開。", "政恐清遊自忘返，不應空棹酒船回。"]'),
('d849289a-de1a-4ebd-822e-03d4bc350eb5','支茂先烟蓑亭','樓鑰','宋','宋诗','song-poetry','','[]','人生逆旅困風波，大似寄居鸚鵡螺。',32,'全唐诗/poet.song.158000.json','["人生逆旅困風波，大似寄居鸚鵡螺。", "月白江空無一事，不須更作釣魚蓑。"]'),
('fdd6b89c-ef65-474c-821b-336a8acdb034','紅梅','樓鑰','宋','宋诗','song-poetry','','[]','南枝零落北枝殘，失喜新蕤苦耐寒。',32,'全唐诗/poet.song.158000.json','["南枝零落北枝殘，失喜新蕤苦耐寒。", "莫道北人渾不識，南人幾作杏花看。"]'),
('f5c64969-a8fd-445c-8427-11c6aee7994f','秋意次林致甫宗丞韵','樓鑰','宋','宋诗','song-poetry','','[]','河漢秋來浄，飛星一點過。',48,'全唐诗/poet.song.158000.json','["河漢秋來浄，飛星一點過。", "好風吹暑盡，疎雨送凉多。", "紈扇收團月，桃笙捲細波。", "自知恩到骨，欹枕夢無何。"]'),
('71fa2fb1-f41b-419c-8e5a-8b9d6da37cff','送春  其一','樓鑰','宋','宋诗','song-poetry','','[]','飛花一片減風光，不待紅稀意已傷。',64,'全唐诗/poet.song.158000.json','["飛花一片減風光，不待紅稀意已傷。", "今歲餘春能幾許，浮生此日更須忙。", "隴頭有雨麥初秀，林下無人蘭自芳。", "夜倚疎欞誦佳句，好風如水月如霜。"]'),
('bcdb5ccf-fa00-4ef5-a9d4-0cf9a9218e74','送春  其二','樓鑰','宋','宋诗','song-poetry','','[]','花披催蝶舞，柳暗受鶑遷。',48,'全唐诗/poet.song.158000.json','["花披催蝶舞，柳暗受鶑遷。", "過眼忽新夢，回頭誰少年。", "溪雲隨筍供，山雨近梅天。", "詩思正無頼，一聲來杜鵑。"]'),
('c11478b0-48e6-4496-ba27-943f48b4677a','病目初愈張子家有詩次韵','樓鑰','宋','宋诗','song-poetry','','[]','年來視物隔褷䙰，祇有昏花似退之。',64,'全唐诗/poet.song.158000.json','["年來視物隔褷䙰，祇有昏花似退之。", "强起歸鴻聊自放，妙穿懸蝨恐難爲。", "相親黄奶交親絕，見代青姑事寖危。", "寫照苦添雲蔽日，不應更誚虎頭癡。"]'),
('9c630997-55c5-4757-a9f0-1476bb118dea','許深父餉酒覆於舟中','樓鑰','宋','宋诗','song-poetry','','[]','千里貽書慰寂寥，更將尊酒餉今朝。',64,'全唐诗/poet.song.158000.json','["千里貽書慰寂寥，更將尊酒餉今朝。", "先生忽已成烏有，用事何因見白超。", "醉裏謾思鯨吸海，夢回誰悟鹿藏蕉。", "何時痛飲論心曲，雲滿江東望眼遥。"]'),
('3ef84d12-f93f-45b4-8c93-e097efc28f86','送胡巨濟宰湘潭','樓鑰','宋','宋诗','song-poetry','','[]','君向瀟湘忽語離，江城離思亂雲飛。',64,'全唐诗/poet.song.158000.json','["君向瀟湘忽語離，江城離思亂雲飛。", "傳聞楚俗尤凋瘵，勿以秦人視瘠肥。", "宰縣要尋行志處，監州空有負丞譏。", "此行得句須頻寄，直到衡陽有雁歸。"]'),
('2915194a-7825-40b0-b24e-c0ed3bbad7ce','即事','樓鑰','宋','宋诗','song-poetry','','[]','芸芸物態見天機，靜裏工夫得細微。',32,'全唐诗/poet.song.158000.json','["芸芸物態見天機，靜裏工夫得細微。", "階下秋紅千萬點，游蜂一一採香歸。"]'),
('96439d21-904e-48d9-8e00-04647b9ade60','正月庚申朔','樓鑰','宋','宋诗','song-poetry','','[]','春來節物一番新，今歲仍逢臘裏春。',32,'全唐诗/poet.song.158000.json','["春來節物一番新，今歲仍逢臘裏春。", "莫訝連宵清不寐，祇緣守歲守庚申。"]'),
('ef65d2b1-f256-40a7-9a10-ae8d2ea967ec','國清寺','樓鑰','宋','宋诗','song-poetry','','[]','夾道青松引客來，五峰雙澗擁樓臺。',64,'全唐诗/poet.song.158000.json','["夾道青松引客來，五峰雙澗擁樓臺。", "豐干饒舌留公案，隋帝遺書暗古煤。", "最喜親知來里社，真成春月上天台。", "陰雲掃盡尋幽去，佳處端疑爲我開。"]'),
('a4bf14a2-0114-4cd5-a5ea-31c65e312cf6','山中懷仲兄','樓鑰','宋','宋诗','song-poetry','','[]','雁山曾御九秋風，更喜春深到此中。',64,'全唐诗/poet.song.158000.json','["雁山曾御九秋風，更喜春深到此中。", "芳草絕憐隨意綠，野花真是映山紅。", "未知方丈景何似，直恐桃源路已通。", "起聽朝雞無恙否，茲遊恨不與君同。"]'),
('aeab7255-b952-4b2f-b86c-ebcaa751e54a','天台道中口占','樓鑰','宋','宋诗','song-poetry','','[]','路上人家短竹籬，繅蠶刈麥自熙熙。',32,'全唐诗/poet.song.158000.json','["路上人家短竹籬，繅蠶刈麥自熙熙。", "可憐日對千尋瀑，不解閒吟半字書。"]'),
('9abba4c6-5e9c-4602-85bb-feea4458437b','宿仙居民家','樓鑰','宋','宋诗','song-poetry','','[]','投暝人家欲睡時，雨聲不斷水平池。',32,'全唐诗/poet.song.158000.json','["投暝人家欲睡時，雨聲不斷水平池。", "回頭已過三江渡，醉看車中總不知。"]'),
('178113ea-1eb0-4e9e-9c5c-0e91ae0b38ec','寄管叔儀通判并同官','樓鑰','宋','宋诗','song-poetry','','[]','執別僧房日未斜，別離愁緒滿天涯。',64,'全唐诗/poet.song.158000.json','["執別僧房日未斜，別離愁緒滿天涯。", "清宵已落柔桑葉，小雨頓開蕎麥花。", "醉裏不知身是客，酒闌無奈客思家。", "憑誰寄語三夫子，歸路還須好句誇。"]'),
('aef52e7d-f3da-407f-b13e-ed95e5b43c01','贈寶藏老道源','樓鑰','宋','宋诗','song-poetry','','[]','骨相昂藏澗底松，平生禪窟儘從容。',64,'全唐诗/poet.song.158000.json','["骨相昂藏澗底松，平生禪窟儘從容。", "幾年大隠清暉閣，今日來瞻獨秀峰。", "打破畫瓶無罣礙，大開飯店喜迎逢。", "今朝且逐征途去，何日重來聽曉鐘。"]'),
('d9da10ef-0d10-48db-a471-ebc7f6ffc6d0','過蒼嶺  其一','樓鑰','宋','宋诗','song-poetry','','[]','黄雲滿塢沙田稻，白雪漫山薺菜花。',32,'全唐诗/poet.song.158000.json','["黄雲滿塢沙田稻，白雪漫山薺菜花。", "路人縉雲頻借問，碧香酒好是誰家。"]'),
('60bc190e-0750-48ae-a599-9fe6b94b875b','過蒼嶺  其二','樓鑰','宋','宋诗','song-poetry','','[]','崇朝辛苦上孱顔，泥徑初平意暫閒。',32,'全唐诗/poet.song.158000.json','["崇朝辛苦上孱顔，泥徑初平意暫閒。", "蒼嶺東頭移野步，眼前便得處州山。"]'),
('f711ad18-144e-4e77-a749-01885236b971','婺女極目亭','樓鑰','宋','宋诗','song-poetry','','[]','危樓雄據郡城東，掃盡秋雲快碧空。',64,'全唐诗/poet.song.158000.json','["危樓雄據郡城東，掃盡秋雲快碧空。", "目力不容山隔斷，詩情長與酒無窮。", "先分樓下雙溪水，高挹人間萬里風。", "興逸不知真近遠，五弦聲裏送歸鴻。"]'),
('e53f069e-fb09-4459-95e2-7ef59fff55d7','自柯山歸再過蒼嶺','樓鑰','宋','宋诗','song-poetry','','[]','雨後過蒼嶺，平生行路難。',48,'全唐诗/poet.song.158000.json','["雨後過蒼嶺，平生行路難。", "危層驚步滑，絕澗覺心寒。", "就嶺山逾險，趨平谷更盤。", "年來輕世故，不作險塗看。"]'),
('adffb580-9c54-47bf-947b-c100dc4372d5','鹿伯可郎中園池雜詠 見一堂','樓鑰','宋','宋诗','song-poetry','','[]','靈澈清詩千載傳，始聞林下有斯賢。',32,'全唐诗/poet.song.158000.json','["靈澈清詩千載傳，始聞林下有斯賢。", "傍人只道休官早，見一名堂已十年。"]'),
('a37e2975-4512-4035-82ee-6c2fb47e23c0','鹿伯可郎中園池雜詠 止室','樓鑰','宋','宋诗','song-poetry','','[]','流行坎止事無多，舉世營營自網羅。',32,'全唐诗/poet.song.158000.json','["流行坎止事無多，舉世營營自網羅。", "珍重主人真止矣，直如古井更無波。"]'),
('a4554596-f980-4859-a088-c236f2da348a','鹿伯可郎中園池雜詠 小東山','樓鑰','宋','宋诗','song-poetry','','[]','安石東山志不渝，歸來尋得靜工夫。',32,'全唐诗/poet.song.158000.json','["安石東山志不渝，歸來尋得靜工夫。", "從教更爲蒼生起，携妓何妨且自娛。"]'),
('88b0d943-3776-45e8-84e4-8f72a304853c','鹿伯可郎中園池雜詠 桂堂','樓鑰','宋','宋诗','song-poetry','','[]','芳樹叢生庭砌間，高枝更許後來攀。',32,'全唐诗/poet.song.158000.json','["芳樹叢生庭砌間，高枝更許後來攀。", "主人勿戀山中桂，招隠還應看小山。"]'),
('e7d0a743-8951-486f-92e6-107e150e5cef','鹿伯可郎中園池雜詠 雲龕','樓鑰','宋','宋诗','song-poetry','','[]','浮雲舒卷原無定，此意誰能爲飽參。',32,'全唐诗/poet.song.158000.json','["浮雲舒卷原無定，此意誰能爲飽參。", "出岫無心歸亦爾，不妨今日與同龕。"]'),
('e5449ed9-18bf-4459-b7a6-86b4d38bdc61','鹿伯可郎中園池雜詠 柑隅','樓鑰','宋','宋诗','song-poetry','','[]','霜著芳苞翠作圍，數椽瀟灑映斜暉。',32,'全唐诗/poet.song.158000.json','["霜著芳苞翠作圍，數椽瀟灑映斜暉。", "木奴何必須千樹，乞得閒身徑且歸。"]'),
('bfb51653-98ff-4bfd-bd62-39116e3493bd','鹿伯可郎中園池雜詠 桃蹊','樓鑰','宋','宋诗','song-poetry','','[]','幾樹桃花相映開，主人歸路入天台。',32,'全唐诗/poet.song.158000.json','["幾樹桃花相映開，主人歸路入天台。", "憑誰寄語玄都觀，前度劉郎不更來。"]'),
('f75e64ff-5832-4cad-9670-f4f498e37749','鹿伯可郎中園池雜詠 月沼','樓鑰','宋','宋诗','song-poetry','','[]','玉潔冰清一壑專，籜龍何處引涓涓。',32,'全唐诗/poet.song.158000.json','["玉潔冰清一壑專，籜龍何處引涓涓。", "深知月滿還虧缺，祇學蟾光一半圓。"]'),
('8da17945-056b-47d4-9f84-8fb726076437','鹿伯可郎中園池雜詠 星潭','樓鑰','宋','宋诗','song-poetry','','[]','山頭分下一泓清，石甃團團瞰小亭。',32,'全唐诗/poet.song.158000.json','["山頭分下一泓清，石甃團團瞰小亭。", "身在赤城名絳闕，至今潭影照郎星。"]'),
('06ea76dc-0e41-4d43-ade0-5886ecb7e23a','鹿伯可郎中園池雜詠 三友徑','樓鑰','宋','宋诗','song-poetry','','[]','公是端人友必端，世情冷暖不相干。',32,'全唐诗/poet.song.158000.json','["公是端人友必端，世情冷暖不相干。", "雖云門外可羅雀，三益還能耐歲寒。"]'),
('494c3a7f-a78b-4da0-956b-a14d5968b9e6','鹿伯可郎中園池雜詠 竹塢','樓鑰','宋','宋诗','song-poetry','','[]','幾年種竹未成叢，一日歸來翠掃空。',32,'全唐诗/poet.song.158000.json','["幾年種竹未成叢，一日歸來翠掃空。", "儘好閉門高枕卧，從今日日是清風。"]'),
('60a849dc-a41d-4fc3-940f-255d273d18d8','鹿伯可郎中園池雜詠 梅坡','樓鑰','宋','宋诗','song-poetry','','[]','江梅留待主人還，見說歸時得飽看。',32,'全唐诗/poet.song.158000.json','["江梅留待主人還，見說歸時得飽看。", "回首殘花飛作雪，一峰當戶正高寒。"]'),
('d9926be6-d797-4466-9208-87d857169f18','鹿伯可郎中園池雜詠 松嶺','樓鑰','宋','宋诗','song-poetry','','[]','翠雲深處曳枯筇，插碧堂堂十八公。',32,'全唐诗/poet.song.158000.json','["翠雲深處曳枯筇，插碧堂堂十八公。", "全似華陽隠君子，掛冠歸去聽松風。"]'),
('a3a2b8a7-1cf2-4c05-b1cf-3865975faf6a','戲贈張漢卿','樓鑰','宋','宋诗','song-poetry','','[]','張侯理窟妙無窮，雅謔于人亦有功。',32,'全唐诗/poet.song.158000.json','["張侯理窟妙無窮，雅謔于人亦有功。", "渺渺江湖千萬頃，未聞餓死信天公。"]'),
('79338d0a-ac81-4a8b-8fab-fa98e6ccc45b','陪沈虞卿使君游錢園','樓鑰','宋','宋诗','song-poetry','','[]','休沐無官事，公庭且放衙。',288,'全唐诗/poet.song.158000.json','["休沐無官事，公庭且放衙。", "城中尋勝地，道上引高牙。", "潭府臨芳徑，東巖玩物華。", "山林真敻絕，棟宇謝豪奢。", "陶令親栽菊，秦侯晚種瓜。", "裴公餘綠野，六一醉琅玡。", "幽阪森三友，飛橋粲百花。", "樹深藏曲折，谷險路谽谺。", "道院羅星斗，禪房供釋迦。", "鼇峰思御氣，畫舸想乘槎。", "佳處城環雉，吟邊路遶蛇。", "登山携翠袖，喝道屏銀檛。", "井市花相映，湖陂柳半遮。", "高歌驚野鳥，疊鼓亂鳴蛙。", "陛級青珉滑，秋千綵旆斜。", "叢篁穿嫩筍，芳草綻新葩。", "靜憩方開宴，徐行更試茶。", "僊醪斟瑪瑙，玉指奏琵琶。", "清絕囂塵遠，蒼茫望眼賒。", "詩情彌海嶠，飲興渺天涯。", "賢尹民同樂，名郎子克家。", "才高修月戶，筆妙補天媧。", "揮麈風流勝，憑欄笑語誇。", "追風慚款段，倚玉媿蒹葭。"]'),
('d10e5266-519f-46f6-994f-7efd17b3d55f','巾山曲肱齋','樓鑰','宋','宋诗','song-poetry','','[]','山立青冥外，人行紫翠間。',48,'全唐诗/poet.song.158000.json','["山立青冥外，人行紫翠間。", "小窗開木末，孤塔映江灣。", "平楚一何遠，白雲相與閒。", "我來不暇寢，冷坐對前山。"]'),
('5b743685-ba89-4bd3-84ee-8a6d27e451e6','廣軒夜望','樓鑰','宋','宋诗','song-poetry','','[]','點點萬家燈，風清醉復醒。',24,'全唐诗/poet.song.158000.json','["點點萬家燈，風清醉復醒。", "廣軒高絕處，俯瞰一天星。"]'),
('e68168b7-fe4c-4636-843f-8bb1b674e77f','玉霄亭玩雪','樓鑰','宋','宋诗','song-poetry','','[]','羣齋高晏雪浮空，同上山城第一重。',64,'全唐诗/poet.song.158000.json','["羣齋高晏雪浮空，同上山城第一重。", "今日無非銀色界，此亭真是玉霄峰。", "雲迷野路舞輕鶴，風急瓦溝噓老龍。", "便欲相將游汗漫，剡溪何必訪遺蹤。"]'),
('72983dc3-ad0d-4fc0-bd05-edfff02f8e43','倅廳雲水亭','樓鑰','宋','宋诗','song-poetry','','[]','山遶澄江江遶城，水雲徑接海冥冥。',64,'全唐诗/poet.song.158000.json','["山遶澄江江遶城，水雲徑接海冥冥。", "萬家曲折在吾目，一郡登臨屬此亭。", "今日詩題隨處有，幾番醉眼望中醒。", "風流鄭老知何在，回首蒼茫島嶼青。"]'),
('aad49c1b-7947-4403-8597-5c6e187d241a','再過鹿伯可','樓鑰','宋','宋诗','song-poetry','','[]','又上先生見一堂，澹然賓主兩相忘。',64,'全唐诗/poet.song.158000.json','["又上先生見一堂，澹然賓主兩相忘。", "不知海內清風滿，但覺山中白晝長。", "小雨絡林妨蠟屐，靚妝環坐快瑶觴。", "曲終扶杖欲歸去，即詠白駒三四章。"]'),
('36ff63e5-e627-4d17-898a-d146b993bd65','天姥嶺','樓鑰','宋','宋诗','song-poetry','','[]','剡水迂回徹底清，濫觴從此一泓澄。',32,'全唐诗/poet.song.158000.json','["剡水迂回徹底清，濫觴從此一泓澄。", "曉來蠟屐沖寒上，踏碎山頭十里冰。"]'),
('289f31b6-50c4-4127-b877-d44ead90020b','虎丘','樓鑰','宋','宋诗','song-poetry','','[]','望望古招提，茲遊恨已遲。',48,'全唐诗/poet.song.158000.json','["望望古招提，茲遊恨已遲。", "池深驚地裂，野曠覺天垂。", "聽法人千數，談空松一枝。", "從誰訪遺跡，惟有石頭知。"]'),
('99b51547-af8b-4034-981c-f50722019dbd','洛社老僧聽琴  其一','樓鑰','宋','宋诗','song-poetry','','[]','宴坐蕭齋不作勞，謂予何事走蓬蒿。',32,'全唐诗/poet.song.158000.json','["宴坐蕭齋不作勞，謂予何事走蓬蒿。", "從容試問今年幾，手植黄楊三丈高。"]'),
('6a6f9c3d-e14e-465f-a7cd-14f246d6d3e9','洛社老僧聽琴  其二','樓鑰','宋','宋诗','song-poetry','','[]','自言幾載不聞琴，屢聽清彈苦契心。',32,'全唐诗/poet.song.158000.json','["自言幾載不聞琴，屢聽清彈苦契心。", "少待庭柯蟬噪靜，爲師更作醉翁吟。"]'),
('b262bbec-282b-4526-b68c-af51a1f90535','中秋','樓鑰','宋','宋诗','song-poetry','','[]','歲歲當秋半，人人待月明。',48,'全唐诗/poet.song.158000.json','["歲歲當秋半，人人待月明。", "絕憐今夜賞，更勝去年晴。", "光彩澄高露，氛埃廓太清。", "衆心方閔雨，却望暮雲生。"]'),
('5c939712-9b08-450b-b66a-2e8f2ba8deca','又次丁端叔韵','樓鑰','宋','宋诗','song-poetry','','[]','好風凉月湛中秋，自笑何爲作遠遊。',64,'全唐诗/poet.song.158000.json','["好風凉月湛中秋，自笑何爲作遠遊。", "不有諸君故人戀，未應連日賈胡留。", "三千銀界俱呈色，十二珠簾總上鉤。", "飲罷客歸清不寐，誰知心折大刀頭。"]'),
('58e92b3a-5e2b-471c-b2a6-50460cd17fb5','游惠山','樓鑰','宋','宋诗','song-poetry','','[]','石徑縈迴入翠林，廿年故步喜重尋。',64,'全唐诗/poet.song.158000.json','["石徑縈迴入翠林，廿年故步喜重尋。", "千山直上雲扉啟，萬木陰中古殿深。", "泉水泓澄風拂拂，洞門幽杳晝沈沈。", "調琴瀹茗清無限，倦客忘歸到夕陰。"]'),
('19d31c7b-c66d-4c3e-a277-0b9dd51960ef','游洞霄宮','樓鑰','宋','宋诗','song-poetry','','[]','宿雨頑雲撥不開，紫霄佳處訪樓臺。',64,'全唐诗/poet.song.158000.json','["宿雨頑雲撥不開，紫霄佳處訪樓臺。", "青山九鎖固奇甚，古洞一深如此哉。", "拔地千林俱秀潤，擎天一柱最崔嵬。", "出山爽氣尚相屬，數里清溪送我回。"]'),
('dbf26f2d-6f5a-46ea-884a-1c1792fcc138','游徑山','樓鑰','宋','宋诗','song-poetry','','[]','起看海日曉團團，更挹神燈照夜闌。',64,'全唐诗/poet.song.158000.json','["起看海日曉團團，更挹神燈照夜闌。", "百萬杉松雙徑杳，三千樓閣五峰寒。", "蟄龍何在渺難問，古井于今竟不眢。", "但覓靈泉歸洗眼，誰能故把細書看。"]'),
('08bf5dc4-3330-48e1-aec6-fe8c3f12d7db','送蘇伯昌大卿  其一','樓鑰','宋','宋诗','song-poetry','','[]','禁路岧嶤欲問津，抗章便自乞閒身。',64,'全唐诗/poet.song.158000.json','["禁路岧嶤欲問津，抗章便自乞閒身。", "閔勞劇部皇情厚，寓直中奎寵數新。", "飛輓正資經濟手，典刑終念老成人。", "赤松未許長爲伴，歸取青氈繼潁濱。"]'),
('ee24245c-6108-4b15-818f-35b646a41693','送蘇伯昌大卿  其二','樓鑰','宋','宋诗','song-poetry','','[]','甬東曾幸拜蘇天，外府官僚復備員。',64,'全唐诗/poet.song.158000.json','["甬東曾幸拜蘇天，外府官僚復備員。", "前輩風流真在眼，名公談笑辱忘年。", "浙江相對一巵酒，婺港欲行雙槳船。", "門鍵馬銜難作遠，西風停立但茫然。"]'),
('ed93f18b-f63d-438f-ab16-58ecba5c4393','送劉淳叟博士倅豫章','樓鑰','宋','宋诗','song-poetry','','[]','熟知明主可忠言，奏牘方陳意已傳。',64,'全唐诗/poet.song.158000.json','["熟知明主可忠言，奏牘方陳意已傳。", "人言能遜千乘國，我自能補九重天。", "拔山轉石孰難易，爛額徙薪誰後先。", "不用更論如許事，把君征袂且茫然。"]'),
('5dcd1e93-32d4-444b-9dda-6a1abb400242','送呂周輔宗丞守崇慶  其一','樓鑰','宋','宋诗','song-poetry','','[]','從昔傳家學，當今良史才。',48,'全唐诗/poet.song.158000.json','["從昔傳家學，當今良史才。", "聲名冠西蜀，風節象東臺。", "朝蹟收何速，歸心挽不回。", "一麾從此去，萬里可能來。"]'),
('cb6d49ed-791d-4200-8490-f3316f36634f','送呂周輔宗丞守崇慶  其二','樓鑰','宋','宋诗','song-poetry','','[]','舊矣唐安郡，龍潛府號新。',48,'全唐诗/poet.song.158000.json','["舊矣唐安郡，龍潛府號新。", "當年一絳帳，今日兩朱輪。", "民意來何暮，仁聲煖似春。", "劍南毋戀却，鼇禁要詞人。"]'),
('ae7a8ebe-7785-4bcb-9d53-a167e6093c81','送呂周輔宗丞守崇慶  其三','樓鑰','宋','宋诗','song-poetry','','[]','祕甚先天學，誰傳陸士龍。',48,'全唐诗/poet.song.158000.json','["祕甚先天學，誰傳陸士龍。", "上方留自近，天豈不相容。", "契託君家厚，情惟我輩鍾。", "慇懃訓猶子，他日使追蹤。"]'),
('afd28b5d-783a-4637-9158-4a84395c5338','上魏丞相','樓鑰','宋','宋诗','song-poetry','','[]','夢菴深坐宴朝曛，祇有梅花對此君。',64,'全唐诗/poet.song.158000.json','["夢菴深坐宴朝曛，祇有梅花對此君。", "今日衣冠有巢許，向來元凱佐華勳。", "入山誰解訪弘景，載酒時應問子雲。", "童諷寫成心未懶，可因貪佛贊論文。"]'),
('ad6dffa8-e674-4fd9-968d-f7c8bb24b989','次韵蔣德言游太白玉几兩山  其一','樓鑰','宋','宋诗','song-poetry','','[]','西山不到幾經春，玉几猶能一再臨。',32,'全唐诗/poet.song.158000.json','["西山不到幾經春，玉几猶能一再臨。", "太白峰前成夢境，直從總角到于今。"]'),
('bac94db8-bd75-4d06-9bd4-f374485a1c9e','次韵蔣德言游太白玉几兩山  其二','樓鑰','宋','宋诗','song-poetry','','[]','少日游山不要歸，老來腰脚不相宜。',32,'全唐诗/poet.song.158000.json','["少日游山不要歸，老來腰脚不相宜。", "羨君勝具了無倦，踏雪尋幽更一奇。"]'),
('730bc65d-ab54-4673-a03c-7cf3a792298e','次韵蔣德言游太白玉几兩山  其三','樓鑰','宋','宋诗','song-poetry','','[]','賸欲扶筇隨意行，要令心跡得雙清。',32,'全唐诗/poet.song.158000.json','["賸欲扶筇隨意行，要令心跡得雙清。", "何時同入翠微去，丈室先參老浄名。"]'),
('5887174d-33f7-4e72-803b-fb2b0916a7b3','次韵蔣德言游太白玉几兩山  其四','樓鑰','宋','宋诗','song-poetry','','[]','落花影裏步春闌，飛鳥翩翩相與還。',32,'全唐诗/poet.song.158000.json','["落花影裏步春闌，飛鳥翩翩相與還。", "若得把茅成小隠，等閒來往兩山間。"]'),
('99e6d60d-44e1-4c34-a8dd-99775beeaa00','次韵蔣德言游太白玉几兩山  其五','樓鑰','宋','宋诗','song-poetry','','[]','誰能饒舌强參禪，何用談因更說緣。',32,'全唐诗/poet.song.158000.json','["誰能饒舌强參禪，何用談因更說緣。", "生死本來無大事，晨朝須起夜須眠。"]'),
('e5684e3d-f7d1-4a53-8338-b075c61b13e7','謝僧道全惠詩并菖蒲','樓鑰','宋','宋诗','song-poetry','','[]','楚楚芳蓀詩樣清，翠苗低護小崢嶸。',64,'全唐诗/poet.song.158000.json','["楚楚芳蓀詩樣清，翠苗低護小崢嶸。", "一泓功借幽根潤，六月能令凉意生。", "雁蕩渾如夢邊事，龍湫頓覺眼中明。", "閒窗坐對思無限，何日隨君遶澗行。"]'),
('cfc60c41-4063-4bb4-9f35-2cece04f83a4','趙安國梅坡','樓鑰','宋','宋诗','song-poetry','','[]','隆暑倦行役，梅坡得暫閒。',48,'全唐诗/poet.song.158000.json','["隆暑倦行役，梅坡得暫閒。", "卷簾南浦岸，終日對成山。", "竹裏清風遠，棋邊夕照還。", "歲寒重卜醉，覓句暗香間。"]'),
('f81a00f2-4f29-456e-af10-4da0454b4098','資聖寺','樓鑰','宋','宋诗','song-poetry','','[]','野溪清淺度危橋，徑策枯筇上紫霄。',64,'全唐诗/poet.song.158000.json','["野溪清淺度危橋，徑策枯筇上紫霄。", "曉霧暗蒸山寺雨，松風深隠海門潮。", "浮杯水漲人何在，洗鉢池清意已消。", "又上樂亭基上望，雲山萬里更逍遥。"]'),
('c3c0562f-79be-43fa-871f-41ba2d930134','次韵蔣德言壁間舊題','樓鑰','宋','宋诗','song-poetry','','[]','一鈴簷角自吟風，兩面松篁翠掃空。',32,'全唐诗/poet.song.158000.json','["一鈴簷角自吟風，兩面松篁翠掃空。", "山卉更藏無盡意，枝頭未作去年紅。"]'),
('8849f6af-0501-44d8-88ab-53b3eb3af3d8','上史太傅  其一','樓鑰','宋','宋诗','song-poetry','','[]','一坡煙水綠灣環，竹樹樓臺縹緲間。',32,'全唐诗/poet.song.158000.json','["一坡煙水綠灣環，竹樹樓臺縹緲間。", "但說一丘藏曲折，誰知更有四明山。"]'),
('e3110dba-b7de-4219-9fbc-4402031cd342','上史太傅  其二','樓鑰','宋','宋诗','song-poetry','','[]','二十里雲隨步生，潺湲洞裏訪青欞。',32,'全唐诗/poet.song.158000.json','["二十里雲隨步生，潺湲洞裏訪青欞。", "山中要識無窮趣，看取南雷問答經。"]'),
('29177d08-44ae-492d-9083-a58af6880645','上史太傅  其三','樓鑰','宋','宋诗','song-poetry','','[]','衮繡堂中語夜分，幾將經史細評論。',32,'全唐诗/poet.song.158000.json','["衮繡堂中語夜分，幾將經史細評論。", "不知世上三公貴，祇是東湖八行孫。"]'),
('a99e61af-d131-456a-8587-e25cf9bb8273','贈鄭相士','樓鑰','宋','宋诗','song-poetry','','[]','知君冰鑑照人寒，我相儒酸未足觀。',32,'全唐诗/poet.song.158000.json','["知君冰鑑照人寒，我相儒酸未足觀。", "東甬從來多俊秀，爲煩著眼細尋看。"]'),
('f74e539b-5a48-4c3c-abdd-906cf59b323c','雪竇道中','樓鑰','宋','宋诗','song-poetry','','[]','城居久矣厭塵勞，來訪名山寫鬰陶。',64,'全唐诗/poet.song.158000.json','["城居久矣厭塵勞，來訪名山寫鬰陶。", "客路行隨流水遠，征人與坐白雲高。", "千林舞翠吹蓬鬢，二麥摇青照紵袍。", "努力共登天尺五，要看飛雪噴雲濤。"]'),
('e580e46a-67d6-4475-9e68-ff1992b234c1','錦鏡','樓鑰','宋','宋诗','song-poetry','','[]','兩溪赴壑若奔虬，此地端能截衆流。',64,'全唐诗/poet.song.158000.json','["兩溪赴壑若奔虬，此地端能截衆流。", "三版放開千丈雪，一匳清徹四山秋。", "幾年空自存公案，今日重新指路頭。", "珍重老師成勝事，清名當與此山留。"]'),
('dd31356d-2e1f-4b23-ba3a-cd5f2f9e9864','妙峰亭','樓鑰','宋','宋诗','song-poetry','','[]','一峰高出白雲端，俯瞰天涯千萬山。',32,'全唐诗/poet.song.158000.json','["一峰高出白雲端，俯瞰天涯千萬山。", "試向岡頭轉圓石，不知何日到人間。"]'),
('59cdf882-cdf7-4fad-a9c0-563a79b0993e','隠潭','樓鑰','宋','宋诗','song-poetry','','[]','靈潭深入白雲堆，带雨春雲爲我開。',64,'全唐诗/poet.song.158000.json','["靈潭深入白雲堆，带雨春雲爲我開。", "乳石半空渾欲墮，瀑泉千尺正中來。", "兩軍酣戰鼓鼙急，一雨生寒霹靂催。", "中有卧龍君勿狎，有時平地起風雷。"]'),
('a1809329-f5cd-4875-b85e-c38746adb70d','游大梅山護聖寺  其一','樓鑰','宋','宋诗','song-poetry','','[]','江東東畔更東山，又過東山數里間。',32,'全唐诗/poet.song.158000.json','["江東東畔更東山，又過東山數里間。", "試問招提在何處，萬山深處白雲環。"]'),
('4ec00775-c992-40d6-a243-8542927c18c3','游大梅山護聖寺  其二','樓鑰','宋','宋诗','song-poetry','','[]','寒雲片日忽吹開，歷井捫參得得來。',32,'全唐诗/poet.song.158000.json','["寒雲片日忽吹開，歷井捫參得得來。", "行盡高山天欲半，不知平地有樓臺。"]'),
('c44b01c5-d3ba-403e-974a-5cf766a36d7d','常禪師塔  其一','樓鑰','宋','宋诗','song-poetry','','[]','當時道價極光華，鷙獸相隨共一家。',32,'全唐诗/poet.song.158000.json','["當時道價極光華，鷙獸相隨共一家。", "象去虎亡師亦老，不須百鳥更銜花。"]'),
('b5b60aeb-9ee8-443f-af3a-f6dc5f0b38f0','常禪師塔  其二','樓鑰','宋','宋诗','song-poetry','','[]','從來猛虎性堅剛，據石依林死不僵。',32,'全唐诗/poet.song.158000.json','["從來猛虎性堅剛，據石依林死不僵。", "何待寒林班侍者，千年陪葬祖師傍。"]'),
('c3cebc1b-e955-4bf7-9a9d-4e16d7e153eb','梅仙巖','樓鑰','宋','宋诗','song-poetry','','[]','梅山遺跡若爲尋，怪石崚嶒一徑深。',32,'全唐诗/poet.song.158000.json','["梅山遺跡若爲尋，怪石崚嶒一徑深。", "未必當時真隠處，清風自覺襲衣襟。"]'),
('d6bbf8ee-5c7c-4eb6-b060-0c2804d5734d','雲巖','樓鑰','宋','宋诗','song-poetry','','[]','但見雲生谷，初無石似巖。',48,'全唐诗/poet.song.158000.json','["但見雲生谷，初無石似巖。", "得名非舊觀，買地作精藍。", "境勝環修竹，門深擁翠杉。", "禪林自家處，莫問後三三。"]'),
('18d7f0ea-2c61-4606-816c-066d80a3be5f','啟霞冰壺亭','樓鑰','宋','宋诗','song-poetry','','[]','拍拍新漪徹底清，兩山寫照翠光凝。',32,'全唐诗/poet.song.158000.json','["拍拍新漪徹底清，兩山寫照翠光凝。", "笑看風動縠紋起，坐我玉壺春夜冰。"]'),
('ccb6eeea-44f2-4c04-a7d5-2e41e609e48b','天童玲瓏巖','樓鑰','宋','宋诗','song-poetry','','[]','捫蘿歷棧上層峰，寖覺芒鞋踏半空。',64,'全唐诗/poet.song.158000.json','["捫蘿歷棧上層峰，寖覺芒鞋踏半空。", "七竅幾時開渾沌，八窗無處不玲瓏。", "已欣古洞容身過，直恐丹丘有路通。", "俯視人間懶歸去，拂衣徑欲御天風。"]'),
('3c8f2ec5-893f-45fd-afc3-f00783174d16','送內弟汪作德赴建德主簿','樓鑰','宋','宋诗','song-poetry','','[]','今日望春下，送春還送行。',48,'全唐诗/poet.song.158000.json','["今日望春下，送春還送行。", "簿書須著意，家世有餘清。", "瀟灑桐廬郡，文章陸士衡。", "公餘定多暇，無廢讀書聲。"]'),
('43996b9a-33c0-41c0-86ce-a8b3d96a199b','南江酒家','樓鑰','宋','宋诗','song-poetry','','[]','南江舟檝飽經行，橋外人家最可人。',64,'全唐诗/poet.song.158000.json','["南江舟檝飽經行，橋外人家最可人。", "賸種寒杉映修竹，快沽村酒趁鮮鱗。", "潮痕落草櫓聲動，日脚銜山凉意新。", "酷愛老樟橫卧處，他時來此坐垂綸。"]'),
('6c9a7804-5cae-45ea-bc40-2c3f6fbc0cfa','宿登山','樓鑰','宋','宋诗','song-poetry','','[]','竹輿來訪小梅山，山在空濛紫翠間。',64,'全唐诗/poet.song.158000.json','["竹輿來訪小梅山，山在空濛紫翠間。", "嵐霧滿林朝漠漠，溪聲和雨夜潺潺。", "峰頭丹井隨潮信，松下禪房舊祖關。", "誰是無生誰不死，晨鐘未響夢先還。"]'),
('915949e4-9238-428a-9f18-6ec0f4281ee7','羣從泛湖次叔韶弟韵','樓鑰','宋','宋诗','song-poetry','','[]','倚遍瀛洲十二欄，老蟾推出爛銀盤。',64,'全唐诗/poet.song.158000.json','["倚遍瀛洲十二欄，老蟾推出爛銀盤。", "絕憐千頃波瀾闊，更覺滿身風露寒。", "境勝能令詩興逸，夜深自喜酒腸寬。", "離離掛影清如許，莫惜終宵作意看。"]'),
('1388dfd2-05be-4caa-bbdc-cf9bd2967ab5','送陳君舉守桂陽','樓鑰','宋','宋诗','song-poetry','','[]','重尋漫壁認題名，十五年來一夢驚。',64,'全唐诗/poet.song.158000.json','["重尋漫壁認題名，十五年來一夢驚。", "誰料今朝携客至，却成此地送君行。", "桂陽卧治真談笑，魯史遺編頼發明。", "文定南軒仙去後，湖湘又得一先生。"]'),
('1c2b9b60-e302-4fc6-aa2d-b10ba91b7cf5','永嘉天慶觀','樓鑰','宋','宋诗','song-poetry','','[]','斗口橫安華蓋山，茂林修竹路灣環。',64,'全唐诗/poet.song.158000.json','["斗口橫安華蓋山，茂林修竹路灣環。", "琳宮迥出滄瀛表，羽士如遊崑閬間。", "東挹江山窮望眼，西臨闤闠笑塵寰。", "自知去此無多日，著意來尋一餉閒。"]'),
('882345be-2195-4745-a85b-948973b9d791','次許深甫寄陳頤剛韵  其一','樓鑰','宋','宋诗','song-poetry','','[]','博物曾經辨實沈，論兵更覺用功深。',64,'全唐诗/poet.song.158000.json','["博物曾經辨實沈，論兵更覺用功深。", "九閽未進六奇計，萬卷空催一寸心。", "流水高山誰復會，寒松春柳解相尋。", "如君豈是長貧者，作計無令歲月侵。"]'),
('50f84f4f-e6a4-4728-a492-75962fdf4cb8','次許深甫寄陳頤剛韵  其二','樓鑰','宋','宋诗','song-poetry','','[]','前朝折戟尚沙沈，志士私憂意向深。',64,'全唐诗/poet.song.158000.json','["前朝折戟尚沙沈，志士私憂意向深。", "謀國未須先問陳，平戎要且務攻心。", "衣冠舊老知誰在，禾黍遺宮尚可尋。", "騎省再新人有望，一言坐復故疆侵。"]'),
('72ef58a2-3026-4828-8d33-431732b735c5','勸農','樓鑰','宋','宋诗','song-poetry','','[]','一番好雨潤桑麻，和氣歡聲十萬家。',64,'全唐诗/poet.song.158000.json','["一番好雨潤桑麻，和氣歡聲十萬家。", "太守勸農纔出郭，老農含哺競隨車。", "土膏澤澤地宜稻，雲物陰陰天養花。", "願得四方無旱潦，盡教樂歲似東嘉。"]'),
('64e2108c-eace-4395-b411-4a293e590a8b','書吳夢予古樂府後','樓鑰','宋','宋诗','song-poetry','','[]','古來樂府近來無，筆力如君却有餘。',64,'全唐诗/poet.song.158000.json','["古來樂府近來無，筆力如君却有餘。", "日恐遺音亡正始，喜聞新作過黄初。", "不誇藝苑徒工瑟，應免侯門久曳裾。", "更向江西詩窟去，他年時寄一行書。"]'),
('af90d115-db51-4d11-b072-79e27b2ffc40','謝景英送鄭景元篇末見屬次韵','樓鑰','宋','宋诗','song-poetry','','[]','張羅清似翟公門，門外都無野雀喧。',64,'全唐诗/poet.song.158000.json','["張羅清似翟公門，門外都無野雀喧。", "可但風流追鮑謝，直教高論到羲軒。", "絕憐父子爲知己，時把文章得細論。", "箇裏是非何足較，乍賢乍佞一王尊。"]'),
('2aa94541-c681-4b2c-8990-de290e76c7f5','喜雨次甄雲卿監簿韵','樓鑰','宋','宋诗','song-poetry','','[]','四郊苗槁勃然興，頓覺歡聲滿郡城。',64,'全唐诗/poet.song.158000.json','["四郊苗槁勃然興，頓覺歡聲滿郡城。", "行且刈雲成歲事，敢因喜雨記亭名。", "昔如魚在釜中活，今見龍從地上行。", "憂國願豐同此樂，讀君佳句欲風生。"]'),
('c13a4825-77c4-44b3-94e2-aa597ff4a17d','又次徐仲宗通判韵','樓鑰','宋','宋诗','song-poetry','','[]','老龍破蟄斬幽關，亂滴天飄不復慳。',64,'全唐诗/poet.song.158000.json','["老龍破蟄斬幽關，亂滴天飄不復慳。", "可但甘霖驅旱魃，自然凉氣滿人寰。", "民心徒切焦熬甚，神力毋勞指顧間。", "遥想清都應表賀，紫宸軒陛曉催班。"]'),
('2fd39ffc-6388-4298-8127-55304d7fdcdd','又次鄭性之懸尉韵  其一','樓鑰','宋','宋诗','song-poetry','','[]','槁項疲農病夏畦，喜聞烟雨四天垂。',32,'全唐诗/poet.song.158000.json','["槁項疲農病夏畦，喜聞烟雨四天垂。", "旋尋秔稻供糜粥，驚見新香玉滿匙。"]'),
('5efcd7bf-55ff-4b31-b6e7-70ab24ecd0af','又次鄭性之懸尉韵  其二','樓鑰','宋','宋诗','song-poetry','','[]','閔雨才寬又畏風，從朝愁到夕陽舂。',32,'全唐诗/poet.song.158000.json','["閔雨才寬又畏風，從朝愁到夕陽舂。", "誰教官到二千石，不學當年邴曼容。"]'),
('050ca671-ede0-4880-87bf-1a6dca4597f0','又次鄭性之懸尉韵  其三','樓鑰','宋','宋诗','song-poetry','','[]','幾番好雨應先占，欣見階庭綠草纖。',32,'全唐诗/poet.song.158000.json','["幾番好雨應先占，欣見階庭綠草纖。", "秋後陰晴猶未定，更看新月卧磨鎌。"]'),
('e31c6fce-854d-48e6-a047-fb2f5fa0a2a7','又次鄭性之懸尉韵  其四','樓鑰','宋','宋诗','song-poetry','','[]','爰居集魯要先知，飛雪侵春久已疑。',32,'全唐诗/poet.song.158000.json','["爰居集魯要先知，飛雪侵春久已疑。", "慚愧風師幸安靜，敢將虎口鬭龍癡。"]'),
('17ea262b-faeb-4f24-a8bb-a497f2243eb8','游隠清  其一','樓鑰','宋','宋诗','song-poetry','','[]','簿領叢中偷得閒，輕輿相與出鄉關。',64,'全唐诗/poet.song.158000.json','["簿領叢中偷得閒，輕輿相與出鄉關。", "亂流先已登孤嶼，采蕨還來上北山。", "藤遶龜身增贔屭，水涵虹影照孱顔。", "老農擁道迎人笑，今日使君來破慳。"]'),
('d5ff143b-58f6-41a7-9442-e2ab9e164a69','游隠清  其二','樓鑰','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','瀑泉奔放石坡陀，回首清游歲幾何。',64,'全唐诗/poet.song.158000.json','["瀑泉奔放石坡陀，回首清游歲幾何。", "脚力不如前日健，詩盟還喜故人多。", "滕王閣上無韓子，還景樓中欠老坡。", "不謂鄙言成宿讖，偶因晚涖得波波。"]'),
('18fbd5b6-e24c-4263-92ab-167c96f95c1f','游隠清  其三','樓鑰','宋','宋诗','song-poetry','','[]','窮冬吏鞅解紛纏，重入茲山憶少年。',64,'全唐诗/poet.song.158000.json','["窮冬吏鞅解紛纏，重入茲山憶少年。", "千里幸同豐歲樂，三生曾結郡人緣。", "幾番山色望空外，今日水聲來耳邊。", "坐上何須聽絲竹，與君嘯詠和風前。"]'),
('53675d08-8345-4c4a-8d74-d246326cc083','富覽亭','樓鑰','宋','宋诗','song-poetry','','[]','城郭占佳勝，眼高貞白鼉。',48,'全唐诗/poet.song.158000.json','["城郭占佳勝，眼高貞白鼉。", "霜天開浩蕩，雲屋涌嵯峨。", "四面山總好，東窗江最多。", "脚跟盤巨石，吞吐任風波。"]'),
('1e3f4748-7ac5-4e8f-93d3-27a41f6631fc','贈陳居靖道人','樓鑰','宋','宋诗','song-poetry','','[]','溈汭道人身御風，棄家求靜慕僊蹤。',32,'全唐诗/poet.song.158000.json','["溈汭道人身御風，棄家求靜慕僊蹤。", "僊都有石立天半，特立要當如此峰。"]'),
('303871fc-ef62-4989-9409-f173f9d3796d','雪中簡林景思劉振之','樓鑰','宋','宋诗','song-poetry','','[]','驟寒忽變雪花飛，抱膝長吟況可知。',32,'全唐诗/poet.song.158000.json','["驟寒忽變雪花飛，抱膝長吟況可知。", "襆被可能來過我，忍寒相與話新詩。"]'),
('c8719fa5-4264-4c4e-84a5-dd89b8e73f64','謝林景思和韵','樓鑰','宋','宋诗','song-poetry','','[]','黄昏門外六花飛，困倚胡牀醉不知。',32,'全唐诗/poet.song.158000.json','["黄昏門外六花飛，困倚胡牀醉不知。", "凍合玉樓猶强項，擁衾方詠雪巢詩。"]'),
('75ddc7b7-a261-4d83-a9af-4b650a5e0a1e','送趙子固吏部帥合肥  其一','樓鑰','宋','宋诗','song-poetry','','[]','少年文價重神京，游宦還聞政有聲。',64,'全唐诗/poet.song.158000.json','["少年文價重神京，游宦還聞政有聲。", "南省但推韓吏部，北方猶問趙先生。", "人傳殿上三千牘，上喜胸中十萬兵。", "暫輟望郎分帥閫，淮南草木更知名。"]'),
('2a2aab9e-0348-4c8c-810a-397f44ae5261','送趙子固吏部帥合肥  其二','樓鑰','宋','宋诗','song-poetry','','[]','老韓同傳我多慙，意氣相傾自不凡。',64,'全唐诗/poet.song.158000.json','["老韓同傳我多慙，意氣相傾自不凡。", "憂患飽更俱白髮，班行獨立見青山。", "羨君真有虎頭相，顧我方爲馬口銜。", "同舍幾何俄話別，可堪目力送風帆。"]'),
('667bac0d-81bb-483f-be6e-b30da604eacd','送趙子固吏部帥合肥  其三','樓鑰','宋','宋诗','song-poetry','','[]','襟带長淮地望崇，勳名當繼古英雄。',64,'全唐诗/poet.song.158000.json','["襟带長淮地望崇，勳名當繼古英雄。", "吳人止解依濡塢，晉將才能過八公。", "可但綏懷邊境靜，直須經略朔庭空。", "折衝不必居遐徼，頗牧尤當在禁中。"]'),
('2f48ed35-1077-4ad4-abef-4e5b98ff7d29','曲竹','樓鑰','宋','宋诗','song-poetry','','[]','放出一頭地，出牆梢更新。',48,'全唐诗/poet.song.158000.json','["放出一頭地，出牆梢更新。", "傍人爲稱屈，素志肯求伸。", "苦節變甘節，曲身成直身。", "青霄看直上，莫忘手援人。"]'),
('a66935e4-e418-47a0-8e16-786eb04b937c','寄題汪端明墳菴真如軒  其一','樓鑰','宋','宋诗','song-poetry','','[]','山藏佳處竹藏廬，見說離家百里餘。',64,'全唐诗/poet.song.158000.json','["山藏佳處竹藏廬，見說離家百里餘。", "已矣空求真學士，傷哉閒殺老尚書。", "後生自恨登門晚，壯歲寧忘跪履初。", "悵望九京那可作，此心徒切慕相如。"]'),
('14e2e8a6-9270-4904-9bb0-1fc70c2b778f','寄題汪端明墳菴真如軒  其二','樓鑰','宋','宋诗','song-poetry','','[]','萬箇篔簹一草廬，傷心埋璧十年餘。',64,'全唐诗/poet.song.158000.json','["萬箇篔簹一草廬，傷心埋璧十年餘。", "革聲誰聽尚書履，金榜空懸少保書。", "無復遺音追正始，尚傳新作過黄初。", "真成一代風流盡，歡息浮生信六如。"]'),
('48056485-a708-459a-80a7-5c8aba147e10','題汪季路太傅所藏龍眠陽關圖  其一','樓鑰','宋','宋诗','song-poetry','','[]','離觴別泪爲君傾，行李匆匆欲問程。',32,'全唐诗/poet.song.158000.json','["離觴別泪爲君傾，行李匆匆欲問程。", "不用陽關尋舊曲，圖中端有斷腸聲。"]'),
('6c32a928-51ac-4e29-9f3e-7903ce94c164','題汪季路太傅所藏龍眠陽關圖  其二','樓鑰','宋','宋诗','song-poetry','','[]','畫出陽關古別離，蕭疎柳質不勝悲。',32,'全唐诗/poet.song.158000.json','["畫出陽關古別離，蕭疎柳質不勝悲。", "行人顧歎離人泣，柳下漁翁總不知。"]'),
('23cb3c04-51c0-4488-a1bf-ee0bf35ef2c9','題陳簡齋寄夫人書','樓鑰','宋','宋诗','song-poetry','','[]','行書滿紙遺君文，可見閨門敬若賓。',32,'全唐诗/poet.song.158000.json','["行書滿紙遺君文，可見閨門敬若賓。", "應與少文能協趣，定因元亮遂忘貧。"]'),
('aa170263-7166-4b61-add2-cfdf9a7e29ff','題韓氏所藏元祐選尚詔草','樓鑰','宋','宋诗','song-poetry','','[]','禁臠當年選尚初，難兄辭寵意何如。',64,'全唐诗/poet.song.158000.json','["禁臠當年選尚初，難兄辭寵意何如。", "裕陵遺旨知難改，元祐湛恩信有餘。", "今日猶存卯君筆，向來誰造粉昆書。", "韓門世寶宜無墜，史有遺文尚取諸。"]'),
('e4e5679e-4ac3-418d-baa3-ed014891496c','秋日懷國仲觀','樓鑰','宋','宋诗','song-poetry','','[]','四明聳秀一溪流，曾記經行十里秋。',64,'全唐诗/poet.song.158000.json','["四明聳秀一溪流，曾記經行十里秋。", "行李今從何處住，宦游自笑幾時休。", "兒時故舊今誰在，老去光陰不借留。", "贏得東歸訪丘壑，約君同上釣魚舟。"]'),
('d9105316-54fc-4443-bee9-e6cdaf99f467','客省聽燕樂','樓鑰','宋','宋诗','song-poetry','','[]','曉入金門拜紫宸，門前錯立士如雲。',32,'全唐诗/poet.song.158000.json','["曉入金門拜紫宸，門前錯立士如雲。", "未容密侍君王宴，祇許鈞天隔殿聞。"]'),
('aae9213a-e4b5-4d92-bc1d-ef0b8f0c9a37','次李季章監簿韵','樓鑰','宋','宋诗','song-poetry','','[]','跪履巽巖今幾年，見君風度喜跫然。',64,'全唐诗/poet.song.158000.json','["跪履巽巖今幾年，見君風度喜跫然。", "長編固已翻青簡，老墨猶能寶漆烟。", "游宦自欣天影近，思家猶在夕陽邊。", "時從甥館追清賞，賸寫新詩繼謫僊。"]'),
('9540cbaf-c4a3-4819-b73d-237774ec5e74','賀雪八盤嶺上作','樓鑰','宋','宋诗','song-poetry','','[]','平時卧雪似袁安，誰肯凌晨犯苦寒。',64,'全唐诗/poet.song.158000.json','["平時卧雪似袁安，誰肯凌晨犯苦寒。", "百辟班中因族賀，八盤嶺上得遥看。", "層層觀闕瓊樓聳，納納乾坤玉宇寬。", "悵望僊山何處是，欲從此地徑驂鸞。"]'),
('99b7d363-ce33-46bb-b673-e830c588c7db','送林子方吏部將漕江東  其一','樓鑰','宋','宋诗','song-poetry','','[]','光堯三紀煥文章，寶閣岧嶤謹祕藏。',32,'全唐诗/poet.song.158000.json','["光堯三紀煥文章，寶閣岧嶤謹祕藏。", "寓直到君才第四，皇華禮樂遠增光。"]'),
('a668e7b4-6a16-4381-abac-a8c0f2cf3ff2','送林子方吏部將漕江東  其二','樓鑰','宋','宋诗','song-poetry','','[]','望郎三度到長安，垂上青雲作好官。',32,'全唐诗/poet.song.158000.json','["望郎三度到長安，垂上青雲作好官。", "暫向江東一澄按，却歸徑著侍臣冠。"]'),
('d32a4125-2044-4775-9e54-b9c6acef5bdf','送林子方吏部將漕江東  其三','樓鑰','宋','宋诗','song-poetry','','[]','自說嵇康七不堪，上教持節向江南。',32,'全唐诗/poet.song.158000.json','["自說嵇康七不堪，上教持節向江南。", "江南父老應相賀，見說清明似晦菴。"]'),
('868a384c-abb6-441b-9586-a53b360d5127','送林子方吏部將漕江東  其四','樓鑰','宋','宋诗','song-poetry','','[]','殿廬官燭對風簾，郎舍修篁共一簷。',32,'全唐诗/poet.song.158000.json','["殿廬官燭對風簾，郎舍修篁共一簷。", "別日苦多良晤少，摻袪不耐雨纖纖。"]'),
('1e6b3b59-b042-4fb7-9034-b1ed154e9351','子方移守四明見於浙江亭','樓鑰','宋','宋诗','song-poetry','','[]','春初送別欠詩篇，歲晚還欣受一廛。',64,'全唐诗/poet.song.158000.json','["春初送別欠詩篇，歲晚還欣受一廛。", "都騎始聞臨浙水，先聲久已讋鄞川。", "里人見說俱延頸，海嶠從今定息肩。", "夜夜故山頻入夢，爲君端欲買歸船。"]'),
('41ed2bfc-4076-4f0c-9e65-d5890766da4b','寄題蜀李氏義概堂','樓鑰','宋','宋诗','song-poetry','','[]','養氣非爲俠，輕財弗市恩。',48,'全唐诗/poet.song.158000.json','["養氣非爲俠，輕財弗市恩。", "仁聲高月旦，義概徹天閽。", "稱美推賢嗣，揚名有順孫。", "活人幾百萬，何止駟容門。"]'),
('af7e8cec-0053-4de5-8428-909db41b24bd','送衛清叔著作提舉淮東  其一','樓鑰','宋','宋诗','song-poetry','','[]','漢庭早已冠羣僊，闊步登瀛最少年。',32,'全唐诗/poet.song.158000.json','["漢庭早已冠羣僊，闊步登瀛最少年。", "竊歎豈惟年叵及，人門才業總翹然。"]'),
('c68ee60d-5122-406d-bf74-fad6c233cb9b','送衛清叔著作提舉淮東  其二','樓鑰','宋','宋诗','song-poetry','','[]','通泰牢盆亙海濱，宅家專欲用儒臣。',32,'全唐诗/poet.song.158000.json','["通泰牢盆亙海濱，宅家專欲用儒臣。", "淮南草木生顔色，又見龍頭第一人。"]'),
('09e42469-a50e-4b06-b527-5d52401164f5','送衛清叔著作提舉淮東  其三','樓鑰','宋','宋诗','song-poetry','','[]','虎榜先登到鳳池，前良多以十年期。',32,'全唐诗/poet.song.158000.json','["虎榜先登到鳳池，前良多以十年期。", "雖知勇退急流去，壯歲功名會及時。"]'),
('22307a9d-e36a-48c6-b7fd-ed54343768e2','送衛清叔著作提舉淮東  其四','樓鑰','宋','宋诗','song-poetry','','[]','羨君持節拜庭闈，未老雙親看綵衣。',32,'全唐诗/poet.song.158000.json','["羨君持節拜庭闈，未老雙親看綵衣。", "若過蓋公煩問信，坐曹日念舊游稀。"]'),
('387b731a-5784-477d-aab0-2c1361ff9cc7','送衛清叔著作提舉淮東  其五','樓鑰','宋','宋诗','song-poetry','','[]','屢從樽酒接從容，叔寶風姿照座中。',32,'全唐诗/poet.song.158000.json','["屢從樽酒接從容，叔寶風姿照座中。", "他日相逢年益老，棋壇尚可角雌雄。"]'),
('20e87a8a-795b-4d1f-bf21-d89443c80d1c','送黄景聲祕丞提舉浙西  其一','樓鑰','宋','宋诗','song-poetry','','[]','江夏無雙第一人，清明久矣動簪紳。',32,'全唐诗/poet.song.158000.json','["江夏無雙第一人，清明久矣動簪紳。", "心平氣勁無偏黨，好在皇朝作爭臣。"]'),
('0f0302a9-09d4-44dd-a780-b7b97b756446','送黄景聲祕丞提舉浙西  其二','樓鑰','宋','宋诗','song-poetry','','[]','宅家親擢得真才，柏府蘭堂更外臺。',32,'全唐诗/poet.song.158000.json','["宅家親擢得真才，柏府蘭堂更外臺。", "未問遄驅向溝壑，半途應有詔書催。"]'),
('40e6039b-63ba-45c9-b4c8-edd476e2ec80','送黄景聲祕丞提舉浙西  其三','樓鑰','宋','宋诗','song-poetry','','[]','從來軒冕一毫輕，朝蹟初收去玉京。',32,'全唐诗/poet.song.158000.json','["從來軒冕一毫輕，朝蹟初收去玉京。", "打破畫瓶無個事，不妨游戲繡衣行。"]'),
('b69fd95b-3b42-4aa6-bc94-59bd28e9886b','送黄景聲祕丞提舉浙西  其四','樓鑰','宋','宋诗','song-poetry','','[]','論詩纔了便談禪，鄙吝冰消更豁然。',32,'全唐诗/poet.song.158000.json','["論詩纔了便談禪，鄙吝冰消更豁然。", "稽首心空先及第，敢將癸未論同年。"]'),
('aa80fe24-28e3-473a-a8c2-4da6b6985f8f','送黄景聲祕丞提舉浙西  其五','樓鑰','宋','宋诗','song-poetry','','[]','玉節光華照日曦，揚清激濁正當時。',32,'全唐诗/poet.song.158000.json','["玉節光華照日曦，揚清激濁正當時。", "阿連幸出百僚底，正恐翁歸不受私。"]'),
('56a44013-19a3-46da-b39f-d4c0fd79fc21','雪中迎駕','樓鑰','宋','宋诗','song-poetry','','[]','都人久不望威顔，驚喜鳴鞘風雪間。',64,'全唐诗/poet.song.158000.json','["都人久不望威顔，驚喜鳴鞘風雪間。", "萬井歡聲迎曉仗，九天和氣下人寰。", "龍樓笑啟瑶池宴，鵷序欣趨玉笋班。", "道上峰頭皆見日，絕勝銜燭照崑山。"]'),
('0f292f45-c80e-4266-9bfe-56e6ca297767','題尤延之給事所藏葛仙翁徙居圖','樓鑰','宋','宋诗','song-poetry','','[]','莫言家具少于車，藥裹衣囊自有餘。',64,'全唐诗/poet.song.158000.json','["莫言家具少于車，藥裹衣囊自有餘。", "老婦親携三稚子，仙翁獨玩一篇書。", "羊牛相與趨新築，雞犬無因戀故廬。", "到處山頭有丹井，不知如此幾遷居。"]'),
('a98b983f-4cc7-4388-bf4f-e9575a2ffcab','又題楊妃上馬圖','樓鑰','宋','宋诗','song-poetry','','[]','金鞍欲上故徐徐，想見華清被寵初。',32,'全唐诗/poet.song.158000.json','["金鞍欲上故徐徐，想見華清被寵初。", "後日延秋門下路，不應有暇作踟躕。"]'),
('570aefbf-3532-4b03-8567-f3c972a56699','題老融歸牛圖','樓鑰','宋','宋诗','song-poetry','','[]','薄宦六年辭故山，故山祇在夢魂間。',32,'全唐诗/poet.song.158000.json','["薄宦六年辭故山，故山祇在夢魂間。", "簪紳何苦自纏縛，却羨歸牛自在閒。"]'),
('16168fad-1d2b-4961-8da1-eb1adbabd36f','天竺禱晴','樓鑰','宋','宋诗','song-poetry','','[]','早奉天香禱白衣，遲明宿霧故凄迷。',64,'全唐诗/poet.song.158000.json','["早奉天香禱白衣，遲明宿霧故凄迷。", "忽驚紅日穿林薄，無數碧山明澗溪。", "上竺寺連中竺寺，蘇公堤映白公堤。", "湖光一碧幾千頃，賸捲荷香送馬蹄。"]'),
('1591e0da-a7bd-4149-a4bd-c0d35d55d484','具美堂','樓鑰','宋','宋诗','song-poetry','','[]','明光殿裏早催班，亭午天街從駕還。',64,'全唐诗/poet.song.158000.json','["明光殿裏早催班，亭午天街從駕還。", "已聽歡聲傳市井，更看喜氣滿湖山。", "聯鑣遠去閒尋勝，爛醉歸來夜叩關。", "但願兩宮千萬壽，退公時得過雲間。"]'),
('9c696cee-85ae-48ba-831e-1f44e8106466','水月園','樓鑰','宋','宋诗','song-poetry','','[]','具美盃殘意未休，相將重上望湖樓。',64,'全唐诗/poet.song.158000.json','["具美盃殘意未休，相將重上望湖樓。", "樓臺忽已居平地，風月何曾識舊游。", "更挈酒樽過水月，坐增詩興滿滄洲。", "春風共約新橋畔，遥拜雙龍萬斛舟。"]'),
('1e93609b-8978-4639-b386-b907d8b4eb89','三月九日從駕','樓鑰','宋','宋诗','song-poetry','','[]','昨日爲親壽，今朝從駕行。',48,'全唐诗/poet.song.158000.json','["昨日爲親壽，今朝從駕行。", "君親俱有喜，家國共增榮。", "淑氣浮黄屋，歡聲動玉京。", "人心真易感，翻手作昇平。"]'),
('fe9788c7-05f5-429c-85df-a8ba107fb5b9','湖上次袁起巖安撫韵','樓鑰','宋','宋诗','song-poetry','','[]','同年紫陌再尋春，力主斯盟頼尹京。',64,'全唐诗/poet.song.158000.json','["同年紫陌再尋春，力主斯盟頼尹京。", "山外斜陽湖外雪，夜來陰靄曉來晴。", "平波灧灧新添綠，凍木欣欣欲向榮。", "此日此身清潔甚，軟紅何苦太忙生。"]'),
('e714e69a-2fa7-4992-b42f-8cb33fbb7720','試俞珣長頭筆','樓鑰','宋','宋诗','song-poetry','','[]','倦游俞老又中州，霜兔抽豪飽盛秋。',32,'全唐诗/poet.song.158000.json','["倦游俞老又中州，霜兔抽豪飽盛秋。", "平日相親管城子，結交今得賈長頭。"]'),
('97f3a933-d1e2-484b-8e30-a919f8e5af43','訪留昭文於范村山閒不得見','樓鑰','宋','宋诗','song-poetry','','[]','黄扉處士掩松關，小立松風去住難。',32,'全唐诗/poet.song.158000.json','["黄扉處士掩松關，小立松風去住難。", "可歎山中真宰相，未容神武掛衣冠。"]'),
('cd9df0d8-63be-49ee-8e9d-ee72eba42841','送倪正父侍郎使虜','樓鑰','宋','宋诗','song-poetry','','[]','經帷親見犯天顔，口伐何勞抗可汗。',64,'全唐诗/poet.song.158000.json','["經帷親見犯天顔，口伐何勞抗可汗。", "故國應悲周黍稷，遺黎猶識漢衣冠。", "殊鄰諜報終難測，累歲要盟恐易寒。", "馳至金城上方略，始知頗牧在金鑾。"]'),
('0002e1e0-ff5e-491d-af72-9a9d3a12aa93','送王仲言添倅海陵  其一','樓鑰','宋','宋诗','song-poetry','','[]','萬卷詩書老雪溪，頎然二子和塤篪。',64,'全唐诗/poet.song.158000.json','["萬卷詩書老雪溪，頎然二子和塤篪。", "絕憐伯氏久亡矣，猶幸夫君及見之。", "來上鵷行人謂晚，往舒驥足自嫌遲。", "他時還向雲門否，布襪青鞋尚可期。"]'),
('c77c5498-f35e-4b7a-8bc1-6dff01a08e31','送王仲言添倅海陵  其二','樓鑰','宋','宋诗','song-poetry','','[]','遂初陳迹遽淒涼，擊歎青箱極薦楊。',64,'全唐诗/poet.song.158000.json','["遂初陳迹遽淒涼，擊歎青箱極薦楊。", "談笑於儂情易厚，典刑使我意差强。", "重屏舊畫論中主，古殿遺文話阿章。", "舊事從今向誰得，尺書時許到淮鄉。"]'),
('339033c7-2fad-4cec-9e8a-227a9a14d6f7','寄題延平范氏六桂堂','樓鑰','宋','宋诗','song-poetry','','[]','高門儒效許誰同，秀氣于今照演峰。',64,'全唐诗/poet.song.158000.json','["高門儒效許誰同，秀氣于今照演峰。", "家學一椿連五桂，地靈兩劍化雙龍。", "三人衣鉢清名接，累世簪纓慶事重。", "彼茁孫枝更林立，不須萬戶羨侯封。"]'),
('73aeaad3-c2ee-4d2b-adb0-a83b4087bfcd','京仲遠尚書爲澹然子作二大字','樓鑰','宋','宋诗','song-poetry','','[]','濃墨新題付澹然，松坡爲子老談天。',32,'全唐诗/poet.song.158000.json','["濃墨新題付澹然，松坡爲子老談天。", "憑君推我行年看，何日歸耕綿上田。"]'),
('14e04811-37c1-4d19-8447-76b132a2007e','送李伯和吏部提舉浙東伯珍寺丞將漕夔門','樓鑰','宋','宋诗','song-poetry','','[]','奕奕君家好弟兄，皇華交映棣華明。',64,'全唐诗/poet.song.158000.json','["奕奕君家好弟兄，皇華交映棣華明。", "幾年並列金閨彥，同日俱持玉節行。", "萬里往臨夔子國，一江先到越王城。", "會聞歸取青氈舊，都似當年老貳卿。"]'),
('2cab3f3c-3bcd-42db-927c-e9a0561bd6bc','送范文叔禮部守彭州','樓鑰','宋','宋诗','song-poetry','','[]','憂國鬢先雪，愛君心似丹。',48,'全唐诗/poet.song.158000.json','["憂國鬢先雪，愛君心似丹。", "旌麾雖自適，懷抱未全寬。", "直道任三黜，故人憐一寒。", "濛陽毋久駐，旋復簉鵷鸞。"]'),
('6328bf8b-b117-486d-8861-525c69412f35','送趙德老端明帥蜀','樓鑰','宋','宋诗','song-poetry','','[]','身名俱泰老尚書，叱馭寧辭萬里途。',64,'全唐诗/poet.song.158000.json','["身名俱泰老尚書，叱馭寧辭萬里途。", "兩地恩榮真赫奕，四川父老定歡呼。", "乖崖袍带今重見，清獻琴龜我更無。", "頻向籌邊樓上望，歸來方畧上新圖。"]'),
('d1d560ad-0e22-4120-b7e9-0da2f2e9ca3f','次盧國華提刑所寄韵','樓鑰','宋','宋诗','song-poetry','','[]','持節歸來上粉闈，祇今一節又何之。',64,'全唐诗/poet.song.158000.json','["持節歸來上粉闈，祇今一節又何之。", "樂天好句追長慶，元亮高風挹義熙。", "我恨別多仍會少，君雖去速豈來遲。", "閩山荔子燻晴晝，莫惜登臨賸賦詩。"]'),
('9667e28f-4ca7-4f1c-a4d2-8ec768b148ba','古梅遺張時可','樓鑰','宋','宋诗','song-poetry','','[]','枝封蒼蘚澹花疎，一種風流高更孤。',32,'全唐诗/poet.song.158000.json','["枝封蒼蘚澹花疎，一種風流高更孤。", "試問約齋三百樹，林中還有此枝無。"]'),
('01254d92-8eab-436f-ba8f-54feb509b5c7','李才翁賀除天官次韵  其一','樓鑰','宋','宋诗','song-poetry','','[]','九年奔走祇思閑，歸夢時時墮故山。',64,'全唐诗/poet.song.158000.json','["九年奔走祇思閑，歸夢時時墮故山。", "已媿演綸詞禁上，更堪曳履侍臣閒。", "官曹顧我空無補，世事惟君了不關。", "但欲相從游物外，不應久此玷清班。"]'),
('1d31592c-fb89-434c-9540-3f6e5c0da97f','李才翁賀除天官次韵  其二','樓鑰','宋','宋诗','song-poetry','','[]','我居銓部閙簪裾，終羨寒窗只蠹魚。',64,'全唐诗/poet.song.158000.json','["我居銓部閙簪裾，終羨寒窗只蠹魚。", "每念故交今有幾，况如盛德豈容疎。", "京塵共嘆催人老，市道誰知有隠居。", "久苦筆端枯渴甚，楚波正欲借君餘。"]'),
('b6ede09f-7a7a-4200-bc99-cbbe91693d39','劉德修右史去國示所和從父東谿及楊子直詩走筆次韵  其一','樓鑰','宋','宋诗','song-poetry','','[]','無人爲辨樂羊書，却向空山問草廬。',64,'全唐诗/poet.song.158000.json','["無人爲辨樂羊書，却向空山問草廬。", "世上榮枯無定在，眼前毀譽竟何如。", "寸心未徹九重上，百口仍行萬里餘。", "只恐君王思舊學，便看飛詔促嚴徐。"]'),
('96af7610-5bc1-4f34-b2f2-9ea2e1282501','劉德修右史去國示所和從父東谿及楊子直詩走筆次韵  其二','樓鑰','宋','宋诗','song-poetry','','[]','東谿詩似老彌明，傾蓋論詩絕點塵。',64,'全唐诗/poet.song.158000.json','["東谿詩似老彌明，傾蓋論詩絕點塵。", "筆墨爲供無盡藏，江湖乞得自由身。", "出門遠送成惆悵，無計相留更主臣。", "但願皇天開老眼，不應空谷滯斯人。"]'),
('20fa82e8-297e-45ae-82d5-279f1986cceb','劉德修右史去國示所和從父東谿及楊子直詩走筆次韵  其三','樓鑰','宋','宋诗','song-poetry','','[]','閣下相期久，山中把酒稀。',48,'全唐诗/poet.song.158000.json','["閣下相期久，山中把酒稀。", "未能容我去，又復送君歸。", "柱史寧終隠，威顔暫咫違。", "壯心誰與語，看劍一燈微。"]'),
('b4c10127-9e58-4657-b5a9-a97d09fb51f2','謝袁起巖侍郎送盆梔奉老母','樓鑰','宋','宋诗','song-poetry','','[]','翠綃飛蓋擁生香，冰雪精神試晚妝。',32,'全唐诗/poet.song.158000.json','["翠綃飛蓋擁生香，冰雪精神試晚妝。", "鶴髮慈親俄一笑，玉人何事晚升堂。"]'),
('82cc95ae-1ccc-40b5-becf-18efef5539de','送曾南仲寺丞守永嘉','樓鑰','宋','宋诗','song-poetry','','[]','六和久坐趣歸鞭，却送旌麾水竹邊。',64,'全唐诗/poet.song.158000.json','["六和久坐趣歸鞭，却送旌麾水竹邊。", "無說可裨新令尹，有詩重送老同年。", "城隅綠竹今安否，庭下朱欒定儼然。", "回首東州真夢境，羨君此去若登仙。"]'),
('e5b90ff2-efeb-4324-96a5-ad8e602218fe','過上虞懷謝驛喜雨','樓鑰','宋','宋诗','song-poetry','','[]','夢回簷溜作驚湍，浄洗炎歊百慮寬。',32,'全唐诗/poet.song.158000.json','["夢回簷溜作驚湍，浄洗炎歊百慮寬。", "咫尺東山見膏澤，令人更憶謝家安。"]'),
('a621f080-28e7-420c-b375-6ecd7f71782d','答杖錫平老','樓鑰','宋','宋诗','song-poetry','','[]','老我平生不願餘，歸來但欲賦閑居。',32,'全唐诗/poet.song.158000.json','["老我平生不願餘，歸來但欲賦閑居。", "灌園自足供朝膳，且奉夫人御版輿。"]'),
('8e5ec88d-9f8f-41d3-9f46-92f15b7bb399','送淳尉海陵併寄示潚  其一','樓鑰','宋','宋诗','song-poetry','','[]','二子俱從宦，重親足自怡。',48,'全唐诗/poet.song.158000.json','["二子俱從宦，重親足自怡。", "汝能行幼學，吾豈恨輕離。", "平日自知己，真心更與誰。", "臨文有遺忘，此是憶兒時。"]'),
('71b3d4a9-1dbf-49cc-a0f8-462840377e17','送淳尉海陵併寄示潚  其二','樓鑰','宋','宋诗','song-poetry','','[]','處己幸寡過，居官勿願餘。',48,'全唐诗/poet.song.158000.json','["處己幸寡過，居官勿願餘。", "動成經歲別，賸寄幾行書。", "公退仍多學，心清任索居。", "但知行所職，通塞聽何如。"]'),
('7c7417ac-8b4e-422b-abc4-7f5cf9dc1301','次潘安叔寄新谿詩韵','樓鑰','宋','宋诗','song-poetry','','[]','曾游明月舊雙谿，老去情懷百不宜。',32,'全唐诗/poet.song.158000.json','["曾游明月舊雙谿，老去情懷百不宜。", "夢繞新谿身不到，更休重和寄來詩。"]'),
('b3000599-2cd5-409f-8004-037a2a87c296','送內弟汪强仲赴台州稅官','樓鑰','宋','宋诗','song-poetry','','[]','雕鞍去去不容攀，柳下門牆輟往還。',64,'全唐诗/poet.song.158000.json','["雕鞍去去不容攀，柳下門牆輟往還。", "可但征商私龍斷，不妨拄頰看巾山。", "右軍墨妙惟修禊，太傅才高亦抱關。", "只尺親庭毋苦戀，有人能伴適齋閑。"]'),
('2fedb3fd-1e4a-4e07-b997-128d3f44439f','少潜兄再立晝錦坊伯中弟有詩次韵','樓鑰','宋','宋诗','song-poetry','','[]','東樓舊日史君家，盛德于今說孟嘉。',64,'全唐诗/poet.song.158000.json','["東樓舊日史君家，盛德于今說孟嘉。", "晝錦門牆再興起，烏衣巷陌倍輝華。", "雖無崔氏聯三戟，肯學楊家簇五花。", "尤喜桂枝香不斷，藏書滿屋是生涯。"]'),
('cfb306c0-65c9-433c-9b6f-5be71102c865','王原慶訴盤餐蕭然走筆次韵  其一','樓鑰','宋','宋诗','song-poetry','','[]','愁絕詩人太瘦生，也無北食與南烹。',32,'全唐诗/poet.song.158000.json','["愁絕詩人太瘦生，也無北食與南烹。", "君看俚語亦堪笑，何日能填鼻下橫。"]'),
('b31529ea-ebfd-45df-a4ac-91ee382fbb85','王原慶訴盤餐蕭然走筆次韵  其二','樓鑰','宋','宋诗','song-poetry','','[]','莫嗜鰒魚如老曹，但應菜飯學參寥。',32,'全唐诗/poet.song.158000.json','["莫嗜鰒魚如老曹，但應菜飯學參寥。", "坡翁晚節更清苦，玉糝新羹手自調。"]'),
('46d2fb73-dd50-4213-b897-dc39cf244974','送趙振文主簿','樓鑰','宋','宋诗','song-poetry','','[]','去去江西不作難，片帆雙槳蕩秋瀾。',64,'全唐诗/poet.song.158000.json','["去去江西不作難，片帆雙槳蕩秋瀾。", "已知官業非時樣，尤喜情親耐歲寒。", "志大自然羞附驥，官卑何用歎棲鸞。", "少卿膝上加文度，更比年時刮眼看。"]'),
('c13e5cc9-e149-4cd7-8d85-23f8c189b15a','病足戲效樂天體','樓鑰','宋','宋诗','song-poetry','','[]','課得退連茹，藥逢新太醫。',48,'全唐诗/poet.song.158000.json','["課得退連茹，藥逢新太醫。", "居閑幸餘暇，養病任多時。", "步屧雖非便，調琴足自怡。", "曉來風雨急，高卧到晨炊。"]'),
('566e37ac-c22a-4b3e-bfcb-a02d81e7323c','叔韶弟上連桂堂牌會群從','樓鑰','宋','宋诗','song-poetry','','[]','我家簪紱百餘年，書種于今幸有傳。',64,'全唐诗/poet.song.158000.json','["我家簪紱百餘年，書種于今幸有傳。", "折桂時能取黄牒，肯堂頼子挹青氈。", "一新扁牓照華屋，共集尊罍招衆賢。", "須信後生尤可畏，要當爭著祖生鞭。"]'),
('c9c1a43f-1473-4b19-97da-ae9cd02e9180','題林氏香嚴庵','樓鑰','宋','宋诗','song-poetry','','[]','緩步尋佳處，林深路欲迷。',48,'全唐诗/poet.song.158000.json','["緩步尋佳處，林深路欲迷。", "偃松披數畝，立竹漱三谿。", "瀹茗憑山檻，呼燈照石梯。", "輕輿空翠濕，投暝喜幽棲。"]'),
('7d3d86bf-f46c-4030-8b07-524ddaf8373a','送汪强仲還官所','樓鑰','宋','宋诗','song-poetry','','[]','又向丹丘去，安書易往還。',48,'全唐诗/poet.song.158000.json','["又向丹丘去，安書易往還。", "固應官事了，莫放舊書閑。", "問訊雪巢老，寄懷巾子山。", "經行皆夢境，自笑日蒼顔。"]'),
('c674c33b-32aa-47f8-bfb0-c43c4df3ca38','寄題吳紹古縣尉經德堂','樓鑰','宋','宋诗','song-poetry','','[]','問舎玉真下，讀書經德中。',48,'全唐诗/poet.song.158000.json','["問舎玉真下，讀書經德中。", "心期知共遠，臭味許誰同。", "吹笛夜涼月，舞雩春暮風。", "直須涵泳熟，毋負象山翁。"]'),
('31800f2d-991b-4391-bdae-0a2f94088278','送季舅汪江州  其一','樓鑰','宋','宋诗','song-poetry','','[]','清直如公天自知，晚年百順了無虧。',64,'全唐诗/poet.song.158000.json','["清直如公天自知，晚年百順了無虧。", "九成臺下方還旆，五老峰前又擁麾。", "題坐喜逢陳仲舉，據牀好繼庾元規。", "太平散吏無由到，倚聽中和樂職詩。"]'),
('8d6bd0ff-9a92-430f-baf6-4d317b53685d','送季舅汪江州  其二','樓鑰','宋','宋诗','song-poetry','','[]','舅甥相與自垂髫，游宦歸來鬢已凋。',64,'全唐诗/poet.song.158000.json','["舅甥相與自垂髫，游宦歸來鬢已凋。", "坐上可無車武子，酒酣時頼蓋寬饒。", "喜公自此驅千騎，顧我從今守一瓢。", "間與適齋同悵望，草堂樽酒幸清朝。"]'),
('f9144366-cad0-4496-9032-fd07cb1e7c74','送內弟汪耐翁隨侍因赴臨川推官','樓鑰','宋','宋诗','song-poetry','','[]','之子長才盍要津，未知此別幾經春。',64,'全唐诗/poet.song.158000.json','["之子長才盍要津，未知此別幾經春。", "且爲湓浦過庭子，徑作臨川入幕賓。", "生長外家身已老，周旋中表意尤親。", "從今家問須情實，莫事虛文學外人。"]'),
('29468898-bfac-4302-a1f1-b1e489adb0cf','環村踏雪  其一','樓鑰','宋','宋诗','song-poetry','','[]','一冬求雪雨還晴，賸喜春朝見玉霙。',64,'全唐诗/poet.song.158000.json','["一冬求雪雨還晴，賸喜春朝見玉霙。", "不爲偶同佳客到，誰能深入亂山行。", "雲窗霧閣知何限，玉樹瓊枝到處明。", "更喚輕舟同穩泛，小谿何似剡谿清。"]'),
('c86e08f5-2d4b-4b05-92a5-6f301a1d969e','環村踏雪  其二','樓鑰','宋','宋诗','song-poetry','','[]','筍輿衝雪過溪橋，流水方東未晚潮。',64,'全唐诗/poet.song.158000.json','["筍輿衝雪過溪橋，流水方東未晚潮。", "白裏不知梅奪色，青邊尤喜麥成苗。", "煙深带雨參差下，空闊隨風自在飄。", "可是忍寒詩更切，故求野路踏瓊瑶。"]'),
('9129cc60-3a6a-487a-861e-3ad6c9eeca41','又次蔣甥仲愚韵','樓鑰','宋','宋诗','song-poetry','','[]','山色空濛雪更奇，滿空擊碎吠琉璃。',64,'全唐诗/poet.song.158000.json','["山色空濛雪更奇，滿空擊碎吠琉璃。", "寒侵茅屋春無寐，凍合梅花夜不知。", "泛泛輕舟勝路滑，洋洋流水樂人饑。", "興來但覺酒腸闊，江海安能實漏巵。"]'),
('ddb614bc-68a2-47b1-bac9-1edbadf29349','送元積弟赴永嘉酒官  其一','樓鑰','宋','宋诗','song-poetry','','[]','宦游五載住中川，似與邦人有夙緣。',64,'全唐诗/poet.song.158000.json','["宦游五載住中川，似與邦人有夙緣。", "昔日江山知好在，舊游人物想依然。", "吾衰無復逢梅福，子去惟應夢阿連。", "或問故侯霜鬢未，爲言潘令是齊年。"]'),
('91eb61b5-b2bb-4d41-9c72-87645b51cbca','送元積弟赴永嘉酒官  其二','樓鑰','宋','宋诗','song-poetry','','[]','我家清白世相傳，工部真清更有年。',64,'全唐诗/poet.song.158000.json','["我家清白世相傳，工部真清更有年。", "百口未曾營活計，一生惟喜種心田。", "吾方奉母耕綿上，子更移封向酒泉。", "兄弟凋零期自勉，只將家訓作青氈。"]'),
('16805314-9782-43c7-9eb9-a74e0d09e455','同王原慶知道游天童','樓鑰','宋','宋诗','song-poetry','','[]','舊游曾記夢中身，一日重來白髮新。',64,'全唐诗/poet.song.158000.json','["舊游曾記夢中身，一日重來白髮新。", "行盡杉松三十里，看來樓閣幾由旬。", "狎鷗亭外波瀾闊，宿鷺池邊草木春。", "自笑賦歸如許久，始來此地作閑人。"]'),
('6cf5142e-e558-41ca-b47f-94844aac598f','東谷','樓鑰','宋','宋诗','song-poetry','','[]','舊說東柯谷，茲來到此山。',48,'全唐诗/poet.song.158000.json','["舊說東柯谷，茲來到此山。", "樹深煙冉冉，花落雨潺潺。", "有客禮師塔，何人叩祖關。", "天連秋水遠，此意尚人間。"]'),
('6664b9b4-3056-4bab-b09d-34cca7ad4ae6','千佛閣','樓鑰','宋','宋诗','song-poetry','','[]','平橫雲棟塞空虛，倒影仍臨碧玉壷。',64,'全唐诗/poet.song.158000.json','["平橫雲棟塞空虛，倒影仍臨碧玉壷。", "千佛威光歸寶所，九霄宸藻粲河圖。", "人天共歎未曾有，燕雀相驚不敢踰。", "試問南詢童子看，化城曾見此樓無。"]'),
('6609b123-e2ae-4b1c-ad62-06223a844acc','從子滌濯寒納凉','樓鑰','宋','宋诗','song-poetry','','[]','楊柳陰陰映粉牆，密雲藏雨晚來凉。',32,'全唐诗/poet.song.158000.json','["楊柳陰陰映粉牆，密雲藏雨晚來凉。", "高荷欲出欄干上，笑挹紅英吸浄香。"]'),
('e4bfc7da-bdf4-4a72-b4a9-bb963d1e2916','淳謁告歸省復還海陵','樓鑰','宋','宋诗','song-poetry','','[]','吾子遠歸省，重闈俱粲然。',48,'全唐诗/poet.song.158000.json','["吾子遠歸省，重闈俱粲然。", "難留毛義檄，又送子真僊。", "西笑仍千里，東歸約二年。", "詞場期自力，收取舊青氈。"]'),
('edd984b1-a584-42d4-aba8-94b49e3c3af9','題少潜兄得閑  其一','樓鑰','宋','宋诗','song-poetry','','[]','亭下水吞空，輕舟處處通。',48,'全唐诗/poet.song.158000.json','["亭下水吞空，輕舟處處通。", "閑情誰得似，逸興更何窮。", "詩社率相過，醉鄉時一中。", "我家元不遠，只在小橋東。"]'),
('0c63cf69-877f-4161-8fa4-79189e8f6b7f','題少潜兄得閑  其二','樓鑰','宋','宋诗','song-poetry','','[]','平日君多暇，如今我亦閑。',48,'全唐诗/poet.song.158000.json','["平日君多暇，如今我亦閑。", "人歸真得地，吏隠勝居山。", "煙浪一千頃，茅簷三四間。", "天寒倚修竹，空翠濕欹鬟。"]'),
('0745c87d-9925-4226-8465-6ec0b378e225','送從子淵宰浦江','樓鑰','宋','宋诗','song-poetry','','[]','誰云宦路足嶇嶔，送子之官獨放心。',64,'全唐诗/poet.song.158000.json','["誰云宦路足嶇嶔，送子之官獨放心。", "廉介有餘無矯亢，謙恭已甚自崇深。", "安輿何用資三釜，慶問時能抵萬金。", "公退讀書三子侍，縣齋松竹已成林。"]'),
('4815050e-0460-47f7-9be3-8e523b49d3e1','慈溪道中','樓鑰','宋','宋诗','song-poetry','','[]','雙櫓真成鵝鸛鳴，客愁厭苦夢魂驚。',32,'全唐诗/poet.song.158000.json','["雙櫓真成鵝鸛鳴，客愁厭苦夢魂驚。", "須臾寖覺耳根熟，一覺醒來天已明。"]'),
('70fb923f-e9e5-407a-93c9-c0273386c708','題惠崇著色四時景物','樓鑰','宋','宋诗','song-poetry','','[]','舊說惠崇真畫師，生綃四幅見天機。',64,'全唐诗/poet.song.158000.json','["舊說惠崇真畫師，生綃四幅見天機。", "鷺翻桃岸韶光嫵，鵝漾蓮塘暑氣微。", "風勁賓鴻霜始肅，寒欺花鴨雪初飛。", "分明知是丹青卷，仍欲沙頭喚渡歸。"]'),
('cf6311f3-a0c6-4463-9df6-6f06218465d1','送吳參議','樓鑰','宋','宋诗','song-poetry','','[]','才氣勇無前，人推季子賢。',96,'全唐诗/poet.song.158000.json','["才氣勇無前，人推季子賢。", "侯藩聯剖竹，制幕晚依蓮。", "勢利從身外，風流到酒邊。", "四明欣會遇，兩載得周旋。", "爲記題名石，仍吟達觀篇。", "留行何及矣，執別但茫然。", "我已甘投老，君方欲引年。", "未知重見日，目斷五湖船。"]'),
('bbbc2be7-4bc8-4a1f-a243-a4cb0f5f90e5','即事','樓鑰','宋','宋诗','song-poetry','','[]','十日陰寒雪不成，臘殘春近更霜晴。',32,'全唐诗/poet.song.158000.json','["十日陰寒雪不成，臘殘春近更霜晴。", "深山高卧如春暖，遶鬢飛蚊自在鳴。"]'),
('aa0caf2d-5fc2-43ee-884d-2e712a62194a','吊陳衛道墓','樓鑰','宋','宋诗','song-poetry','','[]','平生學博更加詳，和會三家儘較量。',64,'全唐诗/poet.song.158000.json','["平生學博更加詳，和會三家儘較量。", "一覺可憐成夢蝶，多岐終是易亡羊。", "門前修竹連巖桂，道上芙蓉間海棠。", "何似剗除閑草木，青松一色蔭高岡。"]'),
('f2e69923-7005-4c1d-8fd8-9aae76cd72da','游大梅山梅仙巖','樓鑰','宋','宋诗','song-poetry','','[]','爲憶西京梅子真，人言羽化匪沉淪。',64,'全唐诗/poet.song.158000.json','["爲憶西京梅子真，人言羽化匪沉淪。", "海瀕古嶴已無跡，山外高峰寧有神。", "鯁論至今光漢傳，清風猶足盪秋旻。", "何須更說神仙事，終老市門良可人。"]'),
('b785ca50-5a92-4a01-b271-61b9453accc5','虎冢','樓鑰','宋','宋诗','song-poetry','','[]','辛勤玉柙更珠襦，或見叉牙出骨須。',64,'全唐诗/poet.song.158000.json','["辛勤玉柙更珠襦，或見叉牙出骨須。", "鷙獸一心能護法，敝帷千載尚全軀。", "餘威凜凜空埋骨，遺像眈眈若負嵎。", "及見當年梅子熟，自應驚倒老妖狐。"]'),
('bae2d567-b6bf-4828-b4a3-c846b8c7bb72','謝潘端叔惠紅梅  其一','樓鑰','宋','宋诗','song-poetry','','[]','舊家桃李種河陽，今日紅梅自楚湘。',32,'全唐诗/poet.song.158000.json','["舊家桃李種河陽，今日紅梅自楚湘。", "根墢送春君意重，爲移絕艷到吾鄉。"]'),
('694e6be8-4f6f-429f-861e-cc82686cd0a9','謝潘端叔惠紅梅  其二','樓鑰','宋','宋诗','song-poetry','','[]','黄姑曾爲點冰肌，亦有緇塵染素衣。',32,'全唐诗/poet.song.158000.json','["黄姑曾爲點冰肌，亦有緇塵染素衣。", "何似烟脂天賜與，暗香猶在是耶非。"]'),
('cf5da02e-e31d-44a6-9f2d-27aac4c32723','謝潘端叔惠紅梅  其三','樓鑰','宋','宋诗','song-poetry','','[]','爲君手種向南堂，誤認昌州移海棠。',32,'全唐诗/poet.song.158000.json','["爲君手種向南堂，誤認昌州移海棠。", "元是玉妃生酒暈，帳中仍带返魂香。"]'),
('5596b97d-f07b-4bcd-abe6-789e1c609635','謝潘端叔惠紅梅  其四','樓鑰','宋','宋诗','song-poetry','','[]','前身施粉忌太白，今日施朱恐太紅。',32,'全唐诗/poet.song.158000.json','["前身施粉忌太白，今日施朱恐太紅。", "說似旁人剛不信，清香萬斛在花中。"]'),
('f2d08bdd-d598-481b-95e2-92400adbd133','謝潘端叔惠紅梅  其五','樓鑰','宋','宋诗','song-poetry','','[]','殿後鞓紅色漫穠，絳桃空自笑春風。',32,'全唐诗/poet.song.158000.json','["殿後鞓紅色漫穠，絳桃空自笑春風。", "何人擊碎珊瑚樹，惱得瑶姬面發紅。"]'),
('dac10368-79b7-4e42-8f8b-88faf8568bfe','謝潘端叔惠紅梅  其六','樓鑰','宋','宋诗','song-poetry','','[]','舊見寒花蠟蔕紅，寧知沁入雪膚中。',32,'全唐诗/poet.song.158000.json','["舊見寒花蠟蔕紅，寧知沁入雪膚中。", "絕憐金谷佳人墜，到地餘香散曉風。"]'),
('a2969073-b481-4de7-a1e8-1042a820532a','謝潘端叔惠紅梅  其七','樓鑰','宋','宋诗','song-poetry','','[]','梅花幾種盡相聞，老矣才欣見此君。',32,'全唐诗/poet.song.158000.json','["梅花幾種盡相聞，老矣才欣見此君。", "相與對花文字飲，絕勝歌舞醉紅裙。"]'),
('0b606617-a898-4464-b7f8-f36e01cbbe20','謝潘端叔惠紅梅  其八','樓鑰','宋','宋诗','song-poetry','','[]','人閒丹桂亦微黄，未見紅葩解有香。',32,'全唐诗/poet.song.158000.json','["人閒丹桂亦微黄，未見紅葩解有香。", "惟喜此花兼衆美，麝臍薰徹絳紗囊。"]'),
('bb7ce797-907e-49c8-b666-449fa1126f94','謝潘端叔惠紅梅  其九','樓鑰','宋','宋诗','song-poetry','','[]','初移湘水一枝春，賸馥還欣爲我分。',32,'全唐诗/poet.song.158000.json','["初移湘水一枝春，賸馥還欣爲我分。", "夢入山房三十樹，何時醉倒看紅雲。"]'),
('d70c0f86-975e-4268-959d-bb1476ea089e','謝潘端叔惠紅梅  其一○','樓鑰','宋','宋诗','song-poetry','','[]','歲晚紅英繞凍柯，玉人無那醉顔酡。',32,'全唐诗/poet.song.158000.json','["歲晚紅英繞凍柯，玉人無那醉顔酡。", "廣平賦就如逢汝，鐵石心腸可柰何。"]'),
('b6c604af-dbb7-4080-93aa-5f0e1d0b9b9a','謝潘端叔惠紅梅  其一一','樓鑰','宋','宋诗','song-poetry','','[]','少陵年後詠花開，未見烟脂一抹腮。',32,'全唐诗/poet.song.158000.json','["少陵年後詠花開，未見烟脂一抹腮。", "可惜當時詩興動，止因東閣看官梅。"]'),
('6d0f55fd-ab3f-456b-ae47-3c5f36adc3e0','謝潘端叔惠紅梅  其一二','樓鑰','宋','宋诗','song-poetry','','[]','坡翁著意賦三詩，謾說穠香已透肌。',32,'全唐诗/poet.song.158000.json','["坡翁著意賦三詩，謾說穠香已透肌。", "若見此花應絕倒，惜君生晚不逢時。"]'),
('cb76b981-426a-460c-8422-909ede18b74d','謝潘端叔惠紅梅  其一三','樓鑰','宋','宋诗','song-poetry','','[]','花品無庸定等差，國香國色屬吾家。',32,'全唐诗/poet.song.158000.json','["花品無庸定等差，國香國色屬吾家。", "海棠正自慙麤俗，莫問漫山桃李花。"]'),
('f63df2d2-9bc4-4755-b735-f9c5dad32ffd','謝潘端叔惠紅梅  其一四','樓鑰','宋','宋诗','song-poetry','','[]','不學江頭玉樹寒，壽陽紅粉舊粧殘。',32,'全唐诗/poet.song.158000.json','["不學江頭玉樹寒，壽陽紅粉舊粧殘。", "嬋娟可是慙隨俗，莫作金沙鎖骨看。"]'),
('5eab9d2d-75c7-4b6c-b166-199df46c5546','謝潘端叔惠紅梅  其一五','樓鑰','宋','宋诗','song-poetry','','[]','客來試與倚欄干，拂拂清香觸鼻端。',32,'全唐诗/poet.song.158000.json','["客來試與倚欄干，拂拂清香觸鼻端。", "儘做北人渾不識，不應敢作杏花看。"]'),
('4ffe2b2f-4520-4b12-8b16-581262738a11','謝潘端叔惠紅梅  其一六','樓鑰','宋','宋诗','song-poetry','','[]','全體江梅臘裏芳，紫綿新拂漢宮妝。',32,'全唐诗/poet.song.158000.json','["全體江梅臘裏芳，紫綿新拂漢宮妝。", "臨川借得江梅句，傾國天教抵死香。"]'),
('ded43100-1620-4b89-8763-47272913276a','謝潘端叔惠紅梅  其一七','樓鑰','宋','宋诗','song-poetry','','[]','詩老爲花空自忙，想應未識此奇芳。',32,'全唐诗/poet.song.158000.json','["詩老爲花空自忙，想應未識此奇芳。", "青枝綠葉何須辨，桃杏安能如許香。"]'),
('4c247458-554b-4f37-ba80-8c633abf7d46','謝潘端叔惠紅梅  其一八','樓鑰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','只說梅花似雪飛，朱顔誰信暗香隨。',32,'全唐诗/poet.song.158000.json','["只說梅花似雪飛，朱顔誰信暗香隨。", "不須添上徐熙畫，付與西湖別賦詩。"]'),
('2e1fc6aa-6903-4b1f-8776-173fa6ad45e3','謝潘端叔惠紅梅  其一九','樓鑰','宋','宋诗','song-poetry','','[]','縞裙練帨玉爲肌，誰點微頳向北枝。',32,'全唐诗/poet.song.158000.json','["縞裙練帨玉爲肌，誰點微頳向北枝。", "若使羅虬見顔色，定須將此比紅兒。"]'),
('49fd4ebf-4958-45cb-8b23-ed0de199fff7','謝潘端叔惠紅梅  其二○','樓鑰','宋','宋诗','song-poetry','','[]','自昔梅花雪作團，紅梅晚出可人看。',32,'全唐诗/poet.song.158000.json','["自昔梅花雪作團，紅梅晚出可人看。", "江梅不解追時好，祇守冰姿度歲寒。"]'),
('28ddc96d-7563-4d4c-8b05-406a80150996','山行','樓鑰','宋','宋诗','song-poetry','','[]','行入春山紫翠中，入山深處更桃紅。',64,'全唐诗/poet.song.158000.json','["行入春山紫翠中，入山深處更桃紅。", "一百五日麥秋冷，二十四番花信風。", "千頃摇青幾蔽地，四山聳翠欲浮空。", "野橋橫跨溪如練，待買輕舟下釣筒。"]'),
('6c77789e-3b48-4f83-9e46-77dfbcccfcf5','金蹄','樓鑰','宋','宋诗','song-poetry','','[]','金蹄垂耳小韓盧，飾以重鐶馴可呼。',32,'全唐诗/poet.song.158000.json','["金蹄垂耳小韓盧，飾以重鐶馴可呼。", "誰擊冬青碧陰下，恍然如見擊梧圖。"]'),
('bc3969d3-06a4-4165-8ecc-571ca7b9e1cf','次吳伯華韵','樓鑰','宋','宋诗','song-poetry','','[]','一身遇坎復乘流，景物當前亦自由。',64,'全唐诗/poet.song.158000.json','["一身遇坎復乘流，景物當前亦自由。", "草淺人行因作徑，水來沙聚看成洲。", "哦詩肯爲鈎棘句，適意即是逍遥游。", "爛醉不知門外事，夕陽日日下西頭。"]'),
('8734fec3-a4f1-470e-99d2-cf2b110d53b3','從子渢送梅枝戲作','樓鑰','宋','宋诗','song-poetry','','[]','向來地暖見東嘉，带葉江梅殿歲華。',32,'全唐诗/poet.song.158000.json','["向來地暖見東嘉，带葉江梅殿歲華。", "不似青春三月暮，南枝梅子北枝花。"]'),
('8ae2e2a1-041d-4d00-8105-e3a226ff4b00','菁江迓客','樓鑰','宋','宋诗','song-poetry','','[]','菁江十里路逶遲，兩岸平疇接翠微。',32,'全唐诗/poet.song.158000.json','["菁江十里路逶遲，兩岸平疇接翠微。", "贏得閑中乘畫舫，隨潮西上趁潮歸。"]'),
('ffed2ede-21d7-47c7-9979-ea6f8ca3e1f3','午睡聽雨','樓鑰','宋','宋诗','song-poetry','','[]','老年樂事莫如閑，午睡醒來夢已闌。',32,'全唐诗/poet.song.158000.json','["老年樂事莫如閑，午睡醒來夢已闌。", "枕上欠伸猶懶起，更聽簷外雨珊珊。"]'),
('d441c3eb-22a6-4334-bbc8-6e044d315a83','放鶴送潘恭叔司理','樓鑰','宋','宋诗','song-poetry','','[]','沖霄六翮困蓬蒿，清唳時時發九皋。',64,'全唐诗/poet.song.158000.json','["沖霄六翮困蓬蒿，清唳時時發九皋。", "鵠立固應能獨出，雞羣未免歎徒勞。", "相從顧我憐冰玉，欲去知君刷羽毛。", "幸脫樊籠隨所適，平平飛去不須高。"]'),
('f4a074ea-4848-4fd7-84c1-46f6bdb3a231','宿育王山涵秋','樓鑰','宋','宋诗','song-poetry','','[]','清秋來此宿涵秋，雨後山泉自在流。',64,'全唐诗/poet.song.158000.json','["清秋來此宿涵秋，雨後山泉自在流。", "夜暗寒聲鏘玉佩，燈明清影粲珠旒。", "枕流正自憐孫楚，洗耳何須效許由。", "我亦暫來專一壑，倚欄耽玩不知休。"]'),
('4b69c987-9dc7-4a14-8581-5719a51df9c3','長女淯歸夫家寄以小詩','樓鑰','宋','宋诗','song-poetry','','[]','胡笳未了遽成歸，婦職如何敢失期。',32,'全唐诗/poet.song.158000.json','["胡笳未了遽成歸，婦職如何敢失期。", "彈到佳聲重入塞，伯喈未免念文姬。"]'),
('856ea36f-1f01-4901-8e7c-42045ec06c18','太湖響石','樓鑰','宋','宋诗','song-poetry','','["\u592a\u6e56"]','何處飛來一段雲，太湖風急到江城。',32,'全唐诗/poet.song.158000.json','["何處飛來一段雲，太湖風急到江城。", "雲中疑有羣仙過，時聽丁東環佩聲。"]'),
('0d3f9058-5463-4dfa-a785-c9ba1ae0d4d3','送朱季公倅嚴陵','樓鑰','宋','宋诗','song-poetry','','[]','朱家族裔甲龍舒，循吏清名史特書。',64,'全唐诗/poet.song.158000.json','["朱家族裔甲龍舒，循吏清名史特書。", "止爲嗇夫恩所部，至今廟食盛鄉閭。", "舍人曾賦嚴公瀨，季子方題仲舉輿。", "但向棠陰增蔽芾，桐鄉今却在桐廬。"]'),
('877cdecb-badf-481c-bec8-370cb9386e74','以十月桃雜松竹置瓶中照以鏡屏用潚韵','樓鑰','宋','宋诗','song-poetry','','[]','中有桃源天地寬，杳然溪照武陵寒。',32,'全唐诗/poet.song.158000.json','["中有桃源天地寬，杳然溪照武陵寒。", "莫言洞府無由入，試向桃花背後看。"]'),
('51e5db59-5c5b-49eb-afde-01503df153ff','次周益公韵  其一','樓鑰','宋','宋诗','song-poetry','','[]','天將間氣孕山川，名世還當五百年。',64,'全唐诗/poet.song.158000.json','["天將間氣孕山川，名世還當五百年。", "已是有官居鼎鼐，不妨平地作神仙。", "書林尚欲校三豕，筆力猶能驅兩肩。", "前日勳名身既退，斯文留與後人傳。"]'),
('b44951c2-e40f-419c-8dd6-94f118ffcb88','次周益公韵  其二','樓鑰','宋','宋诗','song-poetry','','[]','六一先生葛稚川，兩孫俱並相君年。',64,'全唐诗/poet.song.158000.json','["六一先生葛稚川，兩孫俱並相君年。", "詞場鏖戰今成夢，潭府齊盟望若仙。", "政路三公舊同甲，洛陽四老信差肩。", "坊名丙午真奇事，寫入詩編盍並傳。"]'),
('27c28bd4-d702-4a7e-9619-bc0a621aae13','次周益公韵  其三','樓鑰','宋','宋诗','song-poetry','','[]','頃嘗假守向中川，公在黄扉已數年。',64,'全唐诗/poet.song.158000.json','["頃嘗假守向中川，公在黄扉已數年。", "每念夔龍容接武，自期雞犬亦登仙。", "入朝終歎一交臂，問道幾思偏祖肩。", "數仞宮牆天樣遠，此心何日遂親傳。"]'),
('469ff4f4-f0b1-480c-9c25-b6c12ac442a7','次周益公韵  其四','樓鑰','宋','宋诗','song-poetry','','[]','別駕歸來自贛川，相迎方歎別經年。',64,'全唐诗/poet.song.158000.json','["別駕歸來自贛川，相迎方歎別經年。", "爲言相國珠璣語，寄問祠庭山澤僊。", "妙句聳觀親盥手，滿城爭玩日駢肩。", "退憐母子方偕隠，却恐虛名似此傳。"]'),
('219dbe54-aa39-4f6a-a684-8b64271927c9','次周益公韵  其五','樓鑰','宋','宋诗','song-poetry','','[]','舅甥相與老鄞川，況值慈親九十年。',64,'全唐诗/poet.song.158000.json','["舅甥相與老鄞川，況值慈親九十年。", "畫舫時追唐賀監，筍輿聯訪漢梅仙。", "官名自媿偶同轍，才望如何敢並肩。", "誤辱品題稱酷似，此聲梁楚更堪傳。"]'),
('41a2fa0d-00cd-43d9-9c3d-1ecedbd29e6c','題施武子所藏老融二牛圖  其一','樓鑰','宋','宋诗','song-poetry','','[]','佳哉淡墨掃人牛，一笛橫風各自由。',32,'全唐诗/poet.song.158000.json','["佳哉淡墨掃人牛，一笛橫風各自由。", "平日深知焉用稼，如今但欲老西疇。"]'),
('d4dd59fc-4963-4010-a8bd-ff0513d1fa7b','題施武子所藏老融二牛圖  其二','樓鑰','宋','宋诗','song-poetry','','[]','烏犍離立意逶遲，鞭策俱忘取次歸。',32,'全唐诗/poet.song.158000.json','["烏犍離立意逶遲，鞭策俱忘取次歸。", "騃犢跳風仍却顧，老融於此露天機。"]'),
('df954b98-682a-47d7-b16b-60f17faee3ee','謝少微兄惠牡丹  其一','樓鑰','宋','宋诗','song-poetry','','[]','乍觀泉石分新種，想爲黟山憶舊葩。',32,'全唐诗/poet.song.158000.json','["乍觀泉石分新種，想爲黟山憶舊葩。", "病後不妨風韵在，此花之外更無花。"]'),
('36d219af-18c3-45c6-8104-fdeb000c8578','謝少微兄惠牡丹  其二','樓鑰','宋','宋诗','song-poetry','','[]','方剪欄干第四花，玉人聯袂過吾家。',32,'全唐诗/poet.song.158000.json','["方剪欄干第四花，玉人聯袂過吾家。", "捻紅玉翼皆名品，醉眼相看到日斜。"]'),
('90b27b9e-cdff-4cc9-8f3a-734c505888ae','謝少微兄惠牡丹  其三','樓鑰','宋','宋诗','song-poetry','','[]','簫鼓聲中醉九旬，落紅萬點正愁人。',32,'全唐诗/poet.song.158000.json','["簫鼓聲中醉九旬，落紅萬點正愁人。", "眼明忽見傾城色，更向尊前作好春。"]'),
('4e259580-fa90-46e3-b0f4-dd2497d5916e','戲和淳詩卷  其一','樓鑰','宋','宋诗','song-poetry','','[]','琴弈心偏好，丹鉛手自磨。',48,'全唐诗/poet.song.158000.json','["琴弈心偏好，丹鉛手自磨。", "衰翁會同社，吾子揖餘波。", "歌動玉條脫，酒傾金叵羅。", "好爲文字飲，行樂未宜多。"]'),
('5e375002-b8cc-42d0-bde8-3e53cf6166b8','戲和淳詩卷  其二','樓鑰','宋','宋诗','song-poetry','','[]','山色藍初染，湖光鏡始磨。',48,'全唐诗/poet.song.158000.json','["山色藍初染，湖光鏡始磨。", "竹梢輕墜雨，花片亂隨波。", "麈尾揮東晉，龍舟吊汨羅。", "莫愁春易老，暢飲一春多。"]'),
('5468d0ef-be2d-4367-b041-912e61bc979d','戲和淳詩卷  其三','樓鑰','宋','宋诗','song-poetry','','[]','澄江如練浄，新月似鐮磨。',48,'全唐诗/poet.song.158000.json','["澄江如練浄，新月似鐮磨。", "老柳飄輕絮，良苗颭細波。", "歌聲追古郢，詩價怯新羅。", "到處還成醉，芳醪旨且多。"]'),
('81595870-1b7a-4f16-a2db-f184d636aab6','戲和淳詩卷  其四','樓鑰','宋','宋诗','song-poetry','','[]','暮年甘散誕，壯志久消磨。',48,'全唐诗/poet.song.158000.json','["暮年甘散誕，壯志久消磨。", "自媿今摩詰，誰憐老伏波。", "清新慙庾信，敏慧謝甘羅。", "惟有詩情在，猶能益辦多。"]'),
('fb702f82-2824-4b51-a029-a7c9c371cb31','過從子澤家','樓鑰','宋','宋诗','song-poetry','','[]','楚楚初篁脫綠苞，城居約略似荒郊。',32,'全唐诗/poet.song.158000.json','["楚楚初篁脫綠苞，城居約略似荒郊。", "土膏更得春風力，直引薔薇上竹梢。"]'),
('63987ef2-dfd8-4ae6-ba15-bd33748f26f4','題陸放翁詩卷','樓鑰','宋','宋诗','song-poetry','','[]','妙畫初驚渴驥奔，新詩熟讀歎微言。',64,'全唐诗/poet.song.158000.json','["妙畫初驚渴驥奔，新詩熟讀歎微言。", "四明知我豈相屬，一水思君誰與論。", "茶竈筆牀懷甫里，青鞋布襪想雲門。", "何當一棹訪深雪，夜語同傾老瓦盆。"]'),
('9b795d49-85b9-4eb9-8e84-e27ce0c3735b','送內弟汪莊仲赴浙西倉幕','樓鑰','宋','宋诗','song-poetry','','[]','家食八經秋，茲焉喜宦游。',48,'全唐诗/poet.song.158000.json','["家食八經秋，茲焉喜宦游。", "往依王仲寶，况事薛居州。", "寄信憑鴻羽，題詩記虎丘。", "雲飛親舍近，時望海東頭。"]'),
('734ceddc-e191-4a3f-936b-112710e88dcc','贈龍游術士胡杲','樓鑰','宋','宋诗','song-poetry','','[]','方笑劉郎問大鈞，從來禍福本無門。',32,'全唐诗/poet.song.158000.json','["方笑劉郎問大鈞，從來禍福本無門。", "世閒生老病死苦，時至即行何足論。"]'),
('443299a5-b665-4c87-bf8f-5db458aebba8','夜坐','樓鑰','宋','宋诗','song-poetry','','[]','晚涼徐步出柴扃，萬變浮雲在窈冥。',64,'全唐诗/poet.song.158000.json','["晚涼徐步出柴扃，萬變浮雲在窈冥。", "濃似鐵山擎缺月，薄於春絮透疎星。", "正欣夜久沉天籟，尤喜空明鬰帝青。", "雨氣未平龍欲動，電光前後射中庭。"]'),
('64a3296f-baee-4fe1-88f7-62e4dde9151c','再送潘恭叔','樓鑰','宋','宋诗','song-poetry','','[]','我似冥鴻弋猶慕，君如放鶴去還歸。',32,'全唐诗/poet.song.158000.json','["我似冥鴻弋猶慕，君如放鶴去還歸。", "秋空今日真成去，好伴閑雲自在飛。"]'),
('eeef7628-dfd2-4e1f-83c6-d20cd2eb28db','以六經左氏傳莊子遺伯中弟有詩來謝次韵  其一','樓鑰','宋','宋诗','song-poetry','','[]','手披欲究百家編，奴婢年來識鄭玄。',64,'全唐诗/poet.song.158000.json','["手披欲究百家編，奴婢年來識鄭玄。", "顧我幸多千卷富，念君未有一經全。", "詩書心醉不容醒，父子筆耕期有年。", "此但古人糟粕耳，更須從此悟真筌。"]'),
('c67aee0a-fd40-4fb9-9192-6f03e5f9497a','以六經左氏傳莊子遺伯中弟有詩來謝次韵  其二','樓鑰','宋','宋诗','song-poetry','','[]','書種傳來直到今，讀書幾似孝標淫。',64,'全唐诗/poet.song.158000.json','["書種傳來直到今，讀書幾似孝標淫。", "欲君終就九經庫，與子平分一片心。", "更向漆園窮妙旨，何殊清廟奏遺音。", "中郎書籍付王粲，想得知余此意深。"]'),
('c57071f4-3226-4001-bc12-fc2806b621b5','中秋無月','樓鑰','宋','宋诗','song-poetry','','[]','涼意秋將半，深期月影清。',48,'全唐诗/poet.song.158000.json','["涼意秋將半，深期月影清。", "昨宵雲點綴，今夜雨縱橫。", "睡久何曾著，更闌喜暫晴。", "起來聊曠望，終欠十分明。"]'),
('e551303e-3016-474e-9908-ad2db704ba46','贈丁相士','樓鑰','宋','宋诗','song-poetry','','[]','相形何似且論心，眼力工夫見淺深。',32,'全唐诗/poet.song.158000.json','["相形何似且論心，眼力工夫見淺深。", "古怪清奇任君說，靈臺一片若爲尋。"]'),
('09122415-04e0-44eb-9900-7ab126888708','送叔韶弟赴官錢清','樓鑰','宋','宋诗','song-poetry','','[]','蕞爾錢清鎮，茲行正爲貧。',48,'全唐诗/poet.song.158000.json','["蕞爾錢清鎮，茲行正爲貧。", "九夷猶可處，十室豈無人。", "官守毋卑小，城居緩卜鄰。", "老夫平日事，所至若終身。"]'),
('2992e1a4-aad2-4826-8ab9-5e428a9ddddb','浄明方丈','樓鑰','宋','宋诗','song-poetry','','[]','雲深宿雨未忺晴，短艇還來叩曉扃。',64,'全唐诗/poet.song.158000.json','["雲深宿雨未忺晴，短艇還來叩曉扃。", "山溜擁谿侵石磴，天風吹霧暗空庭。", "茵鋪野草滋新綠，玉立修篁洗舊青。", "老我時時假僧榻，夢魂直向醉中醒。"]'),
('0992ac55-dcb9-4ba0-ae09-3824a7eaaab0','新闢門徑或謂太窄','樓鑰','宋','宋诗','song-poetry','','[]','門外頓空曠，雙眸豁太虛。',192,'全唐诗/poet.song.158000.json','["門外頓空曠，雙眸豁太虛。", "誰歟列佳樹，正爾對吾廬。", "蚤歲曾修業，衰年得定居。", "買鄰賢伯仲，衣錦舊門閭。", "未辦三閒屋，先栽數席蔬。", "歡娛戲萊服，晨夕奉潘輿。", "駟馬容雖狹，齋郎住有餘。", "牀金知已盡，瓶粟豈無儲。", "細草沿階嫩，新篁得雨初。", "竊希仁者靜，未覺故人疎。", "晝永翻名畫，更長理舊書。", "何妨抱琴醉，儘好带經鉏。", "耋穉同甘苦，兒孫共卷舒。", "眼花多掩卷，鬢雪不堪梳。", "少飲毋求醉，徐行可當車。", "此生千萬足，祇願老樵漁。"]'),
('ffe73a9c-f5bf-4c85-a734-aa3f13fb68b8','小溪道中  其一','樓鑰','宋','宋诗','song-poetry','','[]','簇簇蒼山隠夕暉，遥看野鴈著行歸。',32,'全唐诗/poet.song.158000.json','["簇簇蒼山隠夕暉，遥看野鴈著行歸。", "久之不動方知是，一搭碎雲寒不飛。"]'),
('d080f2c8-76c3-45dd-b00f-03a40fa86b75','小溪道中  其二','樓鑰','宋','宋诗','song-poetry','','[]','後衕環村儘遡游，鳳山寺下換輕舟。',32,'全唐诗/poet.song.158000.json','["後衕環村儘遡游，鳳山寺下換輕舟。", "舟人努力雙篙急，引得清溪逆岸流。"]'),
('bdf75bb1-adf5-4932-b5b2-5075e4352461','送從子淵葬','樓鑰','宋','宋诗','song-poetry','','[]','晨起霜如雪，天寒水欲冰。',48,'全唐诗/poet.song.158000.json','["晨起霜如雪，天寒水欲冰。", "引舟拖急瀨，扶杖歷危層。", "北阮苦多事，二疎俄喪朋。", "山阿埋白璧，悲慟不能勝。"]'),
('31407fd1-bc1e-4afc-b8f4-f9e2200731ec','早起戲作','樓鑰','宋','宋诗','song-poetry','','[]','枕穩衾溫夢乍回，閒居不怕漏聲催。',32,'全唐诗/poet.song.158000.json','["枕穩衾溫夢乍回，閒居不怕漏聲催。", "天明更欲從容睡，長被孫兒惱覺來。"]'),
('de297432-f49b-494d-aa06-3cff38c019a4','午睡戲作','樓鑰','宋','宋诗','song-poetry','','[]','早起三朝當一工，老來貪睡不相同。',32,'全唐诗/poet.song.158000.json','["早起三朝當一工，老來貪睡不相同。", "偶然一次五更起，却用重眠到日中。"]'),
('ed42ae41-0c9e-46bf-96d9-02a644cbb8ba','南山廣莫軒','樓鑰','宋','宋诗','song-poetry','','[]','廣莫乘風隘九州，亂山無數點平疇。',64,'全唐诗/poet.song.158000.json','["廣莫乘風隘九州，亂山無數點平疇。", "一千里外在吾目，三十年來無此游。", "地下天高俱歷歷，鳶飛魚躍兩悠悠。", "昌黎費盡南山句，曠望還能似此不。"]'),
('f0593a4f-1281-4727-8bfa-4f4e4e98d477','送趙至道節推','樓鑰','宋','宋诗','song-poetry','','[]','君來入幕恰三年，我幸投閑識此賢。',64,'全唐诗/poet.song.158000.json','["君來入幕恰三年，我幸投閑識此賢。", "婉畫時時因事見，素風凜凜信家傳。", "易林律本君須寄，月窟天根語未圓。", "問訊難兄無恙否，相忘千里各瀛壖。"]'),
('4994e056-ce06-4747-89be-bbcc2989ebeb','湖亭觀競渡','樓鑰','宋','宋诗','song-poetry','','[]','涵虛歌舞擁邦君，兩兩龍舟來往頻。',64,'全唐诗/poet.song.158000.json','["涵虛歌舞擁邦君，兩兩龍舟來往頻。", "閏月風光三月景，二分煙水八分人。", "錦標贏得千人笑，畫鼓敲殘一半春。", "薄暮游船分散去，尚餘簫鼓繞湖濱。"]'),
('da786727-6309-4a7d-986e-d3776e141c03','龍潭方丈','樓鑰','宋','宋诗','song-poetry','','[]','又因寒食此中來，窗戶虛明絕點埃。',32,'全唐诗/poet.song.158000.json','["又因寒食此中來，窗戶虛明絕點埃。", "山裏春風無閒斷，海棠開過地棠開。"]'),
('04ddba6f-9ccf-4fff-9306-a220474c9eb8','吊僅老塔','樓鑰','宋','宋诗','song-poetry','','[]','僅老相從五十朞，來瞻遺塔我心悲。',32,'全唐诗/poet.song.158000.json','["僅老相從五十朞，來瞻遺塔我心悲。", "當時舊話無人說，空有門前洗鉢池。"]'),
('19e8d561-699b-40ec-bdb7-33a76e71d505','夜携家登南渡橋','樓鑰','宋','宋诗','song-poetry','','[]','幾過長橋下，清宵得意行。',48,'全唐诗/poet.song.158000.json','["幾過長橋下，清宵得意行。", "風高江水急，月上海潮生。", "空迥寒逾峭，更深境過清。", "扁舟難久駐，轉柂問歸程。"]'),
('167606f8-2ef6-4290-8ca1-633afd22b41d','題蘿月上人送鴻小樓','樓鑰','宋','宋诗','song-poetry','','[]','雨洗春山空翠新，登樓不見送鴻人。',32,'全唐诗/poet.song.158000.json','["雨洗春山空翠新，登樓不見送鴻人。", "薜蘿清夜月依舊，無復新詩泣鬼神。"]'),
('d67a7fce-f1e6-4ada-8d07-07c251752750','贈于湖劉相士','樓鑰','宋','宋诗','song-poetry','','[]','自笑今年卦氣闌，壯心銷盡鬢毛殘。',32,'全唐诗/poet.song.158000.json','["自笑今年卦氣闌，壯心銷盡鬢毛殘。", "明知七十無多子，只問何時可掛冠。"]'),
('0233b0b6-e049-4a99-af6c-0f185cc27129','五月望月蝕曆家又言六月朔日蝕','樓鑰','宋','宋诗','song-poetry','','[]','閭巷夜爭呼，相傳救望舒。',48,'全唐诗/poet.song.158000.json','["閭巷夜爭呼，相傳救望舒。", "偶因雲暫破，真似月之初。", "孰謂蟆能瞎，端知曆不疎。", "太陽交蝕近，試看更何如。"]'),
('5f973925-2d77-4289-9229-f403796d774d','題賀監李謫仙二像  其一','樓鑰','宋','宋诗','song-poetry','','[]','不有風流賀季真，更誰能識謫仙人。',32,'全唐诗/poet.song.158000.json','["不有風流賀季真，更誰能識謫仙人。", "金龜換酒今何在，相對畫圖如有神。"]'),
('98bacf7b-2b26-4fe3-afa5-3ef56d3fb298','題賀監李謫仙二像  其二','樓鑰','宋','宋诗','song-poetry','','[]','斗酒澆詩動百篇，鑑湖牛渚兩俱仙。',32,'全唐诗/poet.song.158000.json','["斗酒澆詩動百篇，鑑湖牛渚兩俱仙。", "早知今日猶相對，不向稽山回酒船。"]'),
('bb61da87-ea12-4c26-8c83-5676d0b31533','病後戲作','樓鑰','宋','宋诗','song-poetry','','[]','河魚腹疾未全除，一飯充饑不願餘。',32,'全唐诗/poet.song.158000.json','["河魚腹疾未全除，一飯充饑不願餘。", "縱有珍羞難下筯，真成頓頓食黄魚。"]'),
('28245b84-0e8e-47e9-87e1-71f2e1501d82','枕上','樓鑰','宋','宋诗','song-poetry','','[]','不守庚申不坐禪，老來觸事總悠然。',32,'全唐诗/poet.song.158000.json','["不守庚申不坐禪，老來觸事總悠然。", "天明門外無來客，儘好蕭蕭聽雨眠。"]'),
('8d823acc-4db5-427f-bc23-fc9be1317c61','謝蔣行之送菊','樓鑰','宋','宋诗','song-poetry','','[]','秋老情懷儘自寬，眼前只欠菊花團。',64,'全唐诗/poet.song.158000.json','["秋老情懷儘自寬，眼前只欠菊花團。", "分來三徑雙株秀，先得重陽兩日看。", "玉軟金輕無限態，風高露冷不勝寒。", "幽人相對成清伴，正爾落英供夕餐。"]'),
('d687d3c0-08a3-4054-90d4-06a4761d0b3f','廳事落成老母置酒喜而成詩','樓鑰','宋','宋诗','song-poetry','','[]','數椽增葺苟全時，我愛吾廬喜得歸。',64,'全唐诗/poet.song.158000.json','["數椽增葺苟全時，我愛吾廬喜得歸。", "兒輩粗能勤父蠱，老夫元不費心機。", "年來每媿踰初望，病裏尤知悟昨非。", "從此蕭然無一事，但當日舞老萊衣。"]'),
('fe0b3f42-fc38-4f9d-9b70-3e9c0d546ba9','十月十七日夜','樓鑰','宋','宋诗','song-poetry','','[]','蟄蟲坯戶六經旬，掣電驚雷若莫春。',32,'全唐诗/poet.song.158000.json','["蟄蟲坯戶六經旬，掣電驚雷若莫春。", "震起昆蟲千百億，不知何處更容身。"]'),
('4ef8fd12-9a94-4b50-9fc2-a91b5f8d6c58','織錦棋盤','樓鑰','宋','宋诗','song-poetry','','[]','錦城巧女費心機，織就一枰如許齊。',64,'全唐诗/poet.song.158000.json','["錦城巧女費心機，織就一枰如許齊。", "彷佛回文仍具體，縱橫方罫若分畦。", "爛柯未易供仙弈，畫紙何須倩老妻。", "如欲拈棋輕且稱，當求白象與烏犀。"]'),
('feca4851-959b-4a07-b1d8-d69863bcee40','叔韶弟以退堂洪老詩來寄謝','樓鑰','宋','宋诗','song-poetry','','[]','不受人天供，甘心樂隠居。',48,'全唐诗/poet.song.158000.json','["不受人天供，甘心樂隠居。", "坐窮千里目，笑擁一樓書。", "攻媿老無用，退堂閑有餘。", "相望可杭葦，何日訪吾廬。"]'),
('804e5081-65fa-4941-ab53-1b7e5d0db2c1','寄題正卿通判可高亭','樓鑰','宋','宋诗','song-poetry','','[]','樟坡直上可高亭，未見高亭祇見名。',64,'全唐诗/poet.song.158000.json','["樟坡直上可高亭，未見高亭祇見名。", "想像豈能勝一覽，登高安得快雙明。", "大龍湫下聽雷吼，白石巖頭看日生。", "咫尺好山隨杖屨，自應老筆擅詩聲。"]'),
('0af3312b-4b1f-4de2-a3ee-381836784430','中秋次從子涔韵','樓鑰','宋','宋诗','song-poetry','','[]','雨餘不見日西沈，將謂中秋又作陰。',64,'全唐诗/poet.song.158000.json','["雨餘不見日西沈，將謂中秋又作陰。", "佳月忽開千里影，騷人滿慰一年心。", "掃除宿翳風雖動，滓穢太清雲尚深。", "坐待寒光誰會此，阿咸爲我發微吟。"]'),
('601f3cb1-4a5c-4c10-ad54-36ac4d8ddcf6','楊花','樓鑰','宋','宋诗','song-poetry','','[]','杜門無緒看芳菲，見說楊花滿路飛。',32,'全唐诗/poet.song.158000.json','["杜門無緒看芳菲，見說楊花滿路飛。", "謝汝不隨人冷暖，因風翻舞到柴扉。"]'),
('cde62c99-08cd-4369-baab-d32430e90716','送趙南仲丞溧水','樓鑰','宋','宋诗','song-poetry','','[]','不用匆匆恨別離，版輿春晝綵衣隨。',64,'全唐诗/poet.song.158000.json','["不用匆匆恨別離，版輿春晝綵衣隨。", "往題斯立藍田壁，更訪清真溧上詩。", "公事毋庸枿牙角，鄰封真是和塤篪。", "日哦新句頻相寄，明月清風慰所思。"]'),
('2ccbbb87-711c-481d-b5a6-071b897ee244','戲題龍眠馬性圖','樓鑰','宋','宋诗','song-poetry','','[]','狗子已知無佛性，馬又何曾有性來。',32,'全唐诗/poet.song.158000.json','["狗子已知無佛性，馬又何曾有性來。", "伯樂若來休著眼，任它騏驥混駑駘。"]'),
('19529bce-1c1a-4185-8b31-5a7344eb2131','它山  其一','樓鑰','宋','宋诗','song-poetry','','[]','素蜺橫卧作雷吼，日射細鱗銀雪光。',32,'全唐诗/poet.song.158000.json','["素蜺橫卧作雷吼，日射細鱗銀雪光。", "安得此身如白鷺，修然終日在梅梁。"]'),
('e1464c5a-6831-4bc9-98cb-a3a32dfc3fe6','它山  其二','樓鑰','宋','宋诗','song-poetry','','[]','過盡水禽并野鳬，風標惟許一舂鉏。',32,'全唐诗/poet.song.158000.json','["過盡水禽并野鳬，風標惟許一舂鉏。", "可憐久立梅梁上，不爲谿光祇爲魚。"]'),
('d0a211c4-2d08-452b-8a28-30b9010a63f7','小酌元衛弟聽雨','樓鑰','宋','宋诗','song-poetry','','[]','小閣臨流暑氣清，藕花的的照人明。',32,'全唐诗/poet.song.158000.json','["小閣臨流暑氣清，藕花的的照人明。", "移牀更近欄邊坐，要聽棋聲雜雨聲。"]'),
('c0fbbbd5-a72b-4893-9ce8-bbef908c2b57','潚再往剡中念之尤切作詩寬之','樓鑰','宋','宋诗','song-poetry','','[]','剡縣不爲遠，丞官勿謂卑。',48,'全唐诗/poet.song.158000.json','["剡縣不爲遠，丞官勿謂卑。", "鼓盆知愛重，去國倍行遲。", "堂上森三老，房中秀一兒。", "加餐了官事，莫賦悼亡詩。"]'),
('07af9947-5399-4dd0-b40a-d58f042ea132','觀雲寄簡講師','樓鑰','宋','宋诗','song-poetry','','[]','蒼狗俄然又白衣，來從何處去何歸。',32,'全唐诗/poet.song.158000.json','["蒼狗俄然又白衣，來從何處去何歸。", "無心出岫還歸去，莫向秋風說是非。"]'),
('bc74a1ee-d44e-4cca-93b2-74c0c951b3fe','過故家','樓鑰','宋','宋诗','song-poetry','','[]','團團桂樹擁簷牙，舊日輕黄滿樹花。',32,'全唐诗/poet.song.158000.json','["團團桂樹擁簷牙，舊日輕黄滿樹花。", "惆悵秋清無一葉，空餘枯枿縋寒瓜。"]'),
('f44c19e7-f816-4482-9ed9-c5c2520be27b','題從子浹娛親','樓鑰','宋','宋诗','song-poetry','','[]','阿戎築屋爲娛親，野草閑花日日新。',32,'全唐诗/poet.song.158000.json','["阿戎築屋爲娛親，野草閑花日日新。", "我奉版輿來舉酒，祈君親壽似夫人。"]'),
('67bc8680-568d-4fe3-9e8d-fee66d07b5ae','丹桂','樓鑰','宋','宋诗','song-poetry','','[]','碧雲步障紫金蕤，風靜秋高千萬枝。',32,'全唐诗/poet.song.158000.json','["碧雲步障紫金蕤，風靜秋高千萬枝。", "嬌額塗黄元自好，是誰深傳蜜烟脂。"]'),
('cdff0c88-0f80-46f8-a2eb-ecfb188aee50','下元日暖甚夜風雨大作早微雪從子潗以酴醾來','樓鑰','宋','宋诗','song-poetry','','[]','眼明喜見早酴醾，窗外風號集霰時。',64,'全唐诗/poet.song.158000.json','["眼明喜見早酴醾，窗外風號集霰時。", "梅蘂已慙前臘破，芳心休用怨春遲。", "納涼除夜昨幾似，見雪芭蕉今不疑。", "若使洛人真得此，應須更詫百宜枝。"]'),
('8c0eee63-cb1e-41b2-a502-28473cef4b3b','送朱叔止守南劍  其一','樓鑰','宋','宋诗','song-poetry','','[]','舍人簪筆舊甘泉，家學相傳子姓賢。',32,'全唐诗/poet.song.158000.json','["舍人簪筆舊甘泉，家學相傳子姓賢。", "未羨夾河爲太守，阿連剖竹向封川。"]'),
('fddf7f0d-0af9-49ad-a9e9-fac6f3a5f381','送朱叔止守南劍  其二','樓鑰','宋','宋诗','song-poetry','','[]','槜李曾蜚剸劇聲，貳車仍贊虎頭城。',32,'全唐诗/poet.song.158000.json','["槜李曾蜚剸劇聲，貳車仍贊虎頭城。", "朱轓小試承流手，要繼桐鄉循吏名。"]'),
('0d13e0be-6894-4c0c-bd24-22d5f160ed4e','送朱叔止守南劍  其三','樓鑰','宋','宋诗','song-poetry','','[]','萬竹蟠山喉不乾，兩龍潛水氣猶寒。',32,'全唐诗/poet.song.158000.json','["萬竹蟠山喉不乾，兩龍潛水氣猶寒。", "郡齋見說真圖畫，公退何妨一倚欄。"]'),
('e9a1a1b7-2af2-481e-a9ad-0edfb136443c','送朱叔止守南劍  其四','樓鑰','宋','宋诗','song-poetry','','[]','下水上山腰带州，人家無數起危樓。',32,'全唐诗/poet.song.158000.json','["下水上山腰带州，人家無數起危樓。", "遨頭不用喧簫鼓，祇把清詩紀勝游。"]'),
('600abcbf-5319-492a-b1ad-51ef9fd770e8','送朱叔止守南劍  其五','樓鑰','宋','宋诗','song-poetry','','[]','同盟東下或西征，老我惟知管送迎。',32,'全唐诗/poet.song.158000.json','["同盟東下或西征，老我惟知管送迎。", "祇恐政成登省戶，未容歸騎向西城。"]'),
('2033b5e2-0fc7-422f-8fad-faa094ab7a64','送朱叔止守南劍  其六','樓鑰','宋','宋诗','song-poetry','','[]','名畫法書知幾編，俸餘寧復計求田。',32,'全唐诗/poet.song.158000.json','["名畫法書知幾編，俸餘寧復計求田。", "麻沙賸買新文字，歸滿米家書畫船。"]'),
('99594b40-d93b-4973-8a83-0609aca9bffd','送杓孫隨侍上虞','樓鑰','宋','宋诗','song-poetry','','[]','阿斗生來十五年，未曾一日去翁前。',64,'全唐诗/poet.song.158000.json','["阿斗生來十五年，未曾一日去翁前。", "聞詩勿廢家庭問，習吏仍求城旦篇。", "婚宦有涯真是幸，巾箱所蓄要相傳。", "榮罍雖小性非魯，口授詩書加愛憐。"]'),
('6fb62584-c39d-4e61-9733-4de98041a941','戲作','樓鑰','宋','宋诗','song-poetry','','[]','二子爲丞分越邑，女兒隨壻過江南。',32,'全唐诗/poet.song.158000.json','["二子爲丞分越邑，女兒隨壻過江南。", "莫言屋裏成岑寂，匹似當初只住庵。"]'),
('4f5ddafe-0221-48ec-8219-10fb8c21aee9','諸瑩拜掃晚歸長汀','樓鑰','宋','宋诗','song-poetry','','[]','雨意早垂垂，寒雲晚更低。',48,'全唐诗/poet.song.158000.json','["雨意早垂垂，寒雲晚更低。", "空中時散點，道上不成泥。", "綠柳桃相映，黄花麥與齊。", "迂回餘百里，喜見舊松隄。"]'),
('b67f1498-82e8-4650-b97d-62dbb8241612','送朱季公守封川  其一','樓鑰','宋','宋诗','song-poetry','','[]','韶陽生長十餘年，城郭重經固宛然。',32,'全唐诗/poet.song.158000.json','["韶陽生長十餘年，城郭重經固宛然。", "嘆息紫微仙去久，尚餘遺墨照山川。"]'),
('903d2844-259d-4a08-ae76-8a9430c70edf','送朱季公守封川  其二','樓鑰','宋','宋诗','song-poetry','','[]','桐鄉漢有大司農，封守今推陳秀公。',32,'全唐诗/poet.song.158000.json','["桐鄉漢有大司農，封守今推陳秀公。", "君向邦人著遺愛，近追相業遠家風。"]'),
('e6f48174-518b-4ea2-bbf0-13535d78b9c6','送朱季公守封川  其三','樓鑰','宋','宋诗','song-poetry','','[]','鄉評久說鴈行賢，剖竹封川與劍川。',32,'全唐诗/poet.song.158000.json','["鄉評久說鴈行賢，剖竹封川與劍川。", "不用對牀風雨約，政成同取舊青氈。"]'),
('87542a64-9455-4143-92cf-0681586985fb','送朱季公守封川  其四','樓鑰','宋','宋诗','song-poetry','','[]','吾鄉棋社寖凋零，頼有朱家好弟兄。',32,'全唐诗/poet.song.158000.json','["吾鄉棋社寖凋零，頼有朱家好弟兄。", "舉酒看看故人少，陽關莫唱斷腸聲。"]'),
('dee8ac98-f15b-474e-90dd-cff4a63d0772','送朱季公守封川  其五','樓鑰','宋','宋诗','song-poetry','','[]','妙舞清歌有二姝，後堂曾見繡羅襦。',32,'全唐诗/poet.song.158000.json','["妙舞清歌有二姝，後堂曾見繡羅襦。", "嶺南太守風流勝，不用歸舟載綠珠。"]'),
('39a33f6a-a730-4c7f-8685-9088d220b08b','以玉蘭贈王習父  其一','樓鑰','宋','宋诗','song-poetry','','[]','一種香蘭玉色新，仙家分得蘂宮春。',32,'全唐诗/poet.song.158000.json','["一種香蘭玉色新，仙家分得蘂宮春。", "調高韵勝誰能稱，付與能言解語人。"]'),
('32d03274-64d3-4c4b-ae33-4774fc5749ad','以玉蘭贈王習父  其二','樓鑰','宋','宋诗','song-poetry','','[]','華屋翬飛慶事綿，芝蘭玉樹喜庭前。',32,'全唐诗/poet.song.158000.json','["華屋翬飛慶事綿，芝蘭玉樹喜庭前。", "似聞楚畹芽初茁，便看藍田生晚煙。"]'),
('6f95b5af-d78f-48b3-b975-a1647b707c22','送趙清臣宰姚江  其一','樓鑰','宋','宋诗','song-poetry','','[]','玉立君家好弟兄，藍田風采照花城。',32,'全唐诗/poet.song.158000.json','["玉立君家好弟兄，藍田風采照花城。", "版輿壽母人間盛，千里何曾去送迎。"]'),
('feafc1c3-06a1-4908-9be0-359b50a0e022','送趙清臣宰姚江  其二','樓鑰','宋','宋诗','song-poetry','','[]','鄞江水與舜江通，久矣威名滿一同。',32,'全唐诗/poet.song.158000.json','["鄞江水與舜江通，久矣威名滿一同。", "試問何時到封部，數聲柔櫓一帆風。"]'),
('66be1f3a-9189-40f8-ae97-6078ae19c5d0','送趙清臣宰姚江  其三','樓鑰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江東去跨虹橋，千丈橫隄捍海潮。',32,'全唐诗/poet.song.158000.json','["長江東去跨虹橋，千丈橫隄捍海潮。", "更向燭谿圖永利，坐令百里沸歌謠。"]'),
('b8f2d11a-dfa8-464f-bacc-f8ded8c84828','送趙清臣宰姚江  其四','樓鑰','宋','宋诗','song-poetry','','[]','才刃恢恢妙撥煩，鄰封撫字尚何難。',32,'全唐诗/poet.song.158000.json','["才刃恢恢妙撥煩，鄰封撫字尚何難。", "更能觸事加長慮，自有甘棠向後看。"]'),
('738c3169-981c-42ba-9c03-463dd7e93f2b','送趙清臣宰姚江  其五','樓鑰','宋','宋诗','song-poetry','','[]','婦家故步懶重尋，藏拙年來恐不深。',32,'全唐诗/poet.song.158000.json','["婦家故步懶重尋，藏拙年來恐不深。", "短棹有時乘興去，徑登竹所聽鳴琴。"]'),
('ebafb850-6239-4464-89b0-d2864054d7f6','楊花  其一','樓鑰','宋','宋诗','song-poetry','','[]','雨壓輕寒春較遲，春深不見柳綿飛。',32,'全唐诗/poet.song.158000.json','["雨壓輕寒春較遲，春深不見柳綿飛。", "忽然飛入閒庭院，疑是故人何處歸。"]'),
('da711c70-be8f-4613-831c-78552ad2bd40','楊花  其二','樓鑰','宋','宋诗','song-poetry','','[]','柳綿無數糝枝頭，日暖隨風撲畫樓。',32,'全唐诗/poet.song.158000.json','["柳綿無數糝枝頭，日暖隨風撲畫樓。", "萬象可觀惟有雪，喜看晴晝滿空游。"]'),
('9cd76309-1fc5-4295-9ba5-aceefa498130','楊花  其三','樓鑰','宋','宋诗','song-poetry','','[]','爲我輕攀綠柳枝，带花低護笑携歸。',32,'全唐诗/poet.song.158000.json','["爲我輕攀綠柳枝，带花低護笑携歸。", "日長深院微風動，要看鬆綿當面飛。"]'),
('127bd6d4-0e7a-4cd8-812a-791391a46b42','楊花  其四','樓鑰','宋','宋诗','song-poetry','','[]','野芳庭草是生涯，老去祇宜閑在家。',32,'全唐诗/poet.song.158000.json','["野芳庭草是生涯，老去祇宜閑在家。", "幾日惜春留不住，小鬟爲我拾楊花。"]'),
('18b36589-04cc-4ead-b010-d5de163fca0f','送王伯奮守筠陽','樓鑰','宋','宋诗','song-poetry','','[]','三槐名德萃清門，七葉爲州頼有君。',64,'全唐诗/poet.song.158000.json','["三槐名德萃清門，七葉爲州頼有君。", "道院無忘山谷賦，郡齋當繼潁濱文。", "君應膝上憐文度，我向東牀憶右軍。", "振起家聲差易耳，便看奏最躡青雲。"]'),
('1f379f46-76ce-49f1-80ca-9645ceb155c9','別王恭叔','樓鑰','宋','宋诗','song-poetry','','[]','兩兒雖近隔江潮，頼有王郎慰寂寥。',64,'全唐诗/poet.song.158000.json','["兩兒雖近隔江潮，頼有王郎慰寂寥。", "遠侍雙親官道院，爲同盡室餞西橋。", "腦脂遮眼最關念，客路尋仙勿憚遥。", "別後飛緘問安否，數來谷口訪山樵。"]'),
('1c801063-87d0-404b-8ad2-4a02a68bbd24','別長女淯','樓鑰','宋','宋诗','song-poetry','','[]','老我年來百念輕，文姬助我以琴鳴。',64,'全唐诗/poet.song.158000.json','["老我年來百念輕，文姬助我以琴鳴。", "等閑相對成三弄，游戲俱彈似一聲。", "舉酒不堪千里別，登途知用幾程行。", "郡齋自是神仙窟，會有階庭玉樹生。"]'),
('71536972-865f-4965-aa9e-ac068c86d300','趙資政園梅篆','樓鑰','宋','宋诗','song-poetry','','[]','小徑回環里許長，寒梅森列間疎篁。',64,'全唐诗/poet.song.158000.json','["小徑回環里許長，寒梅森列間疎篁。", "路如古繭縈繆篆，身似輕煙繚印香。", "九折坂中經蜀險，八盤嶺上趁朝忙。", "歸來游戲通幽處，笑看危途九太行。"]'),
('26aae11c-5f26-44f7-92ea-c2082ec46504','示從子','樓鑰','宋','宋诗','song-poetry','','[]','東院敲棋西院琴，固知猶勝別勞心。',32,'全唐诗/poet.song.158000.json','["東院敲棋西院琴，固知猶勝別勞心。", "少年不比老癡叔，且向書窗惜寸陰。"]'),
('febef19b-1af7-46a4-a8ff-97b59f20133c','贈畫梅呂生','樓鑰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖處士賦疎影，未似希真好樂章。',32,'全唐诗/poet.song.158000.json','["西湖處士賦疎影，未似希真好樂章。", "豈是無情甘澹泊，受它風月幾凄涼。"]'),
('b701d28c-bcc7-4fe5-97bf-41016d076b32','潚自剡川寄水晶蒲萄','樓鑰','宋','宋诗','song-poetry','','[]','馬乳從他堆滿盤，未如清嚼水晶寒。',32,'全唐诗/poet.song.158000.json','["馬乳從他堆滿盤，未如清嚼水晶寒。", "固知一縣蒲萄熟，不用勞人數問安。"]'),
('584b495b-d759-4ece-a656-2d400d049ee0','送汪莊仲赴江東倉幕彊仲荆門簽判  其一','樓鑰','宋','宋诗','song-poetry','','[]','不見適齋老，于今三四秋。',48,'全唐诗/poet.song.158000.json','["不見適齋老，于今三四秋。", "弟兄登宦路，親黨駐行舟。", "老病無詩思，衰懷重別愁。", "外家門戶盛，勉力紹箕裘。"]'),
('7c2e9abb-2ef9-4630-b038-0aba30390f7f','送汪莊仲赴江東倉幕彊仲荆門簽判  其二','樓鑰','宋','宋诗','song-poetry','','[]','外氏蒙恩厚，文昌獨我知。',48,'全唐诗/poet.song.158000.json','["外氏蒙恩厚，文昌獨我知。", "居慙酷似舅，喜有寧馨兒。", "遇事行方便，褆身謹護持。", "公餘定多暇，黄卷有餘師。"]'),
('3c662ba7-3a0f-4403-9090-2631af743e5e','送汪莊仲赴江東倉幕彊仲荆門簽判  其三','樓鑰','宋','宋诗','song-poetry','','[]','蚤歲過秋浦，貪程不入關。',48,'全唐诗/poet.song.158000.json','["蚤歲過秋浦，貪程不入關。", "君今參儉幕，時得上齊山。", "膚使資關決，賢侯伴宴閒。", "好音頻寄我，頼此一開顔。"]'),
('e571df7e-27ac-4919-ac58-6d1612472424','送汪莊仲赴江東倉幕彊仲荆門簽判  其四','樓鑰','宋','宋诗','song-poetry','','[]','之子游何許，平州更玉州。',48,'全唐诗/poet.song.158000.json','["之子游何許，平州更玉州。", "山川稱勝絕，幕府信風流。", "翠巘寒逾秀，金蓮夜不收。", "天涯念鄉國，少上仲宣樓。"]'),
('aa580875-5d48-4e46-811d-183757b06499','送汪莊仲赴江東倉幕彊仲荆門簽判  其五','樓鑰','宋','宋诗','song-poetry','','[]','見說荆門地，如門蔽楚荆。',48,'全唐诗/poet.song.158000.json','["見說荆門地，如門蔽楚荆。", "舊時爲內郡，今日號邊城。", "但守平平策，毋求赫赫名。", "勉哉關決際，從此振家聲。"]'),
('1b8f68b3-aaba-4430-973e-df8e92364245','送元積弟赴淮東總屬  其一','樓鑰','宋','宋诗','song-poetry','','[]','南徐來往飽經過，總餉賓寮入禮羅。',64,'全唐诗/poet.song.158000.json','["南徐來往飽經過，總餉賓寮入禮羅。", "子去幸陪鄒湛輩，君今還是伯休那。", "金閨通籍時方可，鐵甕名城景最多。", "我有浄名遺記在，試從萬井訪維摩。"]'),
('813d6d70-0b06-483d-8bc7-70ae66f4071b','送元積弟赴淮東總屬  其二','樓鑰','宋','宋诗','song-poetry','','[]','十人兄弟五人存，心事方欣得細論。',64,'全唐诗/poet.song.158000.json','["十人兄弟五人存，心事方欣得細論。", "可但衰遲憐遠別，祇因喜懼有慈尊。", "倚門何止期吾子，發策還知望好孫。", "從此三年風雨夜，寂寥棋局與清樽。"]'),
('249c05a1-0a79-4069-acdf-17cbcb8bb84f','陳君舉既亡汪文子携其所作春秋後傳及送行詩來次韵','樓鑰','宋','宋诗','song-poetry','','[]','名盛望尤備，枝披實亦繁。',48,'全唐诗/poet.song.158000.json','["名盛望尤備，枝披實亦繁。", "無由究賢業，猶幸立斯言。", "書在經逾顯，人亡道更尊。", "九京如可作，與子共南轅。"]'),
('f1dfa073-c77b-438f-a985-6ca83b67aee5','送趙伯藏添倅永嘉  其一','樓鑰','宋','宋诗','song-poetry','','[]','當代槔閒老吏師，佳兒官業具而微。',64,'全唐诗/poet.song.158000.json','["當代槔閒老吏師，佳兒官業具而微。", "已煩潘令宰花縣，正要王祥康海沂。", "得助江山詩興逸，平分風月羽觴揮。", "安車何日迎清獻，又向堂前戲綵衣。"]'),
('c7740ccc-53d9-4011-8555-5623bfc85d68','送趙伯藏添倅永嘉  其二','樓鑰','宋','宋诗','song-poetry','','[]','分教分符恰五年，異鄉幾若故鄉然。',64,'全唐诗/poet.song.158000.json','["分教分符恰五年，異鄉幾若故鄉然。", "歸來幾作池塘夢，送別欲隨騶御僊。", "目斷甘林應飽熟，手栽欒實想芳鮮。", "邦人若問老州牧，爲說清霜繞鬢邊。"]'),
('b812a268-7d26-4967-bec0-fe1338a2a4cc','晝寢','樓鑰','宋','宋诗','song-poetry','','[]','彈徹悲風更廣陵，滄浪一爲濯塵纓。',32,'全唐诗/poet.song.158000.json','["彈徹悲風更廣陵，滄浪一爲濯塵纓。", "邯鄲枕上夢初覺，喜聽簷閒秋雨聲。"]'),
('995bb8d5-6fce-484f-b562-f45aca7a0d1b','喚仙閣  其一','樓鑰','宋','宋诗','song-poetry','','[]','上到危層莫喚仙，祇凭橫檻挹江天。',32,'全唐诗/poet.song.158000.json','["上到危層莫喚仙，祇凭橫檻挹江天。", "江天如許來借眼，何用征僑更偓佺。"]'),
('ce0b461f-45e2-49f5-8631-3d4a67d74b68','喚仙閣  其二','樓鑰','宋','宋诗','song-poetry','','[]','多少尋仙更不還，渺茫竟墮有無閒。',32,'全唐诗/poet.song.158000.json','["多少尋仙更不還，渺茫竟墮有無閒。", "使其真有毋庸喚，仙自曾城我自山。"]'),
('410ab4fa-2a05-4afc-a1f2-87ba0aa641ac','喚仙閣  其三','樓鑰','宋','宋诗','song-poetry','','[]','犯暑來登覽，松風爲灑然。',48,'全唐诗/poet.song.158000.json','["犯暑來登覽，松風爲灑然。", "龍泉澄古井，虹影卧中川。", "萬簇寒林秀，四山秋色鮮。", "詩翁不可見，況敢喚飛仙。"]'),
('88ac5458-8b1b-4314-aa00-f0b18a933b7b','送趙晦之丞彭澤  其一','樓鑰','宋','宋诗','song-poetry','','[]','淮甸歸來涉學深，孤雲又出亦何心。',32,'全唐诗/poet.song.158000.json','["淮甸歸來涉學深，孤雲又出亦何心。", "公餘巖下讀書去，遠繼風流石橘林。"]'),
('9f7c2a97-d06f-46b4-acfb-6b7750b80fdc','送趙晦之丞彭澤  其二','樓鑰','宋','宋诗','song-poetry','','[]','淵明事晉肯臣劉，仁傑忠良不附周。',32,'全唐诗/poet.song.158000.json','["淵明事晉肯臣劉，仁傑忠良不附周。", "見說三賢參羽士，盍將吳簿配蘋羞。"]'),
('fb6c4e45-9c69-4a32-af43-c1e64fe4780d','送趙晦之丞彭澤  其三','樓鑰','宋','宋诗','song-poetry','','[]','陶令居官八十日，始爲督郵方賦歸。',32,'全唐诗/poet.song.158000.json','["陶令居官八十日，始爲督郵方賦歸。", "君家門戶要興起，未用飄然詠式微。"]'),
('13b5dcac-20e7-4895-9d05-8c9736a5ea06','阿虞試晬戲作','樓鑰','宋','宋诗','song-poetry','','[]','阿虞匍匐晬盤中，事事都拏要學翁。',32,'全唐诗/poet.song.158000.json','["阿虞匍匐晬盤中，事事都拏要學翁。", "最是傳家清白處，不將雙手向頑銅。"]'),
('cf5a42e6-32ab-4ae7-9f76-e30056acb0b9','贈別盧甥申之歸吳門','樓鑰','宋','宋诗','song-poetry','','[]','千里何妨命駕來，晤言未厭已西馳。',64,'全唐诗/poet.song.158000.json','["千里何妨命駕來，晤言未厭已西馳。", "子休重賦瓊瑰贈，我亦懶歌親戚離。", "好向清江論樂府，更從葉子說新詩。", "樂閒引紙五十尺，爲篆離騷繼李斯。"]'),
('d0b1d7b7-dc10-4213-b18e-441da48b0e4e','又謝申之示詩卷','樓鑰','宋','宋诗','song-poetry','','[]','不見賢甥十一年，新詩示我百餘篇。',64,'全唐诗/poet.song.158000.json','["不見賢甥十一年，新詩示我百餘篇。", "古風已喜能行意，近體尤欣細屬聯。", "宅相真成珠在側，冷官休歎坐無氈。", "作詩勿謂今餘事，更下工夫繼玉川。"]'),
('934e1bc9-b717-4328-b46a-750db1cf0aa6','送秦仲防通判  其一','樓鑰','宋','宋诗','song-poetry','','[]','清德曾瞻啟慶碑，孫曾清更畏人知。',64,'全唐诗/poet.song.158000.json','["清德曾瞻啟慶碑，孫曾清更畏人知。", "祇緣一介弗輕取，坐使斯民不忍欺。", "瀨水家傳御書卦，宣城手寫送行詩。", "典刑尚繼金鑾舊，馬氏一門誰白眉。"]'),
('57a14e24-7f88-4cc9-b3d2-579ced08b91a','送秦仲防通判  其二','樓鑰','宋','宋诗','song-poetry','','[]','題輿再到海東涯，嗜學深於入幕時。',64,'全唐诗/poet.song.158000.json','["題輿再到海東涯，嗜學深於入幕時。", "一字未通終不置，五行俱下尚嫌遲。", "情親端有卜鄰意，別後空勞望月思。", "老我無因可重見，祝君來此擁旌麾。"]'),
('65da5c20-b915-4703-a36a-6be25d729ba1','謝剡中沈元龍惠詩','樓鑰','宋','宋诗','song-poetry','','[]','東陽何事到東州，百語曾無一語酬。',64,'全唐诗/poet.song.158000.json','["東陽何事到東州，百語曾無一語酬。", "深羨松筠無改葉，自言蒲柳已先秋。", "千金既覺成虛擲，雙璧還驚又暗投。", "別後未知何日見，但將吾道付滄洲。"]'),
('585a1b21-8922-461a-80de-1385f41d0818','謝舒景叔寫照見贈','樓鑰','宋','宋诗','song-poetry','','[]','誰寫衰容入畫圖，本來面目舊形模。',32,'全唐诗/poet.song.158000.json','["誰寫衰容入畫圖，本來面目舊形模。", "幾年老瘦鬢如雪，不道今吾非故吾。"]'),
('eac4dbee-52ff-422d-ab28-47eb4e8251e1','庭前一蓮著花','樓鑰','宋','宋诗','song-poetry','','[]','門外荷蓮浥露華，綠雲平地擁秋霞。',32,'全唐诗/poet.song.158000.json','["門外荷蓮浥露華，綠雲平地擁秋霞。", "病夫不能出門去，且看庭前第一花。"]'),
('8c073417-f9cc-46d0-8480-230a8e4b1e79','淯月下鼓琴用淳韵','樓鑰','宋','宋诗','song-poetry','','[]','老穉團欒鯉在庭，文姬爲鼓玉琴聲。',32,'全唐诗/poet.song.158000.json','["老穉團欒鯉在庭，文姬爲鼓玉琴聲。", "起來同作悲風曲，倍覺先秋月影清。"]'),
('5ef5bdfe-c5f6-46c5-89aa-56a3e2a1ec56','國仲觀遷居尹隩訪別','樓鑰','宋','宋诗','song-poetry','','[]','晚年來定一枝巢，到處蓋頭無把茅。',64,'全唐诗/poet.song.158000.json','["晚年來定一枝巢，到處蓋頭無把茅。", "又欲浮家過尹隩，何殊樂道向莘郊。", "君今去此難招隠，老更從誰可定交。", "見說衡門臨野水，秋深容我去推敲。"]'),
('732e8729-0bcc-4eca-b424-3ff7c97f39bf','仲觀有詩來謝次韵','樓鑰','宋','宋诗','song-poetry','','[]','危機屢見劍頭炊，喜及挂冠神武時。',64,'全唐诗/poet.song.158000.json','["危機屢見劍頭炊，喜及挂冠神武時。", "從此含藏三寸舌，算來插得幾張匙。", "讀書窗下病勤舊，攻媿庵中老住持。", "速辦小舟頻往反，及今精力未全衰。"]'),
('ee41eee0-0d32-4c78-b468-35ab71c6de2d','謝王粹中惠白鶴山麟川觀斑竹杖并竹輿','樓鑰','宋','宋诗','song-poetry','','[]','麟川僊館翠琅玕，荷子携來白鶴山。',64,'全唐诗/poet.song.158000.json','["麟川僊館翠琅玕，荷子携來白鶴山。", "未效葛陂龍種化，絕勝湘浦淚痕斑。", "裁爲拄杖一尋許，巧作輕輿四尺慳。", "兒子門生俱努力，病夫欲過虎谿還。"]'),
('3a6049ef-b3e7-4264-a86a-b58225df0ce2','曾無逸郎中名燕居曰和三續社有詩次韵','樓鑰','宋','宋诗','song-poetry','','[]','通地通天祇箇中，千岐雖別大都同。',64,'全唐诗/poet.song.158000.json','["通地通天祇箇中，千岐雖別大都同。", "兩家偶爾流傳盛，一貫臨之內外融。", "欲境掃開心在我，浮雲散盡月當空。", "感而通者從來話，不感須知自有通。"]'),
('232b0473-751a-4de7-9fa7-48b2c968ce77','老來','樓鑰','宋','宋诗','song-poetry','','[]','老來何以度光陰，祇有圍棋與鼓琴。',64,'全唐诗/poet.song.158000.json','["老來何以度光陰，祇有圍棋與鼓琴。", "棋爲心勞疎對局，琴因臂弱倦調音。", "曲肱時復同尼父，面壁何妨學少林。", "氣習未除祇自笑，又還弄筆動微吟。"]'),
('e65ae9bd-9003-470f-8ce1-7fde9b29c409','長生草','樓鑰','宋','宋诗','song-poetry','','[]','玻璃擢葉玉蟠根，千里提携寄海濱。',64,'全唐诗/poet.song.158000.json','["玻璃擢葉玉蟠根，千里提携寄海濱。", "雨澤不霑仍自潤，土膏無著自長春。", "歲寒秀色鎮依舊，日暖素英能一新。", "我欲餌之求久視，恐君靈己不靈人。"]'),
('ef9288e7-8261-4a10-9043-7674b35c0290','謝黄汝濟教授惠建茶并惠山泉','樓鑰','宋','宋诗','song-poetry','','[]','幾年不泛浙西船，每憶林間訪惠泉。',64,'全唐诗/poet.song.158000.json','["幾年不泛浙西船，每憶林間訪惠泉。", "雅好誰如廣文老，親携直到病夫前。", "細傾瓊液清如舊，更瀹雲芽味始全。", "或問此爲真品否，其中自有石如拳。"]'),
('c5515b09-b7e2-4141-89ff-cfc3940e7587','史子仁碧沚  其一','樓鑰','宋','宋诗','song-poetry','','[]','相家小有四明山，更葺桃源渺莽間。',32,'全唐诗/poet.song.158000.json','["相家小有四明山，更葺桃源渺莽間。", "四面樓臺相映發，一川煙水自彎環。"]'),
('50990a4d-dcf8-422a-8168-833645ea5d9d','史子仁碧沚  其二','樓鑰','宋','宋诗','song-poetry','','[]','中川累石勢嵯峩，城上遥岑聳翠螺。',32,'全唐诗/poet.song.158000.json','["中川累石勢嵯峩，城上遥岑聳翠螺。", "舊說夕陽無限好，此中最得夕陽多。"]'),
('8399129b-60d2-496b-99a9-7f9dd549def2','題趙睎遠二畫  其一','樓鑰','宋','宋诗','song-poetry','','[]','藻翻數尾已如生，妙絕魚兒作隊行。',32,'全唐诗/poet.song.158000.json','["藻翻數尾已如生，妙絕魚兒作隊行。", "不是深知濠上趣，未應筆底得縱橫。"]'),
('27adc441-a57d-4d44-8065-7dcb57aa02b6','題趙睎遠二畫  其二','樓鑰','宋','宋诗','song-poetry','','[]','窗前驚見一枝斜，照眼英英十數花。',32,'全唐诗/poet.song.158000.json','["窗前驚見一枝斜，照眼英英十數花。", "千載簡齋僊去後，何人更著好詩誇。"]'),
('fc70fa77-ef2e-41d3-bce6-f6147d9dca97','送陳表道倅岳陽  其一','樓鑰','宋','宋诗','song-poetry','','[]','垂上青雲去，如何乘貳車。',48,'全唐诗/poet.song.158000.json','["垂上青雲去，如何乘貳車。", "輕爲千里別，時寄幾行書。", "剸劇才無滯，傳家學有餘。", "當塗足知己，應不費吹噓。"]'),
('1996483c-4783-4d3e-9793-5f51044d5c18','送陳表道倅岳陽  其二','樓鑰','宋','宋诗','song-poetry','','[]','聞說巴陵好，樓高占古城。',48,'全唐诗/poet.song.158000.json','["聞說巴陵好，樓高占古城。", "湖光千頃白，山色一螺明。", "赤壁沈沙戟，蒼煙老樹精。", "好詩收拾取，寄我慰離情。"]'),
('d51e8361-7e2e-40d8-b685-31c904745001','元珍弟酌別賦此贈之','樓鑰','宋','宋诗','song-poetry','','[]','歸來十暑又三霜，衰病那知謁帝傍。',64,'全唐诗/poet.song.158000.json','["歸來十暑又三霜，衰病那知謁帝傍。", "採菊初期老陶令，種桃應是笑劉郎。", "不辭白首登鰲禁，正欲青衫及鴈行。", "今夕團欒同醉後，未知何日駕歸航。"]'),
('4bb225ad-39ac-4ee2-ad35-093a866aa987','靈芝寺','樓鑰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','送客靈芝寺，恁闌山有無。',48,'全唐诗/poet.song.158000.json','["送客靈芝寺，恁闌山有無。", "自從朝北闕，始得見西湖。", "煙外移輕槳，波間浴野鳬。", "清寒不可駐，回首又神都。"]'),
('9b7b23d5-729e-416f-a48f-4aac12d3d759','閭丘醫視脈曰老人之脈如小春有感','樓鑰','宋','宋诗','song-poetry','','[]','老去光陰似小春，如何比得少年人。',32,'全唐诗/poet.song.158000.json','["老去光陰似小春，如何比得少年人。", "君看桃李秋風後，縱有花開不是真。"]'),
('93081d4e-d109-4b10-8d44-ab8553a62192','貢闈對硯盤發歎','樓鑰','宋','宋诗','song-poetry','','[]','老去未忘黄與朱，琢成三硯樂閒居。',64,'全唐诗/poet.song.158000.json','["老去未忘黄與朱，琢成三硯樂閒居。", "豈能更作諸生業，但欲頻看後世書。", "視草北門才已盡，持衡南省計尤疎。", "便須再挂衣冠去，約汝同歸故草廬。"]'),
('f09c5e62-8a8c-4589-8d8c-08dca7cb881b','次韵李孟達使君與林雪巢子季武詩','樓鑰','宋','宋诗','song-poetry','','[]','古梅巨石瞰清池，觴詠曾陪老啟期。',64,'全唐诗/poet.song.158000.json','["古梅巨石瞰清池，觴詠曾陪老啟期。", "別我遂成千古恨，傳家空有一編詩。", "使君尚爾悲陳迹，處士惜非同此時。", "若使南樓與清賞，胡床應奉庾元規。"]'),
('c5646565-1ffd-4142-9f0e-f50cc2a9265d','玉堂早起','樓鑰','宋','宋诗','song-poetry','','[]','早起多奔走，旬休亦往還。',48,'全唐诗/poet.song.158000.json','["早起多奔走，旬休亦往還。", "偶因二士試，始得一朝閒。", "靈鵲花枝上，金魚荇蔕間。", "素餐終有媿，只憶舊家山。"]'),
('d8412752-d1bb-4037-803a-357f2fd504e9','贈徐松','樓鑰','宋','宋诗','song-poetry','','[]','我爲浮名媿引年，老餘八十尚飄然。',32,'全唐诗/poet.song.158000.json','["我爲浮名媿引年，老餘八十尚飄然。", "不如合却談天口，歸向白雲深處眠。"]'),
('75e8bb69-4921-4bd5-8f6c-78271cb3e675','經筵講詩徹章進詩','樓鑰','宋','宋诗','song-poetry','','[]','聖主承丕祚，于今歲幾遷。',288,'全唐诗/poet.song.158000.json','["聖主承丕祚，于今歲幾遷。", "昭回光飾物，剛健位乘乾。", "善治新更化，當陽獨攬權。", "誅鉏及共鯀，擢任列閎顛。", "曩日方謀始，宸心最急先。", "未遑親政理，首務闢經筵。", "恭儉甘卑室，尊嚴拱細旃。", "晝居勤已甚，坐侍禮無前。", "講徹詩三百，時逢運半千。", "諸儒深誦說，六義極摩研。", "俯閲毛公傳，旁參鄭氏箋。", "慨尋中古意，重是素王編。", "舊本三千首，終存十二篇。", "雖遭煨燼厄，所頼詠歌全。", "開迹因農事，安民在井田。", "成功時邁酌，興業大明綿。", "東國思平賦，南山樂得賢。", "艱難由后稷，勞來美周宣。", "起自紹熙載，迨茲嘉定年。", "關雎從肇彼，殷武遂終焉。", "寵數傳中旨，恩光被邇聯。", "神文期繼踵，元祐信齊肩。", "內廄頒雲騎，雕鞍絢錦韉。", "茗分龍焙品，香拂御爐煙。"]'),
('464f2b8f-7810-43e4-bce9-4d352ebb401f','題天竺珪老復菴','樓鑰','宋','宋诗','song-poetry','','[]','路從天竺更微南，衲子邀余過復菴。',64,'全唐诗/poet.song.158000.json','["路從天竺更微南，衲子邀余過復菴。", "八法照人瞻睿藻，一峰當戶擁晴嵐。", "奇爻初動玩羲畫，萬物竝觀師老聃。", "六用不成均此理，楞嚴容我爲同參。"]'),
('254796f2-8e16-4646-9fe4-c9553288e615','爲倪正父尚書題壯懷堂扁以詩來謝次韵','樓鑰','宋','宋诗','song-poetry','','[]','久矣君宜任弼諧，果隨召馹上天階。',64,'全唐诗/poet.song.158000.json','["久矣君宜任弼諧，果隨召馹上天階。", "幾年不作相逢夢，一日俄傾積別懷。", "情厚夫君幾鮑叔，愚如老我類高柴。", "它時戶冊高懸後，直欲扁舟訪水涯。"]'),
('04e48d03-832d-4895-803a-6354830be407','送趙德老觀文東歸  其一','樓鑰','宋','宋诗','song-poetry','','[]','趣還宗老侍經筵，宿望訏謨信巋然。',64,'全唐诗/poet.song.158000.json','["趣還宗老侍經筵，宿望訏謨信巋然。", "引疾屢煩頒漢制，賦歸先已買吳船。", "去年趨召叨同傳，今日求閑媿著鞭。", "未得相隨出關去，羨公徒御若登僊。"]'),
('f6f7e623-1a9a-4d4b-8460-307036b9bc7b','送趙德老觀文東歸  其二','樓鑰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','往還不過酒三行，成敗同觀棋一枰。',64,'全唐诗/poet.song.158000.json','["往還不過酒三行，成敗同觀棋一枰。", "東海敢言成二老，西湖自足度餘生。", "朅來便覺廢茲事，歸去定須尋舊盟。", "錦里錦坊秋色裏，夢魂先已到江城。"]'),
('0c93cf1a-06e5-4989-ab7b-0c586068d89b','送倪正父尚書守南徐  其一','樓鑰','宋','宋诗','song-poetry','','[]','君如春柳我如松，晚歲重逢意愈通。',64,'全唐诗/poet.song.158000.json','["君如春柳我如松，晚歲重逢意愈通。", "日日公餘搜理窟，時時史暇樂談叢。", "友朋罕有心相照，兄弟惟應姓不同。", "此別未知何日見，摻袪無語對西風。"]'),
('108e37bb-4e04-4443-8572-aed5555a985c','送倪正父尚書守南徐  其二','樓鑰','宋','宋诗','song-poetry','','[]','滿腔忠膜與嘉謨，空洞它無一物餘。',64,'全唐诗/poet.song.158000.json','["滿腔忠膜與嘉謨，空洞它無一物餘。", "有語莫非憂國志，欲行猶上薦賢書。", "已欣勇退成清節，更喜高眠即故廬。", "廊廟須公經濟手，不應歛惠向南徐。"]'),
('79ed758c-0352-4224-8e59-77690b792867','送倪正父尚書守南徐  其三','樓鑰','宋','宋诗','song-poetry','','[]','幾回去國向吳興，出處雖高事不平。',64,'全唐诗/poet.song.158000.json','["幾回去國向吳興，出處雖高事不平。", "茲以優恩臨北固，不妨禁直寓西清。", "羨君決去行何速，媿我求歸計未成。", "淛水東西又千里，壯懷堂上未忘情。"]'),
('0f98d34a-20d0-486b-ab28-d20366434483','戲題十四絃','樓鑰','宋','宋诗','song-poetry','','[]','十四朱弦欲動時，泛商流羽看瑶姬。',64,'全唐诗/poet.song.158000.json','["十四朱弦欲動時，泛商流羽看瑶姬。", "弦疎不隔如花面，聲急還同墮馬兒。", "谿蟹霜餘縈密網，簷蛛雨後理輕絲。", "曲終勸客杯無算，一吐空喉醉不知。"]'),
('06383561-cb98-4d94-bfab-d14458896361','樞密新府  其一','樓鑰','宋','宋诗','song-poetry','','[]','平生苦欲住山間，每恨家居不傍山。',64,'全唐诗/poet.song.158000.json','["平生苦欲住山間，每恨家居不傍山。", "游倦忽來參宥密，公餘却得對孱顔。", "援琴萬壑自同響，緩步一丘猶可攀。", "信美終非吾久處，乞身惟待老鄉關。"]'),
('076143ff-7d8f-40b7-8272-f42ffdd93052','樞密新府  其二','樓鑰','宋','宋诗','song-poetry','','[]','門號簽書府，心存攻媿齋。',48,'全唐诗/poet.song.158000.json','["門號簽書府，心存攻媿齋。", "倚欄臨曲沼，扶杖看懸崖。", "槁葉鳴輕雨，殘山擁半階。", "退公成吏隠，足以暢幽懷。"]'),
('522d190e-957b-4648-8dba-44dedaa44380','大雪趙振文寄詩言乘月泛舟清甚次韵  其一','樓鑰','宋','宋诗','song-poetry','','[]','老我心知筆力衰，頗欣臘雪瑞清時。',32,'全唐诗/poet.song.158000.json','["老我心知筆力衰，頗欣臘雪瑞清時。", "三茅奇觀亦難遇，白玉峰頭燈萬枝。"]'),
('d29061e4-97d3-48b1-bec2-faa53b09aa79','大雪趙振文寄詩言乘月泛舟清甚次韵  其二','樓鑰','宋','宋诗','song-poetry','','[]','萬玉真妃摇佩琚，梁園授簡屬相如。',32,'全唐诗/poet.song.158000.json','["萬玉真妃摇佩琚，梁園授簡屬相如。", "莫嫌一水限吳越，兩岸交輝合太虛。"]'),
('5623f93f-7f6a-4f14-bb17-c8ead5cc397a','大雪趙振文寄詩言乘月泛舟清甚次韵  其三','樓鑰','宋','宋诗','song-poetry','','[]','雪光絕勝水銀銀，未覺僊家隔一塵。',32,'全唐诗/poet.song.158000.json','["雪光絕勝水銀銀，未覺僊家隔一塵。", "真境宜君著佳句，賞心樂事更良辰。"]'),
('49796104-6b1c-4657-8c0d-b626cdd1e5da','大雪趙振文寄詩言乘月泛舟清甚次韵  其四','樓鑰','宋','宋诗','song-poetry','','[]','見說中宵泛綵舟，何人同賞大江流。',32,'全唐诗/poet.song.158000.json','["見說中宵泛綵舟，何人同賞大江流。", "陽冰伯雪應爲伴，更約禪人白道猷。"]'),
('038bad3b-9571-4ced-bb66-9f89422a069b','大雪趙振文寄詩言乘月泛舟清甚次韵  其五','樓鑰','宋','宋诗','song-poetry','','[]','舊聞老具擅詩聲，夜泛錢塘向鳳城。',32,'全唐诗/poet.song.158000.json','["舊聞老具擅詩聲，夜泛錢塘向鳳城。", "今日清游更豪逸，雪花和月带潮生。"]'),
('e19b5c8b-d15e-41e3-b3c8-35ad3765ae66','酒邊戲作','樓鑰','宋','宋诗','song-poetry','','[]','未年六十已言歸，七十重來自覺癡。',32,'全唐诗/poet.song.158000.json','["未年六十已言歸，七十重來自覺癡。", "未報君恩歸未許，樽前羞聽摸魚兒。"]'),
('f4423046-7403-4d00-861b-5344f6bdc65b','葉處士畫貂蟬喜神見惠','樓鑰','宋','宋诗','song-poetry','','[]','重煩妙手費丹鉛，貌出衰容信宛然。',32,'全唐诗/poet.song.158000.json','["重煩妙手費丹鉛，貌出衰容信宛然。", "君看頭顱已如許，豈堪頭上著貂蟬。"]'),
('62fe1dbb-4ebf-4686-a012-dbe98e756087','頃游龍井得一聯王伯齊同兒輩游因足成之','樓鑰','宋','宋诗','song-poetry','','[]','路入風篁上翠微，老龍蟠井四山圍。',64,'全唐诗/poet.song.158000.json','["路入風篁上翠微，老龍蟠井四山圍。", "水真綠浄不可唾，魚若空行無所依。", "勝處雖多終莫及，舊游誰在事皆非。", "祇今匏繫何由到，徒羨聯鑣带月歸。"]'),
('39bb6b50-d0d1-4525-baca-612e233a3f40','海潮圖','樓鑰','宋','宋诗','song-poetry','','[]','錢塘佳月照青霄，壯觀仍看半夜潮。',64,'全唐诗/poet.song.158000.json','["錢塘佳月照青霄，壯觀仍看半夜潮。", "每恨形容無健筆，誰知收拾在生綃。", "蕩摇直恐三山沒，咫尺真成萬里遥。", "金闕岧嶤天尺五，海王自合日來朝。"]'),
('11466af6-fe16-45c5-a085-af79cbfa8af2','題施武子所藏醉白堂記','樓鑰','宋','宋诗','song-poetry','','[]','堂名醉白尚存不，詞翰輝光射兩眸。',64,'全唐诗/poet.song.158000.json','["堂名醉白尚存不，詞翰輝光射兩眸。", "天下曾除蘇氏學，禁中却有太清樓。", "舊碑於世已難見，真蹟惟君乃得收。", "感歎不堪衰淚落，林慮山下水空流。"]'),
('b6fed76f-8777-4145-a503-35dae408b354','謝雷季仲樞密惠社餠','樓鑰','宋','宋诗','song-poetry','','[]','寵分餠卷荷深情，割肉烹鮮不厭精。',64,'全唐诗/poet.song.158000.json','["寵分餠卷荷深情，割肉烹鮮不厭精。", "潭府始知嚴社祭，衰門又得詫侯鯖。", "洗杯用薦逡巡酒，下箸如餐谷董羹。", "回首枌榆未能去，欲隨秋燕問歸程。"]'),
('00e478ed-bb64-46e7-ac6d-a4721bcf2c67','婁彥發參政壽詩','樓鑰','宋','宋诗','song-poetry','','[]','青宮冊寶盛朝章，玉佩珠旒照日光。',96,'全唐诗/poet.song.158000.json','["青宮冊寶盛朝章，玉佩珠旒照日光。", "儲寀久資三善得，生朝相去半旬强。", "五千餘卷學尤富，一百省年身更康。", "都省先曾同舉酒，貢闈最喜又傳觴。", "易逢皓齒令歌曲，難值嚴更聽警場。", "慶事鼎來真可卜，祝公黄髮相虞唐。"]'),
('5514fa27-0944-482c-b598-034840efa7e3','題孫谷橋墦間圖  其一','樓鑰','宋','宋诗','song-poetry','','[]','墦間不足又之他，猶自施施驕室家。',32,'全唐诗/poet.song.158000.json','["墦間不足又之他，猶自施施驕室家。", "齊國一人如許爾，寧知後日事如麻。"]'),
('6fce46fe-b1b3-4636-bf49-98866cb0e456','題孫谷橋墦間圖  其二','樓鑰','宋','宋诗','song-poetry','','[]','因知義利本殊途，莫笑墦間乞祭徒。',32,'全唐诗/poet.song.158000.json','["因知義利本殊途，莫笑墦間乞祭徒。", "正使往來多顯者，此中尤要著工夫。"]'),
('5123ec31-8906-4b71-bfc9-919c61431978','肆赦小雨','樓鑰','宋','宋诗','song-poetry','','[]','端門宣赦樂歡然，膏澤還應降九天。',64,'全唐诗/poet.song.158000.json','["端門宣赦樂歡然，膏澤還應降九天。", "始覺耳邊鳴摵摵，漸看笏上溜涓涓。", "我班金闕雞竿側，君侍玉皇香案前。", "雨立固知同陛楯，一言猶幸頼優旃。"]'),
('154a33e8-03e0-4c26-bb5a-dec764500fa9','題桃源王少卿占山亭','樓鑰','宋','宋诗','song-poetry','','[]','納納乾坤一草亭，西山盡見若秋屏。',64,'全唐诗/poet.song.158000.json','["納納乾坤一草亭，西山盡見若秋屏。", "霜餘遠水呈天碧，雨過遥空現帝青。", "逸叟真成陶令隠，高懷長似屈原醒。", "肯堂固頼賢孫子，精爽猶疑尚有靈。"]'),
('c7a168e0-7da8-4bc9-a168-fbd851292cf7','題汪季路侍郎所藏吳道子天龍八部','樓鑰','宋','宋诗','song-poetry','','[]','妙絕天龍八部圖，細看真不失錙銖。',64,'全唐诗/poet.song.158000.json','["妙絕天龍八部圖，細看真不失錙銖。", "聲名自足高千古，題品尤難遇二蘇。", "旌旆冕旒猶可想，鬼神人物亦何殊。", "君看坐位蘭亭草，費盡工夫學得無。"]'),
('a4aa72e0-b20d-4924-bfd2-135752a9f3cd','謝顔樂閒篆離騷','樓鑰','宋','宋诗','song-poetry','','[]','樂閒下筆素推高，攻媿耽書老更饕。',64,'全唐诗/poet.song.158000.json','["樂閒下筆素推高，攻媿耽書老更饕。", "顧我好看秦小篆，煩君爲作楚離騷。", "晚年應悟成竵匾，痛飲猶堪寫鬰陶。", "喜劇但知藏十襲，瓊瑶無以報投桃。"]'),
('079e84c5-5bf6-49e8-b6f2-891f90ac1722','題徐聖可知縣所藏楊補之二畫  其一','樓鑰','宋','宋诗','song-poetry','','[]','誰種疎梅古岸頭，推蓬瞥見倍清幽。',32,'全唐诗/poet.song.158000.json','["誰種疎梅古岸頭，推蓬瞥見倍清幽。", "君看竹外一枝好，真有江南萬斛愁。"]'),
('53af9ea5-cf6f-47b6-bfd7-5c7fdd8ef913','題徐聖可知縣所藏楊補之二畫  其二','樓鑰','宋','宋诗','song-poetry','','[]','梅花屢見筆如神，松竹寧知更逼真。',32,'全唐诗/poet.song.158000.json','["梅花屢見筆如神，松竹寧知更逼真。", "百卉千華皆面友，歲寒祇見此三人。"]'),
('4df95f80-3851-44b4-9a69-d2e4e281322b','嵩嶽圖','樓鑰','宋','宋诗','song-poetry','','[]','先世前蹤不可追，君從何處得全碑。',64,'全唐诗/poet.song.158000.json','["先世前蹤不可追，君從何處得全碑。", "上橫嵩岳三千丈，下列齊公廿四詩。", "室號揖僊懷舊事，菴名面壁認遺基。", "青氈真是我家物，欲以瓊瑶厚報之。"]'),
('5aaf208e-fc58-4c9e-a8a8-b44e9d555392','寫照葉處士求僧','樓鑰','宋','宋诗','song-poetry','','[]','幾年依樣畫葫蘆，自作葫蘆學佛徒。',32,'全唐诗/poet.song.158000.json','["幾年依樣畫葫蘆，自作葫蘆學佛徒。", "一筆從今勾斷了，一瓶一鉢任江湖。"]'),
('28b5686e-49da-4a4f-b222-c61b5d6bd97b','元日','樓鑰','宋','宋诗','song-poetry','','[]','歲當庚午旦庚寅，最喜明朝遇上辛。',32,'全唐诗/poet.song.158000.json','["歲當庚午旦庚寅，最喜明朝遇上辛。", "五福來臨吳越分，更欣三日即攽春。"]'),
('26ef6329-367a-4f94-ac35-dad9381a8752','題郭恕先雪霽江行圖','樓鑰','宋','宋诗','song-poetry','','[]','妙絕丹青郭恕先，幻成雪霽大江船。',64,'全唐诗/poet.song.158000.json','["妙絕丹青郭恕先，幻成雪霽大江船。", "沿流更飽輕帆舉，上水仍勞百丈牽。", "捩柂長年渾欲動，褰帷佳客若將僊。", "侍親曾泛滄浪月，猶記蘭成射策年。"]'),
('3943d1a4-8eee-4d62-9418-191888cace9f','寄題江西劉氏勤有齋','樓鑰','宋','宋诗','song-poetry','','[]','樸斲敷菑皆用勤，況吾儒者務多聞。',64,'全唐诗/poet.song.158000.json','["樸斲敷菑皆用勤，況吾儒者務多聞。", "萬書插架非關我，一卷入心方屬君。", "爲學從來無止法，立身寧祇富多文。", "自憐習氣今猶在，尚欲焚膏到夜分。"]'),
('3350b3bd-c8ae-48f1-a12a-9105ca8c1f97','書葛氏詩卷','樓鑰','宋','宋诗','song-poetry','','[]','未年六十蚤休官，海角投閑儘自安。',64,'全唐诗/poet.song.158000.json','["未年六十蚤休官，海角投閑儘自安。", "一紀時容奉香火，七旬遂許掛衣冠。", "重來深媿妨賢路，此去終期保歲寒。", "三上封章歸未得，葛家詩卷却羞看。"]'),
('32ee52e6-6d61-4d2b-9017-b35125de7bec','殿上聞杜鵑','樓鑰','宋','宋诗','song-poetry','','[]','衰晚三年侍玉墀，高梧又擢鳳凰枝。',32,'全唐诗/poet.song.158000.json','["衰晚三年侍玉墀，高梧又擢鳳凰枝。", "封章屢上未容去，更向殿頭聞子規。"]'),
('6b14ddff-6be4-4ad6-b6dc-b8ac6280671e','王伯齊染髭','樓鑰','宋','宋诗','song-poetry','','[]','垂髫相見舜江濱，荏苒俄驚過五旬。',64,'全唐诗/poet.song.158000.json','["垂髫相見舜江濱，荏苒俄驚過五旬。", "顧我頹齡真似葉，訝君長鬣亦如銀。", "萬金安得神僊藥，一笑重回舊日春。", "縱使星星還復出，不妨時作少年人。"]'),
('b772960f-f68d-4662-8593-dc11dce60856','乞出過傳法聞伯齊歸姚江','樓鑰','宋','宋诗','song-poetry','','[]','扶病還朝一禿翁，重來寧免笑何公。',64,'全唐诗/poet.song.158000.json','["扶病還朝一禿翁，重來寧免笑何公。", "夢魂長是尋雲北，歸路何時向浙東。", "深願聳身隨畫鷁，空勞舉目送飛鴻。", "主人竹所終須到，最憶東軒一枕風。"]'),
('09a2aede-6775-4154-9c91-af02904907f0','行香聞杜鵑','樓鑰','宋','宋诗','song-poetry','','[]','牆西綠樹杜鵑聲，老我何堪側耳聽。',32,'全唐诗/poet.song.158000.json','["牆西綠樹杜鵑聲，老我何堪側耳聽。", "我自賦歸歸不得，不須苦語更丁寧。"]'),
('7b79adc3-46bb-4aa9-bf44-d1191c186b46','送蔣甥若水使屬北行','樓鑰','宋','宋诗','song-poetry','','[]','曾爲假吏到燕山，送子長征不作難。',64,'全唐诗/poet.song.158000.json','["曾爲假吏到燕山，送子長征不作難。", "故國能無歎禾黍，中原應欲覩衣冠。", "黑甜軟飽宜加愛，紅皺黄團止可觀。", "行矣勿爲兒女戀，指期良月待君還。"]'),
('30acd19e-d929-4f32-8dcc-7d1de8b2fc94','夜讀王承家縣丞詩編  其一','樓鑰','宋','宋诗','song-poetry','','[]','向來深夜快揮犀，不聽清談又許時。',32,'全唐诗/poet.song.158000.json','["向來深夜快揮犀，不聽清談又許時。", "浄洗昏眸急呼燭，爲君讀盡一編詩。"]'),
('80b22d1c-246d-4998-98f5-0d6b14a4f2bb','夜讀王承家縣丞詩編  其二','樓鑰','宋','宋诗','song-poetry','','[]','鍊句工深興味長，固知家學富青箱。',32,'全唐诗/poet.song.158000.json','["鍊句工深興味長，固知家學富青箱。", "莫言一臠能嘗鼎，更欲爲余傾錦囊。"]'),
('f96cf0a4-4813-4ff4-a020-f67ccd66f889','寒食','樓鑰','宋','宋诗','song-poetry','','[]','輔政無功日歉然，佳時攽賚屢傳宣。',64,'全唐诗/poet.song.158000.json','["輔政無功日歉然，佳時攽賚屢傳宣。", "已蒙授粲仍分茗，既荷貽牟更擊鮮。", "酒號流香盛寶榼，燭然新火散青煙。", "孫兒不識君恩重，但覓東宮則劇錢。"]'),
('03575f8c-d47f-416b-b54d-b065052bc988','夫人携家泛湖','樓鑰','宋','宋诗','song-poetry','','[]','三分春色二分休，始見魚軒泛綵舟。',64,'全唐诗/poet.song.159000.json','["三分春色二分休，始見魚軒泛綵舟。", "諸子侍行歡盡日，一翁獨坐淡於秋。", "滿斟美酒應同醉，是處名園爲少留。", "陰靄在前雷雨後，特晴此日稱君游。"]'),
('aa220ba0-e662-4af9-8ce1-d639111b31d7','即事','樓鑰','宋','宋诗','song-poetry','','[]','壯志摧頹貌亦衰，豈知官舍傍巖隈。',32,'全唐诗/poet.song.159000.json','["壯志摧頹貌亦衰，豈知官舍傍巖隈。", "此身不是京塵裏，飯了沿山看臘梅。"]'),
('f578c967-0c62-4338-950f-578f7a113a1d','劉寺即事  其一','樓鑰','宋','宋诗','song-poetry','','[]','不到茲山二十年，豈知重見舊山川。',32,'全唐诗/poet.song.159000.json','["不到茲山二十年，豈知重見舊山川。", "煙深雖不見湖水，且看長空萬里天。"]'),
('1690e88f-4256-4c80-b772-efb5b3996313','劉寺即事  其二','樓鑰','宋','宋诗','song-poetry','','[]','飛泉何事仰空流，無數明珠散不收。',32,'全唐诗/poet.song.159000.json','["飛泉何事仰空流，無數明珠散不收。", "注輦昔時曾撒殿，至今拋擲未曾休。"]'),
('6189ecbd-5b28-4d6d-8fbc-862f644e373d','淳發漕薦喜而成詩併勉杓','樓鑰','宋','宋诗','song-poetry','','[]','戊辰貢舉忝余知，曾礙孫兒到省闈。',64,'全唐诗/poet.song.159000.json','["戊辰貢舉忝余知，曾礙孫兒到省闈。", "欣汝今秋重預薦，喜吾即日可言歸。", "門闌有慶人爭賀，父子同登世所希。", "癡望十人俱上第，坐令晝錦倍光輝。"]'),
('72b32cfc-5e53-4cad-8008-88a287c995bf','十月旦尚煖用夾公服二月初吉雪寒甚服單','樓鑰','宋','宋诗','song-poetry','','[]','尚暖先添夾，方寒却用單。',48,'全唐诗/poet.song.159000.json','["尚暖先添夾，方寒却用單。", "不惟春料峭，况值雪飛翻。", "但欲朝儀肅，難求己分安。", "衣囊如欲懶，歸去老江干。"]'),
('a38ac3d5-131a-40bd-96d7-72bd6ffff78f','從子淮過省寄伯中弟','樓鑰','宋','宋诗','song-poetry','','[]','我家伯父德餘輝，吾弟風標具體微。',64,'全唐诗/poet.song.159000.json','["我家伯父德餘輝，吾弟風標具體微。", "七葉欣聞五爭奮，四人先喜一雄飛。", "忍貧老尚甘簞食，教子今方擢省闈。", "他日雙椿臨六桂，麻衣俱換綠衣歸。"]'),
('c7205773-1956-4c54-a1c0-d833520d5955','贈僧文可往黄州建東坡寺','樓鑰','宋','宋诗','song-poetry','','[]','一坡久矣郡城東，居士來游地望崇。',64,'全唐诗/poet.song.159000.json','["一坡久矣郡城東，居士來游地望崇。", "問舍求田煩作計，拈槌豎拂看談空。", "共分龐老沈江寶，要奉儋州禿鬢翁。", "去作開山第一代，燈燈相續到無窮。"]'),
('a267c4cc-8f36-493c-a79f-a5cd97d5f959','三月七日上賜牡丹并薔薇露勸酒','樓鑰','宋','宋诗','song-poetry','','[]','幾見牡丹東海涯，暮年敢謂到京華。',64,'全唐诗/poet.song.159000.json','["幾見牡丹東海涯，暮年敢謂到京華。", "休論千品洛中譜，驚看百枝天上花。", "况有八珍來禁苑，更加雙榼賜流霞。", "闔門飽暖聊同醉，稽首將何報宅家。"]'),
('86371c03-b64f-457d-b49d-6b611b4b5c7e','史清翁談詩走筆次韵','樓鑰','宋','宋诗','song-poetry','','[]','公退門庭靜，輕風輥絮毬。',48,'全唐诗/poet.song.159000.json','["公退門庭靜，輕風輥絮毬。", "故人驚一見，小酌散千憂。", "西上不容久，東歸又別愁。", "何當附舟尾，從此遂歸休。"]'),
('8dff7286-4a66-407a-8588-688a64c98d52','以興安石阮底寄顔樂閒','樓鑰','宋','宋诗','song-poetry','','[]','興安樂石響於桐，作阮猶堪繼仲容。',32,'全唐诗/poet.song.159000.json','["興安樂石響於桐，作阮猶堪繼仲容。", "茂苑樂閒真好事，爲君添起晉玲瓏。"]'),
('a6fcc5f7-4869-4c4c-b118-28ab9ff5a054','觀冷泉亭放水','樓鑰','宋','宋诗','song-poetry','','[]','冷泉淺濁使人愁，開板黄波去不休。',32,'全唐诗/poet.song.159000.json','["冷泉淺濁使人愁，開板黄波去不休。", "岸側細泉穿亂石，始知別是一清流。"]'),
('6b95552b-d156-4dc8-8a2c-27ade7ec160d','贈蜀二史','樓鑰','宋','宋诗','song-poetry','','[]','老我挂冠慙復彈，羨君登第遽休官。',64,'全唐诗/poet.song.159000.json','["老我挂冠慙復彈，羨君登第遽休官。", "幸哉有子事尤美，專以爲親人更難。", "舊說三賢皆特操，今看二士倍榮觀。", "同歸猶及襄陽老，一舸清風廿四灘。"]'),
('2d05e5a0-34af-4ebe-b0f4-5b7d09d0cf42','題汪季路尚書所藏米元暉蔣山出雲','樓鑰','宋','宋诗','song-poetry','','[]','龍盤往昔名鍾山，雲起從龍意自閑。',32,'全唐诗/poet.song.159000.json','["龍盤往昔名鍾山，雲起從龍意自閑。", "膚寸須臾成戴帽，坐看膏雨滿人間。"]'),
('d6bbecd5-9a9f-4ab8-88f8-ba8f09e2e260','九月十一日杓孫得男','樓鑰','宋','宋诗','song-poetry','','[]','郡齋弧矢記垂門，今日衰翁更覺尊。',64,'全唐诗/poet.song.159000.json','["郡齋弧矢記垂門，今日衰翁更覺尊。", "生晚不能瞻大父，年高却幸見曾孫。", "從今鏡鑷知無用，但喜芝蘭近愈繁。", "願汝孳孳守家法，爲傳衣鉢到仍昆。"]'),
('c9d74d0d-201c-4d0d-8e7d-93fc5b7dd33b','送叔韶弟宰華亭','樓鑰','宋','宋诗','song-poetry','','[]','試邑雲間事最多，直將心力細礲磨。',64,'全唐诗/poet.song.159000.json','["試邑雲間事最多，直將心力細礲磨。", "固知三泖五茸勝，其柰千瘡百孔何。", "敏手未須施霹靂，疲民正欲聽絃歌。", "規橅穩作三年計，徐上青雲鬢未皤。"]'),
('598b12ff-4c2c-4ba8-b020-830814db2e25','又示從子澶','樓鑰','宋','宋诗','song-poetry','','[]','壯縣人歌第一奇，過庭爲有寧馨兒。',64,'全唐诗/poet.song.159000.json','["壯縣人歌第一奇，過庭爲有寧馨兒。", "親旁色養宜加謹，戶外分豪勿預知。", "寓意杯觴須自節，讀書松竹有餘師。", "它時刮目相期待，連桂家風望一夔。"]'),
('93b3c085-d3f1-4435-b163-b794460610ee','寄叔韶弟','樓鑰','宋','宋诗','song-poetry','','[]','阿連試邑有成規，誰謂雲間不可爲。',64,'全唐诗/poet.song.159000.json','["阿連試邑有成規，誰謂雲間不可爲。", "能使鑊湯偏衮處，直如官府太平時。", "容容非欲後多福，赫赫何如去見思。", "子路當年曾請益，更須無倦以終之。"]'),
('0d125aed-fcfe-4ae8-a128-bf0e146a32fd','朝退','樓鑰','宋','宋诗','song-poetry','','[]','謝事不得去，趨朝愈更難。',48,'全唐诗/poet.song.159000.json','["謝事不得去，趨朝愈更難。", "誰憐八旬老，日冒五更寒。", "指凍怯持笏，腰酸强踞鞍。", "細思誰縛汝，只合挂衣冠。"]'),
('723893cb-ad6d-40f4-a622-b123abfc9fbf','劉德脩赴遂寧示和篇改除荆南復寄之','樓鑰','宋','宋诗','song-poetry','','[]','老矣思歸鋏屢彈，七旬望八合拋官。',64,'全唐诗/poet.song.159000.json','["老矣思歸鋏屢彈，七旬望八合拋官。", "我將東去計安出，君欲西還事亦難。", "好向渚宮尋故蹟，更從雄楚縱遐觀。", "上游正倚公爲重，莫向蓬谿更上灘。"]'),
('ce6eeba2-8e7a-4176-a352-9fb7740381c4','李起宗舍人悠然亭','樓鑰','宋','宋诗','song-poetry','','[]','遠游蜀道歷艱難，徑上甘泉豹尾間。',64,'全唐诗/poet.song.159000.json','["遠游蜀道歷艱難，徑上甘泉豹尾間。", "荷橐忽思辭北省，拂衣自喜見南山。", "當時旁舍基猶在，回首垂髫鬢已斑。", "先友碑陰盡陳迹，寒空依舊濕煙鬟。"]'),
('fc779aef-3386-449a-b4aa-2ab68c9efc29','伯中弟可休堂','樓鑰','宋','宋诗','song-poetry','','[]','夫婦老相對，閨門貧甚安。',48,'全唐诗/poet.song.159000.json','["夫婦老相對，閨門貧甚安。", "六兒俱力學，一子幸先官。", "香火祠初奉，勳名鏡屢看。", "更當聯五桂，納祿尚何難。"]'),
('57dadfc0-9896-4b50-95a9-0383d70502fe','海棠  其一','樓鑰','宋','宋诗','song-poetry','','[]','海棠昨日始萌芽，一夜驚雷發萬葩。',32,'全唐诗/poet.song.159000.json','["海棠昨日始萌芽，一夜驚雷發萬葩。", "老眼恍然何所得，凌雲菴外見桃花。"]'),
('7724dc07-72b1-4182-8395-79374d86d922','海棠  其二','樓鑰','宋','宋诗','song-poetry','','[]','海棠初發爲題詩，倏見輕紅萬點吹。',32,'全唐诗/poet.song.159000.json','["海棠初發爲題詩，倏見輕紅萬點吹。", "已惜落英鋪滿地，更憐幾片罥蛛絲。"]'),
('c1c7d52a-bfbc-4298-bd88-33ec1f254589','後圃','樓鑰','宋','宋诗','song-poetry','','[]','春雨才晴氣已和，暖風吹動百花窠。',32,'全唐诗/poet.song.159000.json','["春雨才晴氣已和，暖風吹動百花窠。", "絕憐玉屑如吾髮，綠者全稀白者多。"]'),
('f85f66cc-8cf3-4bae-8cd3-0fce21b2e95e','贈熊道人','樓鑰','宋','宋诗','song-poetry','','[]','十載隠潭衡，居然腑肺清。',48,'全唐诗/poet.song.159000.json','["十載隠潭衡，居然腑肺清。", "枯禪參懶瓚，老氣激彌明。", "筆底煙雲妙，人間勢利輕。", "款門俄告別，江海一浮萍。"]'),
('6f86e205-b9d9-4b49-a4b4-d902b1fd0d87','題汪季路尚書所藏米元暉湖山瑞雪圖','樓鑰','宋','宋诗','song-poetry','','[]','筆力誰能似虎兒，思陵親爲御珍題。',32,'全唐诗/poet.song.159000.json','["筆力誰能似虎兒，思陵親爲御珍題。", "小臣不識湖山好，但欲扁舟泛剡谿。"]'),
('f218d86f-ddd9-4666-8914-2322df517856','楊州瓊花','樓鑰','宋','宋诗','song-poetry','','[]','回憶靈根六十年，秋深恨不見芳鮮。',64,'全唐诗/poet.song.159000.json','["回憶靈根六十年，秋深恨不見芳鮮。", "茲從淮上來千里，非比人間聚八仙。", "曾有畫圖稱小異，諒應后土愛孤妍。", "或言天杖誠虛語，榮悴中分亦偶然。"]'),
('6d37a311-6fa5-47c6-a2a6-393c6e344eed','題林宗魯校書所藏宣和御畫','樓鑰','宋','宋诗','song-poetry','','[]','周公多藝孔多能，徽廟才高更倍增。',32,'全唐诗/poet.song.159000.json','["周公多藝孔多能，徽廟才高更倍增。", "除却萬機都不會，至今遺老話昭陵。"]'),
('d655ba6c-9637-41a3-a33c-24af6723208e','贈別章茂獻尚書','樓鑰','宋','宋诗','song-poetry','','[]','我輩重來鬢已皤，貞元朝士苦無多。',32,'全唐诗/poet.song.159000.json','["我輩重來鬢已皤，貞元朝士苦無多。", "才堪柱石猶歸去，柰此摧頹一老何。"]'),
('1761fb70-df69-40ac-ad98-6991a3037e49','戲詠戎葵簇成芍藥','樓鑰','宋','宋诗','song-poetry','','[]','回首向來婪尾春，橫風吹盡已成塵。',64,'全唐诗/poet.song.159000.json','["回首向來婪尾春，橫風吹盡已成塵。", "戎葵簇就誰嘗巧，紅藥當前太逼真。", "觀洧贈人迷冶子，翻階得句誤詞臣。", "園丁妙手有如許，猶勝隋園剪綵人。"]'),
('8589bb4a-bf8b-41b4-8214-71b342bb9a25','戲題膽瓶蕉','樓鑰','宋','宋诗','song-poetry','','[]','垂膽新甆出汝窯，滿中幾莢浸雲苗。',64,'全唐诗/poet.song.159000.json','["垂膽新甆出汝窯，滿中幾莢浸雲苗。", "瓶非貯水無由罄，葉解流根自不凋。", "露綴疑儲陶令粟，風摇欲響許由瓢。", "相携同到綠天下，別是閩山一種蕉。"]'),
('a9213541-1089-4a04-9943-60efa5aee1d9','午暑','樓鑰','宋','宋诗','song-poetry','','[]','炎官火傘罩中區，病老低垂氣不蘇。',32,'全唐诗/poet.song.159000.json','["炎官火傘罩中區，病老低垂氣不蘇。", "難學孫兒頻飲冷，時將冰水洗霜鬚。"]'),
('e16a16ca-0f37-44b2-9b64-4c294f5e7c06','省宿','樓鑰','宋','宋诗','song-poetry','','[]','樹滿茅山綠正肥，昏鴉日日向南歸。',32,'全唐诗/poet.song.159000.json','["樹滿茅山綠正肥，昏鴉日日向南歸。", "如今身在三茅外，却看歸鴉正北飛。"]'),
('437a843e-23ab-4e5f-a96d-04ac8fa1494b','水蕉','樓鑰','宋','宋诗','song-poetry','','[]','獵獵水芭蕉，如將隠士招。',24,'全唐诗/poet.song.159000.json','["獵獵水芭蕉，如將隠士招。", "清風來處遠，袢暑坐中消。"]'),
('e0a739e8-dda1-49e1-a487-8ee4915ec124','送楊晦叔提舉浙西并寄陳表道','樓鑰','宋','宋诗','song-poetry','','[]','兩兩郎星映使星，老人星彩對晶明。',64,'全唐诗/poet.song.159000.json','["兩兩郎星映使星，老人星彩對晶明。", "褰帷共喜行畿甸，洗印仍欣就帝城。", "五馬况當恩始拜，三吳從此政尤清。", "便看瑞慶來稱壽，同聽嵩呼萬歲聲。"]'),
('2412130e-2386-455c-b720-8df51d510051','八月四日晚霹靂碎大柳木','樓鑰','宋','宋诗','song-poetry','','[]','秋分雷自合收聲，白露明朝忽震霆。',32,'全唐诗/poet.song.159000.json','["秋分雷自合收聲，白露明朝忽震霆。", "怪得坐中驚欲倒，鄰牆老柳碎中庭。"]'),
('f715bd29-e1fa-414b-bc7a-4ba2d4a18423','靈光','樓鑰','宋','宋诗','song-poetry','','[]','魯邦宮殿久蕪荒，惟有靈光最久長。',32,'全唐诗/poet.song.159000.json','["魯邦宮殿久蕪荒，惟有靈光最久長。", "身似靈光終變滅，巋然別有一靈光。"]'),
('9103abad-dab9-4c42-88ea-ed6341576aa6','謝陸伯業通判示淮西小藁','樓鑰','宋','宋诗','song-poetry','','[]','四海詩名老放翁，遺編俱在迹成空。',64,'全唐诗/poet.song.159000.json','["四海詩名老放翁，遺編俱在迹成空。", "忽從淮右傳詩卷，近比劍南真父風。", "暫向壺頭追馬援，何當甫里訪龜蒙。", "江山爲助多佳句，莫惜南來寄斷鴻。"]'),
('794385e8-dc53-4028-a13c-4d5a1e8fef37','蕉菴清坐','樓鑰','宋','宋诗','song-poetry','','[]','薄晚歸來煙已蒼，蠻蕉一葉障斜陽。',32,'全唐诗/poet.song.159000.json','["薄晚歸來煙已蒼，蠻蕉一葉障斜陽。", "不須久住潭潭府，始覺山林興味長。"]'),
('181ddeff-b0f0-4c7d-b37d-92d46e95259d','蕉菴暮歸','樓鑰','宋','宋诗','song-poetry','','[]','綠蕉陰下遶斑衣，飯了從容到夕暉。',32,'全唐诗/poet.song.159000.json','["綠蕉陰下遶斑衣，飯了從容到夕暉。", "老子才携筇杖去，孫兒各捧竹團歸。"]'),
('82b7687c-1c9c-4ed5-b06e-aca745df1bbb','病告','樓鑰','宋','宋诗','song-poetry','','[]','閉戶垂簾儘自如，兀然終日擁紅爐。',32,'全唐诗/poet.song.159000.json','["閉戶垂簾儘自如，兀然終日擁紅爐。", "得歸足可優游老，此地何堪養病軀。"]'),
('196bce2c-0b2c-48db-9b52-e9255413ee48','殿上侍立寒甚','樓鑰','宋','宋诗','song-poetry','','[]','小雪以來霜氣清，今朝寒色倍嚴凝。',32,'全唐诗/poet.song.159000.json','["小雪以來霜氣清，今朝寒色倍嚴凝。", "榻前侍立無遮障，吹得半身真是冰。"]'),
('10c3c403-5c18-477d-acc6-cffdfd267b70','齒落戲作','樓鑰','宋','宋诗','song-poetry','','[]','零落殘牙齒，年來落欲空。',48,'全唐诗/poet.song.159000.json','["零落殘牙齒，年來落欲空。", "得魚惟食凍，捨肉只餐葱。", "休憶紅綾餤，難吞栗棘蓬。", "何須如劍樹，始解振宗風。"]'),
('1d47254f-0b6c-4ba4-9959-45689d557d3c','重陽淳生日時年四十九矣','樓鑰','宋','宋诗','song-poetry','','[]','汝生四十九年春，猶記雙親喜得孫。',64,'全唐诗/poet.song.159000.json','["汝生四十九年春，猶記雙親喜得孫。", "當慕知非過能寡，敢言學易道彌尊。", "喜吾父子爲知己，頼爾詩書遂滿門。", "但得團欒長似此，年年萸菊醉清樽。"]'),
('d208e334-4395-474f-abe1-878a70875aaf','范叔剛舍人示文正公象笏','樓鑰','宋','宋诗','song-poetry','','[]','千載威名文正公，忽瞻遺笏照雙瞳。',64,'全唐诗/poet.song.159000.json','["千載威名文正公，忽瞻遺笏照雙瞳。", "敢從象齒窺清裁，屢批龍鱗奮大忠。", "秉立定知端若植，至今猶想氣如虹。", "舍人接武登廊廟，宜寶甘棠振祖風。"]'),
('1ee3e380-9915-4ba9-86e2-c2bcfae018af','送黄真護道人住茅山贈以小黑玉虎','樓鑰','宋','宋诗','song-poetry','','[]','少從黑虎谷中行，晚得於菟玉琢成。',32,'全唐诗/poet.song.159000.json','["少從黑虎谷中行，晚得於菟玉琢成。", "輟以贈君俱隠處，大茅峰頂看風生。"]'),
('8567fa20-f873-4b4f-aca8-16fdcc463011','贈凌一源道人','樓鑰','宋','宋诗','song-poetry','','[]','知君曾住武當山，更解尋幽灊皖閒。',32,'全唐诗/poet.song.159000.json','["知君曾住武當山，更解尋幽灊皖閒。", "老矣無緣窮勝處，但思歸去卧鄉關。"]'),
('a66dc3ff-3b02-4d76-9707-edd830dfab54','謝滕宰彥可惠詩','樓鑰','宋','宋诗','song-poetry','','[]','與君相遇海東頭，明月如何忽暗投。',64,'全唐诗/poet.song.159000.json','["與君相遇海東頭，明月如何忽暗投。", "自媿重來千歲鶴，永懷靜對五湖鷗。", "新編不覺成三復，妙思誠堪比四愁。", "還肯來遊鄮山否，與君携手上東樓。"]'),
('7ef6d181-512b-4f08-bd4f-b3d8ffa11354','薌林雪中過峽圖','樓鑰','宋','宋诗','song-poetry','','[]','不土之里無言詩，泛雪清圖事已非。',32,'全唐诗/poet.song.159000.json','["不土之里無言詩，泛雪清圖事已非。", "墨隠爲君傳舊跡，宛然興起剡谿西。"]'),
('35ae7f24-f86f-4b49-a6a4-2ca4f3ca586b','賀監湖上  其一','樓鑰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','萬頃平湖一葦杭，此歸喜似賀知章。',32,'全唐诗/poet.song.159000.json','["萬頃平湖一葦杭，此歸喜似賀知章。", "上恩賜與西湖曲，遂老吾家歸照堂。"]'),
('bbbf98a1-a837-49b9-93d7-225dcfc71fbf','賀監湖上  其二','樓鑰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','狂客歸來終好夸，越王城下占烟霞。',32,'全唐诗/poet.song.159000.json','["狂客歸來終好夸，越王城下占烟霞。", "此中信美非吾土，不似西湖是我家。"]'),
('3713ab4d-b197-4a02-8d16-11a341e5b793','史文惠王挽詞','樓鑰','宋','宋诗','song-poetry','','[]','八行源流遠，三師慶系遥。',288,'全唐诗/poet.song.159000.json','["八行源流遠，三師慶系遥。", "樞庭先附鳳，相國薦簪貂。", "感會逢千載，榮華冠四朝。", "甘盤稱舊學，綺季簉儲寮。", "曆數終歸舜，羹牆欲見堯。", "聖圖滋廣大，孝治極光昭。", "善類茅連茹，英才楚刈翹。", "經綸任鈞軸，詢訪及芻蕘。", "未急宣攘狄，先求禹格苗。", "訏謨裨廟筭，長策御天驕。", "衮闕心勤補，羹和手自調。", "臨機杜如晦，處事李文饒。", "越俗懷恩紀，閩人服教條。", "羣公推治行，所至起民謠。", "晚歲車垂薛，皇慈第賜蕭。", "精鏐盃引壽，寶玉带橫腰。", "潭府輝宸翰，頻年走使軺。", "中書輸尚父，封戶溢票姚。", "教子躬師道，傳家作世標。", "紳緌成繼踵，鉛槧到垂髫。", "持論書還著，談經燭屢燒。", "官雖居鼎鼐，樂不改簞瓢。", "門外車長滿，樽前客載招。", "人間等游戲，物表自消摇。"]'),
('bb384730-b3f6-4329-af86-6db9b2624599','王敏肅公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','□□□□□，□□□□□。',48,'全唐诗/poet.song.159000.json','["□□□□□，□□□□□。", "□□□□□，□□□宣公。", "全蜀增天險，長淮折犬戎。", "經綸今已矣，貫日有餘忠。"]'),
('bb8e479b-cba0-4519-9f70-4cb00da224a3','王敏肅公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','賤子慙生晚，龍門莫問津。',48,'全唐诗/poet.song.159000.json','["賤子慙生晚，龍門莫問津。", "詞場沾賸腹，政地仰洪鈞。", "古栝杏壇舊，東嘉棠蔭新。", "九京無馥作，知己更何人。"]'),
('4c290f5e-12c2-47b4-8207-07f11fd940b9','樞密謝公  其一','樓鑰','宋','宋诗','song-poetry','','[]','臣主一意合，風雲平地生。',48,'全唐诗/poet.song.159000.json','["臣主一意合，風雲平地生。", "立朝專論諫，爲國總樞衡。", "行矣登三事，悲哉奠兩楹。", "輟瓜恩意重，終始備哀榮。"]'),
('0464a636-bbae-4edb-9a93-d9375f3aa120','樞密謝公  其二','樓鑰','宋','宋诗','song-poetry','','[]','千古台山秀，名流列鴈行。',48,'全唐诗/poet.song.159000.json','["千古台山秀，名流列鴈行。", "惟公登政路，一旦破天荒。", "故里空華屋，佳城映夕陽。", "送車無路到，東望淚浪浪。"]'),
('93e2af16-d73b-4c6c-9dc7-651af201ec27','觀文殿學士陳公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','台嶽鍾神秀，居然社稷臣。',48,'全唐诗/poet.song.159000.json','["台嶽鍾神秀，居然社稷臣。", "海涵書萬卷，魁冠數千人。", "南服頻懷綬，西垣屢演綸。", "惜哉真漢相，不遂秉洪鈞。"]'),
('ebcdc482-08e3-48aa-aa24-ff7a59404c5f','觀文殿學士陳公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','幾見衣冠偉，終聞羽翼成。',48,'全唐诗/poet.song.159000.json','["幾見衣冠偉，終聞羽翼成。", "先皇崇舊學，大政任名卿。", "神器親傳授，崇朝再太平。", "功成身自退，寵利一豪輕。"]'),
('a4cd7385-2349-4bca-ba66-933578341114','觀文殿學士陳公挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','朝著登門久，詞林辱眷深。',48,'全唐诗/poet.song.159000.json','["朝著登門久，詞林辱眷深。", "代言稱據古，議禮許同心。", "去國臨歸路，還家寄好音。", "病中聞赴告，老淚動盈襟。"]'),
('6c979bfd-4b53-4616-896a-54f6262607be','林正惠公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','愛直趙清獻，忠文范景仁。',48,'全唐诗/poet.song.159000.json','["愛直趙清獻，忠文范景仁。", "累朝推舊德，今日見斯人。", "正色欲劘上，敢言寧顧身。", "紫樞方大用，惜不究經綸。"]'),
('00e6b92e-d272-490d-b313-af1c48383a74','林正惠公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','去國名逾重，還朝道益尊。',48,'全唐诗/poet.song.159000.json','["去國名逾重，還朝道益尊。", "清虛懷骨骾，嚴冷带春溫。", "公綽真無慾，臧孫尚立言。", "騎箕雖永隔，精爽儼如存。"]'),
('c49d6075-dc99-4d88-a84e-9b5c0803a7e1','林正惠公挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','凜凜古循吏，堂堂真巨公。',48,'全唐诗/poet.song.159000.json','["凜凜古循吏，堂堂真巨公。", "死生忘度外，邪正烱胸中。", "憂世心誠切，籌邊事已空。", "龜潭山下水，流慶與無窮。"]'),
('7c447f82-a00e-4a2b-9e82-594a1e510a30','林正惠公挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','百辟素歸重，三朝俱受知。',48,'全唐诗/poet.song.159000.json','["百辟素歸重，三朝俱受知。", "風稜振臺省，名字落戎夷。", "召節叨同命，幾廷踵舊規。", "隧銘書不盡，歸泣峴山碑。"]'),
('c34f9c73-cfc7-4efd-8316-6b829652b7e0','丘文定公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','謀國規模闊，絕人才具高。',48,'全唐诗/poet.song.159000.json','["謀國規模闊，絕人才具高。", "三朝千載遇，四海一身勞。", "儒將通鴛序，樞庭握豹韜。", "皇家資柱石，天遽奪伊皋。"]'),
('9cd6eccf-c58a-41d6-a82b-f35e6ba18c82','丘文定公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','初擬文翁化，誰知懷遠圖。',48,'全唐诗/poet.song.159000.json','["初擬文翁化，誰知懷遠圖。", "廟謨專制閫，世將易兵符。", "養虎竟遺患，斷蛇由不殊。", "寧同死諸葛，空恨失吞吳。"]'),
('90c4e1c6-8be6-40e4-9110-3f3a99b51869','丘文定公挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','十載龐居士，一朝裴晉公。',48,'全唐诗/poet.song.159000.json','["十載龐居士，一朝裴晉公。", "宣威先抗虜，決策竟和戎。", "宥密行誰尼，規恢事已空。", "灰心更霜鬢，千載泣英雄。"]'),
('f65539e6-8b51-4627-b4ae-2e7d8f0b331c','丘文定公挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','處事拘攣外，鉏姦談笑中。',48,'全唐诗/poet.song.159000.json','["處事拘攣外，鉏姦談笑中。", "幾年亡主將，全蜀頼明公。", "畏愛盾衰日，清和夷惠風。", "屢書終不盡，詩意亦何窮。"]'),
('6cf1cbc8-5aba-4581-a82b-0bd02589a4fa','丘文定公挽詞  其五','樓鑰','宋','宋诗','song-poetry','','[]','同與隆興第，嘉禾見兩轓。',48,'全唐诗/poet.song.159000.json','["同與隆興第，嘉禾見兩轓。", "瀛壖迂使節，蜀道送行軒。", "預草前鬚詔，驚傳易簀言。", "不堪鸞鏡舞，雙旐愴丘原。"]'),
('64eb2701-50c9-45da-bd23-acea080a165d','觀文殿學士趙公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','千古盛周宗，皇朝實比隆。',48,'全唐诗/poet.song.159000.json','["千古盛周宗，皇朝實比隆。", "位多窮貴爵，誰見立王功。", "一語國先定，寸心天與通。", "龍飛稽事實，信史詔無窮。"]'),
('ef4889d8-098d-49ba-bce1-fe74cc58ca2e','觀文殿學士趙公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','授受唐虞際，從容平勃閒。',48,'全唐诗/poet.song.159000.json','["授受唐虞際，從容平勃閒。", "宗英誰柄用，人望屬槔閒。", "晚侍經闈讀，寖登規殿班。", "帝鄉留不住，歸去老湖山。"]'),
('e2f8f453-7e9f-4691-85ca-8345e48f7638','觀文殿學士趙公挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','麾節稱循吏，三朝藹政聲。',48,'全唐诗/poet.song.159000.json','["麾節稱循吏，三朝藹政聲。", "治如黄霸最，心慕伯夷清。", "諸道俱遺愛，兩川尤著名。", "起家臨制閫，更羨錦衣榮。"]'),
('2859ef88-c91e-4058-b51f-f93a5f296c63','觀文殿學士趙公挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','皇上初更化，追鋒詔語溫。',48,'全唐诗/poet.song.159000.json','["皇上初更化，追鋒詔語溫。", "同看三老起，今歎一身存。", "別久勞魂夢，人亡濺淚痕。", "從茲歸故隠，舊事與誰論。"]'),
('8215d31f-1cc1-43a4-9830-84a848f82a59','觀文殿學士趙公挽詞  其五','樓鑰','宋','宋诗','song-poetry','','[]','殄瘁人俱駭，伊余獨永歎。',48,'全唐诗/poet.song.159000.json','["殄瘁人俱駭，伊余獨永歎。", "十年交義重，五日舊盟寒。", "求去重維縶，欲歸無羽翰。", "佳城何處是，東盼涕汍瀾。"]'),
('3527057d-98c1-40ea-8883-9faffa30dc35','觀文殿學士趙公挽詞  其六','樓鑰','宋','宋诗','song-poetry','','[]','聽履領簪纓，忠言徹帝庭。',48,'全唐诗/poet.song.159000.json','["聽履領簪纓，忠言徹帝庭。", "公方扶日月，我亦寄雷霆。", "憂世形詞色，卧家存典刑。", "靈光更陳迹，楚些不堪聽。"]'),
('39aaca0b-a40a-41c9-879b-2d6d05d53412','婁忠簡公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','壯歲志先定，耆年氣不衰。',48,'全唐诗/poet.song.159000.json','["壯歲志先定，耆年氣不衰。", "治高爲縣日，名重佐州時。", "雅望登朝著，忠言徹帝墀。", "亨途日千里，闊步不容遲。"]'),
('3f30d791-fca6-4c7b-a49b-7d91f6cfcb44','婁忠簡公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','邊事釁初開，惟公論不回。',48,'全唐诗/poet.song.159000.json','["邊事釁初開，惟公論不回。", "深謀比婁敬，極力阻王恢。", "兒戲何堪用，冰山忽已摧。", "朝廷始更化，大老盍歸來。"]'),
('3cd39d82-9a1c-4a4d-8eaa-fcdd62af3d1e','婁忠簡公挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','共政三年久，蜚英四海尊。',48,'全唐诗/poet.song.159000.json','["共政三年久，蜚英四海尊。", "色詞無假借，風裁靡囂喧。", "但欲持公道，寧容啟幸門。", "經綸終未究，猶有典刑存。"]'),
('0a2ba813-51e1-4fd9-baab-afae6233a59a','婁忠簡公挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','寮寀侍儲闈，如公久任稀。',48,'全唐诗/poet.song.159000.json','["寮寀侍儲闈，如公久任稀。", "載欣商皓起，終惜漢疏歸。", "問字煩參訂，談經頼發揮。", "一書真總要，星日重光輝。"]'),
('39a05b4d-3c20-49db-b772-0e205bcc9667','婁忠簡公挽詞  其五','樓鑰','宋','宋诗','song-poetry','','[]','得姓共東樓，同朝兩故侯。',48,'全唐诗/poet.song.159000.json','["得姓共東樓，同朝兩故侯。", "文編叨二序，誕日頌千秋。", "老矣俱宜去，公乎不少留。", "來書墨猶濕，展讀淚空流。"]'),
('885a113c-9fe6-4359-8302-b518b38319f2','少保李公挽詞','樓鑰','宋','宋诗','song-poetry','','[]','戚閈疏恩厚，勳門積慶餘。',48,'全唐诗/poet.song.159000.json','["戚閈疏恩厚，勳門積慶餘。", "弓彎飛將臂，架插鄴侯書。", "六纛秦官重，三槐漢相如。", "惜哉終半百，聞者爲欷歔。"]'),
('3a6358b2-211f-4f74-b56d-1a19b33bb767','王忠文公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','夙負敢言氣，輸忠不愛身。',48,'全唐诗/poet.song.159000.json','["夙負敢言氣，輸忠不愛身。", "劉蕡仍遇主，綺季更憂民。", "治行真循吏，風稜古爭臣。", "薦紳千載恨，不得究經綸。"]'),
('936491ae-8dfe-4140-86df-4cf39bb784e2','王忠文公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','梁木今其壤，誰能問大鈞。',48,'全唐诗/poet.song.159000.json','["梁木今其壤，誰能問大鈞。", "恩深兩宮賻，哀動四州民。", "已矣天人策，傷哉社稷臣。", "吾生良可耻，不及見斯人。"]'),
('05a6703f-c00d-4a95-ba1b-e7c647a5adaa','端明殿學士汪公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','制閫詩書帥，公朝侍從臣。',48,'全唐诗/poet.song.159000.json','["制閫詩書帥，公朝侍從臣。", "身能全進退，人可得疎親。", "曳履聲猶在，持衡迹遂陳。", "從今幾百載，更復見斯人。"]'),
('a1bf0639-e4f6-4f31-9704-e33a46bd4962','端明殿學士汪公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','蚤歲聲名大，婆娑始遇時。',48,'全唐诗/poet.song.159000.json','["蚤歲聲名大，婆娑始遇時。", "難兄屏隔坐，令子桂芳枝。", "人望還爲用，天胡不憗遺。", "成蹊堪喻大，墮淚不須碑。"]'),
('9b56279b-4dd2-4306-8dae-0e08e6c0eebe','端明殿學士汪公挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','道學不盡試，功名祇緒餘。',48,'全唐诗/poet.song.159000.json','["道學不盡試，功名祇緒餘。", "立朝惟正色，薦士有遺書。", "百贖嗟無及，九京誰與居。", "莫酬推轂意，衰涕濕巾裾。"]'),
('1d0c50b4-2a95-4598-ae17-6c79831b6c08','錢殿撰挽詞  其一','樓鑰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','雋譽蜚庠校，孤忠動冕旒。',48,'全唐诗/poet.song.159000.json','["雋譽蜚庠校，孤忠動冕旒。", "捄荒心欲折，憂國鬢先秋。", "惠滿長江水，風清八詠樓。", "禁途交一臂，人物等閑休。"]'),
('7ff4d9a0-dab1-4a15-96ba-492ba8693491','錢殿撰挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','枌社歸來晚，翛然得故吾。',48,'全唐诗/poet.song.159000.json','["枌社歸來晚，翛然得故吾。", "哦詩頻刻燭，點易細研朱。", "有淚悲連璧，無階奠束芻。", "名門餘慶遠，丹穴看奇雛。"]'),
('6f7e555c-eca8-4063-97c6-aa55fcde93cd','趙待制挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','明主晝三接，清班歲九遷。',48,'全唐诗/poet.song.159000.json','["明主晝三接，清班歲九遷。", "一居周柱史，徑入漢甘泉。", "批敕嚴東省，掄材上小天。", "平生經國志，惜不冠貂蟬。"]'),
('fc3c8516-2392-4224-aafe-7e6836d1ce83','趙待制挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','詩近劉賓客，手追歐率更。',48,'全唐诗/poet.song.159000.json','["詩近劉賓客，手追歐率更。", "雙旌古良吏，萬卷老書生。", "世諦浮雲薄，生緣曉夢驚。", "吁嗟東向議，何日遂施行。"]'),
('8c14fe3b-8f27-4055-960f-a95aef3233f4','趙待制挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','半世誰知己，登門意氣傾。',48,'全唐诗/poet.song.159000.json','["半世誰知己，登門意氣傾。", "交情忘父行，文會忝余盟。", "持論先忠厚，談經歎老成。", "幽光誰爲發，落筆淚縱橫。"]'),
('d8a67d05-50a7-4bc3-a145-3f0bb3259fa9','端明殿學士王公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','片言寤主上亨途，幾向專城佩左魚。',64,'全唐诗/poet.song.159000.json','["片言寤主上亨途，幾向專城佩左魚。", "羊陸遐衝雖坐折，高文宿憤竟誰攄。", "平時屢草千言奏，垂絕猶騰八難書。", "漢殿履聲今已矣，兩州遺老倍欷歔。"]'),
('7518e773-64b8-4a46-b1e5-b9ced3a2e16a','端明殿學士王公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','短檠鐵研用功深，萬卷蟠胸不輟吟。',64,'全唐诗/poet.song.159000.json','["短檠鐵研用功深，萬卷蟠胸不輟吟。", "故國遁身來濟岱，壯年發藻向儒林。", "愛民利物平生事，憂國忘家一片心。", "史館頃年陪潤色，挽公無路涕盈襟。"]'),
('c35e2171-aa26-42b9-a7e9-3a63e9bff7d5','尚書尤公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','敏甚五行下，豪釐耻不知。',48,'全唐诗/poet.song.159000.json','["敏甚五行下，豪釐耻不知。", "千人揮筆陣，萬卷納須彌。", "有夏傳追蠡，先秦拾斷碑。", "鄴侯書插架，分付稱家兒。"]'),
('4b7bf698-9bab-4428-bd99-a6d623285850','尚書尤公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','憂國言多切，回天力有餘。',48,'全唐诗/poet.song.159000.json','["憂國言多切，回天力有餘。", "衆推真學士，上念老尚書。", "直道終難進，高懷只遂初。", "梁溪釣游處，此意竟何如。"]'),
('48c886a7-12eb-4fb9-87b5-267d4a267ef1','尚書尤公挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','舊學方登用，公來領從臣。',48,'全唐诗/poet.song.159000.json','["舊學方登用，公來領從臣。", "末光依日月，聽履上星辰。", "共政將圖舊，騰章屢乞身。", "甘盤終罔顯，雨露未霑新。"]'),
('46a710e6-c90b-4ddf-a7c6-f8412794d318','尚書尤公挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','北面願師承，東臺拜老成。',48,'全唐诗/poet.song.159000.json','["北面願師承，東臺拜老成。", "忘年容末至，敘契若平生。", "風月吟千首，雷霆寄一名。", "送車無路到，寒涕爲君傾。"]'),
('bac760cc-a406-4844-976a-53974f0582a6','程文簡公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','論著大哉堯，英聲早已昭。',48,'全唐诗/poet.song.159000.json','["論著大哉堯，英聲早已昭。", "橫飛欽遠業，特立仰高標。", "言議超千載，風猷聳四朝。", "惜乎經世學，不及珥金貂。"]'),
('450d59a7-161f-4b9d-918c-3b1843631389','程文簡公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','太上崇耆舊，龍鱗手可攀。',48,'全唐诗/poet.song.159000.json','["太上崇耆舊，龍鱗手可攀。", "胡爲遯荒野，竟復老商山。", "漢閣頒綸渥，瀛壖擁旆還。", "靈光遂陳迹，西望涕空潸。"]'),
('9186e15a-ca15-4639-803f-efcfff23bdfc','程文簡公挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','設卦探羲畫，隨山究禹謨。',48,'全唐诗/poet.song.159000.json','["設卦探羲畫，隨山究禹謨。", "仰天真見象，畫地可成圖。", "健筆凌前輩，殘膏浹萬夫。", "登門嗟最晚，猶得覘宏摹。"]'),
('78467c9a-f69b-4f51-9c85-a7e723e4d47c','吳待制挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','御史再乘驄，忠言沃帝聰。',48,'全唐诗/poet.song.159000.json','["御史再乘驄，忠言沃帝聰。", "處心平似水，疾惡迅如風。", "遇合嗟何晚，論思信有功。", "惜哉辛佐治，竟不到三公。"]'),
('46f3ad2a-4326-41e7-9c2e-4ae6ea20b119','吳待制挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','三仕入儲闈，堂堂夾日飛。',48,'全唐诗/poet.song.159000.json','["三仕入儲闈，堂堂夾日飛。", "初同四皓起，終作二疎歸。", "冰玉清班近，衣冠盛事稀。", "間居忽仙去，西望是邪非。"]'),
('e997f569-e4d7-4af1-b9dc-0155517df6eb','吳待制挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','東甬與賓興，文闈頼主盟。',48,'全唐诗/poet.song.159000.json','["東甬與賓興，文闈頼主盟。", "菲葑無下體，衣鉢有門生。", "劍佩今何處，樽罍空復情。", "自慙無報所，老淚爲君傾。"]'),
('c32d9e17-30ef-41e8-bc5a-34f9ae967769','王給事挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','主眷逢千載，寵光傾一時。',48,'全唐诗/poet.song.159000.json','["主眷逢千載，寵光傾一時。", "銓曹著官簿，禁掖粲英辭。", "論議推東省，威聲憺北夷。", "平生經世意，懷卷竟何之。"]'),
('8529304a-0cc8-44f0-b7c4-531622867110','王給事挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','宦學素稱豪，仍聞吏事高。',48,'全唐诗/poet.song.159000.json','["宦學素稱豪，仍聞吏事高。", "精神雖腹滿，撫字亦心勞。", "藩輔連三組，沉痾見二毛。", "胡牀庾樓在，殘月墮江皋。"]'),
('12ccc124-96a9-4cf3-844a-1cce9f517943','王給事挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','自忝年家好，居慙雌甲辰。',48,'全唐诗/poet.song.159000.json','["自忝年家好，居慙雌甲辰。", "賓興蒙異奬，客授喜同寅。", "別去時無幾，年來意益親。", "囿山觴詠地，回首重沾巾。"]'),
('3bbf1d82-5210-4e93-801d-b1e79ee682e0','顔侍郎挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','宴坐勿菴上，睎顔亦是顔。',48,'全唐诗/poet.song.159000.json','["宴坐勿菴上，睎顔亦是顔。", "平心真似水，立說信如山。", "屢擁皇華節，盍登清禁班。", "始終無玷闕，風裁許誰攀。"]'),
('df9b4fcf-4a81-4ab2-af1d-3b03cda3baa9','顔侍郎挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','祿養嗟無及，朝朝飯一僧。',48,'全唐诗/poet.song.159000.json','["祿養嗟無及，朝朝飯一僧。", "移忠躬蹇蹇，錫類日烝烝。", "賦政優吳郡，知賢仰阜陵。", "清忠與公恕，餘慶啟昆仍。"]'),
('e4d6f310-388e-4e1e-862b-4ffe93ab499a','顔侍郎挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','贅倅丹丘日，眼看康濟泉。',48,'全唐诗/poet.song.159000.json','["贅倅丹丘日，眼看康濟泉。", "同朝叨奬予，侍坐得周旋。", "妙畫多傳寶，遺文合細編。", "典刑今已矣，西望涕潸然。"]'),
('f208bc85-389b-4fa7-a078-84b7aadd6dd8','陳文懿公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','衆口推文伯，何人識吏師。',48,'全唐诗/poet.song.159000.json','["衆口推文伯，何人識吏師。", "義襟惟古有，心地只天知。", "至死終無玷，平生本不欺。", "在公亡可憾，猶恨哲人萎。"]'),
('3e02ec16-0ac3-4b95-ac13-0dbe1419d59a','陳文懿公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','文最宜爲誥，尤能簡上心。',48,'全唐诗/poet.song.159000.json','["文最宜爲誥，尤能簡上心。", "周旋鑾掖久，惆悵玉堂深。", "去國身仍遠，還朝病已侵。", "三山風引去，雲海竟沉沉。"]'),
('b04a7b15-6357-4414-bd7a-a36233d6fd8d','陳文懿公挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','珍館徑歸鄞，人猶望秉鈞。',48,'全唐诗/poet.song.159000.json','["珍館徑歸鄞，人猶望秉鈞。", "郵傳千里訃，哀動五州民。", "躃踴森賢嗣，攀號感路人。", "公乎不亡矣，衮衮看簪紳。"]'),
('964b35c6-ae3d-404b-9a16-b36c4d0bddb1','陳文懿公挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','宅相惟公久，伊余忝後塵。',48,'全唐诗/poet.song.159000.json','["宅相惟公久，伊余忝後塵。", "十年追桂籍，兩禁踵詞臣。", "接武參吾舅，承顔奉老親。", "幸成三學士，何意失斯人。"]'),
('c68f9512-9b8b-47fc-b37e-6dea86765936','陳文懿公挽詞  其五','樓鑰','宋','宋诗','song-poetry','','[]','一別屢經歲，歸舟已及門。',48,'全唐诗/poet.song.159000.json','["一別屢經歲，歸舟已及門。", "方期情話悅，空訝語音存。", "善行傳千載，蕪詞媿九原。", "傷心歌楚些，無地可招魂。"]'),
('07566489-3781-4517-b546-a9fad50a96c7','端明殿學士張公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','天分已高明，樂哉賢父兄。',48,'全唐诗/poet.song.159000.json','["天分已高明，樂哉賢父兄。", "勳名希葛亮，問學本諸程。", "襟滿英雄淚，琴亡手足情。", "相從九泉下，何處覓三英。"]'),
('6f004f75-764a-4829-a24d-95fe787ff927','端明殿學士張公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','籍甚張京兆，精神滿腹中。',48,'全唐诗/poet.song.159000.json','["籍甚張京兆，精神滿腹中。", "才高解牛刃，手敏運斤風。", "河滸恩波遠，廛間狡穴空。", "章臺舊時柳，無復映金狨。"]'),
('21cd3f10-a51c-4bfc-a95c-766e77086a17','端明殿學士張公挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','英略古無對，外庸今最良。',48,'全唐诗/poet.song.159000.json','["英略古無對，外庸今最良。", "衆方期共政，人已歎云亡。", "不聽尚書履，猶懷太守章。", "康廬星忽墮，丹旐裊清湘。"]'),
('13643d74-1359-454a-8397-9deee5efdae6','端明殿學士張公挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','昔幸參朝列，於公更有連。',48,'全唐诗/poet.song.159000.json','["昔幸參朝列，於公更有連。", "規橅包世界，風義薄雲天。", "送別詩猶在，貽書墨尚鮮。", "偉人無復見，惟務寶青氈。"]'),
('c755f899-8746-4a6f-8ec3-b5ff8d01dbbf','仲舅敷文閣學士汪公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','籍甚牢之舅，難追宅相風。',48,'全唐诗/poet.song.159000.json','["籍甚牢之舅，難追宅相風。", "惟公能愛我，獨我最知公。", "潭府書無繼，西州事已空。", "形容盡心力，庶或慰幽宮。"]'),
('ea7248bf-9fef-44a5-acee-abc687baed8b','仲舅敷文閣學士汪公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','外氏桂成叢，諸甥長養中。',48,'全唐诗/poet.song.159000.json','["外氏桂成叢，諸甥長養中。", "名稱無酷似，宦達偶相同。", "澹室既長往，適齋俄考終。", "絕憐三學士，只賸一衰翁。"]'),
('0db0602d-10e0-4b13-96ce-7b46eee63529','楊待制挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','望重威無怒，仁深勇有餘。',48,'全唐诗/poet.song.159000.json','["望重威無怒，仁深勇有餘。", "百年憂國志，滿篋薦賢書。", "德政不勝載，才猷未盡攄。", "佳兒人物似，真可大門閭。"]'),
('802c0434-5bce-4f56-9c62-c111f29a4238','楊待制挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','蜀道名天險，馳驅敢憚勞。',48,'全唐诗/poet.song.159000.json','["蜀道名天險，馳驅敢憚勞。", "劍頭懸六印，夢裏益三刀。", "漢殿聯簪橐，燕山擁節旄。", "惜哉覘國意，不得試龍韜。"]'),
('f870939d-f94a-4c0c-a343-3f69ef6d7bd5','楊待制挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','蜀用東南彥，皇家屬意深。',48,'全唐诗/poet.song.159000.json','["蜀用東南彥，皇家屬意深。", "貳卿頻報政，上相最知心。", "泛宅俱杭葦，同朝擬斷金。", "廟廊期引類，疾病兩侵尋。"]'),
('839526d0-a0da-47b8-959b-90916931aa0f','楊待制挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','事契因同薦，交情晚益親。',48,'全唐诗/poet.song.159000.json','["事契因同薦，交情晚益親。", "半生文會少，萬里宦游頻。", "別後書猶濕，歸來迹遽陳。", "何能發潜德，空有淚霑巾。"]'),
('c52a49a7-4731-4970-bb1e-59af05b141c6','沈憲敏公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','天使魁鄉薦，上令卿改官。',48,'全唐诗/poet.song.159000.json','["天使魁鄉薦，上令卿改官。", "蚤峩烏府豸，終著侍臣冠。", "持節威行惠，專城猛濟寬。", "紹熙多舊學，胡不相宮端。"]'),
('90b130e0-9243-4b80-9dba-86d315a0aca2','沈憲敏公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','仕宦接王楊，諸公嘆老蒼。',48,'全唐诗/poet.song.159000.json','["仕宦接王楊，諸公嘆老蒼。", "門生多紫禁，子舍屢黄堂。", "自得垂車樂，誰傳却老方。", "桃花千樹滿，空憶舊劉郎。"]'),
('981f050a-69bf-4968-b903-50edd16a580f','沈憲敏公挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','徐邈今非介，申棖焉得剛。',48,'全唐诗/poet.song.159000.json','["徐邈今非介，申棖焉得剛。", "立朝無附麗，受謫更芬香。", "戲綵衣冠盛，圍棋日月長。", "典刑今已矣，無復巋靈光。"]'),
('b60949df-e9a2-4a42-bb26-a77284b3f66e','沈憲敏公挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','持論真遺直，操心本至公。',48,'全唐诗/poet.song.159000.json','["持論真遺直，操心本至公。", "贏貲寧市寵，平寇不言功。", "光祿文階峻，嘉興色養豐。", "誰能死生際，猶得教之忠。"]'),
('1c187c21-99f8-42db-add9-1db7b1e7d877','沈憲敏公挽詞  其五','樓鑰','宋','宋诗','song-poetry','','[]','晚出荷公知，登門未覺遲。',48,'全唐诗/poet.song.159000.json','["晚出荷公知，登門未覺遲。", "通班依漢橐，試郡守蕭規。", "藻翰猶頻寄，宮牆不再窺。", "新阡何處是，西望不勝悲。"]'),
('bbe3eafe-b027-4bcd-977c-b397ad05dca3','尚書湯公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','先正真良弼，彤墀四拜麻。',48,'全唐诗/poet.song.159000.json','["先正真良弼，彤墀四拜麻。", "決科承奕世，摛藻擅傳家。", "禁路優持橐，侯藩幾建牙。", "相門宜出相，恨不見隄沙。"]'),
('486867b4-6ea3-48f4-a264-3eee29a64bae','尚書湯公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','奏邸崇先契，周旋古括州。',48,'全唐诗/poet.song.159000.json','["奏邸崇先契，周旋古括州。", "殿庭觀唱第，海郡繼承流。", "方快飛騰上，俄聞汗漫游。", "鳳凰山下路，丹旆想悠悠。"]'),
('228db4b5-99bc-48ad-8766-ee07933fdf3a','商侍郎挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','矯矯真御史，風生白筆端。',48,'全唐诗/poet.song.159000.json','["矯矯真御史，風生白筆端。", "出持膚使節，始著侍臣冠。", "給饟鬢先雪，籌邊心爲寒。", "天乎驚玉折，不及上金鑾。"]'),
('08b09078-d476-4aef-85e6-7551328a998e','商侍郎挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','所至仁聲著，甘棠幾去思。',48,'全唐诗/poet.song.159000.json','["所至仁聲著，甘棠幾去思。", "敬姜嗟哭子，伯道痛無兒。", "郎省傷連璧，文闈見刻辭。", "邊民紛墮淚，忍讀峴山碑。"]'),
('10853f10-b8ab-48b2-b930-3f91921bfd5f','尚書張公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','文靖饒風度，高皇記曲江。',48,'全唐诗/poet.song.159000.json','["文靖饒風度，高皇記曲江。", "賢孫真是似，才氣號無雙。", "幾見持英簜，終看擁碧幢。", "誠齋主詩社，到此亦心降。"]'),
('1603cb88-727c-41ea-978d-c57ebd62bee3','尚書張公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','撫字推循吏，論思領從班。',48,'全唐诗/poet.song.159000.json','["撫字推循吏，論思領從班。", "宏才名北闕，高興屬東山。", "同歲叨崇篤，比鄰足往還。", "舊游成昨夢，衰涕不勝潸。"]'),
('ecfa029a-ab34-45f5-9f07-8ebcc01a1a61','曾侍郎挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','文獻南豐裔，源流曲阜公。',48,'全唐诗/poet.song.159000.json','["文獻南豐裔，源流曲阜公。", "巖巖雙法從，凜凜舊家風。", "金玉方交映，人琴忽併空。", "平生心地直，流慶尚無窮。"]'),
('286c3b23-7081-4ddc-bd23-75f88aae323f','曾侍郎挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','紫陌尋春日，惟公最少年。',48,'全唐诗/poet.song.159000.json','["紫陌尋春日，惟公最少年。", "鱣堂慙隗始，熊軾媿盧前。", "寄我書猶濕，思君迹遽僊。", "同登今有幾，揮淚撫遺編。"]'),
('09bc76c5-f0f4-4452-99c9-68b9d8e92835','余給事挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','烏府仍螭陛，銀臺更掖垣。',48,'全唐诗/poet.song.159000.json','["烏府仍螭陛，銀臺更掖垣。", "事幾無弗論，外似不能言。", "厚德鎮浮薄，平心剸劇煩。", "用才殊未盡，無地可招魂。"]'),
('37c48f54-06ad-405b-959a-260254477494','余給事挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','桂籍兄聯弟，蘭階子克家。',48,'全唐诗/poet.song.159000.json','["桂籍兄聯弟，蘭階子克家。", "上恩嘉踵武，京秩爲增華。", "朝著蒙傾蓋，綸闈覩判花。", "遽成千古別，南望想悲笳。"]'),
('f8ee7c7b-4878-40c0-ba71-3469afd2e399','鄭司法挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','襟袍空無礙，精神老不衰。',48,'全唐诗/poet.song.159000.json','["襟袍空無礙，精神老不衰。", "家傳司業學，句逼簡齋詩。", "荒瘠留陰德，平反有去思。", "功名賫志沒，回施稱家兒。"]'),
('2e93d4fb-468a-4a93-a42c-28cff90b8257','鄭司法挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','傾蓋歡如故，相從滄海隅。',48,'全唐诗/poet.song.159000.json','["傾蓋歡如故，相從滄海隅。", "方將理詩社，忽已閟泉途。", "歸路孤飛旐，交情一束芻。", "梅霖將客淚，淒澹灑平蕪。"]'),
('956f3d10-bcce-4307-928c-d24b52ef4cd8','梁仲蒼挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','延賞高三讓，殊科擅一鳴。',48,'全唐诗/poet.song.159000.json','["延賞高三讓，殊科擅一鳴。", "元賓文未極，長吉記先成。", "妙語遺膏馥，玄談悟死生。", "行人痛埋璧，父子若爲情。"]'),
('c3364be4-3094-4463-aa77-fa7698c6716d','梁仲蒼挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','人物如君少，相期上石渠。',48,'全唐诗/poet.song.159000.json','["人物如君少，相期上石渠。", "博文該四部，篤學富三餘。", "淚盡知無及，交深未覺疎。", "何時酹墳草，細讀茂陵書。"]'),
('b781e3fc-d486-4123-8c5c-2fc4a67eba45','吳通判挽詞','樓鑰','宋','宋诗','song-poetry','','[]','一死交情見，鄉評重此翁。',48,'全唐诗/poet.song.159000.json','["一死交情見，鄉評重此翁。", "素車奔夕夢，繡被落天風。", "身任朋僚責，心忘尺寸功。", "毋書卓行傳，非介亦非通。"]'),
('565ca8c9-18ca-4b41-9089-739a86620783','翁府君挽詞','樓鑰','宋','宋诗','song-poetry','','[]','骯髒翁夫子，高才噤不施。',48,'全唐诗/poet.song.159000.json','["骯髒翁夫子，高才噤不施。", "床頭癡叔易，夢裏阿連詩。", "德喪嗟何及，天胡弗憗遺。", "清風終未泯，吹拆謝庭芝。"]'),
('e0a89fd4-f7df-49f3-9cc3-64ea75300b76','徐府君挽詞','樓鑰','宋','宋诗','song-poetry','','[]','孺子人如玉，功名不在身。',48,'全唐诗/poet.song.159000.json','["孺子人如玉，功名不在身。", "死生齊物外，孝友篤天倫。", "已有傳家子，曾充觀國賓。", "他年芳五桂，傷不見靈椿。"]'),
('d92522d9-3880-4811-9f59-2c6b8cd27471','陳崇道挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','學造龜山藴，詩傳汝水餘。',48,'全唐诗/poet.song.159000.json','["學造龜山藴，詩傳汝水餘。", "于公足陰德，陶令竟閑居。", "白業追蓮社，丹經授寢虛。", "平生了無恨，善類勿欷歔。"]'),
('3a7c4661-3c6f-46c4-b196-5e746b01757f','陳崇道挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','未第聲先振，纔官節已奇。',48,'全唐诗/poet.song.159000.json','["未第聲先振，纔官節已奇。", "精誠與神合，隠行畏人知。", "晚境終無玷，遺文尚可師。", "功名齎志歿，回施稱家兒。"]'),
('4868d006-4f1a-4ea3-9c2f-bf63b0a40f7b','魯少卿挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','棣萼儀鴛綴，翛然兩鬢斑。',48,'全唐诗/poet.song.159000.json','["棣萼儀鴛綴，翛然兩鬢斑。", "時清嗟歲晚，游倦得身閑。", "人在羲皇上，經傳伯仲間。", "桂枝芳未已，何止倍燕山。"]'),
('f98d01b7-113b-42d2-92ea-82348ec87cb3','魯少卿挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','前輩風流泯，靈光獨巋然。',48,'全唐诗/poet.song.159000.json','["前輩風流泯，靈光獨巋然。", "指囷推甲族，跪履記丁年。", "有子傷埋璧，惟翁亦蛻蟬。", "功名雖已矣，千載尚遺編。"]'),
('28afbf09-43fa-4e7f-a51d-c3c354d7cd8a','魏監丞挽詞','樓鑰','宋','宋诗','song-poetry','','[]','元老餘風烈，優游挹美官。',48,'全唐诗/poet.song.159000.json','["元老餘風烈，優游挹美官。", "朝行喜銀艾，鄰好許金蘭。", "醫謾肱三折，生惟指一彈。", "難兄秋夜感，風雨舊盟寒。"]'),
('878fd08c-aa9c-41ad-89f1-8d9512c8dec8','族兄道州挽詞','樓鑰','宋','宋诗','song-poetry','','[]','出守舂陵遠，相思瀟水深。',48,'全唐诗/poet.song.159000.json','["出守舂陵遠，相思瀟水深。", "精神雖滿腹，撫字亦勞心。", "人去成千古，書來失萬金。", "懷哉季公諾，已矣漢碑陰。"]'),
('3d962a3d-d586-4681-8e10-92b96c4026d1','周太博挽詞','樓鑰','宋','宋诗','song-poetry','','[]','雨漲雙溪水，風高五柳堂。',48,'全唐诗/poet.song.159000.json','["雨漲雙溪水，風高五柳堂。", "論交成莫逆，撫事祇堪傷。", "訪雪無回櫂，面山空夕陽。", "亂鶑穿綠樹，誰復爲傳觴。"]'),
('5985bab5-08f3-45d2-90fd-15071a2531f8','碩人居氏挽詞','樓鑰','宋','宋诗','song-poetry','','[]','頃侍尚書坐，曾聞閫助賢。',48,'全唐诗/poet.song.159000.json','["頃侍尚書坐，曾聞閫助賢。", "晤言成勇退，裏謁戒私專。", "夢斷松江路，神傷薤露篇。", "悼亡千里淚，疊嶂想新阡。"]'),
('ce6b03db-313a-4690-9646-6393ad3ddfc6','扶風馬君挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','閭里久湛浮，真成馬少游。',48,'全唐诗/poet.song.159000.json','["閭里久湛浮，真成馬少游。", "有才堪辦劇，無命盍歸休。", "雞唱言何達，鴻冥逝不留。", "佳城送君處，風撼白楊秋。"]'),
('8aa26cc3-b7ea-4eca-b0dc-7d9ee597c834','扶風馬君挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','豁野真連璧，一齋寧遺金。',48,'全唐诗/poet.song.159000.json','["豁野真連璧，一齋寧遺金。", "齊家平日學，憂世百年心。", "折券無難色，傾囷想義襟。", "月評何處見，名士列碑陰。"]'),
('0d764951-9baf-4fb4-824a-48dc6027a417','黄君挽詞','樓鑰','宋','宋诗','song-poetry','','[]','積慶源流遠，鄉評數大門。',48,'全唐诗/poet.song.159000.json','["積慶源流遠，鄉評數大門。", "吏才堪世用，心事與誰論。", "骯髒纔三徑，淒涼遽九原。", "傳家五男子，留眼看騰騫。"]'),
('f4c6623b-2903-49fd-8f01-8d5a75f5e267','陳祕撰挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','陳氏多名德，茲來慕典刑。',48,'全唐诗/poet.song.159000.json','["陳氏多名德，茲來慕典刑。", "宮端驚宿草，冷撰又泉扃。", "自古有遺直，祇今誰獨醒。", "蒼蒼何可問，耆舊日彫零。"]'),
('e2cdf0b9-46e4-4868-9410-2c1610846742','陳祕撰挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','跬步不忘孝，掇皮皆是真。',48,'全唐诗/poet.song.159000.json','["跬步不忘孝，掇皮皆是真。", "移忠思致主，務實見臨民。", "三諫言猶炳，平生迹遽陳。", "清風凜衰俗，自足盪秋旻。"]'),
('9353af02-6132-41f8-b003-530861fb3efa','徐季節挽詞','樓鑰','宋','宋诗','song-poetry','','[]','公府推徐穉，山陽薦仲車。',48,'全唐诗/poet.song.159000.json','["公府推徐穉，山陽薦仲車。", "盛時遺此老，沒世竟窮廬。", "行道嗟無命，傳家幸有書。", "魯山終不識，撫卷倍欷歔。"]'),
('92f16f30-2c78-4a5b-b0ba-4260dfe4816d','周德遠挽詞','樓鑰','宋','宋诗','song-poetry','','[]','家世傳儒業，鄉邦聳義風。',48,'全唐诗/poet.song.159000.json','["家世傳儒業，鄉邦聳義風。", "將迎無倦色，交友盡名公。", "太學飛聲早，浮生轉首空。", "怡如堂下月，猶照紫荆叢。"]'),
('6ce62637-e02d-4939-a4c0-7b5219a7373d','盧夫人挽詞','樓鑰','宋','宋诗','song-poetry','','[]','名族著崗頭，幽閨女教修。',48,'全唐诗/poet.song.159000.json','["名族著崗頭，幽閨女教修。", "良人驚夢蝶，衆子慕桑鳩。", "物化了難問，壼彜誰爲收。", "于公有佳兆，衮衮看公侯。"]'),
('c0b391b6-e536-44b1-842c-7c3d8fc8b83d','王夫人挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','閫內誰無助，夫人事特明。',48,'全唐诗/poet.song.159000.json','["閫內誰無助，夫人事特明。", "傾囊資色養，勉學就清名。", "遯世期高節，辭風歎落英。", "丁寧猶在耳，伉儷若爲情。"]'),
('5329ae5b-5a51-4f02-bbf8-9f41f9d770ae','王夫人挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','荆國風流遠，幽閨女教循。',48,'全唐诗/poet.song.159000.json','["荆國風流遠，幽閨女教循。", "鴒原驚逝水，鶴髮倍沾巾。", "厚夜招香魄，英詞列翠珉。", "祇愁書字拙，貽笑衛夫人。"]'),
('c055b931-8454-42a3-b6a9-4de574379485','鹿夫人挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','內外言無間，初終志不移。',48,'全唐诗/poet.song.159000.json','["內外言無間，初終志不移。", "白頭供婦職，彤管著賢規。", "慶衍珠三樹，芳先桂一枝。", "鳳岑歸去路，含笑不應悲。"]'),
('1ee23c73-dc3a-4c6b-8c87-88c96870c856','鹿夫人挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','慶霈疏封日，姑慈不忍違。',48,'全唐诗/poet.song.159000.json','["慶霈疏封日，姑慈不忍違。", "人方侈君賜，我獨避恩輝。", "孝篤神應勞，風高家愈肥。", "新傳快女壻，亦復掛冠歸。"]'),
('1a4e53d3-12d6-4e92-ada8-d447e269e0f5','旌表門閭安人陳氏挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','婦德高千古，鄉評徹九重。',48,'全唐诗/poet.song.159000.json','["婦德高千古，鄉評徹九重。", "柏舟終自誓，石窌啟新封。", "孫子傳清白，閨門慕肅雍。", "死生無憾處，了不媿三從。"]'),
('bbcac303-7789-4157-9d05-a233b0511ccd','旌表門閭安人陳氏挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','族姓朱陳盛，夫人事愈明。',48,'全唐诗/poet.song.159000.json','["族姓朱陳盛，夫人事愈明。", "老姑俱上壽，難弟各清名。", "節行輝彤管，門閭照赤城。", "寶鄰方有託，何忍送銘旌。"]'),
('146c7a77-c3cf-4748-af3b-35d1b591c8a9','孺人陳氏挽詞','樓鑰','宋','宋诗','song-poetry','','[]','追憶宮端舊典刑，三貞况復是難兄。',64,'全唐诗/poet.song.159000.json','["追憶宮端舊典刑，三貞况復是難兄。", "豈惟門戶生光彩，直使朝廷列姓名。", "煙海乘桴誰可奪，天風反火報尤明。", "雖云弟娣相從去，自有英靈凜若生。"]'),
('ccf20ef6-6610-4255-af01-3be3dd77649c','王通判挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','世篤青箱學，驊騮更著鞭。',48,'全唐诗/poet.song.159000.json','["世篤青箱學，驊騮更著鞭。", "半山分近派，巖壑誦新篇。", "竹馬迎雙舄，棠陰憶二天。", "黄扉伸讜論，風節尚翹然。"]'),
('dc8d3c14-ce44-48ef-948c-1df6b208f598','王通判挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','才具盍時用，拂衣俄去之。',48,'全唐诗/poet.song.159000.json','["才具盍時用，拂衣俄去之。", "善藏經世手，回施稱家兒。", "嬴博延陵恨，人琴子敬悲。", "連年事如許，天道杳難知。"]'),
('5d3c669a-81f8-4358-84d2-02d4f9e9f7d7','何司業挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','頃歲游孤嶼，名門說二何。',48,'全唐诗/poet.song.159000.json','["頃歲游孤嶼，名門說二何。", "胡爲終璧水，自合上鑾坡。", "器重連城價，心澄古井波。", "傳家衣鉢在，衮衮並儒科。"]'),
('38d49b66-44ff-49c2-9477-18dee8a626fc','何司業挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','骯髒陽司業，作州如理家。',48,'全唐诗/poet.song.159000.json','["骯髒陽司業，作州如理家。", "源流知有自，悃愊信無華。", "方喜亨途遠，俄驚暮景斜。", "傷心傾蓋舊，何處望東嘉。"]'),
('b230bbb7-7bc5-41fb-bc5a-7a6b9a337546','太碩人潘氏挽詞','樓鑰','宋','宋诗','song-poetry','','[]','玉映清心著壼彜，閨房賓敬到齊眉。',64,'全唐诗/poet.song.159000.json','["玉映清心著壼彜，閨房賓敬到齊眉。", "豈惟山水協高趣，更爲國家生好兒。", "萬口共推諸福備，八旬猶負一年期。", "伯仁冬日應腸斷，不見堂前舉酒時。"]'),
('c8822bfa-6e3e-47c7-aff9-7829b72b88e2','孺人曾氏挽詞','樓鑰','宋','宋诗','song-poetry','','[]','婉嫕應眉壽，天胡弗與齡。',48,'全唐诗/poet.song.159000.json','["婉嫕應眉壽，天胡弗與齡。", "情深孫楚詠，淚盡女挐銘。", "蘋藻空南澗，芝蘭有謝庭。", "越山埋璧處，秋雨濕銘旌。"]'),
('7b587768-c439-45b2-9a46-1c4751522033','孺人陳氏挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','教子推陶母，相望百代前。',48,'全唐诗/poet.song.159000.json','["教子推陶母，相望百代前。", "詩書經口授，名節誦家傳。", "藝苑高鴻筆，忠言徹細氈。", "源流知有自，何止父兄賢。"]'),
('c1e0318d-ded2-4087-8def-e420e713f780','孺人陳氏挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','令子齊年好，相從識壼彜。',48,'全唐诗/poet.song.159000.json','["令子齊年好，相從識壼彜。", "蕭生結綬日，孟母卜鄰時。", "未下升堂拜，俄聞陟屺悲。", "天涯致芻束，淚落薤歌辭。"]'),
('bec00756-a2c4-45cd-a669-2327bca0be3d','孺人林氏挽詞','樓鑰','宋','宋诗','song-poetry','','[]','家世甘泉舊，幽閨有令名。',48,'全唐诗/poet.song.159000.json','["家世甘泉舊，幽閨有令名。", "賢明教陶侃，勤苦佐淵明。", "蘋澗今何處，鳩桑空復情。", "誰知悼亡意，揮涕望佳城。"]'),
('7ec93e23-8015-4fe4-b79c-d73cdff60c2f','石南康挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','挺挺石可轉，恂恂衣不勝。',48,'全唐诗/poet.song.159000.json','["挺挺石可轉，恂恂衣不勝。", "平生憂國志，長夜讀書燈。", "大易窺三古，中庸進百能。", "惜哉天不憗，無復見川增。"]'),
('cf753fd8-a2a3-4106-a8ff-3ee51fcdad74','石南康挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','家有春秋學，淵源更得師。',48,'全唐诗/poet.song.159000.json','["家有春秋學，淵源更得師。", "風高蓋公舍，淚落蔡邕碑。", "官早終難進，才全竟弗施。", "遺編屬賢子，孝謹不應衰。"]'),
('48f115ad-ffb6-4ea7-8c54-e3b60fdc8c1d','石南康挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','伊昔爲君御，儒流頼主盟。',48,'全唐诗/poet.song.159000.json','["伊昔爲君御，儒流頼主盟。", "執經容後進，傾蓋若平生。", "坐見埋黄壤，空勞望赤城。", "友朋相與泣，反袂不勝情。"]'),
('65a3dc5e-07f1-40c0-9dc7-4a7fdc5e8f49','臧溫叟挽詞','樓鑰','宋','宋诗','song-poetry','','[]','白首行逾恭，鄉評敬此翁。',48,'全唐诗/poet.song.159000.json','["白首行逾恭，鄉評敬此翁。", "心開上池水，氣襲舞雩風。", "禮貌諸公厚，聲華一瞬空。", "臧孫知有後，三世著陰功。"]'),
('5194566c-8943-4f81-8255-a3fdf480080d','陸宣城挽詞','樓鑰','宋','宋诗','song-poetry','','[]','奕世承家學，諸公薦吏能。',48,'全唐诗/poet.song.159000.json','["奕世承家學，諸公薦吏能。", "政傳花縣美，心與練江澄。", "易簀去何遠，攀轅悲不勝。", "傷哉嬴博葬，淚盡老延陵。"]'),
('ac8f75ae-7e25-44c9-8f31-df35accbda58','戴縣丞挽詞','樓鑰','宋','宋诗','song-poetry','','[]','蚤歲鄉書薦弟兄，羨君再舉上青冥。',64,'全唐诗/poet.song.159000.json','["蚤歲鄉書薦弟兄，羨君再舉上青冥。", "藍田方欲新漫壁，處士寧知却應星。", "忍向伯高將束帛，誰從小戴授遺經。", "佳城得卜真前定，忍看一翁衰淚零。"]'),
('3ad19194-6b04-445f-b592-fd3cb77c785a','姜總管挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','及見開元盛，曾聞正始音。',48,'全唐诗/poet.song.159000.json','["及見開元盛，曾聞正始音。", "雕蟲徒壯歲，冠鶡豈初心。", "論事風生席，疏恩带錫金。", "精神空滿腹，愁絕病沈沈。"]'),
('a462a80b-0982-45f2-ae89-c5e9faf6972c','姜總管挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','富盛俄遭變，艱難却起家。',48,'全唐诗/poet.song.159000.json','["富盛俄遭變，艱難却起家。", "田園新活計，詩禮舊生涯。", "仙桂應傳秀，庭蘭更茁芽。", "真歸了無恨，超徹妙蓮華。"]'),
('251a9789-f62d-4094-901b-2da8de2e3c9d','胡監嶽挽詞','樓鑰','宋','宋诗','song-poetry','','[]','賦就八叉手，文高三折肱。',48,'全唐诗/poet.song.159000.json','["賦就八叉手，文高三折肱。", "青衫雙鬢雪，黄卷短檠燈。", "夢斷采芹水，神凄下馬陵。", "諸郎追五桂，洗眼看飛騰。"]'),
('09ef3db9-2bb8-4c11-b77b-20b6d6aa1417','余永彥挽詞','樓鑰','宋','宋诗','song-poetry','','[]','戶外諸生屨，門前長者車。',48,'全唐诗/poet.song.159000.json','["戶外諸生屨，門前長者車。", "柳袍空自染，瓶粟竟無儲。", "隠行刑宗黨，清風照里閭。", "沉冥誰爲表，頼有子雲書。"]'),
('1be88619-99d3-402a-9c39-eb5d971540f4','趙路鈴挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','蚤歲游金闕，霞冠拜紫宸。',48,'全唐诗/poet.song.159000.json','["蚤歲游金闕，霞冠拜紫宸。", "可堪天寶亂，及見會昌春。", "宛宛王孫態，飄飄物外身。", "靈光愴陳迹，遺老更何人。"]'),
('d493aeef-517c-4463-9e51-1bc91978ec8d','趙路鈴挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','諸父論交久，忘年許與盟。',48,'全唐诗/poet.song.159000.json','["諸父論交久，忘年許與盟。", "登山陪躡屐，泛月共飛觥。", "來往開三徑，安閑羨一生。", "山深淒薤露，愁憶醉歌聲。"]'),
('ffd75617-78a7-4380-a16d-f159e8202d3c','令人王氏挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','嫁早仍知孝，夫賢自不貧。',48,'全唐诗/poet.song.159000.json','["嫁早仍知孝，夫賢自不貧。", "事姑如事母，憂物勝憂身。", "鳳誥恩榮渥，鳩桑德意均。", "孺哀聲不絕，淚柏不成春。"]'),
('c633ef49-616e-42fd-b141-5d24745e5883','令人王氏挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','宦達方資助，家肥忽悼亡。',48,'全唐诗/poet.song.159000.json','["宦達方資助，家肥忽悼亡。", "一區終異室，千載尚高岡。", "奉倩神猶慘，安仁鬢欲蒼。", "黄昏愁絕處，誰伴紫微郎。"]'),
('a0a12782-8681-44ac-9e25-5a2099df7310','太淑人葉氏挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','婦職躬蘋澗，芳年誓柏舟。',48,'全唐诗/poet.song.159000.json','["婦職躬蘋澗，芳年誓柏舟。", "壼彜全肅睦，梵行極清修。", "貝葉開空性，神篦豁病眸。", "飄然指歸路，浄觀日西流。"]'),
('60337c1a-77ca-4484-8b6b-077f80c226f3','太淑人葉氏挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','爲國生賢子，三遷備母慈。',48,'全唐诗/poet.song.159000.json','["爲國生賢子，三遷備母慈。", "版輿崇色養，從櫜勉論思。", "戲舞老萊子，平反雋不疑。", "孝心天罔極，腸斷蓼莪詩。"]'),
('6b15befb-2eb9-4e14-8167-bad1800ae9a3','從姑太令人挽詞','樓鑰','宋','宋诗','song-poetry','','[]','伯祖八賢女，惟姑壽且康。',48,'全唐诗/poet.song.159000.json','["伯祖八賢女，惟姑壽且康。", "又聞歌薤露，誰復是靈光。", "采藻空南澗，生萱愴北堂。", "平生好心地，持以遺諸郎。"]'),
('6ba1cdea-d45c-4d94-87c3-9723a9c7dd17','太恭人劉氏挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','籍甚成天助，薰然藹婦容。',48,'全唐诗/poet.song.159000.json','["籍甚成天助，薰然藹婦容。", "家肥身愈約，福備禮彌恭。", "上壽九開秩，湛恩四受封。", "何人紀遺德，女壻正乘龍。"]'),
('fff7cf21-8ae0-4883-a12a-f99fd9349cd2','太恭人劉氏挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','衛氏一兒足，他人總不如。',48,'全唐诗/poet.song.159000.json','["衛氏一兒足，他人總不如。", "一麾欣義檄，千騎擁潘輿。", "台嶽傷歸旐，青山滿送車。", "佳城流慶遠，旁可萬家居。"]');
